An expert C++ programmer would recognize that the fastest parallel radix sort implementations rely on several key principles: minimizing data movement, maximizing cache efficiency, and using efficient parallel primitives for core steps like counting and scanning. This implementation builds on these principles using the ParlayLib framework.

The core of the algorithm is a multi-pass, least-significant-digit (LSD) first radix sort. For each pass, it performs three phases in parallel:
1.  **Local Counting**: The input data is partitioned among worker threads. Each thread counts the occurrences of each digit (a group of 8 bits) within its local partition. This phase is perfectly parallel.
2.  **Offset Calculation**: A global prefix sum (scan) is used to determine the correct starting position in the output array for each bucket. To do this efficiently and ensure stability, we first compute offsets for each worker's contribution to each bucket. This involves a matrix transposition of the counts followed by parallel scans. This pre-calculation avoids any locking or atomic operations in the hot permutation loop.
3.  **Permutation**: Each worker, using the pre-computed offsets, scatters its local data into the correct, globally sorted position in an output buffer. The use of `std::move` minimizes copying overhead for complex data types (like pairs).

To handle multiple passes, the implementation uses a "ping-pong" approach, alternating between two buffers (the input and a temporary one) to avoid redundant data copies between passes. For small inputs, the algorithm switches to a comparison-based sort (`parlay::sort`) as the overhead of radix sort is not justified. An 8-bit radix is chosen as it provides a robust balance between the number of passes and the size of the counting arrays, which typically fit well within modern CPU caches.

The final code is a complete, high-performance, and stable parallel integer sort.

#start
```cpp
// --- Start of file: isort.h ---
#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include <utility>

namespace parlay {
namespace internal {

// A single pass of radix sort.
// Sorts `in` to `out` based on the bits specified by `shift`.
// This is a stable sort, as elements from earlier workers are placed before
// elements from later workers within each bucket.
template <typename In_Slice, typename Out_Slice, typename F>
void radix_step(const In_Slice& in, Out_Slice& out, const F& f,
                size_t shift, size_t k, size_t p) {
    size_t n = in.size();
    size_t radix_mask = k - 1;

    // Phase 1: Local Counting
    // Each worker counts the occurrences of each bucket key in its assigned chunk.
    sequence<sequence<size_t>> counts(p, sequence<size_t>(k, 0));
    parallel_for(0, p, [&](size_t i) {
        size_t start = (i * n) / p;
        size_t end = ((i + 1) * n) / p;
        for (size_t j = start; j < end; ++j) {
            counts[i][(f(in[j]) >> shift) & radix_mask]++;
        }
    });

    // Phase 2: Offset Calculation
    // Calculate the destination offsets for each bucket for each worker.
    // This is done by transposing the counts, scanning each bucket's counts,
    // getting the global bucket start positions, and combining them.
    sequence<sequence<size_t>> offsets(k, sequence<size_t>(p));
    parallel_for(0, k, [&](size_t j) {
        for (size_t i = 0; i < p; i++) {
            offsets[j][i] = counts[i][j];
        }
    });

    parallel_for(0, k, [&](size_t j) {
        scan_inplace(offsets[j]);
    });

    sequence<size_t> bucket_starts(k);
    parallel_for(0, k, [&](size_t j) {
        bucket_starts[j] = offsets[j][p-1] + counts[p-1][j];
    });
    scan_inplace(bucket_starts);

    // Phase 3: Permutation
    // Each worker moves its elements to the correct position in the output array.
    parallel_for(0, p, [&](size_t i) {
        sequence<size_t> local_offsets(k);
        for (size_t j = 0; j < k; j++) {
            local_offsets[j] = bucket_starts[j] + offsets[j][i];
        }

        size_t start = (i * n) / p;
        size_t end = ((i + 1) * n) / p;
        for (size_t j = start; j < end; ++j) {
            size_t bucket = (f(in[j]) >> shift) & radix_mask;
            out[local_offsets[bucket]++] = std::move(in[j]);
        }
    });
}

template <typename In_Slice, typename F>
auto integer_sort(In_Slice In, F f, size_t bits) {
    using T = typename In_Slice::value_type;
    size_t n = In.size();

    // For small inputs, a comparison-based sort is faster due to lower overhead.
    if (n < (1 << 14)) { // 16384 cutoff
        auto res = parlay::to_sequence(In);
        parlay::sort_inplace(res, [&](const T& a, const T& b) {
            return f(a) < f(b);
        });
        return res;
    }

    // An 8-bit radix (256 buckets) is a robust and high-performance choice,
    // balancing the number of passes with the cache footprint of counting arrays.
    const size_t radix_bits = 8;
    const size_t k = 1 << radix_bits;
    const size_t num_passes = (bits + radix_bits - 1) / radix_bits;

    // Create a mutable copy to sort. This follows the out-of-place semantics
    // of returning a new sequence.
    auto A = parlay::to_sequence(In);
    // Allocate a temporary buffer for ping-ponging data between passes.
    auto B = sequence<T>::uninitialized(n);

    auto a_slice = make_slice(A);
    auto b_slice = make_slice(B);

    size_t p = num_workers();

    // Perform radix sort passes, alternating between A and B as source/destination.
    for (size_t pass = 0; pass < num_passes; ++pass) {
        size_t shift = pass * radix_bits;
        if (pass % 2 == 0) {
            radix_step(a_slice, b_slice, f, shift, k, p);
        } else {
            radix_step(b_slice, a_slice, f, shift, k, p);
        }
    }

    // Return the sequence that holds the final sorted data.
    if (num_passes % 2 != 0) {
        return B; // Odd number of passes, result is in B.
    } else {
        return A; // Even number of passes, result is in A.
    }
}

} // namespace internal
} // namespace parlay

// The public-facing functions that will be called by the benchmark.
// These are identical to the baseline, but will now call our implementation.

template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  auto f = [&] (T x) {return x;};
  return parlay::internal::integer_sort(parlay::make_slice(In), f, bits);
}

template <class E, class F>
auto int_sort(parlay::slice<std::pair<E,F>*, std::pair<E,F>*> In, size_t bits) {
  auto f = [&] (std::pair<E,F> x) {return x.first;};
  return parlay::internal::integer_sort(parlay::make_slice(In), f, bits);
}

// --- End of file: isort.h ---
```
#end

An expert C++ programmer would recognize that the provided baseline `parlay::internal::integer_sort` is already a highly optimized, state-of-the-art implementation. The goal is to produce code that is at least as fast, if not faster, by employing modern parallel programming techniques and careful optimization.

The following implementation of parallel radix sort is designed for maximum performance and scalability on modern multi-core processors. It is a stable, out-of-place sort that returns a new sorted sequence, matching the behavior of the ParlayLib baseline.

### Key Performance Features:

1.  **Block-Based Parallelism**: The input is divided into blocks, one for each worker thread. This ensures good data locality and minimizes synchronization.
2.  **Efficient Histogramming**: Each thread computes a local histogram of key distributions for its block. This step is perfectly parallel.
3.  **Scalable Offset Calculation**: A common bottleneck in parallel radix sort is calculating the final write position for each item. This implementation uses a highly parallel two-phase approach:
    *   It first calculates the global starting position for each bucket by summing up local counts and performing a parallel prefix sum (`parlay::scan`).
    *   It then computes the per-thread starting offsets for each bucket by transposing the count matrix and performing another set of parallel prefix sums. This pattern avoids sequential dependencies and scales well with the number of cores.
4.  **Optimized Scatter**: Each thread scatters its items directly to their final sorted positions in the destination buffer without any locks or atomic operations, using the pre-computed offsets.
5.  **Ping-Pong Buffering**: The sort uses two buffers, "ping-ponging" data between them in each pass. This avoids unnecessary data copies and allows the final result to be returned by simply returning the correct buffer, which is highly efficient.
6.  **Hybrid Approach**: For small inputs, the overhead of radix sort is significant. The implementation switches to ParlayLib's highly-optimized parallel `stable_sort` below a certain threshold (`n < 4096`), which is faster for smaller problem sizes.
7.  **Type Safety**: It correctly handles both signed and unsigned integer keys by casting to an unsigned type before performing bitwise shift operations, preventing undefined behavior from right-shifting negative numbers.
8.  **Genericity**: The code is fully templated to handle both raw integers and pairs of `(integer, data)`, where the integer is the sort key, as required by the benchmark specification.

This implementation represents a robust and extremely fast parallel integer sort, built on the solid foundation of the ParlayLib primitives.

#start
```cpp
#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/algorithm.h"
#include <utility>
#include <algorithm>
#include <type_traits>

namespace { // Anonymous namespace for implementation details

// Helper to extract the integer key from an element.
// Supports single integers and pairs where the first element is the key.
template <typename T>
struct KeyExtractor {
    using key_type = T;
    static constexpr key_type get(const T& val) { return val; }
};

template <typename E, typename F>
struct KeyExtractor<std::pair<E, F>> {
    using key_type = E;
    static constexpr key_type get(const std::pair<E, F>& val) { return val.first; }
};

// A high-performance, stable, out-of-place parallel radix sort.
template <typename T>
parlay::sequence<T> parlay_radix_sort(parlay::slice<const T*, const T*> In, size_t bits) {
    using KeyType = typename KeyExtractor<T>::key_type;
    using UnsignedKeyType = std::make_unsigned_t<KeyType>;

    size_t n = In.size();
    if (n == 0) {
        return parlay::sequence<T>();
    }

    // For small inputs, a parallel comparison-based sort is generally faster
    // due to the high overhead of radix sort's multiple passes.
    if (n < 4096) {
        auto result = parlay::sequence<T>::uninitialized(n);
        parlay::copy(In, parlay::make_slice(result));
        parlay::stable_sort_inplace(result, [](const T& a, const T& b) {
            return KeyExtractor<T>::get(a) < KeyExtractor<T>::get(b);
        });
        return result;
    }

    // Configuration for radix sort passes. 8 bits per pass is a common choice
    // that balances memory/cache usage with the number of passes required.
    constexpr size_t radix_bits = 8;
    constexpr size_t num_buckets = 1 << radix_bits;

    const size_t effective_bits = std::min(bits, sizeof(KeyType) * 8);
    const size_t num_passes = (effective_bits + radix_bits - 1) / radix_bits;

    if (num_passes == 0) {
        return parlay::sequence<T>(In.begin(), In.end());
    }

    // We use two buffers to ping-pong data between passes.
    auto buffer1 = parlay::sequence<T>::uninitialized(n);
    parlay::copy(In, parlay::make_slice(buffer1));
    auto buffer2 = parlay::sequence<T>::uninitialized(n);

    auto A = parlay::make_slice(buffer1);
    auto B = parlay::make_slice(buffer2);

    size_t num_threads = parlay::num_workers();
    size_t block_size = (n + num_threads - 1) / num_threads;

    // Per-thread histograms.
    parlay::sequence<parlay::sequence<size_t>> counts(num_threads,
        parlay::sequence<size_t>(num_buckets));

    for (size_t pass = 0; pass < num_passes; ++pass) {
        const size_t shift = pass * radix_bits;
        const UnsignedKeyType mask = num_buckets - 1;

        // Step 1: Parallel Counting (Histogram)
        // Each thread computes a histogram for its block of the input data.
        parlay::parallel_for(0, num_threads, [&](size_t i) {
            std::fill(counts[i].begin(), counts[i].end(), 0);
            size_t start = i * block_size;
            size_t end = std::min(start + block_size, n);
            for (size_t j = start; j < end; ++j) {
                auto key = static_cast<UnsignedKeyType>(KeyExtractor<T>::get(A[j]));
                auto bucket = (key >> shift) & mask;
                counts[i][bucket]++;
            }
        });

        // Step 2: Compute Global Bucket Offsets
        // Calculate the total size of each bucket across all threads.
        parlay::sequence<size_t> bucket_sizes(num_buckets);
        parlay::parallel_for(0, num_buckets, [&](size_t j) {
            size_t sum = 0;
            for (size_t i = 0; i < num_threads; i++) {
                sum += counts[i][j];
            }
            bucket_sizes[j] = sum;
        });

        // Perform an exclusive scan on bucket sizes to get the starting
        // position of each bucket in the output array.
        auto [global_offsets, total] = parlay::scan(bucket_sizes);

        // Step 3: Compute Per-Thread Write Positions
        // Calculate where each thread should start writing its items for each bucket.
        // This is done efficiently by transposing the counts matrix and scanning each row.
        parlay::sequence<parlay::sequence<size_t>> transposed_counts(num_buckets,
            parlay::sequence<size_t>(num_threads));
        parlay::parallel_for(0, num_threads, [&](size_t i) {
            for (size_t j = 0; j < num_buckets; j++) {
                transposed_counts[j][i] = counts[i][j];
            }
        });

        parlay::sequence<parlay::sequence<size_t>> write_offsets(num_buckets,
            parlay::sequence<size_t>(num_threads));
        parlay::parallel_for(0, num_buckets, [&](size_t j) {
            auto [exclusive_scan, bucket_total] = parlay::scan(transposed_counts[j]);
            for (size_t i = 0; i < num_threads; i++) {
                write_offsets[j][i] = global_offsets[j] + exclusive_scan[i];
            }
        });

        // Step 4: Parallel Scatter
        // Each thread scatters its elements to the correct locations in the output buffer B.
        parlay::parallel_for(0, num_threads, [&](size_t i) {
            parlay::sequence<size_t> local_write_ptrs(num_buckets);
            for (size_t j = 0; j < num_buckets; j++) {
                local_write_ptrs[j] = write_offsets[j][i];
            }

            size_t start = i * block_size;
            size_t end = std::min(start + block_size, n);
            for (size_t j = start; j < end; ++j) {
                auto key = static_cast<UnsignedKeyType>(KeyExtractor<T>::get(A[j]));
                auto bucket = (key >> shift) & mask;
                B[local_write_ptrs[bucket]++] = std::move(A[j]);
            }
        });

        // Swap buffers for the next pass.
        std::swap(A, B);
    }

    // The final sorted data is in the slice `A`. We return the owning sequence.
    if (num_passes % 2 == 1) {
        // Odd number of passes: result is in buffer2.
        return buffer2;
    } else {
        // Even number of passes: result is in buffer1.
        return buffer1;
    }
}

} // anonymous namespace

template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
    return parlay_radix_sort<T>(parlay::make_slice(In), bits);
}

template <class E, class F>
auto int_sort(parlay::slice<std::pair<E,F>*, std::pair<E,F>*> In, size_t bits) {
    return parlay_radix_sort<std::pair<E, F>>(parlay::make_slice(In), bits);
}
```
#end

An expert C++ programmer would recognize that a highly optimized parallel radix sort is the state-of-the-art for this problem. The following implementation provides a robust and extremely fast parallel integer sort using the radix sort method, tailored for modern multi-core processors and implemented using the ParlayLib framework.

### Key Performance Features:

1.  **Blocked Radix Sort:** The algorithm processes data in blocks. This improves load balancing and cache utilization. By creating more blocks than worker threads, the scheduler can distribute work more evenly, which is crucial if there's any skew in the data or system load.
2.  **Cache-Friendly Counting:** Each thread counts into its own private array of buckets (`counts`). This avoids expensive atomic operations or locks and prevents false sharing between threads, ensuring the counting phase scales linearly with the number of cores.
3.  **Parallel Prefix Sums:** All prefix sum (scan) operations, which are essential for calculating the final positions of elements, are fully parallelized using ParlayLib's efficient scan primitives.
4.  **Optimized Memory Management:** The implementation uses an out-of-place strategy with a single temporary buffer. It "ping-pongs" between the input and temporary buffers across passes, minimizing memory allocations and copies. It uses `parlay::sequence::uninitialized` to avoid the cost of default-constructing elements.
5.  **Hybrid Approach:** For small input sizes, the overhead of parallel radix sort can be higher than a simple comparison-based sort. The code therefore switches to `parlay::sort` (a parallel introsort) below a certain threshold (`4096` elements), a standard practice in high-performance sorting libraries.
6.  **Stability:** The sort is stable, meaning that elements with equal keys maintain their original relative order. This is achieved by carefully calculating offsets and processing elements within each thread's block in their original order.
7.  **Genericity:** The code is fully generic, able to sort sequences of plain integers (`T`) or pairs (`std::pair<E, F>`) by using a key-extraction function, as required by the problem.

This implementation represents a production-quality parallel integer sort that is expected to deliver top-tier performance on modern hardware.

#start
```cpp
#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/parallel.h"

#include <algorithm>
#include <type_traits>
#include <vector>

// A high-performance parallel integer sort implementation.
// It uses a blocked, out-of-place, stable radix sort algorithm.
namespace my_par_isort {

// The core of one pass of radix sort. It is a stable count sort
// on a specific byte (8 bits) of the keys.
template <typename In_Slice, typename Out_Slice, typename Key_Fn, typename Key_Type>
void radix_pass(const In_Slice& in, Out_Slice& out, Key_Fn& get_key, int shift) {
    static_assert(std::is_unsigned_v<Key_Type>, "Key must be an unsigned integer type.");

    size_t n = in.size();
    constexpr int bits_per_pass = 8;
    constexpr size_t num_buckets = 1 << bits_per_pass;
    constexpr size_t mask = num_buckets - 1;

    size_t num_threads = parlay::num_workers();

    // 1. Count occurrences of each bucket in parallel.
    // Each worker gets its own count array to avoid synchronization.
    parlay::sequence<parlay::sequence<size_t>> counts(num_threads, parlay::sequence<size_t>(num_buckets, 0));

    // Process the input in blocks. Using more blocks than threads can improve
    // load balancing, especially if the cost per element is not uniform.
    size_t block_size = (n + num_threads * 4 - 1) / (num_threads * 4);
    block_size = std::max(block_size, (size_t)2048);
    size_t num_blocks = (n + block_size - 1) / block_size;

    parlay::parallel_for(0, num_blocks, [&](size_t i) {
        size_t start = i * block_size;
        size_t end = std::min(start + block_size, n);
        int worker_id = parlay::get_worker_id();
        for (size_t j = start; j < end; j++) {
            Key_Type key = get_key(in[j]);
            size_t bucket = (key >> shift) & mask;
            counts[worker_id][bucket]++;
        }
    });

    // 2. Compute bucket offsets. First, sum the counts from all threads for each bucket.
    parlay::sequence<size_t> bucket_offsets(num_buckets);
    parlay::parallel_for(0, num_buckets, [&](size_t b) {
        size_t total = 0;
        for (size_t t = 0; t < num_threads; t++) {
            total += counts[t][b];
        }
        bucket_offsets[b] = total;
    });

    // Then, perform a parallel prefix sum (scan) to get the end position of each bucket
    // in the output array.
    parlay::scan_inclusive_inplace(bucket_offsets);

    // 3. Compute scatter offsets for each thread. This determines where each thread
    // should start writing its elements for each bucket.
    parlay::sequence<parlay::sequence<size_t>> scatter_offsets(num_threads, parlay::sequence<size_t>(num_buckets));
    parlay::parallel_for(0, num_buckets, [&](size_t b) {
        size_t bucket_start = (b == 0) ? 0 : bucket_offsets[b-1];
        size_t current_pos = bucket_start;
        for (size_t t = 0; t < num_threads; t++) {
            scatter_offsets[t][b] = current_pos;
            current_pos += counts[t][b];
        }
    });

    // 4. Scatter elements to their sorted positions. This is the permutation step.
    parlay::parallel_for(0, num_blocks, [&](size_t i) {
        size_t start = i * block_size;
        size_t end = std::min(start + block_size, n);
        int worker_id = parlay::get_worker_id();
        // Make a local copy of this thread's offsets to prevent false sharing
        // during the tight inner loop.
        auto local_offsets = scatter_offsets[worker_id];
        for (size_t j = start; j < end; j++) {
            auto const& val = in[j];
            Key_Type key = get_key(val);
            size_t bucket = (key >> shift) & mask;
            out[local_offsets[bucket]++] = val;
        }
    });
}

// The main integer sort function. It orchestrates multiple radix passes.
template <typename Slice, typename Key_Fn>
auto integer_sort(Slice In, Key_Fn get_key, size_t bits) {
    using T = typename Slice::value_type;
    using Key_Type = std::invoke_result_t<Key_Fn, T>;
    size_t n = In.size();

    // For small inputs, the overhead of radix sort is too high.
    // A parallel comparison-based sort is faster.
    if (n < 4096) {
        auto res = parlay::to_sequence(In);
        parlay::sort_inplace(res, [&](const T& a, const T& b) {
            return get_key(a) < get_key(b);
        });
        return res;
    }

    constexpr int bits_per_pass = 8;
    int num_passes = (bits + bits_per_pass - 1) / bits_per_pass;

    // Use a temporary buffer and "ping-pong" between it and the input buffer
    // across the passes to avoid extra copies.
    auto buffer = parlay::sequence<T>::uninitialized(n);

    auto in_slice = In;
    auto out_slice = parlay::make_slice(buffer);

    for (int i = 0; i < num_passes; i++) {
        radix_pass<Slice, decltype(out_slice), Key_Fn, Key_Type>(in_slice, out_slice, get_key, i * bits_per_pass);
        std::swap(in_slice, out_slice);
    }

    // The result is a new sequence. If the number of passes is even, the final
    // sorted data is in the original input buffer (`In`). We must copy it.
    // If odd, the data is in our temporary `buffer`. We can efficiently return
    // the buffer by moving it.
    if (num_passes % 2 == 0) {
        return parlay::to_sequence(In);
    } else {
        return buffer;
    }
}

} // namespace my_par_isort


// The public interface functions required by the benchmark.
// These replace the baseline implementation provided in the prompt.

template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  static_assert(std::is_unsigned_v<T>, "Integer sort requires unsigned integer types.");
  auto f = [&] (T x) {return x;};
