// The core implementation of the parallel radix sort
namespace custom_isort {

template <class T, class F>
parlay::sequence<T> integer_sort_impl(parlay::slice<T*, T*> In, F f, size_t bits) {
    using K = typename std::invoke_result_t<F, T>;
    static_assert(std::is_integral_v<K> && std::is_unsigned_v<K>, "Key must be an unsigned integral type.");

    size_t n = In.size();
    if (n == 0) {
        return parlay::sequence<T>();
    }

    // For small inputs, a comparison-based sort is faster due to radix sort's overhead.
    // This threshold is machine-dependent and should be tuned for optimal performance.
    if (n < (1 << 15)) { // 32K elements
        auto get_key = [&](const T& a) { return f(a); };
        return parlay::sort(In, parlay::make_less(get_key));
    }

    constexpr size_t radix_bits = 8;
    constexpr size_t radix_size = 1 << radix_bits;
    constexpr K mask = radix_size - 1;

    size_t num_passes = (bits + radix_bits - 1) / radix_bits;

    // Allocate buffers for ping-ponging data between passes.
    parlay::sequence<T> src = parlay::sequence<T>::from_slice(In);
    parlay::uninitialized_sequence<T> dest(n);

    auto A = src.slice();
    auto B = dest.slice();

    // Setup for block-based parallel computation. Using more blocks than workers
    // can improve load balancing. Block size is kept reasonably large to reduce overhead.
    size_t num_workers = parlay::num_workers();
    size_t num_blocks = std::min((size_t)1024, 4 * num_workers);
    num_blocks = std::min(num_blocks, (n + 2047) / 2048); // Avoid blocks smaller than 2K
    num_blocks = std::max(num_blocks, (size_t)1);
    size_t block_size = (n + num_blocks - 1) / num_blocks;

    // Per-block histograms. hists[block_id][radix_value]
    parlay::sequence<parlay::sequence<size_t>> hists(num_blocks);
    parlay::parallel_for(0, num_blocks, [&](size_t i) {
        hists[i].resize(radix_size, 0);
    });

    // Transposed histograms for better cache performance during scans.
    // T_hists[radix_value][block_id]
    parlay::sequence<parlay::sequence<size_t>> T_hists(radix_size);
    parlay::parallel_for(0, radix_size, [&](size_t i) {
        T_hists[i].resize(num_blocks, 0);
    });

    for (size_t pass = 0; pass < num_passes; ++pass) {
        size_t shift = pass * radix_bits;

        // 1. Compute local histograms for each block in parallel.
        parlay::parallel_for(0, num_blocks, [&](size_t i) {
            size_t start = i * block_size;
            size_t end = std::min(start + block_size, n);
            auto& local_hist = hists[i];
            std::fill(local_hist.begin(), local_hist.end(), 0);
            for (size_t j = start; j < end; ++j) {
                local_hist[(f(A[j]) >> shift) & mask]++;
            }
        });

        // 2. Transpose histograms for cache-efficient column-wise operations.
        parlay::parallel_for(0, num_blocks, [&](size_t b) {
            for (size_t r = 0; r < radix_size; r++) {
                T_hists[r][b] = hists[b][r];
            }
        });

        // 3. Compute global bucket starting offsets via a parallel reduce and scan.
        parlay::sequence<size_t> offsets(radix_size);
        parlay::parallel_for(0, radix_size, [&](size_t r) {
            offsets[r] = parlay::reduce(T_hists[r]);
        });
        parlay::scan_inplace(offsets);

        // 4. Compute local offsets within each bucket for each block by scanning
        // the rows of the transposed histogram matrix.
        parlay::parallel_for(0, radix_size, [&](size_t r) {
            parlay::scan_inplace(T_hists[r]);
        });

        // 5. Scatter elements to their sorted positions in parallel.
        parlay::parallel_for(0, num_blocks, [&](size_t i) {
            size_t start = i * block_size;
            size_t end = std::min(start + block_size, n);

            // Cache the starting write positions for this block to improve locality.
            parlay::sequence<size_t> local_write_offsets(radix_size);
            for (size_t r = 0; r < radix_size; r++) {
                local_write_offsets[r] = offsets[r] + T_hists[r][i];
            }

            for (size_t j = start; j < end; ++j) {
                K key_val = (f(A[j]) >> shift) & mask;
                size_t dest_idx = local_write_offsets[key_val]++;
                B[dest_idx] = std::move(A[j]);
            }
        }, 1);

        // Swap source and destination buffers for the next pass.
        std::swap(A, B);
    }

    // The final sorted data is in A.
    // If num_passes is even, A points to the original src buffer.
    // If odd, A points to the dest buffer.
    if (num_passes % 2 == 0) {
        return src;
    } else {
        // Efficiently convert the filled uninitialized buffer to a sequence.
        return std::move(dest).to_sequence();
    }
}

} // namespace custom_isort
// --- End of file: isort.h ---
