// A single pass of radix sort.
// It is stable and sorts elements from `from` to `to` based on the
// bits specified by `shift`.
template <typename InSlice, typename OutSlice, typename KeyFn>
void parallel_radix_pass(const InSlice& from, const OutSlice& to, KeyFn f, size_t shift) {
    using T = typename InSlice::value_type;
    size_t n = from.size();

    constexpr size_t RADIX_BITS = 8;
    constexpr size_t RADIX_SIZE = 1 << RADIX_BITS;
    constexpr size_t BUCKET_MASK = RADIX_SIZE - 1;

    auto get_bucket = [&](const T& v) {
        return (f(v) >> shift) & BUCKET_MASK;
    };

    // For good load balancing, especially on NUMA machines, we divide the input
    // into a number of blocks, typically several times the number of threads.
    size_t num_threads = parlay::num_workers();
    size_t num_blocks = std::max((size_t)1, 4 * num_threads);
    num_blocks = std::min(num_blocks, (n + 1023) / 1024); // Avoid tiny blocks
    size_t block_size = (n + num_blocks - 1) / num_blocks;

    // Each block computes a local histogram of key frequencies.
    parlay::sequence<size_t> counts(num_blocks * RADIX_SIZE, 0);

    parlay::parallel_for(0, num_blocks, [&](size_t i) {
        size_t start = i * block_size;
        size_t end = std::min(start + block_size, n);
        size_t* my_counts = &counts[i * RADIX_SIZE];
        for (size_t j = start; j < end; j++) {
            my_counts[get_bucket(from[j])]++;
        }
    });

    // Calculate the global starting offset for each bucket. This involves
    // a transpose-like sum and a prefix sum (scan).
    parlay::sequence<size_t> bucket_offsets(RADIX_SIZE);
    parlay::parallel_for(0, RADIX_SIZE, [&](size_t j) {
        size_t sum = 0;
        for (size_t i = 0; i < num_blocks; i++) {
            sum += counts[i * RADIX_SIZE + j];
        }
        bucket_offsets[j] = sum;
    });

    parlay::scan_inplace(bucket_offsets);

    // Calculate the specific offset for each block within each bucket.
    // The `counts` array is repurposed to store these offsets for the final move.
    parlay::parallel_for(0, RADIX_SIZE, [&](size_t j) {
        size_t offset = bucket_offsets[j];
        for (size_t i = 0; i < num_blocks; i++) {
            size_t count = counts[i * RADIX_SIZE + j];
            counts[i * RADIX_SIZE + j] = offset;
            offset += count;
        }
    });

    // Move elements from the input to their sorted positions in the output.
    // This is the permutation step.
    parlay::parallel_for(0, num_blocks, [&](size_t i) {
        size_t start = i * block_size;
        size_t end = std::min(start + block_size, n);
        size_t* my_offsets = &counts[i * RADIX_SIZE];
        for (size_t j = start; j < end; j++) {
            size_t bucket = get_bucket(from[j]);
            size_t dest = my_offsets[bucket]++;
            // Relocate object from `from` to uninitialized memory in `to`.
            parlay::uninitialized_relocate(&to[dest], &from[j]);
        }
    });
