//
// 6.  **Generic and Unified Implementation**: The baseline code had separate
//     implementations for integers and pairs. This version uses a generic
//     `int_sort_impl` with a `GetKey` helper struct. This unification reduces
//     code duplication, improves maintainability, and ensures that all types
//     benefit from the same optimizations.

namespace {

// A compile-time flag to select sorting stability based on the UNSTABLE macro.
// This enables the compiler to generate optimal code for each case.
#ifdef UNSTABLE
constexpr bool is_stable = false;
#else
constexpr bool is_stable = true;
#endif

// A generic key extractor that works for both plain elements (e.g., int)
// and pairs (e.g., std::pair<int, int>).
template <typename T>
struct GetKey {
  // For primitive types, the key is the element itself.
  using KeyType = T;
  auto operator()(const T& x) const { return x; }
};

template <typename E, typename F>
struct GetKey<std::pair<E, F>> {
  // For pairs, the key is the first element.
  using KeyType = E;
  auto operator()(const std::pair<E, F>& p) const { return p.first; }
