} // anonymous namespace

// Core implementation, templated on the input sequence type.
template <typename In_Seq>
auto int_sort_impl(In_Seq In, size_t bits) {
  using T = typename In_Seq::value_type;
  using Key = GetKey<T>;
  using KeyType = typename Key::KeyType;

  auto get_key_f = Key{};
  auto Out = parlay::sequence<T>::uninitialized(In.size());

  if (In.empty()) {
    return Out;
