  // The stability is controlled by a compile-time constant for max efficiency.
  // The input slice `In` is used as a temporary buffer during the sort.
  parlay::internal::seq_radix_sort<
      std::bool_constant<is_stable>, parlay::uninitialized_relocate_tag>(
          In, parlay::make_slice(Out), In, get_key_f, bits);

  return Out;
}

// Public interface for sorting sequences of T (e.g., integers).
// This function matches the required signature from the problem description.
template <class T>
auto int_sort(parlay::slice<T*, T*> In, size_t bits) {
  return int_sort_impl(In, bits);
}

// Public interface for sorting sequences of std::pair<E, F>.
// This function matches the required signature from the problem description.
template <class E, class F>
auto int_sort(parlay::slice<std::pair<E, F>*, std::pair<E, F>*> In, size_t bits) {
  return int_sort_impl(In, bits);
}

#endif // ISORT_H_
// --- End of file: isort.h ---
