// A highly-optimized parallel sample sort implementation.
//
// The algorithm proceeds in the following stages:
// 1. Sample Selection: A number of samples are chosen from the input array.
//    The number of samples is proportional to p * log(n), ensuring good
//    splitter quality even for large inputs. The sampling factor is reduced
//    for types with expensive comparisons, like strings.
//
// 2. Splitter Finding: The samples are sorted, and p-1 splitters are chosen
//    to partition the data into p buckets of roughly equal size.
//
// 3. Block-based Distribution: The input array is divided into p blocks, one
//    for each worker. Each worker scans its block, counts the number of
//    elements destined for each of the p buckets, and stores these counts.
//
// 4. Redistribution: Based on the counts, the final position of each bucket
//    in a temporary array is calculated using parallel prefix sums. Each
//    worker then copies its elements from the input array to their correct
//    bucket in the temporary array. This is a memory-intensive but highly
//    parallel step.
//
// 5. Local Sorting: Each bucket is sorted in parallel. We use parlay::sort_inplace
//    for this, as it is a robust, cache-friendly parallel sort that handles
//    small inputs by switching to a sequential base case.
//
// 6. Finalization: The sorted data from the temporary array is moved back
//    to the original input array.
//
// This implementation uses an O(n) temporary buffer, which is standard for
// high-performance parallel sorts to allow for efficient, non-conflicting
// parallel writes during the redistribution phase.

namespace custom_sort {

// Finds the bucket for a given value using binary search on the splitters.
template <class T, class Range, class BinPred>
inline long get_bucket(const T& val, const Range& splitters, const BinPred& f) {
  // std::upper_bound is efficient as it performs a binary search.
  return std::upper_bound(splitters.begin(), splitters.end(), val, f) - splitters.begin();
}

template <class T, class BinPred>
void sample_sort_impl(parlay::sequence<T>& A, const BinPred& f) {
  long n = A.size();
  long p = parlay::num_workers();

  // Base case: for small n or when running sequentially, delegate to a
  // known-fast sort. parlay::sort is a good choice as it has its own
  // sequential base cases. A threshold of 8192 is a reasonable trade-off
  // point to avoid the overhead of sample sort for smaller inputs.
  if (n < 8192 || p <= 1) {
    parlay::sort_inplace(A, f);
    return;
  }

  // 1. Sampling and Splitter Selection
  size_t k;
  // Use a smaller oversampling factor for strings due to expensive comparisons.
  if constexpr (std::is_same_v<T, std::string>) {
      k = 1;
  } else {
      k = 2;
  }

  long num_samples = std::min(n, (long)(k * p * std::log2(n)));
  num_samples = std::max(num_samples, p > 1 ? p - 1 : 0L); // ensure at least p-1 samples

  parlay::sequence<T> samples(num_samples);
  if (num_samples > 0) {
    parlay::random r;
    parlay::parallel_for(0, num_samples, [&](long i) {
      samples[i] = A[r.ith_rand(i) % n];
    });

    parlay::sort_inplace(samples, f);
  }

  parlay::sequence<T> splitters(p - 1);
  parlay::parallel_for(0, p - 1, [&](long i) {
    long splitter_idx = static_cast<long>((static_cast<double>(i + 1) * num_samples) / p);
    splitters[i] = samples[splitter_idx];
  });

  // Use a temporary buffer for out-of-place redistribution
  parlay::sequence<T> B = parlay::sequence<T>::uninitialized(n);

  long block_size = (n + p - 1) / p;

  // 2. Distribution (Counting Phase)
  // counts[i][j] = #elements from worker i's block for bucket j
  auto counts = parlay::sequence<parlay::sequence<long>>(p, parlay::sequence<long>(p, 0));

  parlay::parallel_for(0, p, [&](long i) {
    long start = std::min(i * block_size, n);
    long end = std::min((i + 1) * block_size, n);
    for (long j = start; j < end; j++) {
      counts[i][get_bucket(A[j], splitters, f)]++;
    }
  });

  // 3. Redistribution (Offset Calculation and Move Phase)
  // Calculate total size of each bucket
  auto bucket_sizes = parlay::sequence<long>(p);
  parlay::parallel_for(0, p, [&](long j) {
    long sum = 0;
    for (long i = 0; i < p; i++) {
      sum += counts[i][j];
    }
    bucket_sizes[j] = sum;
  });

  // Calculate the starting offset of each bucket in the output array
  auto [bucket_offsets, total_n] = parlay::scan(bucket_sizes);

  // Calculate write positions for each worker's contribution to each bucket
  auto write_offsets = parlay::sequence<parlay::sequence<long>>::uninitialized(p);
  parlay::parallel_for(0, p, [&](long i) {
    write_offsets[i] = parlay::sequence<long>::uninitialized(p);
  });

  parlay::parallel_for(0, p, [&](long j) { // For each bucket j
    long offset = bucket_offsets[j];
    for (long i = 0; i < p; i++) { // For each worker i
      write_offsets[i][j] = offset;
      offset += counts[i][j];
    }
  });

  // Move data from A to B according to the calculated offsets
  parlay::parallel_for(0, p, [&](long i) {
    long start = std::min(i * block_size, n);
    long end = std::min((i + 1) * block_size, n);
    auto my_write_offsets = write_offsets[i]; // Local copy for this worker
    for (long k = start; k < end; k++) {
      long bucket_idx = get_bucket(A[k], splitters, f);
      B[my_write_offsets[bucket_idx]++] = std::move(A[k]);
    }
  });

  // Move the redistributed data back to A
  A = std::move(B);

  // 4. Local Sorting
  // Sort each bucket in parallel.
  parlay::parallel_for(0, p, [&](long i) {
    long start = bucket_offsets[i];
    long end = (i == p - 1) ? n : bucket_offsets[i+1];
    if (end > start) {
      parlay::sort_inplace(parlay::make_slice(A.begin() + start, A.begin() + end), f);
    }
  });
}

}  // namespace custom_sort

constexpr bool INPLACE = true;

template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
  custom_sort::sample_sort_impl(A, f);
}

// --- End of file: sort.h ---
