// Finds the bucket an element belongs to by binary searching the splitters.
template<typename T, typename Range, typename BinPred>
inline size_t get_bucket_idx(const T& val, const Range& splitters, const BinPred& f) {
    // std::upper_bound returns an iterator to the first element in splitters
    // that is greater than val. The distance from the beginning is the bucket index.
    return std::upper_bound(splitters.begin(), splitters.end(), val, f) - splitters.begin();
}

// The recursive implementation of the sample sort.
// It operates on a parlay::slice, which is a non-owning view of a sequence.
template <class T, class BinPred>
void sample_sort_impl(parlay::slice<T*, T*> A, const BinPred& f) {
    size_t n = A.size();

    // Base case: For small inputs, a fast sequential sort is best.
    // std::sort is highly optimized (typically Introsort).
    if (n < 4096) {
        std::sort(A.begin(), A.end(), f);
        return;
    }

    // ################ 1. Select Samples and Splitters ################

    // Parameters for sampling. These are chosen based on common practice and
    // provide a good balance between splitter quality and overhead.
    size_t num_workers = parlay::num_workers();

    // Use more buckets than workers to improve load balancing, but not so many
    // that subproblems become too small or overhead increases too much.
    // For large n, create more buckets to keep subproblem sizes reasonable.
    size_t num_buckets = std::min((size_t)n / (128 * 1024), 2 * num_workers);
    if (num_buckets < 2) num_buckets = 2;

    size_t oversample_factor = 32;
    size_t num_samples = std::min(n, oversample_factor * num_buckets);

    // Select random samples from the input array.
    auto samples = parlay::sequence<T>::uninitialized(num_samples);
    parlay::parallel_for(0, num_samples, [&](size_t i) {
        // Use a hash function to generate pseudo-random indices. This can be
        // better than a typical PRNG as it avoids contention and has good
        // memory access patterns.
        size_t index = parlay::hash64(i) % n;
        parlay::uninitialized_construct(&samples[i], A[index]);
    });

    // Sort the samples to find splitters.
    std::sort(samples.begin(), samples.end(), f);

    // Select splitters from the sorted samples.
    auto splitters = parlay::sequence<T>(num_buckets - 1);
    parlay::parallel_for(0, num_buckets - 1, [&](size_t i) {
        splitters[i] = samples[(i + 1) * num_samples / num_buckets];
    });
    // Samples are no longer needed
    samples.clear();

    // ################ 2. Distribute Data into Buckets ################

    // a. Count elements per bucket for each block of the input.
    // Processing in blocks improves cache performance.
    size_t num_blocks = std::min(num_buckets * 8, (n + 4095) / 4096);
    if (num_blocks == 0) num_blocks = 1;
    size_t block_size = (n + num_blocks - 1) / num_blocks;

    auto counts = parlay::sequence<parlay::sequence<size_t>>(
        num_blocks, parlay::sequence<size_t>(num_buckets, 0));

    parlay::parallel_for(0, num_blocks, [&](size_t i) {
        size_t start = i * block_size;
        size_t end = std::min(start + block_size, n);
        for (size_t j = start; j < end; j++) {
            counts[i][get_bucket_idx(A[j], splitters, f)]++;
        }
    });

    // b. Compute the starting position of each bucket in the output.
    auto bucket_sizes = parlay::tabulate(num_buckets, [&](size_t j) {
        return parlay::reduce(parlay::map(counts, [&](auto const& c) { return c[j]; }));
    });
    auto bucket_starts = parlay::scan(bucket_sizes).first;

    // c. Compute the write-offset for each block's contribution to each bucket.
    // This is done by transposing the counts matrix and running a scan on each row.
    auto T_counts = parlay::transpose(counts);
    auto T_block_offsets = parlay::sequence<parlay::sequence<size_t>>(num_buckets);
    parlay::parallel_for(0, num_buckets, [&](size_t j) {
        T_block_offsets[j] = parlay::scan(T_counts[j]).first;
    });
    auto block_offsets = parlay::transpose(T_block_offsets);

    // d. Move elements from A to their sorted-bucket locations in B.
    auto B = parlay::sequence<T>::uninitialized(n);
    parlay::parallel_for(0, num_blocks, [&](size_t i) {
        size_t start = i * block_size;
        size_t end = std::min(start + block_size, n);
        for (size_t k = start; k < end; k++) {
            size_t bucket_idx = get_bucket_idx(A[k], splitters, f);
            size_t dest = bucket_starts[bucket_idx] + block_offsets[i][bucket_idx];
            parlay::move_uninitialized(B[dest], A[k]);
            block_offsets[i][bucket_idx]++;
        }
    });

    // e. Move the bucketed data from B back to A.
    parlay::parallel_for(0, n, [&](size_t i) {
        parlay::move_uninitialized(A[i], B[i]);
    });

    // ################ 3. Recursively Sort Buckets ################

    // Create a sequence of bucket boundaries for recursive calls.
    auto bucket_ends = parlay::sequence<size_t>(num_buckets + 1);
    parlay::parallel_for(0, num_buckets, [&](size_t i) { bucket_ends[i] = bucket_starts[i]; });
    bucket_ends[num_buckets] = n;

    parlay::parallel_for(0, num_buckets, [&](size_t i) {
        size_t start = bucket_ends[i];
        size_t end = bucket_ends[i+1];
        if (end > start) {
            sample_sort_impl(A.cut(start, end), f);
        }
    });
}

} // end anonymous namespace


