void sample_sort_inplace(parlay::sequence<T> &A, const BinPred& f) {
  // Only sort if there are elements to sort.
  if (A.size() > 1) {
    // Call the recursive implementation on a slice representing the whole sequence.
    sample_sort_impl(A.cut(0, A.size()), f);
  }
}
