#include <algorithm>
#include <iterator>

namespace psort_detail {

// A highly optimized, parallel sample sort implementation.
// It is recursive and operates on slices of the original sequence.
template <class T, class BinPred>
void sample_sort_impl(parlay::slice<T*, T*> A, const BinPred& f) {
  size_t n = A.size();

  // Base case: For small inputs, switch to a fast sequential sort.
  // std::sort is typically a highly optimized introsort.
  // The threshold is a key tuning parameter; 4096 is a good starting point.
  constexpr size_t base_case_size = 1 << 12;
  if (n <= base_case_size) {
    std::sort(A.begin(), A.end(), f);
    return;
  }

  // Step 1: Sampling
  // =================
  size_t p = parlay::num_workers();

  // Determine the number of buckets. More buckets can improve load balance,
  // especially for skewed distributions, but add overhead.
  // We use a heuristic that increases buckets with core count and problem size,
  // while ensuring subproblems are not too small.
  size_t num_buckets = 1 << parlay::log2_up(p);
  num_buckets = std::min(num_buckets * 8, n / base_case_size);
  num_buckets = std::max(num_buckets, static_cast<size_t>(2));
  size_t num_splitters = num_buckets - 1;

  // Use an oversampling factor to select a representative sample of the data,
  // leading to high-quality splitters that balance the buckets well.
  // The factor is adaptive to the input size.
  size_t oversample_factor = 10 + parlay::log2_up(n);
  size_t num_samples = std::min(n, num_splitters * oversample_factor);

  parlay::sequence<T> samples(num_samples);
  parlay::random_generator gen;

  // Select random samples in parallel.
  parlay::parallel_for(0, num_samples, [&](size_t i) {
    auto r = gen[i];
    samples[i] = A[r % n];
  });

  // Sort samples sequentially to easily pick splitters.
  std::sort(samples.begin(), samples.end(), f);

  // Select evenly-spaced splitters from the sorted sample set.
  parlay::sequence<T> splitters(num_splitters);
  parlay::parallel_for(0, num_splitters, [&](size_t i) {
    size_t idx = static_cast<size_t>((i + 1.0) * num_samples / (num_splitters + 1.0));
    splitters[i] = samples[idx];
  });

  // samples' memory is freed when it goes out of scope.

  // Step 2: Bucketization
  // ======================
  // Use a block-based approach to improve cache efficiency.
  // Each worker processes blocks of data.
  constexpr size_t block_size = 1 << 12;
  size_t num_blocks = (n + block_size - 1) / block_size;

  // 2a: Count elements per bucket for each block in parallel.
  parlay::sequence<parlay::sequence<size_t>> counts(num_blocks);
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
      counts[i].assign(num_buckets, 0);
      size_t start = i * block_size;
      size_t end = std::min(start + block_size, n);
      for (size_t j = start; j < end; j++) {
          // Find the bucket for the element using binary search on splitters.
          size_t bucket_id = std::upper_bound(splitters.begin(), splitters.end(), A[j], f) - splitters.begin();
          counts[i][bucket_id]++;
      }
  });

  // 2b: Calculate bucket offsets.
  // First, find the total size of each bucket.
  parlay::sequence<size_t> bucket_sizes(num_buckets);
  parlay::parallel_for(0, num_buckets, [&](size_t j) {
      size_t size = 0;
      for (size_t i = 0; i < num_blocks; i++) {
          size += counts[i][j];
      }
      bucket_sizes[j] = size;
  });

  // Then, perform a prefix sum (scan) to find the start of each bucket.
  auto bucket_offsets = parlay::scan(bucket_sizes).first;

  // 2c: Permute elements into buckets in a temporary buffer.
  // This is an out-of-place permutation, which is much faster for parallel execution.
  parlay::sequence<T> B = parlay::sequence<T>::uninitialized(n);

  // To calculate the destination for each element efficiently, we perform a
  // prefix sum on the columns of the counts matrix. This is done via a
  // transpose-and-scan pattern.
  parlay::sequence<parlay::sequence<size_t>> counts_T(num_buckets);
  parlay::parallel_for(0, num_buckets, [&](size_t j) {
    counts_T[j].resize(num_blocks);
    for (size_t i = 0; i < num_blocks; i++) {
      counts_T[j][i] = counts[i][j];
    }
  });

  parlay::parallel_for(0, num_buckets, [&](size_t j) {
    parlay::scan_inplace(counts_T[j], parlay::plus<size_t>());
    for (size_t i = 0; i < num_blocks; i++) {
      counts_T[j][i] += bucket_offsets[j];
    }
  });

  // Now, move elements from A to their correct bucketed position in B.
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    parlay::sequence<size_t> local_offsets(num_buckets);
    for(size_t j = 0; j < num_buckets; ++j) {
      local_offsets[j] = counts_T[j][i];
    }

    size_t start = i * block_size;
    size_t end = std::min(start + block_size, n);
    for (size_t j = start; j < end; j++) {
      size_t bucket_id = std::upper_bound(splitters.begin(), splitters.end(), A[j], f) - splitters.begin();
      size_t dest = local_offsets[bucket_id]++;
      // Use placement new for uninitialized memory to avoid default construction.
      new (static_cast<void*>(std::addressof(B[dest]))) T(std::move(A[j]));
    }
  });

  // Step 3: Move data back and recurse
  // ===================================
  // Move the bucketed elements from the temporary buffer B back to A.
  parlay::parallel_for(0, n, [&](size_t i) {
    A[i] = std::move(B[i]);
    // Explicitly destroy the moved-from object in B.
    B[i].~T();
  });

  // B's memory is freed when it goes out of scope.

  // Recursively sort each bucket in parallel.
  parlay::parallel_for(0, num_buckets, [&](size_t i) {
    size_t start = bucket_offsets[i];
    size_t end = (i == num_buckets - 1) ? n : bucket_offsets[i+1];
    if (end > start) {
      sample_sort_impl(A.cut(start, end), f);
    }
  });
}

} // namespace psort_detail

// The public interface for the in-place sample sort.
template <class T, class BinPred>
void sample_sort_inplace(parlay::sequence<T> &A, const BinPred& f) {
  if (A.size() < 2) return;
  psort_detail::sample_sort_impl(parlay::make_slice(A), f);
}
