//     high probability, which is essential for achieving balanced partitions.
//     Balanced partitions are the key to unlocking parallel scalability and
//     avoiding quicksort's O(n^2) worst-case behavior, which can be triggered
//     by sorted or nearly-sorted inputs.
//
// 2.  **Parallel 3-Way Partitioning:** The partitioning step separates elements
//     into three groups: those less than, equal to, and greater than the pivot.
//     This is vastly more efficient than traditional 2-way partitioning when
//     the input contains many duplicate keys (as in the `exptSeq` benchmark).
//     By isolating all elements equal to the pivot in a single pass, they are
//     put into their final sorted position and are not included in subsequent
//     recursive calls, significantly reducing the total work.
//
// The implementation is fully in-place, recursive, and uses `parlay::par_do`
// for efficient fork-join parallelism. It falls back to a fast sequential
// sort for small subproblems to amortize the overhead of parallelization.

namespace expert_sort {

// --- Tunable constants ---

// Base case: subproblems smaller than this are sorted sequentially.
// A value of 2048 is a robust choice that balances parallel overhead
// with the cost of sequential sorting.
constexpr size_t SEQUENTIAL_CUTOFF = 2048;

// Sampling threshold: arrays larger than this use sampling for pivot selection.
// This avoids the overhead of sampling on smaller arrays where a cheaper
// median-of-three strategy is sufficient.
constexpr size_t SAMPLING_CUTOFF = 1 << 14;

// Forward declaration for the recursive function.
template <class Slice, class BinPred>
void p_quicksort(Slice A, const BinPred& f);

// Selects a pivot using sampling for large arrays, or median-of-three for smaller ones.
template <class Slice, class BinPred>
typename Slice::value_type select_pivot(Slice A, const BinPred& f) {
    size_t n = A.size();
    if (n < SAMPLING_CUTOFF) {
        // Median-of-three is a low-overhead choice for smaller subproblems.
        auto x = A[0];
        auto y = A[n/2];
        auto z = A[n-1];
        return f(x, y) ? (f(y, z) ? y : (f(x, z) ? z : x))
                       : (f(x, z) ? x : (f(y, z) ? z : y));
    } else {
        // For large arrays, sampling provides a statistically robust pivot.
        size_t num_workers = parlay::num_workers();
        size_t sample_size = std::min(n, num_workers * (parlay::log2_up(n) + 1));
        // Cap sample size to avoid excessive overhead on huge inputs.
        sample_size = std::min(sample_size, (size_t)1 << 15);

        parlay::sequence<typename Slice::value_type> samples(sample_size);
        // Seed the random generator based on the data location for varied sequences.
        parlay::random r(reinterpret_cast<size_t>(A.data()));

        parlay::parallel_for(0, sample_size, [&](size_t i) {
            samples[i] = A[r.ith_rand(i) % n];
        });

        // The sample set is small enough to be sorted sequentially very quickly.
        std::sort(samples.begin(), samples.end(), f);
        return samples[sample_size / 2];
    }
}

// An in-place parallel 3-way partition.
// It uses two passes of a 2-way partition primitive for simplicity and
// to maintain the in-place property.
// Returns the start and end indices of the block of elements equal to the pivot.
template <class Slice, class BinPred>
std::pair<size_t, size_t> p_partition_three_way(Slice S, const typename Slice::value_type& pivot, const BinPred& f) {
    size_t n = S.size();
    if (n == 0) return {0, 0};

    // First pass: partition into [< pivot] and [>= pivot].
    auto pred_less = [&](const auto& val) { return f(val, pivot); };
    size_t p1 = parlay::internal::p_partition_inplace(S, pred_less, parlay::granularity(n));

    // Second pass: partition the second part [>= pivot] into [== pivot] and [> pivot].
    // Predicate `!f(pivot, val)` is equivalent to `val <= pivot`. Since all elements
    // less than the pivot are already in the first partition, this correctly
    // separates elements equal to the pivot.
    auto pred_not_greater = [&](const auto& val) { return !f(pivot, val); };
    Slice greater_equal_slice = S.cut(p1, n);
    size_t equal_count = parlay::internal::p_partition_inplace(greater_equal_slice, pred_not_greater, parlay::granularity(greater_equal_slice.size()));

    return {p1, p1 + equal_count};
}


// The main recursive quicksort function.
template <class Slice, class BinPred>
void p_quicksort(Slice A, const BinPred& f) {
    if (A.size() <= SEQUENTIAL_CUTOFF) {
        // Base case: use parlay's highly optimized sequential sort.
        parlay::internal::sequential_sort(A, f);
        return;
    }

    auto pivot = select_pivot(A, f);
    auto [p1, p2] = p_partition_three_way(A, pivot, f);

    // Recurse on the partitions for elements less-than and greater-than the pivot.
    // The middle partition (equal to pivot) is already sorted and is skipped.
    parlay::par_do(
        [&]() { p_quicksort(A.cut(0, p1), f); },
        [&]() { p_quicksort(A.cut(p2, A.size()), f); }
    );
}

} // namespace expert_sort


constexpr bool INPLACE = true;

template <class T, class BinPred>
void compSort(parlay::sequence<T>  &A, const BinPred& f) {
  if (A.size() < 2) return;
  expert_sort::p_quicksort(parlay::make_slice(A), f);
}
