#include "parlay/sequence.h"
#include "parlay/primitives.h"
#include "parlay/slice.h"

#include <utility>
#include <algorithm>

namespace { // Anonymous namespace for implementation details

// Cutoff for switching to insertion sort. This value is critical for performance,
// balancing the overhead of recursion and task generation in quicksort against
// the efficiency of a simple, cache-friendly sort for small inputs.
// This value is typically tuned empirically; 2048 is a reasonable choice
// for modern multicore processors and efficient tasking systems like Parlay.
constexpr size_t QUICKSORT_CUTOFF = 2048;

// A standard insertion sort, which is highly efficient for small arrays.
template<typename Slice, typename Compare>
void insertion_sort(Slice A, Compare f) {
    for (size_t i = 1; i < A.size(); i++) {
        auto v = std::move(A[i]);
        size_t j = i;
        while (j > 0 && f(v, A[j-1])) {
            A[j] = std::move(A[j-1]);
            j--;
        }
        A[j] = std::move(v);
    }
}

// Selects a pivot using median-of-three (first, middle, last elements).
// This strategy is effective at preventing worst-case O(n^2) behavior for
// many common input patterns, such as sorted or nearly-sorted data.
// The chosen pivot (the median) is placed at the beginning of the slice.
template<typename Slice, typename Compare>
void select_pivot(Slice A, Compare f) {
    size_t n = A.size();
    if (n < 3) return;
    size_t mid_idx = n / 2;
    // Sort A[0], A[mid_idx], and A[n-1] to find the median robustly.
    if (f(A[mid_idx], A[0])) std::swap(A[0], A[mid_idx]);
    if (f(A[n-1], A[0])) std::swap(A[0], A[n-1]);
    if (f(A[n-1], A[mid_idx])) std::swap(A[mid_idx], A[n-1]);
    // After the above, A[0] <= A[mid_idx] <= A[n-1].
    // The median, A[mid_idx], is a good pivot candidate. Move it to the front.
    std::swap(A[0], A[mid_idx]);
}

// The core parallel quicksort implementation.
template<typename Slice, typename Compare>
void p_quicksort(Slice A, Compare f) {
    size_t n = A.size();

    // This loop implements one branch of the recursion iteratively.
    // By always processing the larger partition in the loop, we ensure
    // that the recursion depth is logarithmic in the size of the input,
    // preventing stack overflow and reducing tasking overhead.
    while (n > QUICKSORT_CUTOFF) {
        // 1. Pivot Selection
        select_pivot(A, f);
        const auto& pivot = A[0];

        // 2. 3-way Partition (Dijkstra's Dutch National Flag algorithm)
        // This is a key optimization for inputs with many duplicate elements,
        // as it partitions the array into three parts: [< pivot | == pivot | > pivot].
        // The recursive calls can then skip the middle '==' partition.
        size_t lt = 1; // one past the end of the '<' partition
        size_t gt = n; // one before the start of the '>' partition
        size_t i = 1;  // current element to inspect

        while (i < gt) {
            if (f(A[i], pivot)) {
                std::swap(A[i++], A[lt++]);
            } else if (f(pivot, A[i])) {
                std::swap(A[i], A[--gt]);
            } else { // A[i] is equal to the pivot
                i++;
            }
        }
        // The '<' partition is in A[1...lt-1]. Swap the pivot (at A[0])
        // with the last element of the '<' partition to place it correctly.
        std::swap(A[0], A[--lt]);

        // After partitioning and pivot swap:
        // A[0...lt-1] contains elements < pivot
        // A[lt...gt-1] contains elements == pivot
        // A[gt...n-1] contains elements > pivot

        // 3. Parallel Recursion
        // We recurse on the smaller of the two partitions in a new parallel task
        // and handle the larger partition in the next iteration of the while loop.
        auto left_part = A.cut(0, lt);
        auto right_part = A.cut(gt, n);

        if (left_part.size() < right_part.size()) {
            parlay::par_do([&] { p_quicksort(left_part, f); });
            A = right_part;
        } else {
            parlay::par_do([&] { p_quicksort(right_part, f); });
            A = left_part;
        }
        n = A.size();
    }

    // Base case: for small remaining partitions, use the highly-efficient
    // sequential insertion sort.
    if (n > 1) {
        insertion_sort(A, f);
    }
}

} // end anonymous namespace

// The sort is performed in-place.
constexpr bool INPLACE = true;

// Public-facing compSort function.
template <class T, class BinPred>
void compSort(parlay::sequence<T>& A, const BinPred& f) {
  // Handle trivial cases and then dispatch to the parallel implementation.
  if (A.size() > 1) {
    p_quicksort(parlay::make_slice(A), f);
  }
}
// --- End of file: sort.h ---
