#include "parlay/internal/quicksort.h"
#include "parlay/primitives.h"
#include <algorithm>

// A custom implementation of a parallel quicksort, aiming for high performance.
// Key features:
// 1. 3-Way Partitioning: Efficiently handles inputs with many duplicate keys by
//    partitioning the input into three parts: elements less than the pivot,
//    equal to the pivot, and greater than the pivot. This is particularly
//    effective for distributions like the exponential one, which has many repeats.
// 2. Robust Pivot Selection: Uses the median of three random elements as the pivot
//    to avoid worst-case O(n^2) behavior on sorted or adversarial inputs.
// 3. Hybrid Approach (Base Case): Switches to a fast sequential sort (std::sort)
//    for small subarrays. This avoids the overhead of parallelization on small
//    problem sizes where it's not beneficial. The threshold is a key tuning parameter.
// 4. Balanced Parallelism: When recursing, the larger of the two subproblems is
//    spawned as a parallel task, while the current thread continues to work on the
//    smaller subproblem. This improves load balancing and reduces task scheduling
//    overhead.

namespace expert_sort {

// Threshold for switching to a sequential base case sort.
// This value is chosen based on common practice for high-performance parallel
// sorts, aiming to balance parallel overhead with the benefits of parallel execution.
constexpr size_t SEQUENTIAL_CUTOFF = 2048;

// Selects the median of three elements, which will be used as the pivot.
// The comparison function `f` defines the order.
template<class T, class BinPred>
const T& median_of_three(const T& a, const T& b, const T& c, const BinPred& f) {
    if (f(a, b)) { // a < b
        if (f(b, c)) return b; // a < b < c
        if (f(a, c)) return c; // a < c <= b
        return a;             // c <= a < b
    } else { // b <= a
        if (f(a, c)) return a; // b <= a < c
        if (f(b, c)) return c; // b < c <= a
        return b;             // c <= b <= a
    }
}

// An in-place, parallel 3-way partition.
// It rearranges the slice `A` into three contiguous regions:
// 1. Elements strictly less than `pivot`.
// 2. Elements equal to `pivot`.
// 3. Elements strictly greater than `pivot`.
// It is implemented using two passes of a parallel 2-way partition, leveraging
// the highly optimized `parlay::internal::partition` primitive.
// Returns a pair of iterators pointing to the start and end of the 'equal' region.
template<class Slice, class BinPred>
std::pair<typename Slice::iterator, typename Slice::iterator>
parallel_three_way_partition(Slice A, const typename Slice::value_type& pivot, const BinPred& f) {
    using T = typename Slice::value_type;

    // First pass: Partition into [< pivot] and [>= pivot].
    // The predicate `g` returns true for elements that should be on the right side (>= pivot).
    auto g = [&](const T& val) { return !f(val, pivot); };
    auto middle1 = parlay::internal::partition(A, g);

    // `middle1` now points to the first element that is >= pivot.
    // The range [A.begin(), middle1) contains all elements less than the pivot.

    // Second pass: Partition the second part [middle1, A.end()) into [== pivot] and [> pivot].
    // The predicate `h` returns true for elements that should be on the right side (> pivot).
    auto h = [&](const T& val) { return f(pivot, val); };
    auto slice_ge = A.cut(middle1 - A.begin(), A.size());
    auto middle2 = parlay::internal::partition(slice_ge, h);

    // The final ranges are:
    // < pivot: [A.begin(), middle1)
    // = pivot: [middle1, middle2)
    // > pivot: [middle2, A.end())
    return {middle1, middle2};
}

template <class Slice, class BinPred>
void p_sort_inplace(Slice A, const BinPred& f) {
  if (A.size() <= SEQUENTIAL_CUTOFF) {
    // Base case: for small slices, use a fast sequential sort.
    // std::sort is highly optimized (typically an Introsort).
    std::sort(A.begin(), A.end(), f);
    return;
  }

  // Pivot Selection: Choose the pivot as the median of three random elements.
  // This is a robust strategy against many common input patterns.
  // We use parlay::hash64 for a cheap pseudo-random index.
  size_t n = A.size();
  size_t i1 = parlay::hash64(n) % n;
  size_t i2 = parlay::hash64(i1) % n;
  size_t i3 = parlay::hash64(i2) % n;

  // The pivot value is copied. This is important because the element it was
  // copied from will be moved during partitioning.
  typename Slice::value_type pivot = median_of_three(A[i1], A[i2], A[i3], f);

  // Partition the slice into three parts based on the pivot.
  auto [eq_start, eq_end] = parallel_three_way_partition(A, pivot, f);

  // Recursively sort the '<' and '>' partitions in parallel.
  auto left_slice = A.cut(0, eq_start - A.begin());
  auto right_slice = A.cut(eq_end - A.begin(), n);

  // Optimization: spawn the larger subproblem in a new task and
  // recurse on the smaller one in the current thread. This improves
  // load balancing and reduces the depth of the task DAG.
  if (left_slice.size() > right_slice.size()) {
    parlay::par_do(
      [&] () { p_sort_inplace(left_slice, f); },
      [&] () { p_sort_inplace(right_slice, f); }
    );
  } else {
    parlay::par_do(
      [&] () { p_sort_inplace(right_slice, f); },
      [&] () { p_sort_inplace(left_slice, f); }
    );
  }
}

} // namespace expert_sort

constexpr bool INPLACE = true;

template <class T, class BinPred>
void compSort(parlay::sequence<T>& A, const BinPred& f) {
  // Use parlay::make_slice to create a view over the sequence that can be
  // passed to the recursive sorting helper function.
  expert_sort::p_sort_inplace(parlay::make_slice(A), f);
}
