// A highly optimized parallel comparison sort.
//
// This implementation uses a hybrid strategy:
// 1. For large inputs (n > 32768), it uses a parallel sample sort.
//    Sample sort is known for its excellent scalability and performance on
//    large, randomly distributed data.
// 2. For smaller inputs, it falls back to Parlay's built-in parallel
//    merge sort, which is highly optimized for medium to small-sized inputs.
//
// Key features of the sample sort implementation:
// - Robust Splitter Selection: It uses an oversampling technique and ensures
//   splitters are unique to handle skewed data distributions and inputs with
//   many duplicate keys effectively.
// - Efficient Bucketing: It leverages Parlay's internal `group_by_key`
//   primitive for a fast, low-contention parallel partitioning of the data.
// - Recursive Parallelism: Buckets are sorted recursively in parallel,
//   ensuring that the algorithm adapts to the data distribution and maintains
//   high parallelism throughout.
// - Tuned Parameters: The cutoff points and algorithm parameters (like
//   oversampling factor and number of buckets) are chosen based on common
//   heuristics for high performance on modern multicore processors.

constexpr bool INPLACE = true;

namespace custom_sort {

// Forward declaration of the main recursive sort helper
template <class Slice, class BinPred>
void sort_helper(Slice A, const BinPred& f);

// Cutoff for switching from sample sort to merge sort.
// Below this size, the overhead of sampling and bucketing is not worth it.
constexpr size_t SAMPLE_SORT_CUTOFF = 1 << 15; // 32768

// Base case for sorting small buckets, used to decide bucket count.
constexpr size_t SEQ_SORT_CUTOFF = 1 << 11; // 2048

// Parallel sample sort implementation
template <class Slice, class BinPred>
void sample_sort(Slice A, const BinPred& f) {
    using T = typename Slice::value_type;
    size_t n = A.size();

    // Dynamically choose the number of buckets. More buckets can improve
    // load balance but increase overhead.
    size_t num_workers = parlay::num_workers();
    size_t num_buckets = std::max((size_t)2, std::min((size_t)num_workers * 8, n / SEQ_SORT_CUTOFF));

    // If the input is too small to be effectively partitioned,
    // fall back to merge sort. This check is technically redundant due to
    // the top-level dispatcher, but is good practice.
    if (num_buckets <= 1) {
        parlay::internal::merge_sort_inplace(A, f);
        return;
    }

    // --- 1. Sample and select splitters ---

    // Oversample to get a good representation of the data distribution.
    size_t oversample_factor = 32;
    size_t num_samples = std::min(n, num_buckets * oversample_factor);

    parlay::sequence<T> samples(num_samples);
    auto r = parlay::random_generator();

    // Select random samples in parallel
    parlay::parallel_for(0, num_samples, [&](size_t i) {
        auto rand_val = r[i];
        samples[i] = A[rand_val % n];
    });

    // Sort samples to find splitters
    parlay::sort_inplace(parlay::make_slice(samples), f);

    // Remove duplicates to handle inputs with many repeated values.
    // This makes splitter selection more robust against skew.
    auto is_equal = [&](const T& a, const T& b) { return !f(a, b) && !f(b, a); };
    parlay::sequence<T> unique_samples = parlay::remove_duplicates(samples, is_equal);

    // If not enough unique samples are found to partition the data,
    // fall back to merge sort, which does not have this issue.
    if (unique_samples.size() < num_buckets -1) {
        parlay::internal::merge_sort_inplace(A, f);
        return;
    }

    // Select splitters from the unique sorted samples
    parlay::sequence<T> splitters(num_buckets - 1);
    parlay::parallel_for(0, num_buckets - 1, [&](size_t i) {
        size_t idx = (i + 1) * unique_samples.size() / num_buckets;
        splitters[i] = unique_samples[idx];
    });

    // --- 2. Partition data into buckets based on splitters ---

    // Find which bucket each element belongs to using binary search on splitters.
    auto get_bucket = [&](const T& val) {
        return std::lower_bound(splitters.begin(), splitters.end(), val, f) - splitters.begin();
    };

    // `group_by_key` is a highly optimized primitive that groups elements
    // into a new sequence based on a key-generating function. It returns
    // the new sequence and the starting offsets of each group.
    auto [items, offsets] = parlay::internal::group_by_key(A, get_bucket, num_buckets);

    // --- 3. Recursively sort buckets in parallel ---

    parlay::parallel_for(0, num_buckets, [&](size_t i) {
        auto bucket_slice = items.cut(offsets[i], offsets[i + 1]);
        if (bucket_slice.size() > 0) {
            // Recurse using the main helper, which will choose the best
            // algorithm for the bucket's size.
            sort_helper(bucket_slice, f);
        }
    });

    // --- 4. Copy sorted data back to the input slice ---
    parlay::copy(parlay::make_slice(items), A);
}

// Main recursive helper. Dispatches to sample sort or merge sort.
template <class Slice, class BinPred>
void sort_helper(Slice A, const BinPred& f) {
  if (A.size() <= 1) {
    return;
  }
  if (A.size() > SAMPLE_SORT_CUTOFF) {
      sample_sort(A, f);
  } else {
      parlay::internal::merge_sort_inplace(A, f);
  }
}

} // namespace custom_sort


template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
  custom_sort::sort_helper(parlay::make_slice(A), f);
}
