#start
#include <algorithm>
#include <iterator>

#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/sequence.h"

// The baseline code includes parlay/internal/merge_sort.h.
// For a high-performance sample sort, we need the internal counting_sort primitive.
#include "parlay/internal/counting_sort.h"

// A flag for the benchmark harness indicating that the sort is in-place
constexpr bool INPLACE = true;

namespace an_fast_sort {

// The threshold to switch from parallel sample sort to a sequential base case sort.
// This value is tuned for modern multicore processors; larger values reduce
// parallel overhead, while smaller values introduce more parallelism. 4096 is a
// robust choice that works well across various architectures and data types.
constexpr size_t SEQUENTIAL_THRESHOLD = 4096;

// Recursive helper function for the parallel sample sort.
// This function implements an out-of-place sort from the `in` slice to the `out` slice.
// It partitions the `in` slice into buckets which are written to the `out`
// slice. It then recursively calls itself to sort each bucket, swapping the
// roles of `in` and `out` (a "ping-pong" strategy).
template <class In_iter, class Out_iter, class BinPred>
void sample_sort_recursive(parlay::slice<In_iter, In_iter> in,
                           parlay::slice<Out_iter, Out_iter> out,
                           const BinPred& f) {
  size_t n = in.size();

  // Base case: for small slices, use a fast sequential sort.
  if (n <= SEQUENTIAL_THRESHOLD) {
    std::sort(in.begin(), in.end(), f);
    // Copy the sorted result to the output slice.
    parlay::copy(parlay::make_slice(in), out);
    return;
  }

  // --- Step 1: Select Splitters ---

  // Determine the number of buckets. We aim for more buckets than workers to
  // ensure good load balancing. However, we also avoid creating buckets that
  // are too small, as that would be inefficient.
  size_t p = parlay::num_workers();
  size_t num_buckets = std::min((size_t)2 * p, n / SEQUENTIAL_THRESHOLD);
  num_buckets = std::max(num_buckets, (size_t)2);

  // To find good splitters that divide the data evenly, we take a random
  // sample of the input data that is much larger than the number of splitters
  // (oversampling). An oversampling factor of 32 is a good trade-off between
  // splitter quality and sampling overhead.
  size_t num_samples = std::min(num_buckets * 32, n / 2);
  // Ensure we take at least one sample if the input is not empty.
  if (num_samples == 0 && n > 0) num_samples = 1;

  parlay::sequence<typename std::iterator_traits<In_iter>::value_type> samples(num_samples);
  // Select random samples in parallel. Using a hash function on the index is a
  // fast, simple way to get pseudo-random, contention-free indices.
  parlay::parallel_for(0, num_samples, [&](size_t i) {
    size_t index = parlay::hash64(i) % n;
    samples[i] = in[index];
  });

  // Sort the samples to easily pick splitters.
  std::sort(samples.begin(), samples.end(), f);

  // Choose `num_buckets - 1` splitters from the sorted sample by taking
  // evenly spaced elements.
  parlay::sequence<typename std::iterator_traits<In_iter>::value_type> splitters(num_buckets - 1);
  parlay::parallel_for(0, num_buckets - 1, [&](size_t i) {
    size_t sample_idx = (static_cast<double>(i + 1) / num_buckets) * num_samples;
    splitters[i] = samples[sample_idx];
  });

  // --- Step 2: Partition Data ---

  // Determine the bucket index for each element in the input slice.
  // This is done by finding the position of the element within the sorted splitters.
  // We use a delayed sequence to compute these indices on-the-fly, avoiding
  // the need to store them all in memory.
  auto get_bucket_id = parlay::delayed_seq<size_t>(n, [&](size_t i) {
    const auto& val = in[i];
    // std::upper_bound finds the first splitter greater than the value, which
    // corresponds to the bucket index. This correctly handles duplicate values.
    return std::upper_bound(splitters.begin(), splitters.end(), val, f) - splitters.begin();
  });

  // Use Parlay's highly optimized parallel counting sort primitive to partition
  // the data. It efficiently calculates counts, computes bucket offsets, and
  // moves elements from `in` to their correct bucketed location in `out`.
  // It returns the starting offsets of each bucket.
  parlay::sequence<size_t> bucket_offsets = parlay::internal::count_sort_(
      parlay::make_slice(in), parlay::make_slice(out), get_bucket_id, num_buckets);

  // --- Step 3: Recurse on Buckets ---

  // Now that the data is partitioned into buckets in the `out` slice, we
  // recursively sort each bucket in parallel.
  parlay::parallel_for(0, num_buckets, [&](size_t i) {
    size_t start = bucket_offsets[i];
    size_t end = bucket_offsets[i+1];
    if (end > start) {
      // The crucial ping-pong step: the input for the recursive call is the
      // current output slice (`out`), and the output is the corresponding
      // slice of the original input (`in`). This swaps the roles of the buffers.
      sample_sort_recursive(out.slice(start, end), in.slice(start, end), f);
    }
  });
}

} // namespace an_fast_sort

// The main entry point for the parallel comparison sort.
// This function implements a parallel sample sort, which is known for its
// excellent scalability and performance on a wide range of inputs.
// It uses an O(n) temporary buffer to facilitate the out-of-place partitioning
// required by the algorithm, which is a standard technique for high-performance
// sorts that present an "in-place" interface.
template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
  size_t n = A.size();

  // For small inputs, a sequential sort is faster due to lower overhead.
  if (n <= an_fast_sort::SEQUENTIAL_THRESHOLD) {
    std::sort(A.begin(), A.end(), f);
    return;
  }

  // Allocate a temporary buffer of the same size as the input.
  parlay::sequence<T> B(n);

  // The recursive helper `sample_sort_recursive(in, out)` sorts its `in` buffer
  // and places the sorted result in its `out` buffer.
  //
  // Let's trace the data flow for the top-level call:
  // 1. We call `sample_sort_recursive(A, B)`.
  // 2. This call partitions elements from A into buckets in B.
  // 3. It then makes recursive calls for each bucket: `sample_sort_recursive(B_i, A_i)`.
  // 4. Each recursive call sorts its bucket from B and writes the sorted result
  //    back into the corresponding slice of A.
  //
  // When the top-level call to `sample_sort_recursive` returns, all the sorted
  // buckets reside contiguously in the original `A` buffer. Therefore, `A` is
  // now fully sorted, and no final copy from B to A is needed.
  an_fast_sort::sample_sort_recursive(parlay::make_slice(A), parlay::make_slice(B), f);
}
