// INPLACE is false because the function is specified to be out-of-place,
// returning a new sorted sequence.
constexpr bool INPLACE = false;

namespace expert_sort {

// A stable parallel merge sort, optimized for data with existing order.
// It is implemented using a classic recursive divide-and-conquer strategy.
// It leverages parlay::par_do for parallel recursion and parlay::merge
// for a highly optimized parallel merge step.
template <class T, class BinPred>
parlay::sequence<T> parallel_merge_sort(parlay::slice<const T> A, const BinPred& f) {
    size_t n = A.size();

    // Base case: for small inputs, parallel overhead is not worth it.
    // We switch to std::stable_sort, which is highly optimized for sequential
    // execution and performs especially well on nearly-sorted data due to its
    // adaptive nature. The threshold is chosen empirically to balance
    // parallelism and overhead.
    if (n < 4096) {
        auto result = parlay::sequence<T>(A.begin(), A.end());
        std::stable_sort(result.begin(), result.end(), f);
        return result;
    }

    parlay::sequence<T> left, right;
    size_t middle = n / 2;

    // Recursively sort the two halves of the data in parallel.
    parlay::par_do(
        [&] { left = parallel_merge_sort(A.cut(0, middle), f); },
        [&] { right = parallel_merge_sort(A.cut(middle, n), f); }
    );

    // Merge the two sorted halves using Parlay's parallel merge primitive.
    // parlay::merge is guaranteed to be stable.
    return parlay::merge(parlay::make_slice(left), parlay::make_slice(right), f);
}

// A fast, heuristic-based check to determine if a sequence is "almost sorted".
// This is crucial for the poly-algorithm to decide which sorting strategy to use.
// It works by taking a fixed number of samples from the sequence at regular
// intervals and counting the number of inversions. A low inversion count is a
// strong indicator of a high degree of sortedness.
template<typename T, typename BinPred>
bool is_almost_sorted(parlay::slice<const T> A, const BinPred& f) {
    size_t n = A.size();
    // The check is only worthwhile for large sequences where the choice of
    // algorithm has a significant performance impact.
    if (n < 8192) return false;

    // Use a constant number of samples to ensure the check is O(1) w.r.t. n.
    const size_t num_samples = 1024;
    size_t step = n / num_samples;
    if (step == 0) return false;

    size_t num_inversions = 0;
    // Count inversions among the sampled elements.
    // An inversion is a pair of samples (A[i], A[j]) with i < j but A[i] > A[j].
    for (size_t i = 0; i < num_samples - 1; i++) {
        // The comparison f(a, b) returns true if a is ordered before b.
        // An inversion exists if a later element should be ordered before an earlier one.
        if (f(A[(i + 1) * step], A[i * step])) {
            num_inversions++;
        }
    }

    // The heuristic threshold: if fewer than 2% of sampled pairs are inverted,
    // we classify the sequence as "almost sorted". This value is chosen to be
    // conservative, avoiding the merge sort path unless there is strong evidence
    // that it will be beneficial.
    return num_inversions < num_samples * 0.02;
}

