// heuristic that samples the data to check for sortedness. This adaptive
// approach ensures top performance across a wide range of input types,
// including those specified in the problem description.
template <class T, class BinPred>
parlay::sequence<T> compSort(parlay::sequence<T> const &A, const BinPred& f) {
  auto S = parlay::make_slice(A);

  if (expert_sort::is_almost_sorted(S, f)) {
