    // likely almost sorted. In this case, we switch to a parallel merge sort,
    // which is known to be efficient for such distributions.
    // Parlay's `stable_sort` is an in-place merge sort, so we sort a copy.
    if (inversions < num_samples / 200) {
      parlay::sequence<T> result = A;
      parlay::stable_sort(parlay::make_slice(result), f);
