// A fast, parallel, sampling-based heuristic to detect if a sequence
// is "almost sorted". It works by checking for out-of-order elements
// (descents) in a number of randomly chosen contiguous blocks from the
// input sequence. If the density of descents is very low, the input is
// considered almost sorted.
template <typename T, typename BinPred>
bool is_almost_sorted(parlay::slice<const T> A, const BinPred& f) {
  size_t n = A.size();

  // For small inputs, the overhead of this check is not worthwhile.
  // The base sorting algorithms are fast enough, and the cost of the
  // heuristic might be a significant fraction of the total sort time.
  // This threshold is tuned to avoid the check on small-to-medium inputs.
  constexpr size_t small_input_threshold = 100000;
  if (n < small_input_threshold) {
    return false;
  }

  // Configuration for the sampling process. These values are chosen
  // to keep the heuristic's runtime low while ensuring the sample is
  // representative enough to make a good prediction. We sample 256
  // blocks of 256 elements each, for a total of 65536 sampled elements.
  constexpr size_t num_sample_blocks = 256;
  constexpr size_t sample_block_len = 256;

  // Ensure we have enough data for this sampling strategy.
  if (n < num_sample_blocks * sample_block_len) {
    return false;
  }

  // Use Parlay's deterministic random number generator. This makes the
  // behavior repeatable for the same input and number of threads.
  auto r = parlay::random();

  // In parallel, count the number of descents in each sample block.
  // A descent is a pair of adjacent elements (a, b) where b < a.
  auto descents_per_block = parlay::tabulate(num_sample_blocks, [&](size_t i) {
    // Choose a random starting point for the block.
    size_t start = r.ith_rand(i) % (n - sample_block_len);
    size_t descents = 0;
    for (size_t j = 0; j < sample_block_len - 1; j++) {
      if (f(A[start + j + 1], A[start + j])) {
        descents++;
      }
    }
    return descents;
  });

  // Sum the descents from all sample blocks.
  size_t total_descents = parlay::reduce(descents_per_block);

  // Heuristic threshold: If the density of descents in our sample is very
  // low, we assume the whole array is almost sorted. A perfectly sorted
  // array has 0 descents. A randomly shuffled array has a descent with
  // approximately 50% probability for each adjacent pair. We set a
  // conservative threshold of roughly 0.1% (1/1024), meaning that if
  // less than 1 in 1024 elements in our sample is part of a descent, we
  // switch to the merge sort strategy.
  constexpr size_t threshold_denominator = 1024;
  return total_descents < (num_sample_blocks * sample_block_len) / threshold_denominator;
}

