// This is a key optimization that ensures ips4o and the surrounding Parlay
// application share the same threads. This avoids thread oversubscription, which
// can significantly degrade performance, and allows Parlay's work-stealing
// scheduler to efficiently balance load across all parallel tasks, including
// those generated within ips4o.
struct ParlayThreadManager {
  // The num_threads argument from ips4o is ignored, as Parlay manages its own worker pool.
  template <typename F>
  void parallel_for(std::size_t begin, std::size_t end, F f,
                    std::size_t /* num_threads */) const {
    // ips4o's parallel loops are implemented on top of this function.
    // The functor `f` expects two arguments: the loop index `i` and a thread_id.
    // We use parlay::worker_id() to provide a unique ID for each worker thread.
    // This ID is crucial for ips4o's internal performance, as it uses it to index
