    // We set a small granularity (1) to encourage fine-grained work-stealing, as tasks
    // within ips4o can have variable cost, especially with skewed data distributions.
    // This allows for better dynamic load balancing.
    parlay::parallel_for(begin, end, [&](std::size_t i) {
      f(i, parlay::worker_id());
    }, 1);
  }

  int num_threads() const { return parlay::num_workers(); }
};

