/*
 * This implementation provides a high-performance parallel algorithm for removing duplicate
 * elements from a sequence.
 *
 * The overall strategy is hash-based, which offers an average-case time complexity of O(n).
 * This is generally faster than a sort-based approach (O(n log n) for general types)
 * for the specified data distributions (random, exponential, trigram strings).
 *
 * The core logic consists of three main steps:
 * 1. A concurrent hash table is used to find the first occurrence of each unique element
 *    in the input sequence `A`. Each thread processes a portion of `A` and attempts
 *    to "claim" a slot in the hash table for its elements. Atomic compare-and-swap
 *    operations are used to resolve race conditions, ensuring that for each group of
 *    duplicate elements, only the one processed first is marked as unique.
 *
 * 2. This process generates a boolean flag sequence, `is_first`, of the same size as `A`,
 *    where `is_first[i]` is true if and only if `A[i]` is the first occurrence of that
 *    value in the parallel traversal.
 *
 * 3. `parlay::pack` is then used to efficiently and in parallel create the final result
 *    sequence, containing only the elements from `A` that were flagged as first occurrences.
 *
 * A cutoff is used for small inputs, where the overhead of parallelization is not
 * justified. For these cases, the code falls back to a simple and efficient serial
 * implementation using `std::unordered_set`.
 */

namespace { // Anonymous namespace for helper functions

// Helper function containing the main parallel logic.
template <class T>
parlay::sequence<T> parallel_dedup_hash(parlay::sequence<T> const &A) {
    using Hasher = parlay::hash<T>;
    size_t n = A.size();

    // A hash table with a load factor of <= 0.5 significantly reduces collisions.
    // Using a power of two for the size allows for fast modulo via bitwise AND.
    size_t table_size = parlay::internal::next_power_of_2(n * 2);

    // The table stores indices into the input sequence `A`.
    // A special value indicates an empty slot.
    const size_t empty_slot = static_cast<size_t>(-1);
    auto table = parlay::sequence<std::atomic<size_t>>(table_size);

    // Initialize the table in parallel. Relaxed memory order is sufficient
    // as subsequent operations will use stronger ordering to synchronize.
    parlay::parallel_for(0, table_size, [&](size_t i) {
        table[i].store(empty_slot, std::memory_order_relaxed);
    });

    // A flag for each input element, true if it's the first time we've seen it.
    // Using an uninitialized sequence avoids the cost of default-initializing elements.
    auto is_first = parlay::uninitialized_sequence<bool>(n);

    parlay::parallel_for(0, n, [&](size_t i) {
        const T& val = A[i];
        size_t h = Hasher{}(val) & (table_size - 1);

        // Linear probing to find an empty slot or a matching element.
        while (true) {
            size_t current_idx = table[h].load(std::memory_order_relaxed);

            if (current_idx == empty_slot) {
                // Slot is empty. Try to atomically claim it with our index `i`.
                // A successful CAS with `memory_order_release` ensures that our write
                // to the table is visible to all other threads. It establishes a
                // "happens-before" relationship, which is crucial for the correctness
                // of the `A[current_idx] == val` check in other threads.
                if (table[h].compare_exchange_strong(current_idx, i, std::memory_order_release, std::memory_order_relaxed)) {
                    is_first[i] = true;
                    break;
                }
                // If CAS fails, another thread just claimed the slot. `current_idx` is updated
                // with the new value, so we loop again and check it.
            }

            // Slot is not empty. Check if the element at the stored index is equal to ours.
            if (A[current_idx] == val) {
                // A duplicate is found. Another thread processed an equal element first.
                is_first[i] = false;
                break;
            }

            // Collision with a different value. Probe to the next slot.
            h = (h + 1) & (table_size - 1);
        }
    });

    // Pack the elements from A that were flagged as first occurrences.
    // This efficiently constructs the result sequence in parallel.
    // The result preserves the relative order of unique elements from the input.
    return parlay::pack(A, is_first);
}

} // namespace

template <class T>
parlay::sequence<T> dedup(parlay::sequence<T> const &A) {
  size_t n = A.size();
  if (n == 0) {
    return parlay::sequence<T>();
