    std::unordered_set<T> s(A.begin(), A.end());
    return parlay::to_sequence(s);
  }

  // For larger inputs, use the optimized parallel hash-based implementation.
  return parallel_dedup_hash(A);
}
// --- End of file: dedup.h ---
