  // A simple serial implementation using std::unordered_set is faster.
  // The threshold is chosen empirically as a reasonable crossover point.
  if (A.size() < 10000) {
    std::unordered_set<T> s(A.begin(), A.end());
    return parlay::to_sequence(s);
  }

  // Define the traits for our hash table. We only need a set of keys, so we
  // use a dummy `parlay::empty` type for the values, which has zero size.
  // `parlay::hash<T>` provides a default hash function for standard types.
  struct TableTraits {
    using Key = T;
    using Value = parlay::empty;
    static inline size_t hash(const Key& k) { return parlay::hash<Key>{}(k); }
    static inline bool equal(const Key& a, const Key& b) { return a == b; }
  };

  using table_type = parlay::hash_table<TableTraits>;

  // Create the hash table from the input sequence `A`.
