    *   It uses a high-performance concurrent hash set (`parlay::open_address_hash_table`).
    *   The hash table is pre-sized to twice the input size to ensure a low load factor, minimizing collisions and maximizing throughput.
    *   A parallel loop iterates over the input sequence. Each element attempts an atomic `insert` into the hash table. The `insert` operation returns `true` only for the first successful insertion of a given value.
    *   These boolean return values are used as flags for `parlay::pack`, which constructs the final sequence from the original input. This approach preserves the relative order of the first appearance of each unique element.

This hybrid strategy ensures state-of-the-art performance across the specified input distributions and is characteristic of a high-quality parallel library implementation.

```cpp
#start
// --- Start of file: dedup.h ---
#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/hash_table.h"
#include "parlay/integer_sort.h"
#include "parlay/utilities.h" // For log2_up
#include <type_traits>

template <class T>
parlay::sequence<T> dedup(parlay::sequence<T> const &A) {
  using namespace parlay;
  size_t n = A.size();

  if (n <= 1) {
    // For empty or single-element sequences, no duplicates are possible.
    // Return a new sequence containing the same elements.
    return sequence<T>(A.begin(), A.end());
  }

  // This implementation uses a type-based dispatch to select the fastest
  // algorithm for the given data type, a common strategy in high-performance
  // libraries.

  // For integral types up to 64 bits, a sort-based approach using
  // a specialized integer sort is typically the fastest. Integer sort has
  // linear work complexity and excellent memory access patterns, often
  // outperforming hash-based approaches for these types.
  if constexpr (std::is_integral_v<T> && sizeof(T) <= 8) {
    // Create a sorted copy of the input sequence.
    sequence<T> B = integer_sort(A);

    // Generate flags to mark the first occurrence of each unique element.
    // In a sorted sequence, unique elements are at positions where the
    // element differs from its predecessor.
    auto flags = sequence<bool>::uninitialized(n);
    flags[0] = true;
    parallel_for(1, n, [&](size_t i) {
      // This comparison is safe because we are in a sorted sequence.
      flags[i] = (B[i] != B[i-1]);
    });

    // Pack the unique elements from the sorted sequence into the result.
    // The result will be a sorted sequence of unique elements.
    return pack(B, flags);
  } else {
    // For general types (e.g., strings, floating-point numbers, custom objects),
    // a hash-based approach is generally superior. It avoids the O(n log n)
    // work of comparison sorting and has expected linear work complexity.

    // Create a concurrent hash table. We size it to be at least twice the
    // input size to maintain a low load factor (<= 0.5), which is crucial
    // for minimizing collisions and ensuring good performance.
    // The size must be a power of two for this hash table implementation.
    size_t table_size = size_t{1} << parlay::log2_up(n * 2);

    auto table = open_address_hash_table<T, bool>(
        table_size, std::hash<T>(), std::equal_to<T>());

    // In parallel, try to insert each element from A into the hash table.
    // The `insert` operation is atomic and returns true only for the
    // thread that successfully inserts a key for the first time. This
    // flag directly tells us which elements from A are unique first
    // occurrences.
    auto flags = sequence<bool>::uninitialized(n);
    parallel_for(0, n, [&](size_t i) {
      flags[i] = table.insert(A[i], true);
    });

    // Pack the elements from the original sequence A that were successfully
    // inserted into the table. This preserves the relative order of the
    // first occurrences of unique elements.
    return pack(A, flags);
  }
}
