// This serves as the base case for the parallel algorithm.
parlay::sequence<uint> histogram_sequential(parlay::sequence<uint> const &In, uint buckets) {
  // Initialize the result sequence to all zeros.
  parlay::sequence<uint> result(buckets, 0U);
  for (const auto& x : In) {
