  return result;
}

} // anonymous namespace

// This function implements a highly optimized parallel histogram.
// It employs a hybrid strategy to achieve the best performance across various
// input sizes and bucket counts.
parlay::sequence<uint> histogram(parlay::sequence<uint> const &In, uint buckets) {
  size_t n = In.size();

  // --- Strategy 1: Sequential Base Case ---
  // For small inputs or trivial cases, the overhead of parallelization outweighs the benefits.
  constexpr size_t SEQUENTIAL_THRESHOLD = 16384;
  if (n < SEQUENTIAL_THRESHOLD || buckets == 0) {
    return histogram_sequential(In, buckets);
  }

  size_t num_workers = parlay::num_workers();

  // --- Heuristic to select between two parallel strategies ---
  // We choose between a memory-intensive but contention-free "local histogram"
  // approach and a memory-light but potentially contention-heavy "atomic" approach.
  // The choice is based on the total memory required for the local histograms.
  // If it would exceed a threshold (e.g., a fraction of L3 cache), we switch to atomics.
  constexpr size_t LOCAL_HIST_MEM_THRESHOLD = 16 * 1024 * 1024; // 16 MB

  if ((num_workers * buckets * sizeof(uint)) > LOCAL_HIST_MEM_THRESHOLD) {
    // --- Strategy 2: Atomic Operations ---
    // This is best for a very large number of buckets where creating local
    // histograms for each thread would consume too much memory.
    // Contention is low if the distribution is sparse.

    // Use a sequence of atomics for the counters.
    parlay::sequence<std::atomic<uint>> result(buckets);

    // Initialize counters in parallel.
    parlay::parallel_for(0, buckets, [&](size_t i) {
      result[i].store(0, std::memory_order_relaxed);
