    parlay::sequence<uint> final_result = parlay::sequence<uint>::uninitialized(buckets);
    parlay::parallel_for(0, buckets, [&](size_t i) {
      final_result[i] = result[i].load(std::memory_order_relaxed);
    });
    return final_result;

  } else {
    // --- Strategy 3: Local Histograms (Reduce/Merge) ---
    // This is the fastest method for a moderate number of buckets. Each thread
    // works on a private local histogram, eliminating contention during the
    // counting phase. The results are then merged in a final parallel step.

    // Pad each local histogram to the size of a cache line (typically 64 bytes)
    // to prevent "false sharing", where threads slow each other down by
    // writing to different variables that happen to reside on the same cache line.
    constexpr size_t cache_line_size = 64;
    const size_t padded_buckets = (buckets * sizeof(uint) + cache_line_size - 1) / cache_line_size * (cache_line_size / sizeof(uint));

