#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/parallel.h"
#include "parlay/utilities.h"

#include <cstdint>

/**
 * @brief Computes a histogram of a sequence of unsigned integers in parallel.
 *
 * This implementation is designed for maximum performance and follows the widely-used
 * "private histograms" pattern to eliminate contention.
 *
 * The strategy involves two main phases:
 * 1.  **Parallel Counting:** The input sequence is divided among all available worker
 *     threads. Each thread computes a local histogram for its assigned portion of
 *     the input. Since each thread writes to its own private memory, this phase
 *     is completely free of race conditions, locks, or atomic operations,
 *     allowing for maximum parallelism and excellent cache utilization.
 *
 * 2.  **Parallel Reduction:** After all local histograms are computed, the results
 *     are aggregated. The final histogram (of size `buckets`) is partitioned
 *     among the workers. Each worker is responsible for calculating the final
 *     count for a range of buckets by summing the counts from all the private
 *     histograms for those buckets.
 *
 * This approach is extremely effective because the most computationally intensive
 * part (iterating over `n` elements) is perfectly parallel, while the memory
 * overhead (`num_workers * buckets * sizeof(uint)`) is manageable for the
 * problem scales described.
 *
 * @param In The input sequence of integers. All values must be in the range `[0, buckets)`.
 * @param buckets The number of buckets in the histogram, defining the range of input values.
 * @return A sequence of length `buckets` where the i-th element is the count of the value `i`.
 */
parlay::sequence<uint> histogram(parlay::sequence<uint> const &In, uint buckets) {
  size_t n = In.size();
  if (n == 0) {
    return parlay::sequence<uint>(buckets, 0);
  }

  // Get the number of available worker threads from the Parlay scheduler.
  size_t num_workers = parlay::num_workers();

  // For very small inputs, a sequential approach can be faster due to overhead.
  // This threshold is empirical but helps avoid parallel overhead for trivial work.
  if (n < 1000 || buckets == 0) {
    auto result = parlay::sequence<uint>(buckets, 0);
    for (size_t i = 0; i < n; i++) {
      result[In[i]]++;
    }
    return result;
  }

  // Phase 1: Parallel Counting with Per-Thread Private Histograms

  // Allocate a single contiguous block of memory for all private histograms.
  // This improves allocation speed and data locality. Each worker gets a
  // `buckets`-sized slice of this memory.
  // Using uint64_t for counts to prevent overflow on very large inputs,
  // even though the final result is uint. This is a safety measure.
  parlay::sequence<uint64_t> local_histograms(num_workers * buckets, 0);

  parlay::parallel_for(0, num_workers, [&](size_t worker_id) {
    // Partition the input sequence `In` among the workers.
    size_t start = (n * worker_id) / num_workers;
    size_t end = (n * (worker_id + 1)) / num_workers;

    // Get a pointer to this worker's private histogram.
    // Using a raw pointer can be slightly faster than creating a parlay::slice.
    uint64_t* my_hist = local_histograms.data() + worker_id * buckets;

    // Each worker iterates over its chunk of the input and updates its
    // private histogram. There is no data sharing or contention here.
    for (size_t i = start; i < end; i++) {
      // It is a precondition that In[i] < buckets.
      my_hist[In[i]]++;
    }
  });

  // Phase 2: Parallel Reduction

  // The final result sequence.
  auto result = parlay::sequence<uint>(buckets);

  // Parallelize the summation over the buckets. Each worker is responsible
  // for a range of buckets.
  parlay::parallel_for(0, buckets, [&](size_t i) {
    // Sum the counts for bucket `i` from all local histograms.
    uint64_t total_count = 0;
    for (size_t worker_id = 0; worker_id < num_workers; worker_id++) {
      total_count += local_histograms[worker_id * buckets + i];
    }
    // The final count must fit in a uint as per the function signature.
    result[i] = static_cast<uint>(total_count);
  });

  return result;
}
