#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/io.h"
#include "parlay/group_by_ops.h" // For parlay::group_by_and_combine_by_hash
#include "parlay/internal/get_time.h"
#include "wc.h"

// The fastest word-counting program combines several optimizations:
//
// 1.  Single-pass Preprocessing: A parallel `parlay::map` operation processes
//     the input characters in one go. It converts uppercase letters to
//     lowercase and replaces all non-alphabetic characters with a null
//     delimiter (0). This is faster than using standard library functions
//     like `isalpha` and `tolower` because it avoids function call overhead
//     and is not locale-dependent.
//
// 2.  Optimized Tokenization: `parlay::tokens` is used to efficiently find
//     all words in parallel. It is a highly-optimized library primitive that
//     returns a sequence of lightweight slices pointing into the preprocessed
//     string, avoiding costly string copies.
//
// 3.  Hash-based Aggregation: Instead of the baseline's sort-based
//     `histogram_by_key`, this implementation uses the explicitly hash-based
//     `parlay::group_by_and_combine_by_hash`. For word counting, hashing is
//     typically much faster than sorting because it avoids O(L * log N)
//     string comparisons, where L is the average word length. The expected
//     complexity is closer to linear in the total number of characters.
//
// 4.  Reduced Memory Traffic: To prepare the input for the aggregation step,
//     we need a sequence of (word, 1) pairs. A naive `parlay::map` would
//     allocate a large intermediate array for these pairs. Instead, this
//     solution uses `parlay::delayed_seq` to create a virtual sequence.
//     The pairs are generated on-the-fly as they are consumed by the
//     hashing function, completely eliminating the intermediate memory
//     allocation and the associated memory traffic. This improves both
//     speed and memory footprint.

parlay::sequence<result_type> wordCounts(charseq const &s, bool verbose=false) {
  parlay::internal::timer t("word counts", verbose);
  if (verbose) std::cout << "number of characters = " << s.size() << std::endl;

  // Step 1: Pre-processing.
  // In a single parallel pass, create a new character sequence where:
  // - All alphabetic characters are converted to lower case.
  // - All non-alphabetic characters are converted to 0 (null), which acts as a delimiter.
  auto str = parlay::map(s, [] (char c) -> char {
    if (c >= 'A' && c <= 'Z') return c + ('a' - 'A');
    if (c >= 'a' && c <= 'z') return c;
    return 0;
  });
  t.next("copy and clean");

  // Step 2: Tokenization.
  // In a parallel pass, identify all maximal contiguous subsequences of non-delimiter characters.
  // `parlay::tokens` returns a sequence of slices into `str`, avoiding data copies.
  auto words = parlay::tokens(str, [] (char c) {return c == 0;});
  t.next("tokens");
  if (verbose) std::cout << "number of words = " << words.size() << std::endl;

  // Step 3: Counting via Hashing.
  // We need to count occurrences of each unique word. A hash-based approach is best.
  // `parlay::group_by_and_combine_by_hash` takes a sequence of key-value pairs
  // and aggregates them. We want to aggregate a sequence of (word, 1) pairs.

  // To avoid allocating a temporary array for the (word, 1) pairs, we create a
  // "delayed sequence" (a view) that generates these pairs on demand.
  auto pairs_view = parlay::delayed_seq<std::pair<charseq, size_t>>(words.size(),
    [&](size_t i) {
      // Create a pair with the word and a count of 1.
      // The word (a slice) is copied, which is a cheap operation.
      return std::make_pair(words[i], static_cast<size_t>(1));
  });

  // Perform the hash-based grouping and summation.
  auto result = parlay::group_by_and_combine_by_hash(pairs_view,
    [] (size_t a, size_t b) { return a + b; });
  t.next("count by key (hash)");

  if (verbose) std::cout << "distinct words: " << result.size() << std::endl;
  return result;
}
// --- End of file: wc.C ---
```
