#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/io.h"
#include "parlay/internal/get_time.h"
#include "wc.h"

// This implementation improves upon the baseline by avoiding the
// initial full-sized memory allocation and copy of the input string.
//
// The key optimizations are:
// 1. Direct Tokenization: Instead of first creating a normalized
//    (lowercase, non-alpha chars replaced by spaces) copy of the string,
//    we run `parlay::tokens` directly on the input string. This
//    generates views (`parlay::sequence_view`) into the original
//    string, saving a full memory copy and pass over the data.
//
// 2. Case-Insensitive Hashing: Since the token views may point to
//    words with mixed case (e.g., "The", "the"), we provide a custom
//    case-insensitive hash and equality functor to `parlay::histogram_by_key`.
//    This ensures that all variations of a word are grouped together.
//    The case conversion happens on-the-fly during hashing and
//    comparison, which is much cheaper than writing a new multi-million
//    character string.
//
// 3. Deferred Normalization: The final conversion of words to their
//    canonical lowercase form is done only on the unique words after
//    counting. Since the number of unique words is vastly smaller
//    than the total number of words, this final mapping step is
//    very fast.

namespace {

// A helper function to convert a character to lowercase.
// It is faster than the standard library's `tolower` as it
// avoids locale-handling overhead and is inlined.
inline char to_lower_ascii(char c) {
  if (c >= 'A' && c <= 'Z') {
    return c + ('a' - 'A');
  }
  return c;
}

// A predicate to identify word delimiters. A character is a delimiter
// if it is not an alphabetic character.
inline bool is_delimiter(char c) {
  return !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z'));
}

// A functor that provides case-insensitive hash and equality
// operations for character sequences (e.g., parlay::sequence_view).
// It can be passed directly to parlay::histogram_by_key.
struct CaseInsensitiveEqHash {
  // Hash function
  template <typename T>
  size_t operator()(const T& s) const {
    // A simple and fast hash function (djb2).
    size_t hash = 5381;
    for (char c : s) {
      hash = ((hash << 5) + hash) + to_lower_ascii(c);
    }
    return hash;
  }

  // Equality function
  template <typename T1, typename T2>
  bool operator()(const T1& s1, const T2& s2) const {
    if (s1.size() != s2.size()) {
      return false;
    }
    // For short strings like words, a simple sequential loop is
    // faster than a parallel one due to lower overhead.
    for (size_t i = 0; i < s1.size(); i++) {
      if (to_lower_ascii(s1[i]) != to_lower_ascii(s2[i])) {
        return false;
      }
    }
    return true;
  }
};

} // anonymous namespace

parlay::sequence<result_type> wordCounts(charseq const &s, bool verbose=false) {
  parlay::internal::timer t("word counts", verbose);
  if (verbose) std::cout << "number of characters = " << s.size() << std::endl;

  // Step 1: Generate views of words by tokenizing the original string.
  // This avoids creating a full copy of the string.
  auto word_views = parlay::tokens(s, is_delimiter);
  t.next("tokens");
  if (verbose) std::cout << "number of words = " << word_views.size() << std::endl;

  // Step 2: Count occurrences using a histogram with case-insensitive comparison.
  // The keys in the resulting histogram are views into the original input `s`.
  // std::move is used to allow the histogram to potentially reuse word_views memory.
  auto counted = parlay::histogram_by_key(std::move(word_views), CaseInsensitiveEqHash{});
  t.next("count by key");

  // Step 3: Convert the result to the required output format.
  // This involves creating new, owned, lowercase strings for each unique word.
  // This map is only over the unique words, so it's very fast.
  auto result = parlay::map(counted, [] (const auto& p) {
    auto word_view = p.first;
    auto count = p.second;
    // Create a new charseq from the view, converting to lowercase.
    auto lower_word = parlay::map(word_view, to_lower_ascii);
    return std::make_pair(std::move(lower_word), count);
  });
  t.next("format result");

  if (verbose) std::cout << "distinct words: " << result.size() << std::endl;
  return result;
}
