// This approach maximizes parallelism at every stage and leverages high-level
// library primitives for conciseness and performance. It is significantly
// faster than the serial baseline by avoiding serial bottlenecks such as
// `strtok` and serial hash table insertions.
parlay::sequence<result_type> wordCounts(charseq const &s, bool verbose=false) {
  parlay::internal::timer t("Word Counts", verbose);

