  // `parlay::tokens` efficiently splits the sequence based on a separator
  // predicate. It returns a sequence of non-copying views (`parlay::chars`)
  // into the `cleaned_s` sequence. This is very memory-efficient.
  auto words = parlay::tokens(cleaned_s, [](char c) {
    return c == ' ';
  });
  t.next("Tokenize");

