  // We create a "delayed sequence" of (word, 1) pairs. This is a view
  // that computes the pairs on-the-fly, avoiding the allocation of a
  // large intermediate array and reducing memory traffic.
  auto word_pairs = parlay::delayed_seq<std::pair<parlay::chars, size_t>>(
    words.size(),
    [&](size_t i) { return std::make_pair(words[i], size_t{1}); }
  );

  // `reduce_by_key` groups all pairs with the same key (the word)
  // and reduces their values (the counts) using summation. It operates
  // efficiently on the delayed sequence and is the core of the parallel
  // aggregation step.
  auto counts = parlay::reduce_by_key(word_pairs);
  t.next("Count words");

  // 4. Convert the result to the required output format in parallel.
  // The keys in `counts` are views (`parlay::chars`) that point into the
