// The main word counts function
parlay::sequence<result_type> wordCounts(charseq const &s, bool verbose=false) {
  parlay::internal::timer t("word counts", verbose);

  // 1. Clean and Normalize Text
  // In parallel, create a new sequence where all alphabetic characters are
  // converted to lower case and all non-alphabetic characters are
  // converted to spaces. This is an embarrassingly parallel map operation.
  parlay::sequence<char> cleaned_s = parlay::map(s, [](char c) -> char {
    if (c >= 'A' && c <= 'Z') return c + ('a' - 'A');
    if (c >= 'a' && c <= 'z') return c;
    return ' ';
  });
  t.next("Clean and Normalize");

  // 2. Identify Word Starts
  // A character is the start of a word if it is not a space, and the
  // preceding character is a space (or it's the beginning of the string).
  // `parlay::pack_index` efficiently filters the indices from 0 to n-1
  // based on a predicate, avoiding the creation of an intermediate boolean array.
  parlay::sequence<size_t> word_starts = parlay::pack_index(parlay::delayed_seq(cleaned_s.size(), [&](size_t i) {
    return (cleaned_s[i] != ' ') && (i == 0 || cleaned_s[i-1] == ' ');
  }));
  t.next("Find word starts");

  if (word_starts.empty()) {
    return parlay::sequence<result_type>();
  }

  // 3. Create Word Views
  // For each word start index, create a lightweight "view" (or "slice")
  // of the word in the cleaned string. This avoids creating many small strings,
  // which would be expensive. A view is just a pointer and a length.
  auto words = parlay::map(word_starts, [&](size_t start_idx) {
    size_t end_idx = start_idx;
    while (end_idx < cleaned_s.size() && cleaned_s[end_idx] != ' ') {
      end_idx++;
    }
    return cleaned_s.cut(start_idx, end_idx);
  });
  t.next("Create word views");

  // 4. Group and Count Words
  // `parlay::group_by_key` is a powerful primitive that sorts the input
  // sequence and then groups identical adjacent elements. This is the most
  // efficient and idiomatic way to count occurrences in parallel with Parlay.
  auto groups = parlay::group_by_key(words);
  t.next("Group and Count");

  // 5. Format the Output
  // Convert the grouped results into the required output format of
  // (string, count) pairs. This involves converting the word view
  // (the key of the group) into a new, owned string sequence.
  auto result = parlay::map(groups, [](const auto& group) {
    // group.first is the unique word (as a sequence_view)
    // group.second is the range of its occurrences
    // The count is simply the size of this range.
    return std::make_pair(charseq(group.first), group.second.size());
  });
  t.next("Extract results");

  return result;
}
