  auto doc_starts = parlay::sequence<size_t>();
  if (m > 0 && n >= m) {
    auto matches = parlay::tabulate(n - m + 1, [&](size_t i) {
      return s.cut(i, i + m) == doc_start;
    });
    doc_starts = parlay::pack_index(matches);
  }

  size_t num_docs = doc_starts.size();
  if (num_docs == 0) return charseq();
  t.next("find doc starts");

  // 2. Create a mutable copy of the input string.
  // In this copy, convert all letters to lowercase and replace
  // all non-alphabetic characters with a null terminator, which
  // will act as a delimiter for words.
  // This is done in-place and in parallel.
  charseq s_copy = s;
  parlay::parallel_for(0, n, [&](size_t i) {
    if (std::isalpha(s_copy[i])) {
      s_copy[i] = std::tolower(s_copy[i]);
    } else {
      s_copy[i] = '\0';
    }
  });
  t.next("lowercase and clean");

  using word_view = parlay::sequence_view<char>;
  using word_doc_pair = std::pair<word_view, size_t>;

  // 3. For each document, generate a set of (word, doc_id) pairs.
  // This is the "map" step, executed in parallel for each document.
  auto pairs_per_doc = parlay::tabulate(num_docs, [&](size_t i) {
    size_t start = doc_starts[i] + m;
    size_t end = (i == num_docs - 1) ? n : doc_starts[i+1];
    auto doc_view = s_copy.cut(start, end);

    // Use a hash set to find the unique words within the document.
    // This is more efficient than sorting and then unique-ing.
    auto word_hash = [](const word_view& w) { return parlay::hash<word_view>{}(w); };
    auto word_eq = [](const word_view& a, const word_view& b) { return a == b; };
    std::unordered_set<word_view, decltype(word_hash), decltype(word_eq)> unique_words(0, word_hash, word_eq);

    // Tokenize the document view by splitting on null terminators.
    size_t current = 0;
    while(current < doc_view.size()) {
      while(current < doc_view.size() && doc_view[current] == '\0') current++;
      if (current >= doc_view.size()) break;
      size_t word_start = current;
      while(current < doc_view.size() && doc_view[current] != '\0') current++;
      unique_words.insert(doc_view.cut(word_start, current));
    }

    // Convert the set of unique words into a sequence of (word, doc_id) pairs.
    parlay::sequence<word_doc_pair> pairs = parlay::sequence<word_doc_pair>::uninitialized(unique_words.size());
    size_t k = 0;
    for (const auto& w : unique_words) {
      pairs[k++] = std::make_pair(w, i);
    }
    return pairs;
  });

  // Flatten the sequence of sequences of pairs into a single sequence.
  auto all_pairs = parlay::flatten(pairs_per_doc);
  t.next("tokenize");

  // 4. Sort all (word, doc_id) pairs.
  // This is the "shuffle and sort" step. Sorting by pair will first sort
  // by word lexicographically, and then by doc_id for ties. This is
  // exactly the grouping we need.
  parlay::sort_inplace(all_pairs);
  t.next("sort pairs");

  // 5. Identify the start of each word group in the sorted sequence.
  if (all_pairs.empty()) return charseq();
  auto is_group_start = parlay::tabulate(all_pairs.size(), [&](size_t i) {
    return (i == 0) || (all_pairs[i].first != all_pairs[i-1].first);
  });
  auto group_starts = parlay::pack_index(is_group_start);
  size_t num_unique_words = group_starts.size();
  t.next("find groups");

  // 6. Precompute the string representation of all document IDs in parallel.
  auto doc_id_strs = parlay::tabulate(num_docs, [](size_t i) {
    return parlay::to_chars(i);
  });
  t.next("doc_id to_chars");

  // 7. Format the final output string in parallel.
  // This is a two-pass process to avoid string concatenations and allocations.

  // First pass: calculate the length of each line in the output.
  auto line_lengths = parlay::tabulate(num_unique_words, [&](size_t i) {
    size_t group_start_idx = group_starts[i];
    size_t group_end_idx = (i == num_unique_words - 1) ? all_pairs.size() : group_starts[i+1];

    const auto& word = all_pairs[group_start_idx].first;
    size_t len = word.size();

    for (size_t j = group_start_idx; j < group_end_idx; ++j) {
      len += 1 + doc_id_strs[all_pairs[j].second].size(); // ' ' + doc_id_str
    }
    len += 1; // '\n'
    return len;
  });

  // Calculate the starting offset for each line in the final buffer.
  auto [offsets, total_len] = parlay::scan_inclusive(line_lengths);
  charseq result = charseq::uninitialized(total_len);
  t.next("calculate offsets");

  // Second pass: fill the result buffer in parallel.
  parlay::parallel_for(0, num_unique_words, [&](size_t i) {
    size_t group_start_idx = group_starts[i];
    size_t group_end_idx = (i == num_unique_words - 1) ? all_pairs.size() : group_starts[i+1];

    size_t offset = (i == 0) ? 0 : offsets[i-1];
    char* out = result.begin() + offset;

    // Copy the word
    const auto& word = all_pairs[group_start_idx].first;
    out = std::copy(word.begin(), word.end(), out);

    // Copy the document IDs
    for (size_t j = group_start_idx; j < group_end_idx; ++j) {
      *out++ = ' ';
      const auto& doc_str = doc_id_strs[all_pairs[j].second];
      out = std::copy(doc_str.begin(), doc_str.end(), out);
    }
    *out++ = '\n';
  });
  t.next("format output");

  return result;
}
#end

