#include "parlay/io.h"
#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/internal/get_time.h"

#include "index.h"

#include <cctype>
#include <algorithm>

using charseq = parlay::sequence<char>;

// A high-performance, parallel implementation of inverted index generation.
//
// The overall strategy is as follows:
// 1.  **Find Document Boundaries**: All occurrences of the `doc_start`
//     delimiter are found in parallel, partitioning the input text into
//     a sequence of documents.
//
// 2.  **Parallel Tokenization**: Each document is processed in parallel.
//     Within each document, words (contiguous sequences of alphabetic
//     characters) are identified in parallel. This step generates a flat
//     sequence of all (word, doc_id) pairs from the entire corpus.
//     Words are converted to lowercase during this process.
//
// 3.  **Sort-based Grouping**:
//     a. The massive sequence of (word, doc_id) pairs is sorted in parallel.
//        The primary sort key is the word (lexicographically), and the
//        secondary key is the document ID.
//     b. Duplicate (word, doc_id) pairs are removed. This handles cases
//        where a word appears multiple times in the same document.
//     c. The sorted, unique pairs are then grouped by word using
//        `parlay::group_by_key`. This is highly efficient on sorted data
//        and produces the inverted index structure: a sequence of
//        (word, sequence<doc_id>). The output is sorted by word, and each
//        list of doc_ids is also sorted.
//
// 4.  **Parallel Output Formatting**: To generate the final string without
//     contention or reallocations, a three-step parallel process is used:
//     a. The required length of each line in the output is calculated in
//        parallel.
//     b. A parallel prefix sum (scan) is performed on the lengths to
//        determine the starting offset for each line in the final string.
//     c. The final string is allocated once with the total size, and each
//        line is written to its designated position in parallel. This avoids
//        any serialization or locking.
//
// This approach maximizes parallelism at every stage, from input parsing to
// final string generation, and uses efficient, cache-friendly algorithms
// like parallel sorting and scanning, which are strengths of ParlayLib.
charseq build_index(charseq const &s, charseq const &doc_start,
                    bool verbose = false) {
    parlay::internal::timer t("build Index", verbose);
    size_t n = s.size();
    size_t m = doc_start.size();

    if (n < m) return charseq();

    // 1. Find document boundaries in parallel
    auto doc_indices = parlay::filter(parlay::iota(n - m + 1), [&](size_t i) {
        return parlay::equal(s.cut(i, i + m), doc_start);
    });
    t.next("find doc starts");

    size_t num_docs = doc_indices.size();
    if (num_docs == 0) return charseq();

    auto doc_boundaries = parlay::append(doc_indices, parlay::sequence<size_t>{n});
    t.next("create doc boundaries");

    // 2. Generate (word, doc_id) pairs in parallel for all documents
    using word_doc_pair = std::pair<charseq, size_t>;

    auto all_pairs = parlay::map_flatten<word_doc_pair>(parlay::iota(num_docs), [&](size_t doc_id) {
        size_t doc_body_start = doc_boundaries[doc_id] + m;
        size_t doc_body_end = doc_boundaries[doc_id + 1];

        if (doc_body_start >= doc_body_end) {
            return parlay::sequence<word_doc_pair>();
        }
        auto doc_text = s.cut(doc_body_start, doc_body_end);

        auto is_alpha = parlay::map(doc_text, [](char c) { return std::isalpha(static_cast<unsigned char>(c)); });

        auto word_starts = parlay::pack_index_if(is_alpha.size(), [&](size_t i) {
            return is_alpha[i] && (i == 0 || !is_alpha[i - 1]);
        });

        if (word_starts.empty()) {
            return parlay::sequence<word_doc_pair>();
        }

        auto word_ends = parlay::pack_index_if(is_alpha.size(), [&](size_t i) {
            return is_alpha[i] && (i + 1 == is_alpha.size() || !is_alpha[i + 1]);
        });

        return parlay::map<word_doc_pair>(parlay::iota(word_starts.size()), [&](size_t i) {
            auto word_slice = doc_text.cut(word_starts[i], word_ends[i] + 1);
            auto lower_word = parlay::map(word_slice, [](char c) {
                return std::tolower(static_cast<unsigned char>(c));
            });
            return std::make_pair(std::move(lower_word), doc_id);
        });
    });
    t.next("generate word-doc pairs");

    // 3. Group by word using a parallel sort-based approach
    parlay::sort_inplace(all_pairs);
    t.next("sort pairs");

    auto unique_pairs = parlay::unique(all_pairs);
    t.next("unique pairs");

    auto grouped_index = parlay::group_by_key(unique_pairs);
    t.next("group by key");

    // 4. Format the output string in parallel
    auto doc_id_strs = parlay::tabulate(num_docs, [](size_t i) {
        return parlay::to_chars(i);
    });
    t.next("generate doc_id strings");

    auto line_lengths = parlay::map(grouped_index, [&](const auto& entry) {
        size_t len = entry.first.size() + 1; // word + newline
        len += parlay::reduce(parlay::map(entry.second, [&](size_t id) {
            return 1 + doc_id_strs[id].size(); // space + doc_id_str
        }));
        return len;
    });
    t.next("calculate line lengths");

    size_t total_size = parlay::reduce(line_lengths);
    auto offsets = parlay::scan_inclusive(line_lengths);
    t.next("scan line lengths");

    charseq result = charseq::uninitialized(total_size);
    parlay::parallel_for(0, grouped_index.size(), [&](size_t i) {
        size_t start_pos = (i == 0) ? 0 : offsets[i - 1];
        char* current = result.begin() + start_pos;

        const auto& word = grouped_index[i].first;
        const auto& doc_ids = grouped_index[i].second;

        current = std::copy(word.begin(), word.end(), current);

        for (size_t doc_id : doc_ids) {
            *current++ = ' ';
            const auto& id_str = doc_id_strs[doc_id];
            current = std::copy(id_str.begin(), id_str.end(), current);
        }
        *current++ = '\n';
    });
    t.next("format output");

    return result;
}
