#include "parlay/internal/split_at.h"
#include "index.h"

using namespace std;

// A character slice (string view) is used to represent words
// without owning the underlying memory.
using char_slice = parlay::chars_slice;

charseq build_index(charseq const &s, charseq const &doc_start,
		    bool verbose = false) {
  parlay::internal::timer t("build Index", verbose);
  size_t n = s.size();
  size_t m = doc_start.size();

  // Find the start of each document
  auto starts = parlay::filter(parlay::iota(n-m+1), [&] (size_t i) {
    // A simple loop is often fast enough for short patterns
    for (size_t j=0; j < m; j++)
      if (doc_start[j] != s[i+j]) return false;
    return true;
  });
  auto num_docs = starts.size();
  t.next("get starts");
  if (verbose) cout << "num docs = " << num_docs << endl;

  // A concurrent hash table to "intern" all unique words.
  // This avoids creating many copies of the same word. Words are
  // represented as slices pointing to the table's memory.
  // It uses the default parlay::hash<char_slice> which is efficient.
  auto intern_table = parlay::hash_table<char_slice>(num_docs * 50);

  // Process each document in parallel to generate (word, doc_id) pairs.
  auto docs = parlay::tabulate(num_docs, [&] (unsigned int doc_id) {
    size_t start = starts[doc_id] + m;					
    size_t end = (doc_id == num_docs-1) ? n : starts[doc_id+1];

    // Create a mutable copy of the document's content
    auto doc_content = s.cut(start, end);

    // In-place: convert to lowercase and change non-letters to null chars
