        char c = doc_content[i];
        if (c >= 'A' && c <= 'Z') doc_content[i] = c + 32;
        else if (c >= 'a' && c <= 'z') { /* keep */ }
        else doc_content[i] = 0;
    });

    // Tokenize the processed content into slices pointing to doc_content
    auto is_break = [] (char c) { return c == 0; };
    auto tokens = parlay::internal::split_at(parlay::make_slice(doc_content), is_break);

    if (tokens.empty()) {
        return parlay::sequence<std::pair<char_slice, unsigned int>>{};
    }

    // Remove duplicate tokens within the document
    parlay::sort_inplace(tokens);
    auto unique_tokens = parlay::unique(tokens);

    // For each unique token, intern it and create a pair with the doc_id.
    // The returned slice from insert points to memory owned by the hash table.
    return parlay::map(unique_tokens, [&](const auto& token_slice) {
        return std::make_pair(intern_table.insert(token_slice), doc_id);
    });
