// A helper to check if a character is an alphabet character.
// This is faster than std::isalpha for ASCII.
inline bool is_alpha(char c) {
  return (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z');
}

// A helper to convert a character to lowercase.
// This is faster than std::tolower for ASCII.
inline char to_lower(char c) {
  return (c >= 'A' && c <= 'Z') ? c + ('a' - 'A') : c;
}

// Extracts unique, lowercased words from a document view and pairs them with a doc_id.
// This function is designed to be more efficient than the baseline's map-then-tokenize approach
// by avoiding the allocation of a temporary, full-size copy of the document.
auto get_unique_word_pairs(parlay::chars_view doc_text, unsigned int doc_id) {
  // 1. In parallel, find the starting position of every word in the document.
  // A character is a start of a word if it's an alphabet character and the
  // preceding character is not (or it's the first character).
  auto word_starts = parlay::pack_index(parlay::iota(doc_text.size()),
    [&](size_t i) {
      return is_alpha(doc_text[i]) && (i == 0 || !is_alpha(doc_text[i-1]));
    });

  // 2. In parallel for each word start, create the lower-cased word string.
  auto tokens = parlay::tabulate(word_starts.size(), [&](size_t i) {
    size_t start = word_starts[i];
    size_t end = start + 1;
    while (end < doc_text.size() && is_alpha(doc_text[end])) {
      end++;
    }
    // Create the new lower-cased word.
    // A simple sequential loop is faster than a parallel map for short words.
    parlay::sequence<char> word(end - start);
    for (size_t j = 0; j < word.size(); j++) {
      word[j] = to_lower(doc_text[start + j]);
    }
    return word;
  });

  // 3. Remove duplicate words within the document. This involves a parallel sort.
  tokens = parlay::remove_duplicates(std::move(tokens));

  // 4. Tag each unique word with the document ID.
  return parlay::map(tokens, [doc_id] (auto&& str) {
    // Using std::move on the string is important for performance.
    return std::make_pair(std::move(str), doc_id);
  });
}

charseq build_index(charseq const &s, charseq const &doc_start,
		    bool verbose = false) {
  parlay::internal::timer t("build Index", verbose);
  size_t n = s.size();
  size_t m = doc_start.size();

  // Find all occurrences of the doc_start string in parallel.
  // This returns a "delayed" sequence, which is evaluated on-demand.
  auto starts_delayed = parlay::filter(parlay::iota(n-m+1), [&] (size_t i) {
    // A simple loop is fast enough for short doc_start strings.
    for (size_t j=0; j < m; j++)
      if (doc_start[j] != s[i+j]) return false;
    return true;
  });
  // Convert the delayed sequence to a concrete sequence for faster random access.
  auto starts = parlay::to_sequence(starts_delayed);
  auto num_docs = starts.size();
  t.next("get starts");

  // In parallel, for each document, extract all unique (word, doc_id) pairs.
  auto docs = parlay::tabulate(num_docs, [&](unsigned int doc_id) {
    size_t start = starts[doc_id] + m;
    size_t end = (doc_id == num_docs - 1) ? n : starts[doc_id + 1];
    return get_unique_word_pairs(s.cut(start, end), doc_id);
  });
  t.next("generate document tokens");

  // Flatten the sequence of sequences of pairs into a single sequence of pairs.
  auto word_doc_pairs = parlay::flatten(std::move(docs));
  t.next("flatten document tokens");

  // Group pairs by word. This is the core of building the inverted index.
  // For each word, we get a sequence of all doc_ids where it appeared.
  auto words = parlay::group_by_key(std::move(word_doc_pairs));
  t.next("group by word");

  // For each word, sort its list of document IDs. This is required for correctness
  // as per the problem description ("list of entries are sorted by document identifier").
  // This is done in parallel over all the words.
  parlay::for_each(words, [] (auto& word_pair) {
    parlay::sort_inplace(word_pair.second);
  });
  t.next("sort doc_ids");

  // Sort the words lexicographically.
  parlay::sort_inplace(words, [] (auto const &l, auto const &r) {
    return l.first < r.first;
  });
  t.next("sort words");

  // --- High-performance string formatting ---
  // This section replaces the baseline's nested-flatten approach with a much
  // more efficient scan-and-write pattern.

  // Pre-compute the string representation for every document ID to avoid repeated conversion.
  auto docstr = parlay::tabulate(num_docs, [] (size_t i) {
    return parlay::to_chars(i);
  });

  // In parallel, calculate the exact length of each output line.
  auto line_lengths = parlay::map(words, [&](auto const& wd_pair) {
    size_t len = wd_pair.first.size(); // word
    // Add length of all doc_ids and the spaces between them.
    for (unsigned int doc_id : wd_pair.second) {
      len += 1 + docstr[doc_id].size(); // ' ' + doc_id_str
    }
    len += 1; // '\n'
    return len;
  });

  // Calculate the starting offset of each line in the final output string using a parallel scan.
  auto offsets = parlay::scan_inclusive(line_lengths);
  if (offsets.empty()) return charseq();
  size_t total_len = offsets.back();
  t.next("calculate output size");

  // Allocate the output string once, in an uninitialized state.
  charseq result = charseq::uninitialized(total_len);

  // In parallel, write each formatted line directly into its final position.
  parlay::for_each(parlay::iota(words.size()), [&](size_t i) {
    size_t offset = (i == 0) ? 0 : offsets[i-1];
    char* out = result.begin() + offset;

    auto const& word = words[i].first;
    auto const& doc_ids = words[i].second;

    // Use memcpy for efficient copying of the word and doc_id strings.
    std::memcpy(out, word.data(), word.size());
    out += word.size();

    for (unsigned int doc_id : doc_ids) {
      *out++ = ' ';
      auto const& id_str = docstr[doc_id];
      std::memcpy(out, id_str.data(), id_str.size());
      out += id_str.size();
    }
    *out++ = '\n';
  });
  t.next("format and generate final string");

  return result;
}
