#include <iostream>
#include "parlay/parallel.hh"
#include "parlay/primitives.h"
#include "parlay/io.h"
#include "parlay/internal/get_time.h"
#include "parlay/group_by.h"
#include "parlay/remove_duplicates.h"
#include "index.h"

using namespace std;

charseq build_index(charseq const &s, charseq const &doc_start,
		    bool verbose = false) {
  parlay::internal::timer t("build Index", verbose);
  size_t n = s.size();
  size_t m = doc_start.size();

  // Find the start of each document. This is efficient and parallel.
  // The approach is the same as the baseline.
  auto starts = parlay::filter(parlay::iota(n - m + 1), [&](size_t i) {
    if (s[i] != doc_start[0]) return false;
    // Using memcmp is typically faster for comparing fixed-size blocks of memory.
    return (m <= 1) || (memcmp(s.begin() + i + 1, doc_start.begin() + 1, m - 1) == 0);
  });
  auto num_docs = starts.size();
  t.next("get starts");
  if (verbose) cout << "num docs = " << num_docs << endl;

  // For each document, generate a sequence of (token, doc_id) pairs.
  // The tokens within each document are unique.
  using word_doc_pair = std::pair<charseq, unsigned int>;
  auto docs = parlay::tabulate(num_docs, [&](unsigned int doc_id) -> parlay::sequence<word_doc_pair> {
    size_t start = starts[doc_id] + m;
    size_t end = (doc_id == num_docs - 1) ? n : starts[doc_id + 1];

    // Create a mutable copy of the document content where non-alphabetic
    // characters are replaced by nulls and letters are lowercased.
    auto str = parlay::map(s.cut(start, end), [](char c) -> char {
      if (c >= 'A' && c <= 'Z') return c + ('a' - 'A');
      if (c >= 'a' && c <= 'z') return c;
      return 0; // Use null as a delimiter
    });

    // Extract tokens (words) from the normalized string.
    auto tokens = parlay::tokens(str, [](char c) { return c == 0; });

    if (tokens.empty()) {
      return parlay::sequence<word_doc_pair>();
    }

    // OPTIMIZATION: Use a hash-based algorithm for faster per-document unique
    // token generation. This is generally faster than the baseline's sort-based
    // `parlay::remove_duplicates`.
    auto unique_tokens = parlay::remove_duplicates_by_hashing(tokens);

    // Tag each unique token with the document ID.
    return parlay::map(unique_tokens, [doc_id](auto const &token) {
      return std::make_pair(token, doc_id);
    });
  });
  t.next("generate document tokens");

  auto word_doc_pairs = parlay::flatten(std::move(docs));
  t.next("flatten document tokens");
  if (verbose)
    cout << "num words in docs = " << word_doc_pairs.size() << endl;

  // OPTIMIZATION: Group by word using a hash-based algorithm, which is
  // typically faster for strings than the baseline's sort-based `group_by_key`.
  auto words_unstable = parlay::unstable_group_by_key(std::move(word_doc_pairs));
  t.next("group by word (hash)");

  // The problem requires the output to be sorted lexicographically by word.
  auto words = parlay::sort(std::move(words_unstable), [](auto const &l, auto const &r) {
    return l.first < r.first;
  });
  t.next("sort words");
  if (verbose)
    cout << "num unique words = " << words.size() << endl;

  // The problem also requires the document IDs for each word to be sorted.
  // `unstable_group_by_key` does not preserve order, so we must sort them.
  parlay::for_each(words, [](auto &wd_pair) {
    parlay::sort_inplace(wd_pair.second);
  });
  t.next("sort doc_ids");

  // OPTIMIZATION: Generate the output string efficiently. Instead of creating
  // many small strings and flattening them (which is slow), calculate the
  // total size, allocate a single buffer, and fill it in parallel.

  // Pre-convert all document IDs to strings to avoid repeated conversions.
  auto doc_id_strs = parlay::tabulate(num_docs, [](size_t i) {
    return parlay::to_chars(i);
  });

  // 1. Calculate the length of each line in the output string in parallel.
  auto line_lengths = parlay::map(words, [&](auto const &wd_pair) {
    auto const &word = wd_pair.first;
    auto const &doc_ids = wd_pair.second;
    size_t docs_len = parlay::reduce(parlay::map(doc_ids, [&](unsigned int id) {
      return doc_id_strs[id].size();
    }));
    // Line format: word id1 id2 ... \n
    // Length = word_len + (num_spaces = num_ids) + sum_of_id_lens + newline
    return word.size() + doc_ids.size() + docs_len + 1;
  });

  // 2. Calculate the starting offset of each line using a prefix sum (scan).
  auto [offsets, total_len] = parlay::scan(line_lengths);
  t.next("calculate output layout");

  // 3. Allocate the final output string.
  auto result = charseq::uninitialized(total_len);

  // 4. Fill the output string in parallel. Each thread writes one line.
  parlay::for_each_i(words, [&](auto const &wd_pair, size_t i) {
    char *out = result.begin() + offsets[i];
    auto const &word = wd_pair.first;
    auto const &doc_ids = wd_pair.second;

    // Copy word
    std::copy(word.begin(), word.end(), out);
    out += word.size();

    // Copy document IDs, separated by spaces
    for (unsigned int id : doc_ids) {
      *out++ = ' ';
      auto const &id_str = doc_id_strs[id];
      std::copy(id_str.begin(), id_str.end(), out);
      out += id_str.size();
    }
    *out++ = '\n';
  });
  t.next("format output string");

  return result;
}
