  auto mod3is1 = [&](size_t i) { return i % 3 == 1; };
  parlay::sequence<uint> s0_pred = parlay::filter(SA12, mod3is1);
  size_t s0_pred_n = s0_pred.size();

  auto D = parlay::sequence<uint_pair>::uninitialized(n0);
