  // is a sentinel, not in S12.
  D[0] = std::make_pair(s[n - 1], n - 1);
  parlay::parallel_for(0, s0_pred_n, [&](size_t i) {
    D[i + n0 - s0_pred_n] = std::make_pair(s[s0_pred[i] - 1], s0_pred[i] - 1);
