    }
    // Both are S0 or S2. Compare trigrams.
    uint s_i = s[i], s_j = s[j];
    if (s_i != s_j) return s_i < s_j;
    uint s_i1 = s[i + 1], s_j1 = s[j + 1];
    if (s_i1 != s_j1) return s_i1 < s_j1;
    return rank[i + 2] < rank[j + 2];
  };

  // The offset logic handles the sentinel suffix correctly.
  int offset = (n % 3 == 1);
  parlay::sequence<uint> SA = parlay::merge(parlay::make_slice(SA0).cut(offset, n0),
                                            parlay::make_slice(SA12).cut(1 - offset, n12),
                                            less);

