  // The alphabet is mapped to [1, K] so that 0 can be a unique terminator.
  auto ss = parlay::tabulate(n + 3, [&](size_t i) -> uint {
    if (i >= n) return 0;
    else return ((uint)s[i]) + 1;
  });

  size_t k = 1 + parlay::reduce(parlay::make_slice(ss.begin(), ss.begin() + n), parlay::maxm<uint>());

  return suffixArrayRec(ss, k);
}
