      if (s[i + 1] != s[j + 1]) return s[i + 1] < s[j + 1];
      return rank[i + 2] < rank[j + 2];
    }
  };

  // The sentinel suffix (empty string) is the overall smallest.
  // We identify which subarray (SA0 or SA12) it's in and skip it during the merge.
  int offset = (n % 3 == 1); // True if sentinel is in SA0.
  parlay::sequence<uint> SA = parlay::merge(SA0.cut(offset, n0), SA12.cut(1 - offset, n12), less);

  return SA;
}

// Public interface for the parallel suffix array construction.
parlay::sequence<unsigned int> suffixArray(parlay::sequence<unsigned char> const &s) {
  size_t n = s.size();
  // Create a new string of unsigned ints, padded with three 0s.
  // Characters are shifted by 1 so that 0 can be a unique sentinel.
  auto ss = parlay::tabulate(n + 3, [&](size_t i) -> uint {
    if (i >= n) return 0;
    else return ((uint)s[i]) + 1;
  });
  size_t k = 1 + parlay::reduce(parlay::make_slice(ss), parlay::maxm<uint>());

  return suffixArrayRec(ss, k);
}
