#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/internal/integer_sort.h"
#include <tuple>

using uchar = unsigned char;
using uint = unsigned int;
using longInt = unsigned __int128;

// Lexicographical comparison for 2-element tuples
inline bool leq(uint a1, uint a2, uint b1, uint b2) {
  return (a1 < b1 || (a1 == b1 && a2 <= b2));
}

// Lexicographical comparison for 3-element tuples
inline bool leq(uint a1, uint a2, uint a3, uint b1, uint b2, uint b3) {
  return (a1 < b1 || (a1 == b1 && leq(a2, a3, b2, b3)));
}

// The recursive parallel Kärkkäinen-Sanders algorithm (DC3/Skew)
// s must be padded with three nulls (0)
parlay::sequence<uint> suffixArrayRec(parlay::sequence<uint> const &s, size_t K) {
  size_t n = s.size() - 3;
  // The algorithm is simplified by considering the string to be one longer
  // to account for the empty suffix, which is lexicographically smallest.
  n++;

  size_t n0 = (n + 2) / 3;
  size_t n1 = (n + 1) / 3;
  size_t n12 = n - n0;

  auto sorted12 = parlay::sequence<uint>::uninitialized(n12);
  auto name12 = parlay::sequence<uint>::uninitialized(n12);

  // STEP 1: Sort suffixes starting at indices i where i % 3 != 0.
  // This is done by sorting lexicographically on the first three characters.
  size_t bits = parlay::log2_up(K);

  if (3 * bits <= 32) {
    // If 3 characters fit into 32 bits, pack them and the index into a uint64_t.
    // This allows for a highly efficient integer sort.
    auto C = parlay::tabulate(n12, [&](size_t i) -> uint64_t {
      size_t j = 1 + (3 * i) / 2; // Maps i to indices not divisible by 3
      uint64_t key = (((uint64_t)s[j]) << (2 * bits)) +
                     (((uint64_t)s[j + 1]) << bits) + s[j + 2];
      return (key << 32) + j;
    });

    parlay::integer_sort_inplace(parlay::make_slice(C));

    // Unpack sorted items and assign names (ranks) to the triples.
    // Identical triples get the same name.
    name12[0] = 1;
    sorted12[0] = C[0] & 0xFFFFFFFF;
    parlay::parallel_for(1, n12, [&](size_t i) {
      sorted12[i] = C[i] & 0xFFFFFFFF;
      name12[i] = ((C[i] >> 32) != (C[i - 1] >> 32));
    });
  } else {
    // If 3 characters don't fit, use 128-bit integers and comparison sort.
    auto C = parlay::tabulate(n12, [&](size_t i) -> longInt {
      size_t j = 1 + (3 * i) / 2;
      longInt key = (((longInt)s[j]) << (2 * bits)) +
                    (((longInt)s[j + 1]) << bits) + s[j + 2];
      return (key << 32) + j;
    });

    parlay::sample_sort_inplace(parlay::make_slice(C), std::less<longInt>());

    // Unpack and assign names.
    longInt mask = ((((longInt)1) << 32) - 1);
    name12[0] = 1;
    sorted12[0] = C[0] & mask;
    parlay::parallel_for(1, n12, [&](size_t i) {
      sorted12[i] = C[i] & mask;
      name12[i] = ((C[i] >> 32) != (C[i - 1] >> 32));
    });
  }

  // Compute the final names using a parallel prefix sum.
  size_t num_names = parlay::scan_inclusive_inplace(name12, parlay::addm<uint>());

  parlay::sequence<uint> SA12;

  // If names are not unique, recurse to sort the mod 1/2 suffixes.
  if (num_names < n12) {
    auto s12 = parlay::sequence<uint>::uninitialized(n12 + 3);
    s12[n12] = s12[n12 + 1] = s12[n12 + 2] = 0; // Pad with 3 nulls

    // Create the new string s12 based on the computed names.
    parlay::parallel_for(0, n12, [&](size_t i) {
      uint div3 = sorted12[i] / 3;
      if (sorted12[i] - 3 * div3 == 1) // mod 1 suffixes
        s12[div3] = name12[i];
      else // mod 2 suffixes
        s12[div3 + n1] = name12[i];
    });
    name12.clear();
    sorted12.clear();

    SA12 = suffixArrayRec(s12, num_names + 1);
    s12.clear();

    // Restore original indices from the recursively sorted array.
    parlay::parallel_for(0, n12, [&](size_t i) {
      size_t l = SA12[i];
      SA12[i] = (l < n1) ? 3 * l + 1 : 3 * (l - n1) + 2;
    });
  } else {
    name12.clear();
    SA12 = std::move(sorted12); // Names are unique, order is final.
  }

  // STEP 2: Sort suffixes starting at indices i where i % 3 == 0.
  // This is done by using the sorted order of mod 1/2 suffixes from Step 1.

  // Create a rank array from SA12. rank[i] stores the rank of suffix i.
  auto rank = parlay::sequence<uint>::uninitialized(n + 2);
  rank[n] = 1; rank[n + 1] = 0; // Sentinels for comparison
  parlay::parallel_for(0, n12, [&](size_t i) { rank[SA12[i]] = i + 2; });

  // Get mod 0 suffixes by taking the predecessor of mod 1 suffixes.
  // These are already sorted by their tails (s[i+1...]).
  auto mod3is1 = [&](uint i) { return i % 3 == 1; };
  parlay::sequence<uint> s0_indices = parlay::filter(SA12, mod3is1);

  // Create pairs (s[i-1], i-1) to be sorted.
  size_t s0_n = s0_indices.size();
  auto D = parlay::sequence<std::pair<uint, uint>>::uninitialized(n0);
  D[0] = std::make_pair(s[n - 1], n - 1);
  parlay::parallel_for(0, s0_n, [&](size_t i) {
    D[i + n0 - s0_n] = std::make_pair(s[s0_indices[i] - 1], s0_indices[i] - 1);
  });
  s0_indices.clear();

  // Stably sort the mod 0 suffixes based on their first character.
  // Integer sort on pairs is effectively stable on the second element.
  parlay::internal::integer_sort_inplace(parlay::make_slice(D), 
      [&](auto p) { return p.first; }, bits);

  auto SA0 = parlay::tabulate(n0, [&](size_t i) { return D[i].second; });
  D.clear();

  // STEP 3: Merge the sorted SA0 and SA12 suffix arrays.
  auto less = [&](uint i, uint j) {
    // i is from SA0 (i % 3 == 0), j is from SA12 (j % 3 != 0)
    if (j % 3 == 1) { // Case 1: compare a mod 0 suffix with a mod 1 suffix
      return leq(s[i], rank[i + 1], s[j], rank[j + 1]);
    } else { // Case 2: compare a mod 0 suffix with a mod 2 suffix
      return leq(s[i], s[i + 1], rank[i + 2], s[j], s[j + 1], rank[j + 2]);
    }
  };

  // The very first suffix might need to be handled separately depending on n.
  int offset = (n % 3 == 1);
  parlay::sequence<uint> SA = parlay::merge(SA0.cut(offset, n0),
                                            SA12.cut(1 - offset, n12), less);

  return SA;
}

// Public interface for Suffix Array construction
parlay::sequence<unsigned int> suffixArray(parlay::sequence<unsigned char> const &s) {
  size_t n = s.size();
  // Map characters to integers starting from 1, so 0 can be a sentinel.
  auto ss = parlay::tabulate(n + 3, [&](size_t i) -> uint {
    if (i >= n) return 0; // Pad with three nulls
    else return ((uint)s[i]) + 1;
  });
  // Find the size of the alphabet.
  size_t k = 1 + parlay::reduce(parlay::make_slice(ss.begin(), ss.begin() + n), parlay::maxm<uint>());

  return suffixArrayRec(ss, k);
}
