    // Parallel prefix-doubling suffix array construction algorithm.
    // It has O(n log n) work and O(log^2 n) depth.

    auto sa = parlay::sequence<indexT>::uninitialized(n);
    auto rank = parlay::sequence<indexT>::uninitialized(n);
    auto p = parlay::iota<indexT>(n);

    // Initial sort (k=1) based on single characters.
    // The number of buckets for integer_sort is 256 for ASCII characters.
    sa = parlay::integer_sort(p, [&](indexT i) { return s[i]; }, 256);

    // Compute initial ranks.
    auto flags = parlay::sequence<indexT>::uninitialized(n);
    parlay::parallel_for(0, n, [&](size_t i) {
        if (i == 0) {
            flags[i] = 1;
        } else {
            flags[i] = (s[sa[i]] != s[sa[i-1]]);
        }
    });

    auto ranks_sorted = parlay::scan_inclusive(flags);
    parlay::parallel_for(0, n, [&](size_t i) {
        rank[sa[i]] = ranks_sorted[i] - 1;
    });

    size_t num_ranks = ranks_sorted[n-1];

    auto next_rank = parlay::sequence<indexT>::uninitialized(n);
    auto sa_by_k = parlay::sequence<indexT>::uninitialized(n);

    for (size_t k = 1; num_ranks < n; k *= 2) {
        // Sort by the second half of the 2k-length string.
        // The key is rank[i+k]. Sentinel for out-of-bounds is 0.
        // All other ranks are shifted by 1 to be > 0.
        auto key1 = [&](indexT i) { return (i + k < n) ? rank[i + k] + 1 : 0; };
        sa_by_k = parlay::integer_sort(p, key1, num_ranks + 1);

        // Stable sort by the first half, using the result from the previous sort.
        // The key is rank[i].
        auto key2 = [&](indexT i) { return rank[i]; };
        sa = parlay::integer_sort(sa_by_k, key2, num_ranks);

        // Update ranks based on the new sorted order.
        parlay::parallel_for(0, n, [&](size_t i) {
            if (i == 0) {
                flags[i] = 1;
                return;
            }
            const indexT prev_sa = sa[i-1];
            const indexT curr_sa = sa[i];
            bool different = (key2(curr_sa) != key2(prev_sa) || key1(curr_sa) != key1(prev_sa));
            flags[i] = different;
        });

        ranks_sorted = parlay::scan_inclusive(flags);
        parlay::parallel_for(0, n, [&](size_t i) {
            next_rank[sa[i]] = ranks_sorted[i] - 1;
        });

        std::swap(rank, next_rank);
        num_ranks = ranks_sorted[n-1];
    }

    return sa;
}
