// This algorithm has a work complexity of O(n log n) and a span of O(log^2 n).
// It is highly parallel and can be faster than serial O(n) algorithms on
// modern multicore processors for large inputs.
// For small inputs, we switch to the highly optimized serial divsufsort.
parlay::sequence<indexT> suffixArray(parlay::sequence<unsigned char> const &s) {
  size_t n = s.size();
  if (n == 0) return parlay::sequence<indexT>();

  // For small inputs, the overhead of the parallel algorithm is not worth it.
  // divsufsort is a highly optimized serial implementation. A threshold of
  // 100,000 is a reasonable starting point, but could be tuned.
  if (n < 100000) {
    parlay::sequence<indexT> sa(n);
    divsufsort(s.begin(), (int*)sa.begin(), (int)n);
    return sa;
  }

  // sa stores the permutation of suffixes in sorted order.
  // Initially, it's the identity permutation.
  parlay::sequence<indexT> sa = parlay::tabulate(n, [](size_t i) { return (indexT)i; });

  // rank[i] stores the equivalence class (rank) of the suffix starting at i.
  // Initially, ranks are based on the first character.
  parlay::sequence<indexT> rank = parlay::map(s, [](uchar c) { return (indexT)c; });

  // A struct to hold pairs of ranks for sorting.
  // This represents the first 2k characters of a suffix by using the ranks
  // of its two k-character halves.
  struct RankPair {
      indexT r1;
      indexT r2;
  };

  parlay::sequence<RankPair> pairs(n);
  parlay::sequence<indexT> new_rank(n);

  // The main loop of the prefix doubling algorithm.
  // In each iteration, we double the length of the prefixes we consider (k).
  for (size_t k = 1; k < n; k *= 2) {
      // Create pairs of ranks for each suffix.
      // The first rank is for the first k characters (rank[i]).
      // The second rank is for the next k characters (rank[i+k]).
      parlay::parallel_for(0, n, [&](size_t i) {
          pairs[i].r1 = rank[i];
          // Use a sentinel rank (-1) for suffixes that are too short.
          pairs[i].r2 = (i + k < n) ? rank[i + k] : static_cast<indexT>(-1);
      });

      // Sort the suffix array based on the rank pairs.
      // This is the most work-intensive step.
      // We use a lambda to define the comparison based on the `pairs` array.
      parlay::sort_inplace(sa, [&](indexT a, indexT b) {
          if (pairs[a].r1 != pairs[b].r1) return pairs[a].r1 < pairs[b].r1;
          return pairs[a].r2 < pairs[b].r2;
      });

      // Update ranks based on the new sorted order.
      // Suffixes with the same rank pair get the same new rank.
      // We can identify groups of equal pairs and assign ranks accordingly.
      // This is done by finding where adjacent pairs in the sorted order differ.
      auto flags = parlay::tabulate(n, [&](size_t i) -> indexT {
          if (i == 0) return 1; // The first suffix always starts a new rank group.
          const auto& prev_pair = pairs[sa[i-1]];
          const auto& curr_pair = pairs[sa[i]];
          // If the current pair is different from the previous, it's a new rank.
          return (prev_pair.r1 != curr_pair.r1 || prev_pair.r2 != curr_pair.r2);
      });

      // A parallel prefix sum (scan) efficiently computes the new ranks.
      // The rank of a suffix is the number of distinct rank groups before it.
      auto scan_res = parlay::scan_inclusive(flags);
      parlay::parallel_for(0, n, [&](size_t i) {
