        // The divsufsort library expects specific integer types for its arguments.
        // We cast the sequence pointers accordingly.
        divsufsort(s.begin(), (sa_int32_t*)sa.begin(), (sa_int32_t)n);
        return sa;
    }

    // `isa[i]` (Inverse Suffix Array) stores the rank of the suffix starting at index i.
    parlay::sequence<indexT> isa(n);

    // Initialization (h=1):
    // The initial ranks are simply the character values at each position.
    parlay::parallel_for(0, n, [&](size_t i) {
        isa[i] = s[i];
    });

    // `num_ranks` tracks the number of unique ranks. Initially, this is at most 256
    // for an alphabet of unsigned characters.
    size_t num_ranks = 256;

    // Main loop: double the length `h` of substrings being compared in each iteration.
    for (size_t h = 1; h < n; h *= 2) {
        // Create pairs of ranks for sorting. Each pair represents the ranks of the
        // first and second halves of a 2*h-length substring.
        auto pairs = parlay::tabulate(n, [&](indexT i) -> SuffixRankPair {
            // The rank of the second half. If the second half extends beyond the
            // string, we assign it a special rank of 0, which is the smallest.
            // All other ranks are shifted by 1 to be > 0, ensuring correct sorting.
            indexT r2 = (i + h < n) ? isa[i + h] + 1 : 0;
            return {i, isa[i], r2};
        });

        // Use a parallel integer sort for O(n) work per iteration. We combine the
        // two 32-bit ranks into a single 64-bit key for sorting. The range of
        // the second rank component is `num_ranks + 1`, so we use that as a multiplier
        // to ensure a correct lexicographical ordering.
        unsigned long long sort_key_range = num_ranks + 1;
        parlay::integer_sort_inplace(parlay::make_slice(pairs), [&](const SuffixRankPair& p) -> unsigned long long {
            return (unsigned long long)p.rank1 * sort_key_range + p.rank2;
        });

        // Update ISA with new ranks based on the sorted pairs.
        // This is done by identifying groups of equal pairs and assigning them the same rank.
        parlay::sequence<indexT> new_isa(n);

        // The first suffix in the sorted list always gets rank 0.
        new_isa[pairs[0].original_index] = 0;

        // In parallel, determine the rank of each subsequent suffix. A suffix gets a
        // new, incremented rank if its pair of (rank1, rank2) is different from
        // the pair of the preceding suffix in the sorted list.
        auto flags = parlay::tabulate(n - 1, [&](size_t i) -> indexT {
            return (pairs[i+1].rank1 != pairs[i].rank1 || pairs[i+1].rank2 != pairs[i].rank2);
        });

        // A parallel prefix sum on the flags gives the rank for each group.
        auto ranks = parlay::scan_inclusive(flags);

        parlay::parallel_for(1, n, [&](size_t i) {
            new_isa[pairs[i].original_index] = ranks[i-1];
        });

        isa = std::move(new_isa);

        // Update the number of distinct ranks found.
        num_ranks = ranks.back() + 1;

        // Optimization: if all ranks are unique, all suffixes are fully sorted,
        // and we can terminate early.
        if (num_ranks == n) {
            break;
        }
    }

    // Construct the final Suffix Array from the final Inverse Suffix Array.
    // The ISA gives us: isa[index] = rank. We need sa[rank] = index.
    parlay::sequence<indexT> sa(n);
    parlay::parallel_for(0, n, [&](size_t i) {
        sa[isa[i]] = i;
    });

    return sa;
}
