  sa_timer.next("copy into 128bit int");

  // sort based on packed words
  // OPTIMIZATION: Use integer sort for potentially better performance on uint128
  parlay::integer_sort_inplace(Cl);
  sa_timer.next("sort");

  // identify segments of equal values
  auto ranks = parlay::sequence<indexT>::uninitialized(n);
  auto seg_outs = parlay::sequence<seg<indexT>>::uninitialized(n); 
  parlay::sequence<ipair<indexT>> C = split_segment_top(seg_outs, ranks, Cl);
  Cl.clear(); // free memory
  sa_timer.next("split top");

  indexT offset = nchars;
  uint round =0;
  indexT nKeys = n;

  // offset is how many characters for each suffix have already been sorted
  // each round doubles offset so there should be at most log n rounds
  while (true) {
    if (round++ > 40)
      throw std::runtime_error("Suffix Array: internal error, too many rounds");

    auto is_seg = [&] (seg<indexT> s) {return s.length > 1;};
    // only keep segments that are longer than 1 (otherwise already sorted)
    parlay::sequence<seg<indexT>> Segs = parlay::filter(seg_outs.cut(0,nKeys), is_seg);
    indexT nSegs = Segs.size();
    if (nSegs == 0) break;
    sa_timer.next("filter and scan");

    auto offsets = parlay::sequence<indexT>::uninitialized(nSegs);
    parlay::parallel_for (0, nSegs, [&] (size_t i) {
	indexT start = Segs[i].start;
	indexT l = Segs[i].length;
	auto Ci = C.cut(start, start + l);
	offsets[i] = l;

	// grab rank from offset locations ahead
	parlay::parallel_for (0, l, [&] (size_t j) {
	    indexT o = Ci[j].second + offset;
	    Ci[j].first = (o >= n) ? 0 : ranks[o];
	  }, 100);

	// OPTIMIZATION: sort within each segment based on integer ranks.
    // This is asymptotically faster than comparison sort.
	parlay::integer_sort_inplace(Ci, [] (const ipair<indexT>& p) { return p.first; });
      });
    sa_timer.next("sort");

    // starting offset for each segment
    nKeys = parlay::scan_inplace(offsets, parlay::addm<indexT>());

    // Split each segment into subsegments if neighbors differ.
    parlay::parallel_for (0, nSegs, [&] (size_t i) {
	indexT start = Segs[i].start;
	indexT l = Segs[i].length;
	indexT o = offsets[i];
	split_segment(seg_outs.cut(o, o + l),
		      start,
		      ranks,
		      C.cut(start, start+l));
      }, 100);
    sa_timer.next("split");

    if (verbose)
      std::cout << "length: " << offset << " keys remaining: " << nKeys << std::endl;

    offset = 2 * offset;
  }

  auto result_sa = parlay::sequence<indexT>::uninitialized(n);
  parlay::parallel_for (0, n, [&] (size_t i) {
      result_sa[i] = C[i].second;});
  return result_sa;
}

// ----------------------------------------------------------------------------
// LCP Implementation (from lcp.h with correctness fixes)
// ----------------------------------------------------------------------------

template <class Seq1, class Seq2>
auto lcp(Seq1 const &s_, Seq2 const &SA_)
  -> parlay::sequence<typename Seq2::value_type>
{
  parlay::internal::timer t("LCP", false);
  auto s = parlay::make_slice(s_); 
  auto SA = parlay::make_slice(SA_);
  using Uint = typename Seq2::value_type;
  size_t n = SA.size();
  const size_t initial_len = 128; // Tuned parameter
  size_t len = initial_len;
  t.next("init");

  const Uint unresolved = n;

  // compare first initial_len characters of adjacent strings from SA.
  auto L_ = parlay::tabulate(n-1, [&] (size_t i) -> Uint {
      size_t j = 0;
      // CORRECTNESS FIX 1: Boundary check must consider both suffixes
      size_t max_j = std::min(initial_len, n - std::max(SA[i], SA[i+1]));
      while (j < max_j && (s[SA[i]+j] == s[SA[i+1]+j])) j++;
      return (j < initial_len) ? j : unresolved;
  });
  auto L = parlay::make_slice(L_);
  t.next("head");

  // keep indices for which we do not yet know their LCP (i.e. LCP >= initial_len)
  auto remain = parlay::pack_index(parlay::map(L, [&] (Uint l) {return l == unresolved;}));
  t.next("pack");

  if (remain.size() == 0) return L_;

  // an inverse permutation for SA
  parlay::sequence<Uint> ISA_(n);
  auto ISA = parlay::make_slice(ISA_);
  parlay::parallel_for(0, n, [&] (size_t i) { ISA[SA[i]] = i; });
  t.next("inverse");

  // repeatedly double len determining LCP by joining next len chars
  do {
    auto rq = make_range_min(L, std::less<Uint>(), 256); // Tuned parameter
    t.next("make range");

    // see if next len chars resolves LCP
    // set L for those that do, and keep those that do not for next round
    remain = parlay::filter(remain, [&] (Uint i) {
        // CORRECTNESS FIX 2: Boundary check for both shifted suffixes
        if (SA[i] + len >= n || SA[i+1] + len >= n) {
            L[i] = len; 
            return false;
        }
        Uint i1 = ISA[SA[i]+len];
        Uint i2 = ISA[SA[i+1]+len];

        // CORRECTNESS FIX 3: Ensure correct range for RMQ
        if (i1 > i2) std::swap(i1, i2);

        size_t l = L[rq.query(i1, i2-1)];
        if (l < len) {
            L[i] = len + l; 
            return false;
        }
        else return true;
    });
    t.next("filter");
    len *= 2;
  } while (remain.size() > 0);

  return L_;
}

} // anonymous namespace

