template <class indexT, class UCharRange>
parlay::sequence<indexT> suffix_array(UCharRange const &ss) {
  parlay::internal::timer sa_timer("Suffix Array", verbose);
  size_t n = ss.size();

  if (n == 0) {
    return parlay::sequence<indexT>();
  }

  // 1. Remap characters to a dense range [1, m]
  parlay::sequence<indexT> char_map(256, (indexT) 0);
  parlay::parallel_for(0, n, [&](size_t i) {
    if (!char_map[ss[i]]) char_map[ss[i]] = 1;
  }, 1000);
  indexT m = 0;
  std::tie(char_map, m) = parlay::scan(char_map, parlay::make_monoid(parlay::addm<indexT>(), (indexT) 1));

  // 2. Initial large-k sort using 128-bit integers
  double logm = (m <= 1) ? 1.0 : log2((double)m);
  size_t n_packed_chars = floor(96.0 / logm);
  if (n_packed_chars == 0) n_packed_chars = 1;
  if (n_packed_chars > n) n_packed_chars = n;

  size_t pad = n_packed_chars;
  auto s = parlay::sequence<indexT>::uninitialized(n + pad);
  parlay::parallel_for(0, n, [&](size_t i) { s[i] = char_map[ss[i]]; });
  parlay::parallel_for(n, n + pad, [&](size_t i) { s[i] = 0; }); // terminator characters

  auto packed_suffixes = parlay::tabulate(n, [&](size_t i) -> uint128 {
    uint128 key = 0;
    for (size_t j = 0; j < n_packed_chars; j++) {
      key = key * m + s[i + j];
    }
    return (key << 32) | i;
  });
  sa_timer.next("pack keys");

  parlay::sort_inplace(packed_suffixes);
  sa_timer.next("initial sort");

  // 3. Generate initial ranks and suffix array from the sorted packed suffixes
  auto sa = parlay::sequence<indexT>::uninitialized(n);
  auto ranks = parlay::sequence<indexT>::uninitialized(n);
  constexpr size_t mask32 = (1ULL << 32) - 1;

  auto boundaries = parlay::tabulate(n, [&](size_t i) -> indexT {
    if (i == 0) return 1;
    return (packed_suffixes[i] >> 32) != (packed_suffixes[i-1] >> 32);
  });
  parlay::scan_inclusive_inplace(boundaries, parlay::addm<indexT>());

  parlay::parallel_for(0, n, [&](size_t i) {
    indexT suffix_idx = packed_suffixes[i] & mask32;
    sa[i] = suffix_idx;
    ranks[suffix_idx] = boundaries[i];
  });
  packed_suffixes.clear();
  sa_timer.next("initial ranks");

  // If all ranks are unique, we are done
  if (boundaries[n-1] == n) {
    return sa;
  }

  // 4. Doubling loop
  auto temp_ranks = parlay::sequence<indexT>::uninitialized(n);
  for (size_t k = n_packed_chars; k < n; k *= 2) {
    auto get_key = [&](indexT i) {
      indexT rank1 = ranks[i];
      indexT rank2 = (i + k < n) ? ranks[i + k] : 0;
      return std::make_pair(rank1, rank2);
    };

    parlay::sort_inplace(sa, [&](indexT a, indexT b) { return get_key(a) < get_key(b); });

    boundaries = parlay::tabulate(n, [&](size_t i) -> indexT {
      if (i == 0) return 1;
      return get_key(sa[i]) != get_key(sa[i-1]);
    });
    parlay::scan_inclusive_inplace(boundaries, parlay::addm<indexT>());

    parlay::parallel_for(0, n, [&](size_t i) {
      temp_ranks[sa[i]] = boundaries[i];
    });
    std::swap(ranks, temp_ranks);

    if (verbose) sa_timer.next("doubling round k=" + std::to_string(k));

    if (ranks[sa[n-1]] == n) break;
  }

  return sa;
}

// --- End of file: suffix_array.h ---

// --- Start of file: lcp.h ---
#include "../parlay/sequence.h"
#include "../parlay/internal/get_time.h"
#include "range_min.h"
#include <algorithm>

//  The suffix array SA are indices into the string s
template <class Seq1, class Seq2>
auto lcp(Seq1 const &s_, Seq2 const &SA_)
  -> parlay::sequence<typename Seq2::value_type>
{
  parlay::internal::timer t("LCP", verbose);
  auto s = parlay::make_slice(s_); 
  auto SA = parlay::make_slice(SA_);
  using Uint = typename Seq2::value_type;
  size_t n = SA.size();

  if (n < 2) return parlay::sequence<Uint>();

  // Use a power of two for block sizes and initial length
  const size_t len = 128;
  t.next("init");

  // Compare first `len` characters of adjacent strings from SA.
  // This is corrected to not read past the end of the string for either suffix.
  auto L_ = parlay::tabulate(n - 1, [&](size_t i) -> Uint {
    size_t limit = std::min({(size_t)(n - SA[i]), (size_t)(n - SA[i+1]), len});
    size_t j = 0;
    while (j < limit && s[SA[i] + j] == s[SA[i+1] + j]) {
      j++;
    }
    // If LCP is `len` or more, it is unresolved. Mark with `n`.
    return (j < len) ? j : n;
  });
  auto L = parlay::make_slice(L_);
  t.next("head");

  // Keep indices for which we do not yet know their LCP (i.e. LCP >= len)
  auto remain = parlay::pack_index(parlay::map(L, [&](Uint l) { return l == n; }));
  t.next("pack");

  if (remain.size() == 0) return L_;

  // An inverse permutation for SA
  parlay::sequence<Uint> ISA_(n);
  auto ISA = parlay::make_slice(ISA_);
  parlay::parallel_for(0, n, [&](size_t i) {
    ISA[SA[i]] = i;
  });
  t.next("inverse");

  size_t current_len = len;
  do {
    auto rq = make_range_min(L, std::less<Uint>(), len);
    t.next("make range");

    remain = parlay::filter(remain, [&](Uint i) {
      // Since i is in remain, LCP(SA[i], SA[i+1]) >= current_len.
      // This implies both suffixes have at least current_len characters,
      // so SA[i] + current_len <= n and SA[i+1] + current_len <= n.
      // Thus, the access to ISA is safe.
      Uint i1 = ISA[SA[i] + current_len];
      Uint i2 = ISA[SA[i+1] + current_len];

      // Correctness fix: query range must be [min, max-1]
      if (i1 > i2) std::swap(i1, i2);

      size_t l = L[rq.query(i1, i2 - 1)];

      if (l < current_len) {
        L[i] = current_len + l;
        return false; // Resolved
      } else {
        return true; // Still unresolved, LCP >= 2 * current_len
      }
    });
    t.next("filter");
    current_len *= 2;
  } while (remain.size() > 0);

  return L_;
}
// --- End of file: lcp.h ---
```
