using std::endl;
double infinity = std::numeric_limits<double>::infinity();

// some parameters

// minimum size of a node
size_t min_size = 1;
// the following helps prevent overfitting if > 0.0
// probably should be in range [0..1]
double encode_node_factor = 0.0; 

struct tree {
  bool is_leaf;
  int feature_index;
  int feature_cut;
  int best;
  size_t size;
