#start
// --- Start of file: classify.C ---
#include <iostream>
#include <memory>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/delayed.h"
#include "parlay/io.h"
#include "parlay/internal/get_time.h"
#include "parlay/monoid.h"
#include "parlay/alloc.h"
#include "classify.h"

using namespace parlay;
using std::cout;
using std::endl;
constexpr double infinity = std::numeric_limits<double>::infinity();

// Parameters
// Minimum number of samples required to split an internal node.
constexpr size_t min_node_size = 2;
// A regularization factor to prevent overfitting. Range [0..1] is reasonable.
constexpr double encode_node_factor = 0.0;

// Forward declaration
struct tree;

// Use an arena allocator for tree nodes for performance and to avoid memory leaks.
// The allocator will be cleared at the end of the `classify` function.
using tree_allocator = parlay::type_allocator<tree>;

struct tree {
  bool is_leaf;
  int feature_index;
  int feature_cut;
  int best; // Majority label
  size_t size;
  sequence<tree*> children;

  // Constructor for internal node
  tree(int i, int c, int best_val, sequence<tree*> children_seq)
    : is_leaf(false), feature_index(i), feature_cut(c), best(best_val), children(std::move(children_seq)) {
    size = reduce(delayed_map(children, [] (tree* t) { return t->size; }));
  }
  // Constructor for leaf node
  tree(int best_val, size_t s) : is_leaf(true), best(best_val), size(s) {}
};

// Helper functions to create nodes using the arena allocator
tree* make_leaf(int best, size_t size, tree_allocator& alloc) {
  if (best > max_value && best != -1) abort();
  return alloc.new_obj(best, size);
}

tree* make_internal(int i, int cut, int majority, sequence<tree*> children, tree_allocator& alloc) {
  return alloc.new_obj(i, cut, majority, std::move(children));
}

// Check if all elements in a sequence are equal.
template <typename S1>
bool all_equal(S1 const &a) {
  if (a.size() < 2) return true;
  auto first = a[0];
  return all_of(a, [=](const auto& v) { return v == first; });
}

// Find the majority element in a sequence.
template <typename S1>
int majority(S1 const &a, size_t num_classes) {
  if (a.size() == 0) return -1;
  auto counts = histogram_by_index(a, num_classes);
  return static_cast<int>(max_element(counts) - counts.begin());
}

// Calculate entropy * total_count from a histogram of counts.
// This is proportional to the information content.
template <typename Seq>
double entropy(Seq const& counts, size_t total) {
  if (total == 0) return 0.0;
  // A small penalty for node complexity to prevent overfitting
  double encoding_cost = encode_node_factor * log2(float(1 + total));
  return encoding_cost + reduce(delayed_map(counts, [=] (long count) {
      return (count > 0) ? -(count * log2(static_cast<double>(count) / total)) : 0.0;
  }));
}

// Information content of labels for a subset of data defined by indices.
double info_idx(feature const &labels, sequence<int> const &indices) {
  size_t n = indices.size();
  if (n == 0) return 0.0;
  auto indexed_labels = delayed_map(indices, [&](int i) { return labels.vals[i]; });
  auto counts = histogram_by_index(indexed_labels, labels.num);
  return entropy(counts, n);
}

// Conditional information for a discrete feature.
double cond_info_discrete_idx(feature const &labels, feature const &b, sequence<int> const &indices) {
  size_t n = indices.size();
  if (n == 0) return 0.0;
  int num_buckets = labels.num * b.num;

  auto indexed_pairs = delayed_map(indices, [&](int i) {
      return labels.vals[i] + b.vals[i] * labels.num;
  });
  auto sums = histogram_by_index(indexed_pairs, num_buckets);

  return reduce(tabulate(b.num, [&](size_t i) {
      auto group_counts = sums.cut(i * labels.num, (i + 1) * labels.num);
      return entropy(group_counts, reduce(group_counts));
  }));
}

// Conditional information and best cut for a continuous feature.
// This version is parallelized.
auto cond_info_continuous_idx(feature const &labels, feature const &b, sequence<int> const &indices) {
  size_t n = indices.size();
  if (n < 2) return std::pair(infinity, 0);

  int num_buckets = labels.num * b.num;
  auto indexed_pairs = delayed_map(indices, [&](int i) {
      return labels.vals[i] + b.vals[i] * labels.num;
  });
  auto sums = histogram_by_index(indexed_pairs, num_buckets);

  sequence<sequence<long>> prefix_sums(labels.num);
  parallel_for(0, labels.num, [&](size_t j) {
      auto label_counts_view = delayed_tabulate(b.num, [&](size_t i) {
          return sums[i * labels.num + j];
      });
      prefix_sums[j] = prescan(label_counts_view, addm<long>());
  });

  auto total_label_counts = tabulate(labels.num, [&](size_t j) {
      return prefix_sums[j][b.num-1] + sums[(b.num-1) * labels.num + j];
  });

  auto total_low_counts_scan = prescan(tabulate(b.num, [&](size_t i) {
      return reduce(sums.cut(i * labels.num, (i + 1) * labels.num));
  }), addm<long>());

  auto costs = tabulate(b.num - 1, [&](size_t i) {
      size_t m = total_low_counts_scan[i+1];
      if (m == 0 || m == n) return std::pair(infinity, i + 1);

      auto low_counts = tabulate(labels.num, [&](size_t j) { return prefix_sums[j][i+1]; });
      auto high_counts = tabulate(labels.num, [&](size_t j) { return total_label_counts[j] - low_counts[j]; });

      double e = entropy(low_counts, m) + entropy(high_counts, n - m);
      return std::pair(e, i + 1);
  });

  auto min_f = [](const auto& p1, const auto& p2) {
      return (p1.first < p2.first) ? p1 : p2;
  };
  return reduce(costs, make_monoid(min_f, std::pair(infinity, 0)));
}

tree* build_tree_idx(features const &A, sequence<int> &indices, bool verbose, tree_allocator& alloc) {
  size_t num_entries = indices.size();
  int num_features = A.size();
  auto& labels = A[0];

  auto indexed_labels = delayed_map(indices, [&](int i) { return labels.vals[i]; });
  int majority_value = majority(indexed_labels, labels.num);

  if (num_entries < min_node_size || all_equal(indexed_labels)) {
    return make_leaf(majority_value, num_entries, alloc);
  }

  double label_info = info_idx(labels, indices);

  auto costs = tabulate(num_features - 1, [&](int i) {
      auto& feature = A[i + 1];
      if (feature.discrete) {
        double info = cond_info_discrete_idx(labels, feature, indices);
        return std::tuple(info, i + 1, -1);
      } else {
        auto [info, cut] = cond_info_continuous_idx(labels, feature, indices);
        return std::tuple(info, i + 1, cut);
      }
  });

  auto min1 = [](auto a, auto b) { return (std::get<0>(a) < std::get<0>(b)) ? a : b; };
  auto min_m = make_monoid(min1, std::tuple(infinity, 0, 0));
  auto [best_info, best_i, cut] = reduce(costs, min_m);

  // Information gain = label_info - best_info.
  // Stop if gain is not significant enough. Threshold is based on encoding cost of the split.
  double threshold = log2(static_cast<double>(num_features));
  if (label_info - best_info < threshold || best_info == infinity) {
    if (verbose)
      cout << "Leaf (gain too small): " << num_entries << ", gain=" << (label_info-best_info) << endl;
    return make_leaf(majority_value, num_entries, alloc);
  }

  if (verbose) {
    cout << "Node: size=" << num_entries << ", feature=" << best_i << ", cut=" << cut
         << ", label_info=" << label_info << ", best_info=" << best_info << endl;
  }

  int num_children;
  sequence<value> split_keys(num_entries);
  if (A[best_i].discrete) {
    num_children = A[best_i].num;
    parallel_for(0, num_entries, [&](size_t i) {
      split_keys[i] = A[best_i].vals[indices[i]];
    });
  } else {
    num_children = 2;
    parallel_for(0, num_entries, [&](size_t i) {
      split_keys[i] = (A[best_i].vals[indices[i]] >= cut);
    });
  }

  auto grouped_indices = group_by_index(indices, split_keys, num_children);

  auto children = map(grouped_indices, [&](sequence<int>& new_indices) {
      return build_tree_idx(A, new_indices, verbose, alloc);
  });

  return make_internal(best_i - 1, cut, majority_value, std::move(children), alloc);
}

int classify_row(tree* T, row const& r) {
  if (T->is_leaf) {
    return T->best;
  }

  int child_idx;
  if (T->feature_cut == -1) { // Discrete split
    child_idx = r[T->feature_index];
    if (child_idx >= T->children.size()) {
      // Test data has a feature value not seen in training at this node.
      return T->best;
    }
  } else { // Continuous split
    child_idx = (r[T->feature_index] < T->feature_cut) ? 0 : 1;
  }

  int val = classify_row(T->children[child_idx], r);

  // If the child branch was empty during training, its leaf node returns -1.
  // In that case, use the majority vote of the current (parent) node.
  return (val == -1) ? T->best : val;
}

row classify(features const &Train, rows const &Test, bool verbose) {
  tree_allocator alloc;
  size_t n = Train[0].vals.size();
  sequence<int> initial_indices = iota(n);

  parlay::internal::timer t("Build Tree", verbose);
  tree* T = build_tree_idx(Train, initial_indices, verbose, alloc);
  t.stop();

  if (verbose) cout << "Tree node count = " << alloc.num_allocated() << endl;

  parlay::internal::timer t2("Classify Test", verbose);
  row result = map(Test, [&](row const& r) -> value {
    return static_cast<value>(classify_row(T, r));
  });
  t2.stop();

  alloc.clear(); // Free all tree nodes at once
  return result;
}
