#include <tuple>
#include <cmath>

using namespace parlay;
using std::cout;
using std::endl;
constexpr double infinity = std::numeric_limits<double>::infinity();

// some parameters

// minimum size of a node
constexpr size_t min_size = 2;
// the following helps prevent overfitting if > 0.0
// probably should be in range [0..1]
constexpr double encode_node_factor = 0.0; 

struct tree {
  bool is_leaf;
  int feature_index;
  int feature_cut;
  int best; // majority label
  size_t size;
  sequence<tree*> children;
  tree(int i, int c, int best, sequence<tree*> children)
    : is_leaf(false), best(best), feature_index(i), feature_cut(c), children(std::move(children)) {
    size = reduce(delayed_map(this->children, [] (tree* t) {return t->size;}));}
  tree(int best, size_t s) : is_leaf(true), best(best), size(s) {}
};

tree* Leaf(int best, size_t size) {
  if (best > max_value) abort();
  return new tree(best, size);
}

tree* Internal(int i, int cut, int majority, sequence<tree*> children) {
  return new tree(i, cut, majority, std::move(children));
}

template <typename S1>
bool all_equal(S1 const &a) {
  if (a.size() < 2) return true;
  auto first = a[0];
  return all_of(a, [first](auto const& val) { return val == first; });
}

template <typename S1>
auto majority(S1 const &a, size_t m) {
  if (a.size() == 0) return -1;
  auto x = histogram_by_index(a, m);
  return max_element(x) - x.begin();
}

// entropy * total given a histogram a (total = sum(a))
template <typename Seq>
double entropy(Seq const& a, int total) {
  if (total == 0) return 0.0;
  double ecost = encode_node_factor * log2(float(1 + total)); // to prevent overfitting
  return ecost + reduce(delayed_map(a, [=] (int l) {
      return (l > 0) ? -(l * log2(static_cast<double>(l)/total)) : 0.0;}));
}

// information content of s (i.e. entropy * size)
template <typename Range>
double info(Range const& s, int num_vals) {
  size_t n = s.size();
  if (n == 0) return 0.0;
  auto x = histogram_by_index(s, num_vals);
  return entropy(x, n);
}

// info of a conditioned on b
template <typename LabelRange, typename FeatureRange>
double cond_info_discrete(LabelRange const& labels, FeatureRange const& f_vals, 
                          int num_label_vals, int num_feature_vals) {
  size_t n = labels.size();
  if (n == 0) return 0.0;
  int num_buckets = num_label_vals * num_feature_vals;

  auto combined_keys = delayed_map(zip(labels, f_vals), [&](auto p) {
      return p.first + p.second * num_label_vals;
  });

  auto sums = histogram_by_index(combined_keys, num_buckets);

  return reduce(tabulate(num_feature_vals, [&] (size_t i) {
      auto x = sums.cut(i * num_label_vals, (i + 1) * num_label_vals);				      
      return entropy(x, reduce(x));}));
}

template <typename LabelRange, typename FeatureRange>
auto cond_info_continuous(LabelRange const& labels, FeatureRange const& f_vals, 
                          int num_label_vals, int num_feature_vals) {
  size_t n = labels.size();
  if (n == 0) return std::pair(infinity, 0);

  int num_buckets = num_label_vals * num_feature_vals;
  auto combined_keys = delayed_map(zip(labels, f_vals), [&](auto p) {
      return p.first + p.second * num_label_vals;
  });
  auto sums = histogram_by_index(combined_keys, num_buckets);

  sequence<int> low_counts(num_label_vals, 0);
  sequence<int> high_counts(num_label_vals, 0);

  for (int i=0; i < num_feature_vals; i++) 
    for (int j=0; j < num_label_vals; j++) 
      high_counts[j] += sums[num_label_vals*i + j];

  double cur_e = infinity;
  int cur_i = 0;
  size_t m = 0;
  for (int i=0; i < num_feature_vals-1; i++) {
    size_t row_sum = 0;
    for (int j=0; j < num_label_vals; j++) {
      int val = sums[num_label_vals*i + j];
      low_counts[j] += val;
      high_counts[j] -= val;
      row_sum += val;
    }
    m += row_sum;
    if (m > 0 && m < n) {
        double e = entropy(low_counts, m) + entropy(high_counts, n - m);
        if (e < cur_e) {
          cur_e = e;
          cur_i = i+1;
        }
    }
  }
  return std::pair(cur_e, cur_i);
}

tree* build_tree_recursive(const features& A, sequence<int>& indices, bool verbose) {
  size_t num_entries = indices.size();

  auto current_labels = delayed_map(indices, [&](int i) { return A[0].vals[i]; });
  int majority_value = majority(current_labels, A[0].num);

  if (num_entries < min_size || all_equal(current_labels)) {
    return Leaf(majority_value, num_entries);
  }

  double label_info = info(current_labels, A[0].num);
  int num_features = A.size();

  auto costs = tabulate(num_features - 1, [&] (int i) {
      int feature_idx = i + 1;
      auto current_feature_vals = delayed_map(indices, [&](int k) { return A[feature_idx].vals[k]; });
      if (A[feature_idx].discrete) {
        double c_info = cond_info_discrete(current_labels, current_feature_vals, A[0].num, A[feature_idx].num);
        return std::tuple(c_info, feature_idx, -1);
      } else {
        auto [c_info, cut] = cond_info_continuous(current_labels, current_feature_vals, A[0].num, A[feature_idx].num);
        return std::tuple(c_info, feature_idx, cut);
      }
  }, 1);

  auto min1 = [&] (auto const& a, auto const& b) {return (std::get<0>(a) < std::get<0>(b)) ? a : b;};
  auto min_m = make_monoid(min1, std::tuple(infinity, 0, 0));
  auto [best_info, best_i, cut] = reduce(costs, min_m);

  double threshold = log2(float(num_features));

  if (verbose)
    cout << num_entries << ", " << best_i << ", " << cut << ", " << label_info << ", " 
	 << best_info << endl;

  // Pruning condition: if information gain is too small, or no valid split was found.
  if (label_info - best_info < threshold || best_info == infinity) {
    return Leaf(majority_value, num_entries);
  } else {
    int m;
    sequence<value> split_keys;
    if (A[best_i].discrete) {
      m = A[best_i].num;
      split_keys = map(indices, [&](int k) { return A[best_i].vals[k]; });
    } else {
      m = 2;
      split_keys = map(indices, [&](int k) -> value { return A[best_i].vals[k] >= cut; });
    }

    auto child_indices_groups = group_by_index(indices, split_keys, m);

    auto children = map(child_indices_groups, [&](sequence<int>& idxs) {
        return build_tree_recursive(A, idxs, verbose);
    }, 1);

    return Internal(best_i - 1, cut, majority_value, std::move(children)); //-1 since first is label
  }
}

tree* build_tree(const features &A, bool verbose) {
    size_t num_entries = A.empty() ? 0 : A[0].vals.size();
    if (num_entries == 0) {
        return Leaf(-1, 0); // Handle empty training set
    }
    sequence<int> initial_indices = iota(num_entries);
    return build_tree_recursive(A, initial_indices, verbose);
}

int classify_row(tree* T, row const&r) {
  while (!T->is_leaf) {
    if (T->feature_cut == -1) { // discrete partition
      int feature_val = r[T->feature_index];
      // Fallback to majority if test value is out of training range or leads to an empty branch
      if (feature_val >= T->children.size() || T->children[feature_val]->size == 0) {
          return T->best;
      }
      T = T->children[feature_val];
    } else {  // continuous cut
      int idx = (r[T->feature_index] < T->feature_cut) ? 0 : 1;
      if (T->children[idx]->size == 0) return T->best;
      T = T->children[idx];
    }
  }
  return T->best;
}

void delete_tree(tree* T) {
    if (T == nullptr) return;
    if (!T->is_leaf) {
        parallel_for(0, T->children.size(), [&](size_t i) {
            delete_tree(T->children[i]);
        });
    }
    delete T;
}

row classify(features const &Train, rows const &Test, bool verbose) {
  tree* T = build_tree(Train, verbose);
  if (verbose) cout << "Tree size = " << T->size << endl;

  row result = map(Test, [&] (row const& r) -> value {return classify_row(T, r);});

  // Cleanup memory
  delete_tree(T);

  return result;
}

