using namespace parlay;
using std::cout;
using std::endl;

constexpr double infinity = std::numeric_limits<double>::infinity();

// --- Parameters ---
// Minimum number of samples required to split an internal node.
constexpr size_t min_size = 2;
// A factor to penalize model complexity (larger value -> smaller tree).
// Setting to 0.0 disables this penalty.
constexpr double encode_node_factor = 0.0;

// --- Tree structure ---
struct tree {
  bool is_leaf;
  int feature_index;
  int feature_cut;
  int best;
  size_t size;
  sequence<tree*> children;

  // Constructor for internal nodes
  tree(int i, int c, int majority, sequence<tree*> children_nodes)
    : is_leaf(false), feature_index(i), feature_cut(c), best(majority), children(std::move(children_nodes)) {
    size = reduce(delayed_map(children, [] (tree* t) { return t->size; }));
  }
  // Constructor for leaf nodes
  tree(int best_label, size_t node_size) : is_leaf(true), best(best_label), size(node_size),
                                           feature_index(-1), feature_cut(-1) {}
};

// Helper to create a leaf node
tree* Leaf(int best, size_t size) {
  if (best > max_value) abort();
  return new tree(best, size);
}

// Helper to create an internal node
tree* Internal(int i, int cut, int majority, sequence<tree*> children) {
  return new tree(i, cut, majority, std::move(children));
}

// Recursively delete the tree to prevent memory leaks
void delete_tree(tree* t) {
  if (t == nullptr) return;
  if (!t->is_leaf) {
    parallel_for(0, t->children.size(), [&](size_t i) {
      delete_tree(t->children[i]);
    });
  }
  delete t;
}

// --- Information Theory and Cost Functions ---

// Find the majority element in a (potentially delayed) sequence
template <typename S1>
int majority(S1 const &a, size_t m) {
  if (a.size() == 0) return -1;
  auto counts = histogram_by_index(a, m);
  return max_element(counts) - counts.begin();
}

// Calculate entropy * total for a given histogram of counts
template <typename Seq>
double entropy(Seq const& a, long total) {
  if (total <= 0) return 0.0;
  double ecost = encode_node_factor * log2(float(1 + total));
  return ecost + reduce(delayed_map(a, [=] (long l) {
      return (l > 0) ? -(static_cast<double>(l) * log2(static_cast<double>(l) / total)) : 0.0;
  }));
}

// Calculate the information content of a (potentially delayed) sequence
template <typename S>
double info(S const& s, int num_vals) {
  size_t n = s.size();
  if (n == 0) return 0.0;
  auto counts = histogram_by_index(s, num_vals);
  return entropy(counts, n);
}

// Calculate conditional information for discrete features
template <typename Labels, typename Attrs>
double cond_info_discrete(Labels const &labels, int labels_num,
                          Attrs const &attrs, int attrs_num) {
  size_t n = labels.size();
  if (n == 0) return 0.0;
  int num_buckets = labels_num * attrs_num;
  auto sums = histogram_by_index(delayed_tabulate(n, [&](size_t i) {
    return labels[i] + attrs[i] * labels_num;
  }), num_buckets);
  return reduce(tabulate(attrs_num, [&](size_t i) {
    auto group_counts = sums.cut(i * labels_num, (i + 1) * labels_num);
    return entropy(group_counts, reduce(group_counts));
  }));
}

// Calculate conditional information and the best cut for continuous features
template <typename Labels, typename Attrs>
auto cond_info_continuous(Labels const &labels, int labels_num,
                          Attrs const &attrs, int attrs_num) {
  size_t n = labels.size();
  if (n == 0) return std::pair(infinity, 0);
  int num_buckets = labels_num * attrs_num;
  auto sums = histogram_by_index(delayed_tabulate(n, [&](size_t i) {
    return labels[i] + attrs[i] * labels_num;
  }), num_buckets);

  sequence<long> low_counts(labels_num, 0);
  sequence<long> high_counts(labels_num, 0);

  for (int i = 0; i < attrs_num; i++)
    for (int j = 0; j < labels_num; j++)
      high_counts[j] += sums[labels_num * i + j];

  double min_e = infinity;
  int best_cut = 0;
  long m = 0;

  for (int i = 0; i < attrs_num - 1; i++) {
    long current_m = 0;
    for (int j = 0; j < labels_num; j++) {
      long val = sums[labels_num * i + j];
      low_counts[j] += val;
      high_counts[j] -= val;
      current_m += val;
    }
    m += current_m;
    if (m > 0 && n - m > 0) {
        double e = entropy(low_counts, m) + entropy(high_counts, n - m);
        if (e < min_e) {
            min_e = e;
            best_cut = i + 1;
        }
    }
  }
  return std::pair(min_e, best_cut);
}

// --- Tree Building ---

// Forward declaration for recursion
tree* build_tree(const features& A, sequence<int>& indices, bool verbose);

// Core recursive tree-building function using an index-based approach
tree* build_tree(const features& A, sequence<int>& indices, bool verbose) {
  size_t num_entries = indices.size();
  int num_features = A.size();

  auto current_labels = delayed_map(indices, [&](int i) { return A[0].vals[i]; });
  int majority_value = majority(current_labels, A[0].num);

  if (num_entries < min_size) {
    return Leaf(majority_value, num_entries);
  }

  bool all_same = false;
  if (num_entries > 0) {
    value first_label = A[0].vals[indices[0]];
    all_same = all_of(indices, [&](int i) { return A[0].vals[i] == first_label; });
  }

  if (all_same) {
    return Leaf(majority_value, num_entries);
  }

  double label_info = info(current_labels, A[0].num);

  // Find the best feature to split on
  auto costs = tabulate(num_features - 1, [&](int i) {
    int feature_idx = i + 1;
    auto current_feature_vals = delayed_map(indices, [&](int k) { return A[feature_idx].vals[k]; });

    if (A[feature_idx].discrete) {
      double info_val = cond_info_discrete(current_labels, A[0].num, current_feature_vals, A[feature_idx].num);
      return std::tuple(info_val, feature_idx, -1);
    } else {
      auto [info_val, cut] = cond_info_continuous(current_labels, A[0].num, current_feature_vals, A[feature_idx].num);
      return std::tuple(info_val, feature_idx, cut);
    }
  });

  auto min_f = [](const auto& a, const auto& b) { return (std::get<0>(a) < std::get<0>(b)) ? a : b; };
  auto min_monoid = make_monoid(min_f, std::tuple(infinity, 0, 0));
  auto [best_info, best_i, cut] = reduce(costs, min_monoid);

  // Use information gain to decide whether to split or create a leaf
  double threshold = log2(static_cast<double>(num_features));

  if (verbose) {
    cout << "n=" << num_entries << ", best_feature=" << best_i << ", cut=" << cut 
         << ", label_info=" << label_info << ", best_info=" << best_info 
         << ", gain=" << label_info - best_info << endl;
  }

  if (best_info == infinity || (label_info - best_info < threshold)) {
    return Leaf(majority_value, num_entries);
  } else {
    // Partition the indices for the child nodes
    int m;
    sequence<value> split_on_vals;
    if (A[best_i].discrete) {
      m = A[best_i].num;
      split_on_vals = map(indices, [&](int k) { return A[best_i].vals[k]; });
    } else {
      m = 2;
      split_on_vals = map(indices, [&](int k) -> value { return A[best_i].vals[k] >= cut; });
    }

    auto child_indices = group_by_index(indices, split_on_vals, m);

    // Recursively build child trees in parallel
    auto children = map(child_indices, [&](auto& idxs) {
      return build_tree(A, idxs, verbose);
    });

    return Internal(best_i - 1, cut, majority_value, std::move(children));
  }
}

// --- Classification ---

// Classify a single row by traversing the decision tree
int classify_row(tree* T, row const& r) {
  if (T->is_leaf) {
    return T->best;
  }

  int val = -1;
  if (T->feature_cut == -1) { // Discrete feature split
    value feature_val = r[T->feature_index];
    if (feature_val < T->children.size()) {
      val = classify_row(T->children[feature_val], r);
    }
  } else {  // Continuous feature split
    int child_idx = (r[T->feature_index] < T->feature_cut) ? 0 : 1;
    val = classify_row(T->children[child_idx], r);
  }
  // If a path leads to an empty leaf (val == -1) or an unseen discrete value,
  // return the majority vote of the parent node.
  return (val == -1) ? T->best : val;
}

// Main entry point: build tree, classify test data, and clean up.
row classify(features const &Train, rows const &Test, bool verbose) {
  size_t n = (Train.empty() || Train[0].vals.empty()) ? 0 : Train[0].vals.size();
  if (n == 0) {
      // Handle empty training set
      return sequence<value>(Test.size(), 0);
  }

  // Start with indices for the entire training set
  sequence<int> indices = iota(n);
  tree* T = build_tree(Train, indices, verbose);

  if (verbose) cout << "Tree size = " << T->size << endl;

  // Classify all test rows in parallel
  auto result = map(Test, [&](row const& r) -> value {
    return classify_row(T, r);
  });

  delete_tree(T);
  return result;
}
