    // Flip sign bit for positive floats, and all bits for negative floats.
    // This maps them to unsigned integers that preserve the original order.
    if (w_bits & 0x80000000) {
        w_bits = ~w_bits;
    } else {
        w_bits ^= 0x80000000;
    }
    // Combine weight bits (high part) and id (low part) into a 64-bit key.
    return (static_cast<uint64_t>(w_bits) << 32) | e.id;
  };

