  // Process the heavy edges.
  pbbs::speculative_for(UFStep2, 0, IW2.size(), 256, false);
  t.next("union find loop on remaining");

  // Collect the indices of edges that form the MST.
  parlay::sequence<edgeId> mst = parlay::internal::pack_index<edgeId>(mstFlags);
  t.next("pack out results");

  return mst;
}


