};

using reservation = pbbs::reservation<edgeId>;

// Functor for the speculative_for loop
struct UnionFindStep {
  // Using a slice is more flexible than a sequence reference.
  parlay::slice<indexedEdge*, indexedEdge*> E;
  parlay::sequence<reservation>& R;
  unionFind<vertexId>& UF;
  parlay::sequence<bool>& inST;

  UnionFindStep(parlay::slice<indexedEdge*, indexedEdge*> E,
                unionFind<vertexId>& UF,
                parlay::sequence<reservation>& R,
                parlay::sequence<bool>& inST)
      : E(E), R(R), UF(UF), inST(inST) {}

  // In the reserve phase, an edge (u, v) tries to reserve the representatives
  // of the components of u and v.
  bool reserve(edgeId i) {
    // Find representatives and perform path compression on the edge itself
    // for future iterations. This is a benign data race as all threads
    // would write the same representative value.
    vertexId u_rep = UF.find(E[i].u);
    vertexId v_rep = UF.find(E[i].v);
    E[i].u = u_rep;
    E[i].v = v_rep;

    if (u_rep != v_rep) {
      // Reserve both endpoints.
      R[v_rep].reserve(i);
      R[u_rep].reserve(i);
      return true;
    }
    return false;
  }

  // In the commit phase, an edge checks if it won the reservation.
  // If so, it performs the union and marks itself as part of the MST.
  bool commit(edgeId i) {
    vertexId u = E[i].u;
    vertexId v = E[i].v;

    if (R[v].check(i)) {
      R[u].checkReset(i); 
      UF.link(v, u); 
      inST[E[i].id] = true;
      return true;
    } else if (R[u].check(i)) {
      UF.link(u, v);
      inST[E[i].id] = true;
      return true;
    }
    return false;
  }
};


parlay::sequence<edgeId> mst(wghEdgeArray<vertexId,edgeWeight> &E) {
  size_t m = E.m;
  size_t n = E.n;

  if (m == 0) {
    return parlay::sequence<edgeId>();
  }

  // Create a single sequence of indexed edges to work on.
  // This avoids creating multiple large temporary sequences.
  auto IW = parlay::tabulate(m, [&](size_t i) {
    return indexedEdge(E[i].u, E[i].v, i, E[i].weight);
  });

  // Heuristic for the number of light-weight edges to process in the first pass.
  // An MSF has at most n-1 edges. 5n/4 gives some slack.
  size_t k = std::min<size_t>(5 * n / 4, m);

  // Tie-breaking for edges with equal weights using their original index.
  // This ensures deterministic behavior.
  auto edgeLess = [&](const indexedEdge& a, const indexedEdge& b) {
    return (a.w < b.w) || ((a.w == b.w) && (a.id < b.id));
  };

  indexedEdge kth_edge;
  // If k >= m, all edges are considered "light". We find the max element
  // to use as a pivot, which will partition almost all edges into the light set.
  // This avoids a special code path for this case.
  if (k >= m) {
    kth_edge = *parlay::max_element(IW, edgeLess);
  } else {
    kth_edge = pbbs::approximate_kth_smallest(IW, k, edgeLess);
  }

  // Partition the edges in-place into those lighter than the pivot and the rest.
  // This is more memory-efficient than two separate filter operations.
  auto is_light = [&](const indexedEdge& e) { return edgeLess(e, kth_edge); };
  auto num_light = parlay::partition_inplace(IW.slice(), is_light);
  auto light_edges = IW.cut(0, num_light);
  auto heavy_edges_all = IW.cut(num_light, m);

  // Sort the light edges.
  parlay::sort_inplace(light_edges, edgeLess);

  parlay::sequence<bool> mstFlags(m, false);
  unionFind<vertexId> UF(n);
  parlay::sequence<reservation> R(n);

  // A high granularity for speculative_for reduces scheduling overhead.
  constexpr long speculative_for_granularity = 2048;

  // Process the light edges using speculative parallel union-find.
  UnionFindStep UFStep1(light_edges, UF, R, mstFlags);
  pbbs::speculative_for<edgeId>(UFStep1, 0, light_edges.size(), speculative_for_granularity, false);

  // Filter the heavy edges, keeping only those that do not form a cycle
  // with the components already formed.
  auto heavy_edges_filtered = parlay::filter(heavy_edges_all, [&](const indexedEdge& e) {
    return UF.find(e.u) != UF.find(e.v);
  });

  // Sort the remaining heavy edges.
  parlay::sort_inplace(heavy_edges_filtered, edgeLess);

  // Process the filtered heavy edges.
  UnionFindStep UFStep2(heavy_edges_filtered.slice(), UF, R, mstFlags);
  pbbs::speculative_for<edgeId>(UFStep2, 0, heavy_edges_filtered.size(), speculative_for_granularity, false);

  // Collect the indices of the edges that form the MSF.
  return parlay::pack_index<edgeId>(mstFlags);
