```cpp
#include <iostream>
#include <algorithm>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "common/graph.h"
#include "common/get_time.h"
#include "algorithm/union_find.h"
#include "MST.h"

// This implementation uses a parallelized version of Kruskal's algorithm.
// The core idea is to process edges in batches to exploit parallelism while
// respecting the weight-sorted order required by Kruskal's.
//
// The algorithm proceeds as follows:
// 1. Augment Edges: The input edges are augmented with their original indices
//    to meet the output requirement. This is done in parallel using
//    `parlay::tabulate`.
//
// 2. Global Sort: All augmented edges are sorted by weight in parallel using
//    `parlay::sort`. This is the most work-intensive step and is fully
//    parallelized. Ties are broken deterministically using the original edge index.
//
// 3. Batched Processing: The sorted edges are processed in rounds, each
//    handling a batch of edges. This allows for a mix of parallel and
//    sequential processing.
//    a. Parallel Filtering: In each round, the current batch of edges is
//       filtered in parallel. An edge is kept only if its endpoints currently
//       belong to different components in the minimum spanning forest being built.
//       This is checked using a union-find data structure. This step efficiently
//       discards edges that would form cycles.
//    b. Sequential Union: The small number of edges that pass the filter are
//       processed sequentially. This is the classic Kruskal's loop: for each
//       edge, if it connects two different components, it is added to the MST,
//       and the components are merged. This sequential step is fast because the
//       number of edges to process is drastically reduced by the parallel filter.
//
// 4. Adaptive Batching: The batch size starts small and grows exponentially.
//    This is a performance heuristic. Early on, edges have a high probability
//    of being in the MST, so smaller batches with lower parallel overhead are
//    effective. Later, as the graph connects, most edges are discarded by the
//    filter, so larger batches are used to reduce the number of rounds and
//    associated overheads.
//
// This approach balances the massive parallelism available in sorting and filtering
// with the necessarily sequential nature of the union-find updates in Kruskal's
// algorithm, resulting in a high-performance implementation.

struct edgeAndIndex {
  vertexId u;
  vertexId v;
  edgeWeight weight;
  edgeId id;

  edgeAndIndex() : u(0), v(0), weight(0.0), id(0) {}
  edgeAndIndex(vertexId _u, vertexId _v, edgeWeight w, edgeId _id)
    : u(_u), v(_v), weight(w), id(_id) {}
};

parlay::sequence<edgeId> mst(wghEdgeArray<vertexId,edgeWeight> &G) {
  // 1. Create an array of edges with their original indices.
  auto EI = parlay::tabulate(G.m, [&](size_t i) {
    return edgeAndIndex(G.E[i].u, G.E[i].v, G.E[i].weight, i);
  });

  // 2. Sort all edges by weight in parallel. Tie-break with edge ID for determinism.
  parlay::sort_inplace(EI, [&](const edgeAndIndex& a, const edgeAndIndex& b) {
    if (a.weight != b.weight) return a.weight < b.weight;
    return a.id < b.id;
  });

  unionFind<vertexId> UF(G.n);
  parlay::sequence<edgeId> mst_edges;
  if (G.n > 0) {
    mst_edges.reserve(G.n - 1);
  }

  size_t mst_size = 0;
  size_t edges_processed = 0;
  const size_t n_minus_1 = (G.n == 0) ? 0 : G.n - 1;

  // 3. Process edges in batches.
  size_t batch_size = 1024; // Initial batch size

  while (edges_processed < G.m && mst_size < n_minus_1) {
    size_t end = std::min(edges_processed + batch_size, G.m);
    auto batch = EI.cut(edges_processed, end);

    // 3a. Filter the batch in parallel to find edges connecting distinct components.
    auto cross_component_edges = parlay::filter(batch, [&](const edgeAndIndex& e) {
      return UF.find(e.u) != UF.find(e.v);
    });

    // 3b. Process the filtered edges sequentially. This is fast as the set is small.
    if (!cross_component_edges.empty()) {
      for (const auto& e : cross_component_edges) {
        vertexId root_u = UF.find(e.u);
        vertexId root_v = UF.find(e.v);
        if (root_u != root_v) {
          UF.union_roots(root_u, root_v);
          mst_edges.push_back(e.id);
          mst_size++;
        }
      }
    }

    edges_processed = end;

    // 4. Adaptively increase batch size.
    if (batch_size < (1 << 20)) { // Cap batch size to avoid large temporary allocations
        batch_size *= 2;
    }
  }

  return mst_edges;
}
