An expert C++ programmer would choose a hybrid algorithm that combines the strengths of different classic MST algorithms to achieve the best performance in a parallel setting. Boruvka's algorithm is excellent for rapidly reducing the number of components in a graph, making it highly parallel and effective in the initial phases. Kruskal's algorithm is very efficient once the number of remaining edges and components is small.

This implementation uses a hybrid of Boruvka's algorithm and Kruskal's algorithm.

1.  **Boruvka's Phases**: The algorithm begins by running several rounds of a parallel implementation of Boruvka's algorithm.
    *   **Find Minimum Edges**: In each round, for every active component (represented by a root in a union-find data structure), we find the minimum-weight edge connecting it to another component. This is done in parallel over all edges, using atomic `write_min` operations to update the minimum edge for each component without locks.
    *   **Component Contraction**: The components are then merged (contracted) by adding these minimum-weight edges. To do this concurrently and correctly, we use a deterministic "hooking" strategy: a component with a smaller representative ID links itself to a component with a larger one. This is implemented using an atomic `tryLink` operation on the union-find structure, which prevents race conditions and ensures no cycles are formed.
    *   This process is repeated, and with each round, the number of components decreases significantly (ideally, by at least a factor of two), rapidly simplifying the graph.

2.  **Switch to Kruskal's**: Boruvka's algorithm becomes less efficient as the number of components dwindles. Once the number of components drops below a certain threshold (a heuristic, e.g., `n/50`), the algorithm switches to a parallel version of Kruskal's algorithm.

3.  **Kruskal's Phase**:
    *   **Edge Filtering**: First, all edges that connect vertices within the same super-component (formed during the Boruvka phases) are filtered out in parallel using `parlay::pack`. This leaves a much smaller set of edges to process.
    *   **Sort and Finish**: These remaining edges are sorted by weight in parallel using `parlay::sort`. Finally, a sequential loop iterates through the sorted edges, adding them to the Minimum Spanning Forest if they connect distinct components. This final loop is fast because the number of edges has been drastically reduced.

This hybrid approach leverages parallelism effectively at each stage, minimizing sequential bottlenecks and adapting its strategy as the problem is reduced. It is a standard and highly effective method for computing MSF on modern multi-core processors.

```cpp
#start
#include <iostream>
#include <algorithm>
#include <atomic>

#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/sequence.h"

#include "common/graph.h"
#include "common/get_time.h"
#include "algorithm/union_find.h"
#include "MST.h"
#include "common/atomics.h"

// **************************************************************
//    PARALLEL MSF USING A HYBRID OF BORUVKA'S AND KRUSKAL'S
// **************************************************************

// A struct to hold edge information along with its original index.
struct edgeAndIndex {
  vertexId u;
  vertexId v;
  edgeWeight weight;
  edgeId id;
  edgeAndIndex() {}
  edgeAndIndex(vertexId _u, vertexId _v, edgeWeight w, edgeId _id)
    : u(_u), v(_v), weight(w), id(_id) {}
};

// The main function to compute the Minimum Spanning Forest.
parlay::sequence<edgeId> mst(wghEdgeArray<vertexId,edgeWeight> &G) {
    size_t n = G.n;
    size_t m = G.m;

    // Create a sequence of edges with their original indices.
    auto EI = parlay::tabulate(m, [&](size_t i) {
        return edgeAndIndex(G.E[i].u, G.E[i].v, G.E[i].weight, i);
    });

    // Initialize union-find structure for tracking components.
    unionFind<vertexId> UF(n);
    parlay::sequence<edgeId> mst_edges;
    mst_edges.reserve(n > 0 ? n - 1 : 0);

    size_t num_components = n;
    size_t last_num_components = n;

    // Heuristic: switch to Kruskal's when the number of components is small.
    size_t boruvka_threshold = std::max((size_t)2, n / 50);

    // --- Boruvka's Algorithm Rounds ---
    while (num_components > boruvka_threshold) {
        // Find representatives for all vertices. Pre-calculating reduces
        // redundant UF.find() calls inside the parallel loop.
        auto reps = parlay::tabulate(n, [&](vertexId i) { return UF.find(i); });

        // Find the minimum weight edge for each component.
        auto min_component_edges = parlay::sequence<std::atomic<edgeId>>(n);
        parlay::parallel_for(0, n, [&](size_t i) { min_component_edges[i] = m; }); // Use m as an invalid index

        auto weight_less = [&](edgeId i, edgeId j) {
            if (j >= m) return true;
            if (i >= m) return false;
            if (EI[i].weight != EI[j].weight) return EI[i].weight < EI[j].weight;
            return EI[i].id < EI[j].id; // Deterministic tie-breaking
        };

        parlay::parallel_for(0, m, [&](size_t i) {
            const auto& e = EI[i];
            auto r_u = reps[e.u];
            auto r_v = reps[e.v];
            if (r_u != r_v) {
                pbbs::write_min(&min_component_edges[r_u], (edgeId)i, weight_less);
                pbbs::write_min(&min_component_edges[r_v], (edgeId)i, weight_less);
            }
        });

        // Identify roots that have found an outgoing edge.
        auto candidates = parlay::filter(parlay::iota<vertexId>(n), [&](vertexId i) {
            return UF.is_root(i) && min_component_edges[i] < m;
        });

        // Hook components together in a deterministic way to avoid cycles.
        // Smaller ID roots link to larger ID roots.
        auto successful_links = parlay::filter(candidates, [&](vertexId i) {
            edgeId edge_idx = min_component_edges[i];
            const auto& e = EI[edge_idx];
            auto r_u = reps[e.u];
            auto r_v = reps[e.v];
            auto other_rep = (r_u == i) ? r_v : r_u;

            if (i < other_rep) {
                // UF.tryLink is atomic and safe for this usage pattern.
                return UF.tryLink(i, other_rep);
            }
            return false;
        });

        if (successful_links.size() == 0) {
            break; // No progress, remaining graph is a forest.
        }

        // Collect the original IDs of the edges that formed successful links.
        auto new_edges = parlay::map(successful_links, [&](vertexId i) {
            return EI[min_component_edges[i].load()].id;
        });

        mst_edges.append(new_edges);

        // Path compress all vertices for the next round.
        parlay::parallel_for(0, n, [&](size_t i) { UF.find(i); });

        // Update component count and check for progress.
        auto root_flags = parlay::tabulate(n, [&](vertexId i) { return UF.is_root(i); });
        num_components = parlay::reduce(root_flags);

        if (num_components == last_num_components) {
            break; // No reduction in components.
        }
        last_num_components = num_components;
    }

    // --- Final Kruskal's Algorithm Phase ---
    // Filter out edges that are internal to the current components.
    auto remaining_edges = parlay::pack(EI, [&](const auto& e) {
        return UF.find(e.u) != UF.find(e.v);
    });

    auto edgeLess = [&](const auto& a, const auto& b) {
        if (a.weight != b.weight) return a.weight < b.weight;
        return a.id < b.id;
    };
    parlay::sort(remaining_edges, edgeLess);

    // Final sequential union-find on the much smaller set of remaining edges.
    for (const auto& e : remaining_edges) {
        auto r_u = UF.find(e.u);
        auto r_v = UF.find(e.v);
        if (r_u != r_v) {
            UF.union_roots(r_u, r_v);
            mst_edges.push_back(e.id);
        }
    }

    return mst_edges;
}
