// A thread-safe union-find data structure with atomic parent pointers
// and CAS-based path compression (path halving).
template <class vertexId>
struct unionFind_safe {
  parlay::sequence<std::atomic<vertexId>> parents;

  unionFind_safe(size_t n) {
    parents = parlay::sequence<std::atomic<vertexId>>::uninitialized(n);
    parlay::parallel_for(0, n, [&](size_t i) {
      new (&parents[i]) std::atomic<vertexId>(-1);
    });
  }

  // Find the root of the component containing vertex i with path compression.
  vertexId find(vertexId i) {
    while (true) {
      vertexId p = parents[i].load(std::memory_order_relaxed);
      if (p < 0) return i; // Found the root
      vertexId gp = parents[p].load(std::memory_order_relaxed);
      if (gp < 0) return p; // Parent is the root
      // Path halving: try to set parent to grandparent
      parents[i].compare_exchange_strong(p, gp, std::memory_order_relaxed);
      // Move up the tree; read parent again in case another thread changed it.
      i = parents[i].load(std::memory_order_relaxed);
    }
  }

  // Link component u to component v. Assumes u is a root.
  void link(vertexId u, vertexId v) {
    parents[u].store(v, std::memory_order_relaxed);
  }
};

using reservation = pbbs::reservation<edgeId>;

// Functor for the speculative_for loop.
struct unionFindStep {
  vertexId u;
  vertexId v;
  edgeArray<vertexId> const &E;
  parlay::sequence<reservation> &R;
  unionFind_safe<vertexId> &UF;

  unionFindStep(edgeArray<vertexId> const &E,
                unionFind_safe<vertexId> &UF,
                parlay::sequence<reservation> &R)
    : E(E), R(R), UF(UF) {}

  // Reserve phase: find components and try to reserve one.
  bool reserve(edgeId i) {
    u = UF.find(E[i].u);
    v = UF.find(E[i].v);

    if (u != v) {
      // Randomized linking: use a hash to create a total order on roots,
      // which prevents cycles and helps build shallower trees.
      if (parlay::hash64(u) > parlay::hash64(v)) std::swap(u, v);
      R[v].reserve(i);
      return true;
    } else {
      return false;
    }
  }

  // Commit phase: if reservation was successful, perform the link.
  bool commit(edgeId i) {
    if (R[v].check(i)) {
      UF.link(v, u);
      return true;
    } else {
      return false;
    }
  }
};

parlay::sequence<edgeId> st(edgeArray<vertexId> const &G) {
  size_t m = G.nonZeros;
  size_t n = G.numRows;
  unionFind_safe<vertexId> UF(n);
  parlay::sequence<reservation> R(n);
  parlay::parallel_for(0, n, [&] (size_t i) { R[i].reset(); });

  unionFindStep UFStep(G, UF, R);
  // speculative_for processes all edges, retrying those that fail
  // due to conflicts until a spanning forest is formed.
  pbbs::speculative_for<edgeId>(UFStep, 0, m, 256);

  // Collect the edges that successfully joined components.
  // This is a single-pass filter and map operation.
  return parlay::map_maybe(R, [](const reservation& r) {
    if (r.reserved()) {
      return std::optional<edgeId>{r.get()};
    } else {
      return std::optional<edgeId>{};
    }
  });
}
