// A concurrent union-find data structure using atomics.
// It uses path compression and linking by ID to keep the trees flat.
template <class vertexId>
struct ConcurrentUnionFind {
  parlay::sequence<std::atomic<vertexId>> parents;

  explicit ConcurrentUnionFind(size_t n) {
    parents = parlay::sequence<std::atomic<vertexId>>(n);
    parlay::parallel_for(0, n, [&](size_t i) {
      parents[i].store(static_cast<vertexId>(i), std::memory_order_relaxed);
    });
  }

  // Finds the root of the component containing vertex i, with path compression.
  vertexId find(vertexId i) {
    vertexId root = i;
    // Find the root by traversing parent pointers.
    // Acquire semantics ensure we see writes from successful unite operations.
    while (root != parents[root].load(std::memory_order_acquire)) {
      root = parents[root].load(std::memory_order_acquire);
    }
    // Path compression: set parent of all nodes on the path to the root.
    // This is an optimization; relaxed memory order is sufficient as it's a benign race.
    while (i != root) {
      vertexId next = parents[i].load(std::memory_order_relaxed);
      parents[i].store(root, std::memory_order_relaxed);
      i = next;
    }
    return root;
  }

  // Attempts to union the components of u and v.
  // Returns true if they were successfully unioned, false if they were already in the same component.
  bool unite(vertexId u, vertexId v) {
    while (true) {
      vertexId root_u = find(u);
      vertexId root_v = find(v);
      if (root_u == root_v) {
        return false;
      }
      // To prevent cycles, always link the vertex with the smaller ID to the one with the larger ID.
      if (root_u > root_v) {
        std::swap(root_u, root_v);
      }

      vertexId expected_parent_of_u = root_u;
      // Try to link root_u to root_v. This is the core atomic operation.
      // Release semantics ensure that if this succeeds, other threads that see this
      // change will also see any memory operations that happened before it.
      if (parents[root_u].compare_exchange_strong(expected_parent_of_u, root_v, std::memory_order_release, std::memory_order_relaxed)) {
        return true;
      }
      // If CAS fails, another thread has modified the parent of root_u.
      // We loop and retry the whole find-unite process.
    }
  }
};

