using reservation = pbbs::reservation<edgeId>;

// A thread-safe union-find data structure optimized for parallel execution.
// It uses path splitting, a common technique in parallel union-find that is
// both efficient and simpler to implement correctly than full path compression
// with atomic compare-and-swap operations.
template <class vertexId>
struct parallel_union_find {
  parlay::sequence<std::atomic<vertexId>> parents;

  parallel_union_find(size_t n) {
    parents = parlay::sequence<std::atomic<vertexId>>(n);
    parlay::parallel_for(0, n, [&](size_t i) {
      parents[i].store(-1, std::memory_order_relaxed);
    });
  }

  // Finds the root of the component containing vertex i.
  // Uses path splitting for concurrent path compression.
  vertexId find(vertexId i) {
    while (true) {
      vertexId p = parents[i].load(std::memory_order_relaxed);
      if (p < 0) return i; // is a root
      vertexId gp = parents[p].load(std::memory_order_relaxed);
      if (gp < 0) return p; // parent is a root

      // Path splitting: attempt to make i's parent its grandparent.
      // This is a benign race; even if it fails, progress is made by
      // traversing up to p in the next iteration.
      parents[i].compare_exchange_strong(p, gp, std::memory_order_relaxed, std::memory_order_relaxed);
      i = p;
    }
  }

  // Atomically links component u to component v if u is a root.
  // This is a conditional, atomic operation.
  // Returns true on success.
  bool link(vertexId u, vertexId v) {
    vertexId root_val = -1;
    return parents[u].load(std::memory_order_relaxed) == root_val &&
           parents[u].compare_exchange_strong(root_val, v, std::memory_order_relaxed, std::memory_order_relaxed);
  }
};


// Defines the logic for a single step in the speculative_for loop.
struct unionFindStep {
  vertexId u_root, v_root;
  const edgeArray<vertexId>& E;
