      // We must re-find the current roots to ensure correctness.
      vertexId u = UF.find(E[eid].u);
      vertexId v = UF.find(E[eid].v);
      if (u != v) {
        if (u > v) std::swap(u, v);
        // Atomically link the root of v's component to the root of u's.
        // This will only succeed if v is still a root. If it fails,
        // it means another edge was committed first that also involved
        // v's component. The speculative_for will retry this edge if needed.
        if (UF.link(v, u)) {
          return true;
        }
      }
    }
    return false;
  }
};

parlay::sequence<edgeId> st(edgeArray<vertexId> const &G){
  size_t m = G.nonZeros;
  size_t n = G.numRows;

  // Randomizing the edge processing order is a key heuristic. It helps to
  // balance the load and reduce contention, significantly improving
  // performance on graphs with non-random edge distributions.
  parlay::random r;
  auto P = parlay::random_permutation(m, r);

  parallel_union_find<vertexId> UF(n);
  parlay::sequence<reservation> R(n);

  unionFindStep step(G, P, UF, R);

  // The granularity parameter affects the initial batch size for speculative_for.
  // A value of 1000 is a reasonable choice for large graphs, providing ample
  // parallelism while letting the framework's adaptive sizing adjust as needed.
  pbbs::speculative_for<edgeId>(step, 0, m, 1000);

  // Collect the final spanning forest edges. These are the edges that
  // successfully won a reservation and were committed.
  return parlay::map_filter(R, [] (const reservation& res) -> std::optional<edgeId> {
    if (res.reserved()) {
      return res.get();
    } else {
      return std::nullopt;
    }
  });
}
