//    concurrent settings as it involves fewer writes and thus less cache coherency
//    traffic, while still being very effective at flattening the union-find trees.
// 3. Contention Management: The main loop uses a test-and-CAS approach on a
//    `hooks` array to decide which edge connects a component. A `while(true)`
//    loop handles races, ensuring that if an edge's endpoints are merged by another
//    thread, the edge is re-evaluated with the updated component information.

namespace {

// An optimized find operation with path splitting.
// In a concurrent setting, parent pointers can be updated by other threads.
// This implementation is non-blocking and lock-free. While a write may be based
// on a stale read, it always points a node further up its tree, guaranteeing
// progress and eventual convergence to the correct root.
template <class vertexId>
inline vertexId find_with_splitting(vertexId i, parlay::sequence<vertexId>& parents) {
    vertexId curr = i;
    while (parents[curr] >= 0) {
        vertexId parent = parents[curr];
        if (parents[parent] < 0) { // parent is root
            return parent;
        }
        // Path splitting: point current node to its grandparent.
        parents[curr] = parents[parent];
        curr = parent;
    }
    return curr; // curr is root
}

} // anonymous namespace

parlay::sequence<edgeId> st(edgeArray<vertexId> const &E){
  edgeId m = E.nonZeros;
  vertexId n = E.numRows;

  // Parent array for the union-find data structure. A negative value indicates
  // a root, and all other values are parent pointers.
  auto parents = parlay::sequence<vertexId>(n, -1);

  // `hooks[i]` stores the edge index used to connect the component rooted at `i`.
  // Initialize with a sentinel value.
  const edgeId unhooked = std::numeric_limits<edgeId>::max();
  parlay::sequence<edgeId> hooks(n, unhooked);

  // Generate a random permutation of edge indices. Processing edges in a
  // random order is crucial for performance as it breaks patterns that can
  // lead to high contention.
  auto P = parlay::random_permutation(m);

  // Process all edges in parallel.
  parlay::parallel_for (0, m, [&] (edgeId i) {
      edgeId edge_idx = P[i];
      vertexId u = E[edge_idx].u;
      vertexId v = E[edge_idx].v;

      // This loop is necessary to handle race conditions. If another thread
      // modifies the component structure while this thread is processing an
      // edge, the loop ensures the edge is re-evaluated.
      while(true) {
        u = find_with_splitting(u, parents);
        v = find_with_splitting(v, parents);

        if (u == v) break; // Already in the same component.

        // Use a canonical ordering (smaller ID to larger ID) for linking
        // to prevent creating cycles in the parent-pointer graph.
        if (u > v) std::swap(u,v);

        // Attempt to "hook" the component rooted at `u` to the component
        // rooted at `v`. We first check if `u` has already been hooked to
        // avoid an unnecessary atomic operation.
        if (hooks[u] == unhooked) {
            if (pbbs::atomic_compare_and_swap(&hooks[u], unhooked, edge_idx)) {
                // This thread successfully claimed the hook for component `u`.
                // The edge is added to the spanning forest.
                parents[u] = v;
                break;
            }
        }
        // If the CAS fails or the hook was already taken, it means another
        // thread has just connected component `u`. We loop again to re-find
        // the roots and see if this edge is now redundant.
      }
    }, 1024);

  // Collect the edge indices that were successfully used for hooking.
  parlay::sequence<edgeId> stIdx = parlay::filter(hooks, [&] (edgeId eid) {
      return eid != unhooked;
  });

  std::cout << "nInSt = " << stIdx.size() << std::endl;
  return stIdx;
}
