#include <iostream>
#include <limits>
#include <utility> // For std::swap
#include "common/graph.h"
#include "parlay/primitives.h"
#include "parlay/random.h"
#include "common/atomics.h"
#include "ST.h"

using namespace std;

// A lock-free union-find data structure optimized for parallel execution.
// It uses atomic compare-and-swap for both finding the root (with path
// compression) and uniting two sets. This allows many threads to process
// edges concurrently, which is key to a high-performance parallel
// spanning forest algorithm. A root of a set is represented by a vertex `v`
// such that `parents[v] == v`.
template <typename vertexId>
struct parallel_union_find {
    parlay::sequence<vertexId> parents;

    parallel_union_find(size_t n) {
        parents = parlay::tabulate(n, [](size_t i) { return static_cast<vertexId>(i); });
    }

    // Finds the representative of the set containing `i` with path compression.
    // This implementation is thread-safe.
    vertexId find(vertexId i) {
        vertexId curr = i;
        // First, find the root of the component without modification.
        while (curr != parents[curr]) {
            curr = parents[curr];
        }
        vertexId root = curr;

        // Second, perform path compression. We walk from i to the root and try
        // to set each parent pointer directly to the root. This is done with
        // compare-and-swap to handle concurrent updates gracefully.
        curr = i;
        while (curr != root) {
            vertexId p = parents[curr];
            // Atomically update parent pointer to point to the root.
            // We don't need to spin if this fails; another thread might be doing
            // the same work, and the structure will eventually converge.
            pbbs::atomic_compare_and_swap(&parents[curr], p, root);
            curr = p;
        }
        return root;
    }

    // Tries to unite the sets containing u and v.
    // Returns true if they were in different sets and are now united.
    // Returns false if they were already in the same set.
    // This implementation is thread-safe and uses a spinning approach
    // to handle race conditions where multiple threads attempt to unite
    // the same components simultaneously.
    bool unite(vertexId u, vertexId v) {
        vertexId root_u = find(u);
        vertexId root_v = find(v);

        // Keep trying to unite until they are in the same component.
        while (root_u != root_v) {
            // To prevent cycles, we establish a consistent link direction,
            // e.g., from the smaller root ID to the larger one.
            if (root_u > root_v) std::swap(root_u, root_v);

            // Now, root_u < root_v. We try to link root_u -> root_v.
            // We must check if root_u is still a root before the atomic operation.
            vertexId expected_parent = root_u;
            if (parents[root_u] == expected_parent) {
                // If it is, attempt the atomic link.
                if (pbbs::atomic_compare_and_swap(&parents[root_u], expected_parent, root_v)) {
                    // Success! The two components are now united.
                    return true;
                }
            }

            // If the check `parents[root_u] == expected_parent` failed or the CAS failed,
            // it means another thread has modified the parent of `root_u` in the meantime.
            // We must re-read the state by calling find() again and retry the loop.
            root_u = find(u);
            root_v = find(v);
        }

        // u and v were already in the same component.
        return false;
    }
};


// Computes a spanning forest of the given graph using a parallel,
// randomized version of Kruskal's algorithm. This approach is highly
// parallel and efficient for large graphs.
parlay::sequence<edgeId> st(edgeArray<vertexId> const &E) {
  edgeId m = E.nonZeros;
  vertexId n = E.numRows;

  if (n == 0) {
    return parlay::sequence<edgeId>();
  }

  // Initialize our thread-safe union-find data structure.
  parallel_union_find<vertexId> UF(n);

  // To improve load balancing and avoid worst-case performance on structured
  // graphs, we process the edges in a random order. This is a crucial step
  // for achieving good parallel speedup.
  auto edge_indices = parlay::random_shuffle(parlay::iota<edgeId>(m));

  // Use parlay::filter to concurrently process all edges. Each thread
  // will take an edge and attempt to unite the components of its endpoints.
  // The `unite` function is lock-free and handles all race conditions.
  // The filter operation will return a sequence containing only the indices
  // of the edges that successfully united two previously disconnected components,
  // which by definition form the spanning forest.
  auto st_edges = parlay::filter(edge_indices, [&](edgeId i) {
    return UF.unite(E[i].u, E[i].v);
  });

  return st_edges;
}
