// --- Start of file: BFS.C ---
#include <atomic>
#include <utility>
#include "parlay/primitives.h"
#include "parlay/parallel.h"
// block_delayed.h provides lazy/delayed versions of flatten and filter_map,
// which are critical for performance by avoiding the materialization of the
// full edge set from the frontier.
#include "parlay/internal/block_delayed.h"
#include "common/graph.h"
#include "BFS.h"

namespace delayed = parlay::block_delayed;

// This implementation uses a top-down, frontier-based approach, which is highly
// parallelized using the Parlay library. It is designed for performance on
// shared-memory multicore machines.
//
// The core idea is to process each level of the BFS in parallel. Starting with a
// frontier containing only the source vertex, each step expands the frontier by
// finding all unvisited neighbors of the current frontier vertices. This process
// repeats until no new vertices can be reached.
//
// Key performance features of this implementation:
// 1.  **Non-deterministic updates:** Multiple threads can concurrently try to visit
//     the same vertex. An atomic compare-and-swap (`compare_exchange_strong`) on
//     the `parent` array ensures that each vertex is visited and assigned a parent
//     exactly once. This avoids serialization but means the resulting BFS tree may
//     differ between runs, which is permitted by the problem specification.
//
// 2.  **Lazy evaluation:** The use of `parlay::delayed_tabulate` and
//     `delayed::flatten` is crucial. Instead of allocating a massive intermediate
//     array to hold all edges from the frontier, this approach creates a "delayed"
//     or "lazy" sequence of edges. The operations are fused, allowing
//     `delayed::filter_map` to process the edges as they are generated,
//     significantly reducing peak memory usage and memory bandwidth.
//
// 3.  **Efficient filtering:** A single `delayed::filter_map` call processes all
//     potential edges from the frontier. It efficiently filters for edges that
//     lead to unvisited vertices and maps them to the new frontier, all in one
//     parallel pass. This gives the Parlay scheduler maximum freedom to balance
//     the load.
//
// 4.  **Optimized atomics:** A "test-and-test-and-set" pattern is used for visiting
//     vertices. A cheap, relaxed-memory-order load (`parent[v].load`) first checks
//     if a vertex has been visited. Only if it appears unvisited is the more
//     expensive atomic `compare_exchange_strong` attempted. This reduces atomic
//     contention and bus traffic.
//
// While a direction-optimizing (hybrid top-down/bottom-up) BFS can be faster,
// especially on low-diameter graphs, a pure bottom-up step requires an efficient
// way to access vertex in-edges, which the provided graph structure does not
// offer. Given this constraint, this highly-optimized top-down implementation
// is expected to be the fastest approach.
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, 
			       bool verbose = false) {
  size_t n = G.numVertices();
  // The parent array stores the BFS tree. `parent[i]` is the parent of vertex `i`.
  // Initialized to -1 for unvisited vertices. The root's parent is itself.
  // We use `std::atomic` to allow for safe concurrent writes from multiple threads.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [&] (size_t i) {
      return -1;});
  parent[start].store(start, std::memory_order_relaxed);

  // The frontier stores the vertices to visit in the current level of the BFS.
  parlay::sequence<vertexId> frontier(1,start);

  while (frontier.size() > 0) {

    // Step 1: Generate all outgoing edges from the current frontier.
    // We use delayed sequences to avoid creating a large intermediate array of edges.
    // `nested_edges` is a sequence of delayed sequences, one for each vertex in the frontier.
    auto nested_edges = parlay::map(frontier, [&] (vertexId u) {
      // delayed_tabulate creates a lazy sequence of (parent, neighbor) pairs.
	    return parlay::delayed_tabulate(G[u].degree, [&, u] (size_t i) {
	      return std::pair(u, G[u].Neighbors[i]);});});

    // Step 2: Flatten the sequence of sequences into a single (delayed) sequence of edges.
    auto edges = delayed::flatten(nested_edges);

    // Step 3: Filter the edges to find ones that lead to unvisited vertices.
    // For each such edge (u, v), we atomically update parent[v] = u.
    // The new frontier is the set of all newly visited vertices `v`.
    // `delayed::filter_map` efficiently combines the filtering and mapping operations.
    auto edge_f = [&] (auto u_v) {
      vertexId expected = -1;
      auto [u, v] = u_v;
      // This is an optimized "test-and-test-and-set".
      // The cheap relaxed load avoids the expensive atomic CAS if `v` is already visited.
      return (parent[v].load(std::memory_order_relaxed) == -1) && 
             parent[v].compare_exchange_strong(expected, u);
    };

    frontier = delayed::filter_map(edges, edge_f, [] (auto x) {return x.second;});
  }

  // Convert the atomic parent array back to a regular sequence for output.
  return parlay::map(parent, [] (auto const &x) -> vertexId {
      return x.load();});
}
