// **************************************************************
//    A direction-optimizing parallel BFS implementation
// **************************************************************

// Builds the transpose of a graph, required for the PULL phase of the BFS.
// This is a parallel implementation that constructs the reversed graph
// in Compressed Sparse Row (CSR) format by sorting the edge list.
Graph build_transpose(const Graph& G) {
    using edge = std::pair<vertexId, vertexId>;
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    if (m == 0) {
        auto offsets = parlay::sequence<edgeId>(n + 1, 0);
        auto edges = parlay::sequence<vertexId>();
        return Graph(std::move(offsets), std::move(edges), n);
    }

    // 1. Create a sequence of reversed edges (v, u) for each edge (u, v).
    auto edge_pairs = parlay::flatten(parlay::tabulate(n, [&](size_t u) {
        auto vtx = G[u];
        return parlay::tabulate(vtx.degree, [&](size_t i) {
            return std::make_pair(vtx.Neighbors[i], (vertexId)u);
        });
    }));

    // 2. Sort pairs by key (the new source vertex).
    // This groups all incoming edges for each vertex together.
    parlay::sort_inplace(edge_pairs);

    // 3. Extract the new edge list from the sorted pairs.
    auto T_edges = parlay::map(edge_pairs, [](const auto& p) { return p.second; });

    // 4. Create the offset array by finding the start of each vertex's block.
    auto T_offsets = parlay::sequence<edgeId>(n + 1);
    T_offsets[n] = m;

    // Mark the start of each new vertex's adjacency list.
    parlay::parallel_for(1, m, [&](size_t i) {
        if (edge_pairs[i].first != edge_pairs[i-1].first) {
            T_offsets[edge_pairs[i].first] = i;
        }
    });
    if (m > 0) {
        T_offsets[edge_pairs[0].first] = 0;
    }

    // Identify which vertices have incoming edges to know which offsets were set.
    auto has_incoming = parlay::sequence<bool>(n + 1, false);
    parlay::parallel_for(0, m, [&](size_t i) {
        if (i == 0 || edge_pairs[i].first != edge_pairs[i-1].first) {
            has_incoming[edge_pairs[i].first] = true;
        }
    });

    // Fill in the offsets for vertices with no incoming edges using a parallel scan.
    // First, set all unset offsets to a sentinel value (m).
    parlay::parallel_for(0, n, [&](size_t i) {
        if (!has_incoming[i]) T_offsets[i] = m;
    });

    // A right-to-left inclusive scan with min propagates the correct offset
    // from right to left, filling in the gaps.
    parlay::scan_inclusive(parlay::make_slice(T_offsets).rbegin(), parlay::make_slice(T_offsets).rbegin(),
                           parlay::minm<edgeId>());

    return Graph(std::move(T_offsets), std::move(T_edges), n);
}

// A parallel direction-optimizing Breadth-First Search implementation.
// It uses a "push" based approach for small frontiers and switches to a
// "pull" based approach for large frontiers to improve performance and
// memory access patterns. The pull-based approach requires the graph
// transpose for directed graphs, which is computed on-demand.
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();
  size_t m = G.numEdges();

  // Parent array to store the BFS tree. `std::atomic` handles concurrent writes.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
  parent[start] = start;

  // The frontier of the BFS, starting with the source vertex.
  parlay::sequence<vertexId> frontier(1, start);

  // Heuristics for switching between push and pull (direction-optimization).
  // These are standard values from frameworks like Ligra.
  const size_t alpha = 15; // Controls switch-to-pull based on frontier edges
  const size_t beta = 20;  // Controls switch-to-push based on frontier vertices

  bool use_pull = false; // Start in PUSH mode.
  Graph GT;              // Transpose graph for PULL mode.
  bool gt_built = false;

  while (!frontier.empty()) {
    // --- Heuristic to decide between PUSH and PULL ---
    if (use_pull) {
      // If in PULL mode, check if frontier is small enough to switch back to PUSH
      if (frontier.size() < n / beta) {
        use_pull = false;
        if(verbose) t.next("switch_to_push");
      }
    } else {
      // If in PUSH mode, check if frontier is large enough to switch to PULL
      auto out_degrees = parlay::map(frontier, [&](vertexId u) { return G[u].degree; });
      size_t frontier_edges = parlay::reduce(out_degrees);
      if (frontier.size() + frontier_edges > m / alpha && n > 1) {
        use_pull = true;
        if(verbose) t.next("switch_to_pull");
      }
    }

    if (use_pull) {
      // --- PULL direction ---
      // Iterates over unvisited vertices and checks for neighbors in the current frontier.
      // Better for large frontiers due to improved memory locality.
      // Requires the transpose graph for directed graphs.
      if (!gt_built) {
        GT = build_transpose(G);
        gt_built = true;
        if(verbose) t.next("transpose");
      }

      auto dense_frontier = parlay::sequence<bool>(n, false);
      parlay::parallel_for(0, frontier.size(), [&](size_t i) {
          dense_frontier[frontier[i]] = true;
      });
      if(verbose) t.next("convert_to_dense");

      auto next_frontier_flags = parlay::tabulate(n, [&](vertexId v) -> bool {
        if (parent[v] == -1) {
          auto vtx_t = GT[v]; // Incoming neighbors from transpose graph
          for (size_t i = 0; i < vtx_t.degree; ++i) {
            vertexId u = vtx_t.Neighbors[i];
            if (dense_frontier[u]) {
              vertexId expected = -1;
              if (parent[v].compare_exchange_strong(expected, u)) {
                return true; // Successfully visited, add to next frontier.
              }
              return false; // Already visited by another thread in this step.
            }
          }
        }
        return false;
      });
      frontier = parlay::pack_index<vertexId>(next_frontier_flags);
      if(verbose) t.next("pull");
    } else {
      // --- PUSH direction ---
      // Iterates over vertices in the frontier and visits their unvisited neighbors.
      // Work-efficient for small frontiers.
      auto nested_next_frontier = parlay::map(frontier, [&](vertexId u) {
        auto vtx = G[u];
        auto neighbors = parlay::make_slice(vtx.Neighbors, vtx.Neighbors + vtx.degree);

        auto successful_visits = parlay::filter(neighbors, [&](vertexId v) {
          vertexId expected = -1;
          return parent[v].compare_exchange_strong(expected, u);
        });
        return successful_visits;
      });
      frontier = parlay::flatten(nested_next_frontier);
      if(verbose) t.next("push");
    }
  }

  // Convert atomic parent array to a regular one for the return value.
  return parlay::map(parent, [](auto const& x) { return x.load(); });
}
