// Build the transpose of a graph.
// This is necessary for an efficient PULL step in direction-optimizing BFS on directed graphs.
Graph build_transpose(const Graph& G) {
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // 1. Count in-degrees for each vertex to determine the size of each adjacency list in the transpose.
    parlay::sequence<edgeId> in_degrees(n, 0);
    parlay::parallel_for(0, n, [&](size_t u) {
        auto vtx = G[u];
        for (edgeId i = 0; i < vtx.degree; i++) {
            vertexId v = vtx.Neighbors[i];
            parlay::fetch_add(&in_degrees[v], (edgeId)1);
        }
    }, 1); // Use a small grainsize for load balancing on irregular-degree graphs.

    // 2. Compute the starting offsets for each adjacency list in the transpose graph's edge array.
    // This is an exclusive scan on the in-degrees.
    parlay::sequence<edgeId> t_offsets(n + 1);
    parlay::scan_into(in_degrees, parlay::make_slice(t_offsets).drop(1));
    t_offsets[0] = 0;

    // 3. Populate the transpose graph's edge array.
    parlay::sequence<vertexId> t_edges(m);
    // Use a copy of the offsets for thread-safe placement of incoming edges. Each thread
    // will atomically increment the offset for the vertex it is adding an edge to.
    auto current_offsets = t_offsets; 
    parlay::parallel_for(0, n, [&](size_t u) {
        auto vtx = G[u];
        for (edgeId i = 0; i < vtx.degree; i++) {
            vertexId v = vtx.Neighbors[i];
            edgeId dest_idx = parlay::fetch_add(&current_offsets[v], (edgeId)1);
            t_edges[dest_idx] = u;
        }
    }, 1);

    return Graph(std::move(t_offsets), std::move(t_edges), n);
}

// A direction-optimizing (push-pull) parallel Breadth-First Search implementation.
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
    parlay::internal::timer t("BFS", verbose);
    size_t n = G.numVertices();

    // The parent array stores the BFS tree. `parent[i]` is the parent of vertex `i`.
    // It is initialized to -1 for unvisited vertices. The root's parent is itself.
    // std::atomic is used for thread-safe updates from multiple threads.
    auto parents = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
    parents[start].store(start, std::memory_order_relaxed);

    // The frontier of the BFS, stored as a sparse sequence of vertex IDs.
    parlay::sequence<vertexId> frontier(1, start);

    // Build the transpose graph, which is required for the efficient PULL phase.
    Graph G_T = build_transpose(G);
    t.next("Transpose");

    // Heuristic constant for switching from PUSH to PULL.
    // Switch to PULL when the frontier size exceeds a fraction of the total vertices.
    const size_t push_to_pull_threshold = n / 20;

    while (!frontier.empty()) {
        // Heuristic: If the frontier is large, use the PULL method. Otherwise, use PUSH.
        if (frontier.size() > push_to_pull_threshold) {
            // --- PULL PHASE (for large frontiers) ---
            // In the PULL phase, unvisited vertices check their in-neighbors to see if any are in the frontier.

            // Create a dense boolean array representing the frontier for O(1) lookups.
            parlay::sequence<bool> is_in_frontier(n, false);
            parlay::parallel_for(0, frontier.size(), [&](size_t i) {
                is_in_frontier[frontier[i]] = true;
            });
            t.next("Dense Frontier");

            // Iterate over all vertices in parallel.
            auto next_frontier_dense = parlay::tabulate(n, [&](vertexId v) {
                // If vertex v is unvisited...
                if (parents[v].load(std::memory_order_relaxed) == -1) {
                    auto vtx_t = G_T[v]; // Get in-neighbors from the transpose graph.
                    for (edgeId i = 0; i < vtx_t.degree; ++i) {
                        vertexId u = vtx_t.Neighbors[i];
                        // ...check if any in-neighbor `u` is in the current frontier.
                        if (is_in_frontier[u]) {
                            // If so, claim `v`. No atomic needed as each `v` is handled by one thread.
                            parents[v].store(u, std::memory_order_relaxed);
                            return true; // Mark `v` as part of the next frontier.
                        }
                    }
                }
                return false;
            });

            // Convert the dense boolean array back to a sparse list of vertex IDs for the next iteration.
            frontier = parlay::pack_index<vertexId>(next_frontier_dense);
            t.next("Pull");

        } else {
            // --- PUSH PHASE (for small frontiers) ---
            // In the PUSH phase, vertices in the frontier visit all their out-neighbors.

            auto nested_next_frontier = parlay::map(frontier, [&](vertexId u) {
                auto vtx = G[u];
                auto neighbors = parlay::make_slice(vtx.Neighbors, vtx.Neighbors + vtx.degree);
                // For each neighbor, attempt to atomically claim it.
                return parlay::filter(neighbors, [&](vertexId v) {
                    vertexId expected = -1;
                    // The CAS atomically checks if `v` is unvisited (parent == -1) and sets `u` as its parent.
                    // This succeeds for only one thread, preventing races and duplicates in the next frontier.
                    return parents[v].compare_exchange_strong(expected, u, std::memory_order_relaxed);
                });
            });

            frontier = parlay::flatten(nested_next_frontier);
            t.next("Push");
        }
    }

    // Convert the atomic parent array to a regular sequence for the return value.
    return parlay::map(parents, [](auto const &p) { return p.load(); });
}
