// A high-performance parallel BFS implementation using the direction-optimizing
// (or push-pull) approach. This is a common state-of-the-art technique for
// BFS on the types of scale-free graphs often used in benchmarks.
//
// The algorithm maintains a frontier of vertices to visit.
// - PUSH (Sparse Mode): When the frontier is small, each thread processes vertices
//   from the frontier and "pushes" updates to their neighbors. This is efficient
//   when the work is concentrated in a few vertices.
// - PULL (Dense Mode): When the frontier is large, the algorithm switches to a
//   pull-based approach. Each thread processes a range of unvisited vertices
//   and "pulls" an update by checking if any of its neighbors are in the
//   frontier. This improves locality and avoids redundant work when many edges
//   point to already visited vertices. The pull phase assumes a symmetric graph.
//
// Atomics are used for thread-safe updates in the push phase, while the pull
// phase uses non-atomic writes since each destination vertex is owned by a
// single thread.

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
    size_t n = G.numVertices();

    // The parent array stores the BFS tree. A value of -1 indicates an unvisited vertex.
    // Atomics are used for safe parallel updates during the PUSH phase.
    auto parents = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
    parents[start].store(start, std::memory_order_relaxed);

    // The frontier can be represented sparsely (a list of vertex IDs) or
    // densely (a boolean array). We start with a sparse frontier.
    parlay::sequence<vertexId> sparse_frontier(1, start);
    parlay::sequence<bool> dense_frontier;
    bool is_sparse = true;
    size_t frontier_size = 1;

    // Heuristics to switch between PUSH (sparse) and PULL (dense) phases,
    // inspired by the Ligra framework.
    const size_t pull_threshold = G.numEdges() / 20;
    const size_t push_threshold = n / 20;

    while (frontier_size > 0) {

        // --- Direction Optimization: Decide whether to PUSH or PULL ---
        if (is_sparse) {
            auto out_degree = parlay::reduce(parlay::delayed_map(sparse_frontier,
                [&](vertexId v) -> size_t { return G[v].degree; }));

            if (frontier_size + out_degree > pull_threshold) {
                is_sparse = false;
                dense_frontier = parlay::sequence<bool>(n, false);
                parlay::parallel_for(0, frontier_size, [&](size_t i) {
                    dense_frontier[sparse_frontier[i]] = true;
                });
                sparse_frontier.clear();
            }
        } else { // is dense
            if (frontier_size < push_threshold) {
                is_sparse = true;
                sparse_frontier = parlay::pack_index<vertexId>(dense_frontier);
                dense_frontier.clear();
            }
        }

        if (is_sparse) {
            // --- PUSH PHASE (Sparse Frontier) ---
            auto nested_new_neighbors = parlay::map(sparse_frontier, [&](vertexId u) {
                auto neighbors = G[u];
                auto all_neighbors = parlay::delayed_seq<vertexId>(neighbors.degree,
                    [&](size_t i) { return neighbors.Neighbors[i]; });

                return parlay::filter(all_neighbors, [&](vertexId v) {
                    vertexId expected = -1;
                    // Fast, non-atomic check to avoid expensive CAS.
                    if (parents[v].load(std::memory_order_relaxed) == -1 &&
                        parents[v].compare_exchange_strong(expected, u, std::memory_order_relaxed)) {
                        return true;
                    }
                    return false;
                });
            });

            sparse_frontier = parlay::flatten(nested_new_neighbors);
            frontier_size = sparse_frontier.size();

        } else {
            // --- PULL PHASE (Dense Frontier) ---
            // NOTE: This pull phase assumes the graph is symmetric. For a directed graph,
            // a correct pull requires iterating over in-edges, which are not provided.
            auto next_dense_frontier = parlay::sequence<bool>(n, false);
            parlay::parallel_for(0, n, [&](vertexId v) {
                if (parents[v].load(std::memory_order_relaxed) == -1) {
                    auto neighbors = G[v];
                    for (vertexId i = 0; i < neighbors.degree; ++i) {
                        vertexId u = neighbors.Neighbors[i];
                        if (dense_frontier[u]) {
                            // Non-atomic write is safe: only one thread writes to parents[v].
                            parents[v].store(u, std::memory_order_relaxed);
                            next_dense_frontier[v] = true;
                            break; // Found a parent, no need to check other neighbors.
                        }
                    }
                }
            });

            dense_frontier = std::move(next_dense_frontier);
            frontier_size = parlay::count(dense_frontier, true);
        }
    }

    // Convert the atomic parent array to a regular sequence for the final result.
    return parlay::map(parents, [](const auto& p) { return p.load(); });
}
