// A structure to represent the frontier, which can be either sparse 
// (a sequence of vertex IDs) or dense (a boolean sequence).
struct Frontier {
    parlay::sequence<vertexId> sparse_f;
    parlay::sequence<bool> dense_f;
    bool is_sparse;
    size_t n;
    size_t f_size;

    explicit Frontier(size_t _n) : is_sparse(true), n(_n), f_size(0) {}

    void to_sparse() {
        if (!is_sparse) {
            sparse_f = parlay::pack_index<vertexId>(dense_f);
            dense_f.clear();
            is_sparse = true;
        }
    }

    void to_dense() {
        if (is_sparse) {
            dense_f = parlay::sequence<bool>(n, false);
            parlay::parallel_for(0, sparse_f.size(), [&](size_t i) {
                dense_f[sparse_f[i]] = true;
            });
            sparse_f.clear();
            is_sparse = false;
        }
    }

    void set_sparse(parlay::sequence<vertexId>&& f) {
        sparse_f = std::move(f);
        f_size = sparse_f.size();
        is_sparse = true;
        dense_f.clear();
    }

    // This function takes ownership of the atomic flags and converts them to the new dense frontier
    void set_next_frontier_from_flags(parlay::sequence<std::atomic<bool>>& flags) {
        dense_f = parlay::sequence<bool>(n);
        parlay::parallel_for(0, n, [&](size_t i) {
            dense_f[i] = flags[i].load(std::memory_order_relaxed);
        });
        f_size = parlay::count(dense_f, true);
        is_sparse = false;
        sparse_f.clear();
    }

    size_t size() const { return f_size; }
    bool empty() const { return f_size == 0; }
};

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
    parlay::internal::timer t("BFS", verbose);
    size_t n = G.numVertices();

    auto parents = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) {
        return static_cast<vertexId>(-1);
    });
    parents[start].store(start, std::memory_order_relaxed);
    t.next("init");

    Frontier frontier(n);
    frontier.set_sparse(parlay::sequence<vertexId>(1, start));

    // Heuristics for switching between sparse and dense frontiers, inspired by Ligra/GAPBS.
    const size_t alpha = 15; // Controls top-down to dense switch
    const size_t beta = 24;  // Controls dense to top-down switch

    while (!frontier.empty()) {
        if (frontier.is_sparse) {
            size_t frontier_out_degree = parlay::reduce(parlay::delayed_map(frontier.sparse_f,
                [&](vertexId u) -> size_t { return G[u].degree; }));
            if (frontier.size() + frontier_out_degree > G.numEdges() / alpha) {
                frontier.to_dense();
            }
        } else { // is_dense
            if (frontier.size() < n / beta) {
                frontier.to_sparse();
            }
        }
        t.next("heuristic");

        if (frontier.is_sparse) {
            // --- Top-Down (Sparse Push) Step ---
            auto new_vertices_nested = parlay::map(frontier.sparse_f, [&](vertexId u) {
                auto u_vtx = G[u];
                auto neighbors = parlay::make_slice(u_vtx.Neighbors, u_vtx.Neighbors + u_vtx.degree);
                return parlay::filter(neighbors, [&](vertexId v) {
                    vertexId expected = -1;
                    // Atomically check and claim the unvisited neighbor
                    return parents[v].load(std::memory_order_relaxed) == -1 &&
                           parents[v].compare_exchange_strong(expected, u, std::memory_order_relaxed);
                });
            });

            auto next_frontier_dups = parlay::flatten(new_vertices_nested);

            if (next_frontier_dups.empty()) {
                frontier.set_sparse({});
            } else {
                // Deduplicate using a boolean flag array. This is O(n + |next_frontier_dups|).
                auto flags = parlay::sequence<std::atomic<bool>>::from_function(n, [](size_t){ return false; });
                parlay::parallel_for(0, next_frontier_dups.size(), [&](size_t i) {
                    vertexId v = next_frontier_dups[i];
                    bool expected = false;
                    flags[v].compare_exchange_strong(expected, true, std::memory_order_relaxed);
                });
                auto next_f = parlay::pack_index_if<vertexId>(n, [&](size_t i) {
                    return flags[i].load(std::memory_order_relaxed);
                });
                frontier.set_sparse(std::move(next_f));
            }
        } else { // Dense frontier
            // --- Dense Push Step ---
            // A true bottom-up (pull) step requires the transpose graph. Without it, we perform a "dense push", 
            // which is correct for directed graphs. It explores all outgoing edges from the dense frontier.
            auto next_f_flags = parlay::sequence<std::atomic<bool>>::from_function(n, [](size_t){ return false; });

            parlay::parallel_for(0, n, [&](vertexId u) {
                if (frontier.dense_f[u]) {
                    auto u_vtx = G[u];
                    for (vertexId i = 0; i < u_vtx.degree; i++) {
                        vertexId v = u_vtx.Neighbors[i];
                        vertexId expected_parent = -1;
                        if (parents[v].load(std::memory_order_relaxed) == -1 &&
                            parents[v].compare_exchange_strong(expected_parent, u, std::memory_order_relaxed)) {
                            bool expected_flag = false;
                            // Atomically mark the vertex for the next frontier
                            next_f_flags[v].compare_exchange_strong(expected_flag, true, std::memory_order_relaxed);
                        }
                    }
                }
            });
            frontier.set_next_frontier_from_flags(next_f_flags);
        }
        t.next("iteration");
    }

    return parlay::map(parents, [](const auto& p) { return p.load(std::memory_order_relaxed); });
}
