using namespace std;

// **************************************************************
//    FAST, DETERMINISTIC, PARALLEL BREADTH FIRST SEARCH
// **************************************************************

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose=true) {
  size_t n = G.numVertices();

  // The parent of a vertex is the vertex that discovered it.
  // We use a value of `n` to represent an unassigned parent.
  // This allows us to use `write_min` to deterministically select the
  // parent with the smallest vertex ID among all candidates in a round.
  const vertexId unassigned_parent = n;
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [&](size_t i) {
    return unassigned_parent;
  });

  // `visited` marks vertices that have been added to a frontier.
  // This ensures that each vertex is processed in exactly one round.
  auto visited = parlay::sequence<std::atomic<bool>>::from_function(n, [&](size_t i) {
    return false;
  });

  parent[start] = start;
  visited[start] = true;

  parlay::sequence<vertexId> frontier(1, start);

  while (!frontier.empty()) {
    // Generate a delayed sequence of all outgoing edges from the current frontier.
    // An edge is represented as a pair of (source, destination).
    auto nested_edges = parlay::map(frontier, [&](vertexId u) {
      return parlay::delayed_tabulate(G[u].degree, [&, u](size_t i) {
        return std::pair(u, G[u].Neighbors[i]);
      });
    });
    auto edges = delayed::flatten(nested_edges);

    // Filter the edges to find those that visit a new vertex.
    // For each unvisited neighbor `v`, multiple vertices `u` in the frontier
    // might attempt to become its parent. `write_min` is used as a deterministic
    // tie-breaker: the `u` with the minimum ID will win.
    // `write_min` returns true if it successfully lowered the value of parent[v].
    auto visiting_edges = delayed::filter(edges, [&](auto u_v) {
      auto [u, v] = u_v;
      // We only attempt to visit `v` if it has not been added to a frontier before.
      return (!visited[v].load(std::memory_order_relaxed)) &&
             parlay::internal::write_min(&parent[v], u, std::less<vertexId>());
    });

    // A new frontier is formed by the vertices that were successfully visited.
    // A vertex `v` is added to the next frontier if its final parent is the source
    // `u` from a `visiting_edge`. This check ensures that only the winning parent
    // causes the vertex to be added to the frontier.
    auto new_frontier_optional = delayed::map(visiting_edges, [&](auto u_v) {
        auto [u, v] = u_v;
        std::optional<vertexId> result;
        // Check if this `u` is the final winner of the `write_min` race for `v`.
        if (parent[v].load(std::memory_order_relaxed) == u) {
          // Atomically mark `v` as visited. If we are the first to do so,
          // add `v` to the next frontier. This ensures `v` is added exactly once.
          bool already_visited = false;
          if (visited[v].compare_exchange_strong(already_visited, true)) {
            result = v;
          }
        }
        return result;
      });

    // Realize the delayed sequence to form the concrete frontier for the next round.
    // `pack` will collect all non-empty optionals.
    frontier = parlay::pack(new_frontier_optional);
  }

  // Convert the parent array to the required output format.
  // Unvisited vertices should have a parent of -1.
  return parlay::map(parent, [=](auto const& p_atomic) {
    vertexId p = p_atomic.load();
    return (p == unassigned_parent) ? -1 : p;
  });
}
