#include <utility>
#include <algorithm>

#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/sequence.h"
#include "parlay/integer_sort.h"
#include "parlay/internal/block_delayed.h"

#include "common/graph.h"
#include "BFS.h"

namespace delayed = parlay::block_delayed;

// **************************************************************
//    DETERMINISTIC PARALLEL BREADTH FIRST SEARCH
// **************************************************************
// This implementation is a parallel top-down BFS.
// It is deterministic by ensuring that when multiple vertices in the current
// frontier can visit the same unvisited vertex, the one with the smallest
// vertex ID is chosen as the parent. This is a common requirement for
// reproducible results in graph algorithms.
//
// The main steps at each level of the BFS are:
// 1. In parallel, gather all neighbors of the current frontier. This results
//    in a sequence of (neighbor, parent) pairs. Delayed evaluation is used
//    to improve performance and reduce peak memory usage.
// 2. Filter this sequence to keep only pairs where the neighbor has not
//    yet been visited (i.e., its parent is -1).
// 3. Use `parlay::group_by_and_combine` to process these candidate edges.
//    This primitive groups the pairs by the neighbor (the key) and for each
//    group, it combines the parent IDs (the values) using a reduction -- in
//    this case, `std::min`. This efficiently and deterministically selects
//    the minimum-ID parent for each newly discovered vertex.
// 4. The result is a unique list of (newly_visited_vertex, parent) pairs.
//    A parallel map over this result updates the main parent array and
//    constructs the frontier for the next level.
//
// This approach is work-efficient, with work at each level proportional to
// the number of outgoing edges from the frontier. The use of Parlay's
// highly-optimized primitives, especially `group_by_and_combine` which is
// based on parallel integer sort, ensures high performance without the
// overhead of atomics or locks for achieving determinism.
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  size_t n = G.numVertices();

  // The parent array stores the BFS tree.
  // parent[i] = -1 if vertex i is unvisited.
  // parent[start] = start for the root.
  // Otherwise, parent[i] is the vertex that first discovered i.
  auto parent = parlay::sequence<vertexId>::from_function(n, [](size_t) {
    return -1;
  });

  if (n == 0) {
    return parent;
  }

  parent[start] = start;

  parlay::sequence<vertexId> frontier(1, start);

  while (!frontier.empty()) {
    // Step 1: Gather all neighbors of the current frontier as (neighbor, parent) pairs.
    // Using delayed evaluation can improve performance by fusing operations.
    auto nested_edges = parlay::map(frontier, [&](vertexId u) {
      return parlay::delayed_tabulate(G[u].degree, [=](size_t i) {
        return std::pair<vertexId, vertexId>(G[u].Neighbors[i], u);
      });
    });
    auto edges = delayed::flatten(nested_edges);

    // Step 2: Filter out neighbors that have already been visited.
    // A vertex v is unvisited if parent[v] is -1. This materializes the sequence.
    auto candidates = parlay::filter(edges, [&](const auto& edge) {
      // Non-atomic read is safe. `parent` is read-only in this parallel section
      // for any vertex that could be a candidate. Writes happen in a later step.
      return parent[edge.first] == -1;
    });

    if (candidates.empty()) {
      break;
    }

    // Step 3: Deterministically select one parent for each new vertex.
    // Group candidate edges by destination (edge.first), and for each
    // destination, find the minimum-ID source (edge.second).
    auto min_f = [](vertexId a, vertexId b) { return std::min(a, b); };
    auto new_parents = parlay::group_by_and_combine(candidates, min_f);

    // Step 4: Update the parent array and form the next frontier.
    frontier = parlay::map(new_parents, [&](const auto& pair) {
      auto [v, u] = pair;
      // This write is safe without atomics because `group_by_and_combine`
      // guarantees that each `v` in `new_parents` is unique.
      parent[v] = u;
      return v;
    });
  }

  // The final parent array represents the BFS tree.
  return parent;
}
