```cpp
#include <limits>
#include <algorithm>
#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/sequence.h"
#include "common/graph.h"
#include "BFS.h"

// **************************************************************
//    DETERMINISTIC PARALLEL BREADTH FIRST SEARCH
// **************************************************************

// This is a high-performance, deterministic, parallel Breadth-First Search.
// The algorithm is level-synchronous (top-down). Determinism is achieved
// by ensuring that for any vertex, the parent selected is always the one
// with the minimum vertex ID among all possible parents in the current frontier.
//
// In each step of the BFS, the algorithm performs the following:
// 1. Expands the frontier by gathering all neighbors of vertices in the current frontier.
// 2. Filters out neighbors that have already been visited in previous steps.
// 3. For the remaining candidate neighbors, it deterministically assigns a parent.
//    This is done by sorting all (parent, neighbor) edges. The primary sort key
//    is the neighbor's ID, and the secondary key is the parent's ID.
// 4. After sorting, the first edge for each unique neighbor corresponds to the
//    parent with the minimum ID. These "winning" edges are selected.
// 5. The parents of the newly visited vertices are updated, and these vertices
//    form the frontier for the next level.
//
// This approach avoids the non-determinism of atomic race-based writes (e.g.,
// compare-and-swap) while remaining highly parallel. The use of ParlayLib's
// optimized parallel primitives for operations like map, flatten, filter, sort,
// and pack ensures high efficiency.

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose=true) {
  using edge = std::pair<vertexId, vertexId>;
  size_t n = G.numVertices();

  // The parent array stores the BFS tree.
  // parent[i] = -1 indicates vertex i has not been visited.
  // The root of the BFS tree points to itself.
  auto parent = parlay::sequence<vertexId>::from_function(n, [&](size_t) {
    return -1;
  });

  // The start vertex is the root of the tree.
  parent[start] = start;

  parlay::sequence<vertexId> frontier(1, start);

  while (!frontier.empty()) {
    // 1. Generate all outgoing edges (u, v) from the current frontier,
    // where u is in the frontier and v is a neighbor of u.
    auto nested_edges = parlay::map(frontier, [&](vertexId u) {
      return parlay::delayed_seq<edge>(G[u].degree, [u, &G](size_t i) {
        return std::make_pair(u, G[u].Neighbors[i]);
      });
    });
    auto all_edges = parlay::flatten(nested_edges);

    // 2. Filter out edges leading to vertices that have already been visited.
    // A vertex v is considered visited if parent[v] is not -1.
    // This read is safe in parallel because parent state is read-only for this step.
    auto candidate_edges = parlay::filter(all_edges, [&](const edge& e) {
      return parent[e.second] == -1;
    });

    if (candidate_edges.empty()) break;

    // 3. Sort candidate edges to group them by destination vertex.
    // The primary sort key is the destination (e.second), and the secondary
    // key is the source (e.first). This ensures that for each
    // destination, the valid parent with the minimum ID comes first.
    parlay::sort_inplace(candidate_edges, [](const edge& a, const edge& b) {
      if (a.second != b.second) return a.second < b.second;
      return a.first < b.first;
    });

    // 4. Select the winning parent for each new vertex.
    // A winning edge is the first one for a given destination in the sorted list.
    // We can identify these by checking if a destination is different from the previous one.
    auto is_winner = parlay::delayed_seq<bool>(candidate_edges.size(), [&](size_t i) {
      return (i == 0) || (candidate_edges[i].second != candidate_edges[i-1].second);
    });

    // Use pack to collect all the winning edges.
    auto winning_edges = parlay::pack(candidate_edges, is_winner);

    // 5. Update the parent array and construct the next frontier.
    // Since each vertex appears as a destination in winning_edges at most
    // once, these writes to the parent array can be done in parallel without conflict.
    parlay::for_each(winning_edges, [&](const edge& e) {
        const auto& [u, v] = e;
        parent[v] = u;
    });

    // The new frontier consists of the destinations of the winning edges.
    frontier = parlay::map(winning_edges, [](const edge& e) {
      return e.second;
    });
  }

  return parent;
}
```
