    vertexId v = Frontier[bot++];
    size_t k = 0;
    for (size_t j = 0; j < G[v].degree; j++) {
      vertexId ngh = G[v].Neighbors[j];
      if (Parent[ngh] == -1) {
	Frontier[top++] = ngh;
	Parent[ngh] = v;
      }
    }
  }
  return Parent;
}



