#include <optional>

using namespace std;
using vertexId = int;
using edgeId = uint;
using Graph = graph<vertexId,edgeId>;

// **************************************************************
//    HIGH-PERFORMANCE PARALLEL BREADTH-FIRST SEARCH
// **************************************************************
// This implementation uses a top-down (or push-based) parallel BFS approach.
// It processes the graph level by level, starting from the source vertex.
//
// Note on Hybrid BFS (Top-Down/Bottom-Up):
// A common optimization for BFS is to switch to a bottom-up (pull-based)
// approach when the frontier becomes large. However, the standard bottom-up
// approach requires iterating over the incoming edges of unvisited vertices.
// The provided graph data structure only supports efficient access to outgoing
// edges. Without a transpose graph, a pure top-down approach, as implemented
// here, is the most performant and correct strategy.
//
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G,
                               bool verbose = false) {
    size_t n = G.numVertices();

    // The Parent array stores the parent of each vertex in the BFS tree.
    // It is also used to mark visited vertices (Parent[v] != -1).
    // We use std::atomic to allow for thread-safe concurrent updates.
    auto Parent = parlay::sequence<std::atomic<vertexId>>::uninitialized(n);
    parlay::parallel_for(0, n, [&](size_t i) {
        // Initialize all parents to -1 (unvisited). Relaxed memory order is
        // sufficient because synchronization occurs at level boundaries.
        Parent[i].store(-1, std::memory_order_relaxed);
    });

    // The start vertex is the root of the BFS tree; its parent is itself.
    Parent[start].store(start, std::memory_order_relaxed);

    // The frontier contains all vertices at the current level of the BFS.
    parlay::sequence<vertexId> Frontier(1, start);

    // Continue as long as there are vertices in the frontier to process.
    while (!Frontier.empty()) {
        // In parallel, for each vertex u in the current Frontier, explore its neighbors.
        // The result is a sequence of sequences, where each inner sequence
        // contains the newly visited neighbors of a vertex from the Frontier.
        auto nested_next_frontier = parlay::map(Frontier, [&](vertexId u) {
            auto v_struct = G[u];
            auto neighbors_slice = parlay::make_slice(v_struct.Neighbors, v_struct.Neighbors + v_struct.degree);

            // Use map_filter to efficiently visit neighbors in parallel.
            // For each neighbor, it attempts to claim it. If successful, the
            // neighbor is included in the returned sequence.
            return parlay::map_filter(neighbors_slice, [&](vertexId ngh) -> std::optional<vertexId> {
                vertexId unvisited = -1;
                // Atomically attempt to transition Parent[ngh] from -1 to u.
                // If successful, this thread has claimed the vertex.
                if (Parent[ngh].compare_exchange_strong(unvisited, u, std::memory_order_relaxed)) {
                    return ngh; // Success: return the newly visited neighbor.
                }
                return std::nullopt; // Failure: neighbor was already visited.
            });
        });

        // Flatten the sequence of sequences into a single flat sequence for the next frontier.
        Frontier = parlay::flatten(nested_next_frontier);
    }

    // Convert the atomic parent array back to a regular sequence for the return value.
    // This final map is also performed in parallel.
    return parlay::map(parlay::make_slice(Parent), [](const auto& p) {
        return p.load(std::memory_order_relaxed);
    });
}
