#include "common/graph.h"
#include "parlay/sequence.h"
#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/atomics.h"
#include <optional>

using vertexId = int;
using edgeId = uint;
using Graph = graph<vertexId,edgeId>;

// **************************************************************
//    PARALLEL BREADTH FIRST SEARCH
// **************************************************************
// This implementation uses a direction-optimizing (hybrid) approach,
// switching between a top-down (push) and bottom-up (pull) strategy.
//
// - Top-down: Efficient for small frontiers. Each vertex in the frontier
//   "pushes" its parent status to its unvisited neighbors. This is
//   parallelized over the frontier vertices.
//
// - Bottom-up: Efficient for large frontiers. Each unvisited vertex
//   "pulls" from its neighbors, checking if any of them are in the
//   frontier. This is parallelized over all vertices. This assumes
//   the graph is symmetric, allowing outgoing edges to be treated as
//   incoming edges for the check.
//
// A heuristic based on the frontier size and its total degree is used
// to switch between the two strategies.

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G,
			       bool verbose = false) {
  size_t n = G.numVertices();
  auto parents = parlay::sequence<vertexId>(n, -1);

  // Trivial case: no vertices
  if (n == 0) {
    return parents;
  }

  parents[start] = start;
  parlay::sequence<vertexId> frontier(1, start);

  // Heuristic constant for switching from top-down to bottom-up.
  // This is based on a common heuristic (e.g., from the GAP Benchmark Suite),
  // which balances the number of vertices and edges to visit.
  const size_t switch_threshold = n / 18;

  while (!frontier.empty()) {
    // Heuristic: If the frontier is large, use bottom-up. Otherwise, use top-down.
    // We estimate the work for a top-down step by summing the frontier size
    // and the total degree of the frontier vertices.
    size_t frontier_size = frontier.size();
    auto out_degrees = parlay::map(frontier, [&](vertexId u) { return G[u].degree; });
    size_t frontier_out_edges = parlay::reduce(out_degrees);

    if (frontier_size + frontier_out_edges > switch_threshold) {
      // --- Bottom-Up (Pull) Step ---
      // Efficient when the frontier is large.

      // Convert sparse frontier to a dense boolean array for O(1) lookup
      auto frontier_dense = parlay::sequence<bool>(n, false);
      parlay::parallel_for(0, frontier.size(), [&](size_t i) {
          frontier_dense[frontier[i]] = true;
      });

      frontier = parlay::pack_index<vertexId>(n, [&](size_t v) {
          if (parents[v] == -1) {
              auto neighbors = G[v].Neighbors;
              auto degree = G[v].degree;
              // Check neighbors (assuming symmetry for finding in-edges)
              for (vertexId i = 0; i < degree; i++) {
                  vertexId u = neighbors[i];
                  if (frontier_dense[u]) {
                      // Benign race: multiple threads might write to parents[v],
                      // but any valid parent from the frontier is correct.
                      // pack_index ensures v is added to the next frontier only once.
                      parents[v] = u;
                      return true; // Pack v, and stop checking its neighbors
                  }
              }
          }
          return false; // Already visited or no parent in frontier
      });

    } else {
      // --- Top-Down (Push) Step ---
      // Efficient when the frontier is small.

      frontier = parlay::map_flatten(frontier, [&](vertexId u) {
          auto neighbors = parlay::make_slice(G[u].Neighbors, G[u].Neighbors + G[u].degree);

          // For each neighbor, try to claim it if unvisited
          return parlay::map_maybe(neighbors, [&](vertexId v) {
              vertexId expected = -1;
              std::optional<vertexId> result;
              // Use atomic CAS to be the first to visit the neighbor.
              // This is necessary because multiple vertices in the frontier
              // could have the same neighbor v.
              if (parents[v] == -1 && parlay::atomic_compare_and_swap(&parents[v], &expected, u)) {
                  result = v;
              }
              return result;
          });
      });
    }
  }
  return parents;
}
