```cpp
#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "common/graph.h"
#include "common/speculative_for.h"
#include "common/get_time.h"
#include "matching.h"
#include <atomic> // For std::atomic used within pbbs::reservation

// The reservation struct in speculative_for.h uses a `freeze` method that
// sets the atomic value to -1. For the priority logic (write_min) to work
// correctly with non-negative edge indices, the index type for reservations
// must be signed. We define `s_edgeId` as a signed counterpart to `edgeId`.
using s_edgeId = long;

// Functor for the speculative_for loop, encapsulating the logic for a single edge.
struct MatchStep {
    const edges& E;
    parlay::sequence<pbbs::reservation<s_edgeId>>& R; // Reservations on vertices
    parlay::sequence<bool>& in_M;                      // Flags indicating which edges are in the matching

    MatchStep(const edges& E, parlay::sequence<pbbs::reservation<s_edgeId>>& R, parlay::sequence<bool>& in_M)
        : E(E), R(R), in_M(in_M) {}

    // speculative_for creates copies of the functor; a default copy constructor is sufficient.
    MatchStep(const MatchStep& other) = default;

    // The reserve function is called for each edge `i` in a speculative batch.
    // It returns true to proceed to the commit phase, false to abandon this edge.
    bool reserve(s_edgeId i) {
        auto [u, v] = E[static_cast<size_t>(i)];

        // If either vertex is already permanently matched (frozen), this edge cannot be added.
        // A frozen reservation holds the value -1.
        if (R[u].get() == -1 || R[v].get() == -1) {
            return false;
        }

        // Optimistically try to reserve both endpoints for the current edge `i`.
        // If other edges in the same batch compete for the same vertex, the one with
        // the lowest index will win the reservation due to `write_min`.
        R[u].reserve(i);
        R[v].reserve(i);
        return true;
    }

    // The commit function is called for edges that returned true from `reserve`.
    // It returns true on success (edge added to matching), false on failure (conflict).
    // Failed edges will be retried by speculative_for in a later round.
    bool commit(s_edgeId i) {
        auto [u, v] = E[static_cast<size_t>(i)];

        // Check if this edge `i` successfully won the reservation for both its endpoints.
        if (R[u].check(i) && R[v].check(i)) {
            // Success. Mark the edge as part of the matching.
            in_M[static_cast<size_t>(i)] = true;

            // Freeze the vertices to permanently mark them as matched.
            // This prevents any other edge from claiming them in subsequent rounds.
            R[u].freeze();
            R[v].freeze();
            return true; // Commit successful
        }

        return false; // Commit failed; another edge won one of the vertices.
    }
};

parlay::sequence<edgeId> maximalMatching(edges const &E) {
  size_t n = std::max(E.numCols, E.numRows);
  size_t m = E.nonZeros;

  if (m == 0) return parlay::sequence<edgeId>();

  // A reservation for each vertex.
  // Must use a signed type for `freeze` to work correctly.
  auto R = parlay::sequence<pbbs::reservation<s_edgeId>>(n);

  // A boolean flag for each edge to mark if it's in the matching.
  auto in_M = parlay::sequence<bool>(m, false);

  // Create the stateful functor for the speculative loop.
  MatchStep step(E, R, in_M);

  // Use speculative_for to process all edges in parallel.
  // It handles the complex logic of batching, conflict detection, and retries.
  // The granularity parameter can be tuned for performance. A value of 2048 is
  // a reasonable starting point, balancing parallelism with conflict rates.
  pbbs::speculative_for<s_edgeId, MatchStep>(step, 0, static_cast<s_edgeId>(m), 2048);

  // Filter the original edge indices to get the final matching.
  return parlay::pack_index<edgeId>(in_M);
}
