#define NOTMAIN 1
#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/random.h"
#include "common/graph.h"
#include "common/speculative_for.h"
#include "common/get_time.h"
#include "matching.h"

using reservation = pbbs::reservation<edgeId>;

// The matchStep structure encapsulates the logic for a single step of
// the speculative parallel execution. It defines how to "reserve" resources
// (vertices) for an edge and how to "commit" the edge to the matching if
// the reservations are successful.
struct matchStep {
  edges const &E;
  parlay::sequence<reservation> &R;
  parlay::sequence<bool> &matched;
  const parlay::sequence<edgeId>& P; // A random permutation of edge indices

  matchStep(edges const &E,
	    parlay::sequence<reservation> &R,
	    parlay::sequence<bool> &matched,
        const parlay::sequence<edgeId>& P)
    : E(E), R(R), matched(matched), P(P) {}

  // The reserve function is the first phase of a speculative step.
  // It tries to tentatively claim the endpoints of an edge.
  // 'i' is the index in the permuted sequence of edges.
  bool reserve(edgeId i) {
    edgeId eid = P[i]; // Get the actual edge index from the permutation
    size_t u = E[eid].u;
    size_t v = E[eid].v;

    // An edge cannot be in a matching if its endpoints are already matched
    // or if it's a self-loop. This check filters out such edges early.
    if (matched[u] || matched[v] || (u == v)) return false;

    // Atomically attempt to reserve both vertices for this edge.
    // The reservation stores the edge's index. `write_min` ensures that
    // among competing edges for the same vertex, the one with the smallest
    // index wins. This provides a deterministic tie-breaking rule.
    R[u].reserve(eid);
    R[v].reserve(eid);
    return true; // Proceed to the commit phase if not filtered.
  }

  // The commit function is the second phase. It checks if the reservations
  // from the first phase were successful and finalizes adding the edge to
  // the matching. 'i' is the index in the permuted sequence of edges.
  bool commit(edgeId i) {
    edgeId eid = P[i]; // Get the actual edge index
    size_t u = E[eid].u;
    size_t v = E[eid].v;

    // To be successfully committed, an edge must have won the reservation
    // race for BOTH of its endpoints. `R.check(eid)` verifies this.
    if (R[u].check(eid) && R[v].check(eid)) {
      // If reservations are secured, mark the vertices as matched.
      // This is safe without atomics because `speculative_for` works in
      // rounds, and no other thread in the same commit phase can have
      // won the reservations for u or v. Updates will be visible in
      // subsequent rounds' reserve phases.
	  matched[u] = true;
      matched[v] = true;
	  return true; // Commit successful
    }
    return false; // Commit failed
  }
};

parlay::sequence<edgeId> maximalMatching(edges const &E) {
  size_t n = max(E.numCols, E.numRows);
  size_t m = E.nonZeros;
  timer t("max matching", true);

  // Using a random permutation of edges is a key strategy for high performance
  // in parallel graph algorithms. It helps break symmetries and greatly reduces 
  // contention, leading to fewer retries in the speculative execution.
  // We use a fixed seed for deterministic output, which is good for benchmarking.
  auto P = parlay::random_permutation<edgeId>(m, 12345);
  t.next("permutation");

  // R is a sequence of reservation objects, one for each vertex. It is used
  // to manage conflicts between edges competing for the same vertex.
  parlay::sequence<reservation> R(n);

  // matched[i] is a flag indicating whether vertex i has been included in the
  // matching. It provides a fast path to discard edges incident to already
  // matched vertices in the reserve step.
  parlay::sequence<bool> matched(n, false);

  matchStep mStep(E, R, matched, P);
  t.next("init");

  // pbbs::speculative_for implements a general-purpose framework for parallel
  // speculative execution. It iterates through the edges (via the permuted
  // indices 0 to m-1), trying to add them to the matching. Edges that fail
  // due to conflicts are automatically retried in later rounds.
  // The granularity parameter is tunable; 20 is a reasonable default.
  pbbs::speculative_for<edgeId>(mStep, 0, m, 20, false);
  t.next("speculative for");

  // After the speculative execution, the R array holds the IDs of the edges
  // that are part of the matching. We must collect these IDs into the final
  // result sequence. To avoid duplicates (since an edge is stored for both 
  // its endpoints), we pack the edge ID only if the current vertex `i` is the 
  // `u` endpoint of the edge. This is an efficient, standard technique for 
  // collecting edges uniquely in parallel.
  auto matchingIdx = parlay::pack(
    parlay::delayed_seq<edgeId>(n, [&](size_t i) { return R[i].get(); }),
    parlay::tabulate(n, [&](size_t i) -> bool {
        if (!R[i].reserved()) return false;
        edgeId eid = R[i].get();
        // Condition to add edge only once, using one of its endpoints
        // as the canonical source.
        return E[eid].u == i;
    })
  );

  t.next("pack results");
  std::cout << "number of matches = " << matchingIdx.size() << std::endl;
  return matchingIdx;
}
