```cpp
#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/random.h" // For parlay::random_permutation
#include "common/graph.h"
#include "common/speculative_for.h"
#include "common/get_time.h"
#include "matching.h"

// The reservation object from speculative_for.h
using reservation = pbbs::reservation<edgeId>;

// The step struct for the speculative_for loop.
// It encapsulates the logic for reserving and committing edges.
struct matchStep {
  const edges& E;
  const parlay::sequence<edgeId>& P; // A random permutation of edge indices
  parlay::sequence<reservation>& R;
  parlay::sequence<bool>& matched;

  matchStep(const edges& E, const parlay::sequence<edgeId>& P,
            parlay::sequence<reservation>& R,
            parlay::sequence<bool>& matched)
      : E(E), P(P), R(R), matched(matched) {}

  // The reserve function is called in the first phase of speculative_for.
  // It tries to reserve the two endpoints of an edge.
  // k is an index into the random permutation P.
  bool reserve(edgeId k) {
    edgeId i = P[k]; // Get the actual edge index.
    vertexId u = E[i].u;
    vertexId v = E[i].v;

    // An edge cannot be in the matching if its endpoints are already matched,
    // or if it's a self-loop.
    // This check on `matched` prunes the graph of matched vertices.
    if (matched[u] || matched[v] || u == v) {
      return false; // Fail reservation, do not retry this edge.
    }

    // Attempt to reserve both endpoints using an atomic write_min.
    // This resolves conflicts: if multiple edges want to reserve the same
    // vertex, only the one with the smallest edge index will win.
    R[u].reserve(i);
    R[v].reserve(i);
    return true; // Reservation placed, proceed to commit phase.
  }

  // The commit function is called for edges that succeeded in the reserve phase.
  // It checks if the reservations were successful (i.e., we won the race for both endpoints).
  bool commit(edgeId k) {
    edgeId i = P[k]; // Get the actual edge index.
    vertexId u = E[i].u;
    vertexId v = E[i].v;

    // This asymmetric check is a key part of the baseline's correctness.
    // It checks v first. If it won the reservation on v, it tentatively
    // resets it and then checks u.
    if (R[v].check(i)) {
      R[v].reset();
      if (R[u].check(i)) {
        // Won reservations for both u and v. The edge is added to the matching.
        matched[u] = true;
        matched[v] = true;
        // The reservation for u is kept. This is used to reconstruct the
        // matching at the end. The reservation for v is already reset.
        // This asymmetry ensures that each matched edge is recorded only once.
        return true; // Commit successful, edge is in the matching.
      }
    } else if (R[u].check(i)) {
      // Won reservation on u, but not on v. Must release the reservation on u.
      R[u].reset();
    }
    return false; // Commit failed, edge is not in the matching this round and should be retried.
  }
};

parlay::sequence<edgeId> maximalMatching(edges const &E) {
  size_t n = std::max(E.numCols, E.numRows);
  size_t m = E.nonZeros;
  if (m == 0) return parlay::sequence<edgeId>();

  // Using a random permutation of edges is a standard, powerful technique to
  // improve performance and avoid worst-case scenarios for reservation-based
  // algorithms. It helps break symmetries and reduce contention on high-degree
  // vertices, leading to fewer retries in speculative_for and faster convergence.
  auto P = parlay::random_permutation<edgeId>(m, parlay::random(0));

  // R is the reservation array for vertices.
  parlay::sequence<reservation> R(n);
  // matched[i] is true if vertex i is already part of the matching.
  // This is read in reserve and written in commit. The speculative_for
  // execution model ensures that these accesses are safe without atomics.
  parlay::sequence<bool> matched(n, false);

  matchStep mStep(E, P, R, matched);

  // pbbs::speculative_for processes the edges in parallel rounds.
  // In each round, it attempts to reserve and then commit a batch of edges.
  // Edges that fail due to conflicts are automatically retried in later rounds.
  // `hasState=false` means the mStep object is shared among threads, which is efficient.
  pbbs::speculative_for<edgeId>(mStep, 0, m, 10, false);

  // Reconstruct the matching from the reservation array.
  // An edge (u,v) with index i is in the matching if R[u] or R[v] contains i.
  // The clever asymmetric commit logic ensures that only one of them will hold
  // the reservation post-commit. This prevents duplicate edges in the output.
  parlay::sequence<edgeId> matchingIdx =
    parlay::pack(parlay::delayed_seq<edgeId>(n, [&](size_t i) { return R[i].get(); }),
                 parlay::tabulate(n, [&](size_t i) -> bool { return R[i].reserved(); }));

  return matchingIdx;
}
