#include "common/get_time.h"
#include "matching.h"
using namespace std;

using reservation = pbbs::reservation<edgeId>;

struct matchStep {
  const edges& E;
  parlay::sequence<reservation>& R;
  parlay::sequence<bool>& matched;
  const parlay::sequence<edgeId>& p; // Permutation of edge indices

  matchStep(const edges& E,
            parlay::sequence<reservation>& R,
            parlay::sequence<bool>& matched,
            const parlay::sequence<edgeId>& p)
    : E(E), R(R), matched(matched), p(p) {}

  // i is the loop index from 0 to m-1
  bool reserve(edgeId i) {
    edgeId eid = p[i]; // Get the actual edge index from the permutation
    auto [u, v] = E[eid];

    // Self-loops cannot be in a matching.
    if (u == v) return false;

    // If either endpoint is already matched, this edge cannot be added.
    // Reading non-atomic `matched` is safe due to the structure of
    // speculative_for (all reserves in a batch happen before all commits).
    if (matched[u] || matched[v]) {
        return false;
    }

    // Try to reserve both endpoints for this edge.
    // The edge with the smallest ID will win the reservation.
    R[u].reserve(eid);
    R[v].reserve(eid);
    return true;
  }

  // i is the loop index from 0 to m-1
  bool commit(edgeId i) {
    edgeId eid = p[i]; // Get the actual edge index
    auto [u, v] = E[eid];

    // Asymmetric check to ensure each matched edge is recorded only once.
    // Check if this edge won the reservation for v.
    if (R[v].check(eid)) {
      // It did. Tentatively reset v's reservation.
      R[v].reset();
      // Now check if it also won the reservation for u.
      if (R[u].check(eid)) {
        // It won both. This edge is now in the matching.
        matched[u] = true;
        matched[v] = true;
        // Keep R[u] reserved with eid for collection, but R[v] is now free.
        return true; // Return true for success (i.e., don't retry this edge).
      }
    } else if (R[u].check(eid)) {
        // This edge won u but lost v to a higher-priority edge.
        // Reset u's reservation so it can be matched by another edge.
        R[u].reset();
    }
    return false; // Return false for failure (i.e., this edge is not in the matching for this round).
  }
};

parlay::sequence<edgeId> maximalMatching(edges const &E) {
  size_t n = std::max(E.numCols, E.numRows);
  size_t m = E.nonZeros;
  if (m == 0) return parlay::sequence<edgeId>();

  // Process edges in a random order to improve performance by reducing
  // contention and avoiding worst-case scenarios on structured graphs.
  auto p = parlay::random_permutation(m, parlay::random());

  // R[i] stores the ID of the edge that has reserved vertex i.
  parlay::sequence<reservation> R(n);
  // matched[i] is true if vertex i is part of the final matching.
  parlay::sequence<bool> matched(n, false);

  matchStep mStep(E, R, matched, p);

  // Use speculative_for to process edges in parallel batches, retrying conflicts.
  // The 5th argument `false` sets hasState=false, a small optimization as
  // matchStep has no per-thread state.
  // Granularity is tuned to 100 (from baseline's 10) to use smaller
  // initial batches, which can help reduce contention.
  pbbs::speculative_for<edgeId>(mStep, 0, m, 100, false);

  // Collect the results.
  // Based on the asymmetric commit logic, a matched edge (u,v) with ID 'eid'
  // will result in R[u] holding 'eid' and R[v] being reset.
  // Therefore, we can iterate over all vertices and collect the edge IDs
  // from the reservations that are still held.
  auto is_reserved_by_u = parlay::tabulate(n, [&](size_t i) -> bool {
      edgeId eid = R[i].get();
      // Check if reservation is valid and this vertex `i` is the .u endpoint.
      // This makes the collection robust and correctly interprets the commit logic.
      return (eid < m) && (E[eid].u == i);
  });

  parlay::sequence<edgeId> matchingIdx =
    parlay::pack(parlay::delayed_seq<edgeId>(n, [&](size_t i) { return R[i].get(); }),
                 is_reserved_by_u);

  return matchingIdx;
}
