using namespace std;

// This implementation uses a parallel Luby's algorithm, a classic randomized 
// approach for Maximal Independent Set. The algorithm is significantly more 
// scalable than the provided baseline, which relies on fine-grained locking 
// and can suffer from high contention and spinning.
//
// The algorithm proceeds in bulk-synchronous rounds:
// 1. Assign a random priority to each undecided vertex.
// 2. A vertex joins the MIS if it has a higher priority than all its undecided neighbors.
//    Ties are broken by vertex ID to ensure determinism within a round and prevent livelock.
// 3. Vertices that join the MIS, and all their neighbors, are marked as decided and
//    removed from consideration for the next round.
// 4. Repeat until all vertices are decided.
//
// This round-based approach avoids fine-grained locks, replacing them with parallel
// loops over the set of active vertices (the "frontier"). This leads to better
// cache performance, less contention, and better scalability on multi-core processors.
// The number of rounds is expected to be O(log n).
parlay::sequence<char> maximalIndependentSet(const Graph &G) {
  size_t n = G.n;
  if (n == 0) {
    return parlay::sequence<char>();
  }

  // Flags: 0 = undecided, 1 = in MIS, 2 = not in MIS (neighbor of an MIS node)
  // We use std::atomic for thread-safe updates. Relaxed memory order is sufficient
  // due to the bulk-synchronous nature of the algorithm (synchronization happens
  // between rounds, not within a parallel loop).
  auto flags = parlay::sequence<std::atomic<char>>(n);
  parlay::parallel_for(0, n, [&](size_t i) {
    flags[i].store(0, std::memory_order_relaxed);
  });

  // active_nodes represents the set of undecided vertices (the "frontier").
  // Processing only the active nodes is much more efficient than iterating over
  // all n vertices in every round, especially as the frontier shrinks.
  parlay::sequence<vertexId> active_nodes = parlay::tabulate(n, [](size_t i) { return static_cast<vertexId>(i); });

  auto priorities = parlay::sequence<uint64_t>(n);
  parlay::random_generator rand_gen;
  size_t round = 0;

  while (!active_nodes.empty()) {
    round++;

    // Step 1: Assign random priorities to all active nodes.
    parlay::parallel_for(0, active_nodes.size(), [&](size_t i) {
      vertexId u = active_nodes[i];
      // Each thread gets its own random number generator from the pool.
      // Seeding with the round number ensures different priorities in each round.
      auto r = rand_gen[i];
      priorities[u] = r.ith_rand(round);
    });

    // Step 2: Identify nodes to be added to the MIS in this round.
    // An active node `u` is chosen if its priority is higher than all its active neighbors.
    // Tie-breaking using vertex IDs ensures that for any edge, at most one endpoint can be chosen.
    auto to_add_indicators = parlay::sequence<bool>(active_nodes.size());
    parlay::parallel_for(0, active_nodes.size(), [&](size_t i) {
      vertexId u = active_nodes[i];
      uint64_t u_p = priorities[u];
      bool is_max = true;
      for (size_t j = 0; j < G[u].degree; j++) {
        vertexId v = G[u].Neighbors[j];
        // Only compare with neighbors that are also active (undecided).
        if (flags[v].load(std::memory_order_relaxed) == 0) {
          uint64_t v_p = priorities[v];
          if (v_p > u_p || (v_p == u_p && v > u)) {
            is_max = false;
            break;
          }
        }
      }
      to_add_indicators[i] = is_max;
    });

    auto new_mis_nodes = parlay::pack(active_nodes, to_add_indicators);

    // Step 3: Update flags based on the new MIS nodes.
    // This loop is parallelized over the nodes just added to the MIS.
    // For graphs with skewed degrees, a flatter parallelization over all edges
    // might be better, but this approach has less overhead and better locality.
    parlay::parallel_for(0, new_mis_nodes.size(), [&](size_t i) {
      vertexId u = new_mis_nodes[i];

      // Mark u as in the MIS. This is race-free because the logic in Step 2 ensures
      // no two adjacent vertices are in new_mis_nodes.
      flags[u].store(1, std::memory_order_relaxed);

      // Mark u's neighbors as not in the MIS.
      for (size_t j = 0; j < G[u].degree; j++) {
        vertexId v = G[u].Neighbors[j];
        // Use compare-and-swap to safely update undecided neighbors.
        // This handles the benign race where multiple new MIS nodes share a neighbor.
        char expected = 0; // The neighbor must be undecided.
        flags[v].compare_exchange_strong(expected, 2, std::memory_order_relaxed, std::memory_order_relaxed);
      }
    });

    // Step 4: Generate the next frontier of active nodes by filtering out
    // nodes that have been decided in this round.
    active_nodes = parlay::filter(active_nodes, [&](vertexId v) {
      return flags[v].load(std::memory_order_relaxed) == 0;
    });
  }

  // Convert the atomic char flags to a plain char sequence for the return value,
  // as required by the function signature.
  return parlay::tabulate(n, [&](size_t i) {
    return flags[i].load(std::memory_order_relaxed);
  });
}
