#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/random.h"
#include "common/graph.h"
#include "common/atomics.h"
#include "MIS.h"

// This implementation is a parallel greedy algorithm based on priorities,
// commonly known as Luby's algorithm. It operates in rounds and is significantly
// more scalable than the baseline's fine-grained locking approach, which can
// suffer from high contention and livelock on challenging graph structures.
//
// The algorithm works as follows:
// 1. Assign a random priority to each vertex.
// 2. In each round, consider the set of "active" (undecided) vertices.
// 3. A vertex is chosen to be in the MIS if it has a higher priority than all
//    of its active neighbors. Ties are broken by vertex ID.
// 4. All vertices chosen in a round are added to the MIS. They and their
//    neighbors are removed from the active set for the next round.
// 5. Repeat until the active set is empty.
//
// This round-based approach avoids the race conditions and retries of the
// baseline, leading to more predictable and generally superior performance.
parlay::sequence<char> maximalIndependentSet(const Graph &G) {
  size_t n = G.n;

  // flags: 0 = undecided, 1 = in MIS, 2 = not in MIS (neighbor of MIS vertex)
  auto flags = parlay::sequence<char>::uninitialized(n);
  parlay::parallel_for(0, n, [&] (size_t i) { flags[i] = 0; });

  // Assign a random priority to each vertex to break symmetries.
  // Using parlay::random provides good quality random numbers to avoid
  // pathological cases and improve convergence speed.
  parlay::random_generator gen;
  auto priorities = parlay::tabulate(n, [&](size_t i) {
    auto r = gen[i];
    return parlay::hash64(r);
  });

  // The set of vertices that are still undecided.
  auto active_vertices = parlay::iota<vertexId>(n);

  while (active_vertices.size() > 0) {
    // 1. Identify local maxima: In parallel, each active vertex checks if it has a
    //    higher priority than all its active neighbors.
    auto is_max = parlay::sequence<bool>::uninitialized(active_vertices.size());
    parlay::parallel_for(0, active_vertices.size(), [&](size_t i) {
      vertexId u = active_vertices[i];
      auto u_neighbors = G[u];
      bool max_so_far = true;
      for (size_t j = 0; j < u_neighbors.degree; j++) {
        vertexId v = u_neighbors.Neighbors[j];

        // Only compare with neighbors that are also still active (undecided).
        if (flags[v] == 0) {
          if (priorities[v] > priorities[u] || (priorities[v] == priorities[u] && v > u)) {
            max_so_far = false;
            break;
          }
        }
      }
      is_max[i] = max_so_far;
    });

    // 2. Pack the vertices that will be added to the MIS in this round.
    auto to_add = parlay::pack(active_vertices, is_max);

    // 3. Update flags for the newly added MIS vertices and their neighbors.
    // First, mark the vertices in `to_add` as being in the MIS.
    parlay::parallel_for(0, to_add.size(), [&](size_t i) {
      // Since two vertices in `to_add` cannot be neighbors (by construction),
      // there are no race conditions on writing `flags[u] = 1`.
      flags[to_add[i]] = 1;
    });

    // Second, mark the neighbors of these new MIS vertices as out of the MIS.
    parlay::parallel_for(0, to_add.size(), [&](size_t i) {
      vertexId u = to_add[i];
      auto u_neighbors = G[u];
      for (size_t j = 0; j < u_neighbors.degree; j++) {
        vertexId v = u_neighbors.Neighbors[j];
        // Use an atomic CAS to mark a neighbor. This correctly handles the
        // case where a vertex `v` is a neighbor of multiple vertices being
        // added to the MIS in the same round. We only want to change its
        // state if it's currently undecided (0 -> 2).
        pbbs::atomic_compare_and_swap(&flags[v], (char)0, (char)2);
      }
    });

    // 4. Update the active set for the next round by removing all vertices
    //    that are no longer undecided.
    active_vertices = parlay::filter(active_vertices, [&](const vertexId u) {
      return flags[u] == 0;
    });
  }

  return flags;
}
