// --- Start of file: MIS.C ---
#include <iostream>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/random.h"
#include "common/graph.h"
#include "common/atomics.h"
#include "MIS.h"

// **************************************************************
//    MAXIMAL INDEPENDENT SET
// **************************************************************

// An efficient parallel MIS algorithm based on an asynchronous greedy approach
// with random priorities. This approach avoids the high contention of the baseline
// and the synchronization overhead of round-based (e.g., Luby's) algorithms.
//
// Algorithm:
// 1. Assign a unique random priority to each vertex.
// 2. In parallel, each vertex `u` attempts to join the MIS.
// 3. A vertex `u` spins until its state is decided (either in MIS or not).
// 4. In its spin loop, `u` checks its neighbors `v`:
//    - If any neighbor `v` is already in the MIS (`flags[v] == 1`), `u` cannot be.
//      It marks itself as not in the MIS (`flags[u] = 2`) and is done.
//    - If it finds an undecided neighbor `v` with a higher priority, `u` must wait.
//      It continues to spin.
// 5. If `u` has checked all its neighbors and found none in the MIS and no
//    undecided neighbor with a higher priority, it considers itself a local
//    maximum and attempts to join the MIS by atomically swapping its flag
//    from 0 (undecided) to 1 (in MIS).
// 6. If the atomic swap succeeds, `u` is officially in the MIS. It then marks
//    all its undecided neighbors as not in MIS (`flags[v] = 2`) and is done.
// 7. If the atomic swap fails, it means a neighbor just joined the MIS and
//    marked `u` as not in MIS. The spin loop condition will then terminate.
//
// This algorithm ensures progress because priorities create a directed acyclic
// graph among undecided vertices, guaranteeing that at least one vertex can
// always make a decision. The use of random priorities provides good load
// balancing in practice.

parlay::sequence<char> maximalIndependentSet(const Graph &G) {
  size_t n = G.n;
  // flags: 0 = undecided, 1 = in MIS, 2 = not in MIS
  parlay::sequence<char> flags(n, (char)0);

  // 1. Assign unique random priorities to all vertices.
  parlay::sequence<uint64_t> priorities(n);
  parlay::random_generator<std::mt19937_64> rand_gen;
  parlay::parallel_for(0, n, [&](size_t i) {
    auto& R = rand_gen[parlay::worker_id()];
    // Combine a random number with the vertex ID to ensure uniqueness.
    priorities[i] = (R() << 32) | i;
  });

  // 2. Each thread processes a vertex until its status is decided.
  parlay::parallel_for(0, n, [&](size_t i) {
    vertexId u = i;

    // Spin until u is decided.
    while (flags[u] == 0) {
      bool is_local_max = true;
      auto u_neighbors = G[u];

      // 4. Check all neighbors.
      for (size_t j = 0; j < u_neighbors.degree; j++) {
        vertexId v = u_neighbors.Neighbors[j];

        // Reading flags[v] without a lock is fine. If it changes while we
        // are checking, our subsequent CAS on flags[u] will fail correctly,
        // preventing any race that would violate correctness.
        char v_flag = flags[v];

        if (v_flag == 1) {
          // A neighbor is already in the MIS, so u cannot be.
          // Mark u as not in MIS and terminate.
          pbbs::atomic_compare_and_swap(&flags[u], (char)0, (char)2);
          return;
        }

        // If neighbor v is undecided and has higher priority, u must wait.
        if (v_flag == 0 && priorities[v] > priorities[u]) {
          is_local_max = false;
          break; // Stop checking neighbors and spin again.
        }
      }

      if (is_local_max) {
        // 5. u is a local maximum. Attempt to join the MIS.
        if (pbbs::atomic_compare_and_swap(&flags[u], (char)0, (char)1)) {
          // 6. Success! u is in the MIS. Mark neighbors and terminate.
          for (size_t j = 0; j < u_neighbors.degree; j++) {
            vertexId v = u_neighbors.Neighbors[j];
            // Atomically mark undecided neighbors as not in MIS.
            // This handles races where multiple new MIS members are
            // neighbors of the same vertex v.
            if (flags[v] == 0) {
                pbbs::atomic_compare_and_swap(&flags[v], (char)0, (char)2);
            }
          }
          return;
        }
        // 7. CAS failed. This means flags[u] was just changed by another
        // thread (e.g., set to 2 by a neighbor that won). The while-loop
        // condition will detect this and terminate the loop.
      }
    }
  });

  return flags;
}
