parlay::sequence<char> maximalIndependentSet(Graph const &G)
{
  size_t n = G.n;
  parlay::sequence<char> Flags(n, (char) 0);
  for (size_t i = 0; i < n; i++) {
    Flags[i] = 1;
    for (size_t j = 0; j< G[i].degree; j++) {
