#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/hash.h"
#include "common/graph.h"
#include "MIS.h"

// **************************************************************
//    MAXIMAL INDEPENDENT SET
// **************************************************************

// This implementation uses a parallel randomized algorithm (related to Luby's algorithm).
// In each round, it selects a set of vertices to add to the MIS based on random priorities.
// 1. Each undecided vertex is assigned a random priority.
// 2. A vertex is added to the MIS if it has a higher priority than all its undecided neighbors.
//    These vertices are called "winners". By construction, the set of winners is an independent set.
// 3. The winners are added to the MIS, and their neighbors are marked as not in the MIS.
// 4. The process repeats with the remaining undecided vertices until none are left.
// This algorithm is efficient in parallel, with an expected polylogarithmic number of rounds.
parlay::sequence<char> maximalIndependentSet(Graph const &G) {
  size_t n = G.n;
  if (n == 0) {
    return parlay::sequence<char>();
  }

  // State: 0 = undecided, 1 = in MIS, 2 = not in MIS
  auto flags = parlay::sequence<char>(n, (char)0);

  // Assign a random priority to each vertex.
  // A deterministic hash is a standard and effective technique for reproducibility and performance.
  auto priorities = parlay::tabulate(n, [&](size_t i) {
    return parlay::hash64(i);
  });

  auto active_vertices = parlay::iota<vertexId>(n);
  size_t num_active = n;

  while (num_active > 0) {
    // In each round, a vertex is a "winner" if its priority is greater
    // than all of its currently active neighbors.
    auto winners = parlay::filter(active_vertices, [&](vertexId v) {
      auto v_neighbors = G[v];
      for (edgeId i = 0; i < v_neighbors.degree; i++) {
        vertexId u = v_neighbors.Neighbors[i];
        // Consider only active neighbors (flags[u] == 0).
        if (flags[u] == 0) {
          // If neighbor u has higher priority, v cannot be a winner.
          // Break ties using vertex ID to ensure determinism and progress.
          if (priorities[u] > priorities[v] ||
              (priorities[u] == priorities[v] && u < v)) {
            return false;
          }
        }
      }
      return true;
    });

    // Add winners to the MIS. This can be done in parallel since winners
    // form an independent set by definition.
    parlay::parallel_for(0, winners.size(), [&](size_t i) {
      flags[winners[i]] = 1;
    });

    // Mark all neighbors of winners as removed from consideration.
    // First, create a flat list of all neighbors for better load balancing.
    auto neighbors_to_remove = parlay::flatten(parlay::map(winners, [&](vertexId v) {
        return parlay::make_slice(G[v].Neighbors, G[v].Neighbors + G[v].degree);
    }));

    // In parallel, mark the neighbors. This may have write-write conflicts if two winners
    // share a neighbor. The race is benign since both threads would write '2'.
    parlay::parallel_for(0, neighbors_to_remove.size(), [&](size_t i) {
        vertexId u = neighbors_to_remove[i];
        // Only update if the neighbor is currently undecided.
        // A simple write is sufficient due to the benign race.
        if (flags[u] == 0) {
            flags[u] = 2;
        }
    });

    // The new set of active vertices are those that are still undecided.
    // This pack operation is a standard way to manage the active set.
    active_vertices = parlay::filter(active_vertices, [&](vertexId v) {
      return flags[v] == 0;
    });
    num_active = active_vertices.size();
  }

  return flags;
}
