```cpp
#include <iostream>
#include "parlay/primitives.h"
#include "parlay/random.h"
#include "parlay/sequence.h"
#include "parlay/parallel.h"
#include "parlay/atomics.h"

#include "common/graph.h"
#include "MIS.h"

// **************************************************************
//    MAXIMAL INDEPENDENT SET
// **************************************************************

// A parallel randomized algorithm for Maximal Independent Set (MIS).
// The algorithm is based on Luby's algorithm. It proceeds in rounds.
// In each round:
// 1. Assign a random priority to each active vertex.
// 2. A vertex is added to the independent set if it has a higher
//    priority than all of its active neighbors.
// 3. Vertices added to the set and all their neighbors are removed
//    from the graph (marked as inactive).
// 4. Repeat until no vertices remain.
// This implementation uses an explicit list of active vertices to
// improve performance in later rounds when the graph becomes sparse.
parlay::sequence<char> maximalIndependentSet(Graph const &G) {
  size_t n = G.n;
  if (n == 0) {
    return parlay::sequence<char>();
  }

  // Flags for each vertex:
  // 0: undecided (active)
  // 1: in the MIS
  // 2: not in the MIS (neighbor of a vertex in the MIS)
  auto flags = parlay::sequence<char>(n, (char)0);

  // Sequence of currently active vertex indices.
  auto active_vertices = parlay::iota<vertexId>(n);

  auto priorities = parlay::sequence<uint64_t>(n);
  parlay::random r;

  while (!active_vertices.empty()) {
    // 1. Assign random, unique priorities to all active vertices.
    // The vertex ID is included in the lower bits to break ties and ensure uniqueness.
    parlay::parallel_for(0, active_vertices.size(), [&](size_t i) {
      vertexId u = active_vertices[i];
      priorities[u] = (static_cast<uint64_t>(r.ith_rand(u)) << 32) | u;
    });

    // 2. Select vertices that are local maxima with respect to priorities.
    // These vertices form an independent set, S.
    auto is_in_S = parlay::sequence<bool>(active_vertices.size());
    parlay::parallel_for(0, active_vertices.size(), [&](size_t i) {
      vertexId u = active_vertices[i];
      auto u_vtx = G[u];
      bool is_max = true;
      for (size_t j = 0; j < u_vtx.degree; j++) {
        vertexId v_id = u_vtx.Neighbors[j];
        // Only compare with neighbors that are also active.
        if (flags[v_id] == 0 && priorities[v_id] > priorities[u]) {
          is_max = false;
          break;
        }
      }
      is_in_S[i] = is_max;
    });

    // Pack the vertex indices of the selected vertices into a new sequence S.
    auto S = parlay::pack(active_vertices, is_in_S);

    // Safeguard: if no vertex is selected, which is theoretically impossible with unique
    // priorities, select the first active vertex to ensure progress.
    if (S.empty() && !active_vertices.empty()) {
        S.push_back(active_vertices[0]);
    }

    // 3. Update flags: add vertices in S to the MIS and remove their neighbors.
    // This is done in a single parallel loop for better locality.
    parlay::parallel_for(S, [&](vertexId u) {
      // Add u to the MIS. This write is safe because only one thread can
      // be responsible for a given u in S.
      flags[u] = 1;

      // Mark neighbors of u as removed.
      auto u_vtx = G[u];
      for (size_t j = 0; j < u_vtx.degree; j++) {
        vertexId v_id = u_vtx.Neighbors[j];
        char expected = 0;
        // Atomically set the flag to 2 if it is currently 0.
        // This is safe from race conditions where multiple vertices in S
        // share a neighbor. It also avoids overwriting a flag of 1.
        parlay::atomic_compare_swap(&flags[v_id], expected, (char)2);
      }
    });

    // 4. Create the active set for the next round by filtering out
    // vertices that are no longer undecided.
    active_vertices = parlay::filter(active_vertices, [&](vertexId u) {
      return flags[u] == 0;
    });
  }

  return flags;
}
