### `k_nearest_neighbors.h`
This header contains the high-performance implementation of the parallel octree and the k-NN search logic.

```cpp
#pragma once

#include <algorithm>
#include <vector>
#include <memory>
#include <limits>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/slice.h"
#include "parlay/type_allocator.h"
#include "common/geometry.h"

// *************************************************************
//    A Bounded Priority Queue to store the K best neighbors
// *************************************************************
// Implemented as a max-heap of size at most K.
template<typename Vtx, int max_k>
struct KBest {
  int k;
  int count = 0;
  // Heap property: distances[0] is the largest distance
  std::pair<Vtx*, double> heap[max_k];

  KBest(int k_val) : k(k_val) {}

  // returns squared distance to k-th neighbor
  double worst_dist() const {
    return (count < k) ? std::numeric_limits<double>::max() : heap[0].second;
  }

  bool full() const { return count == k; }

  void sift_down(int i) {
    int left = 2 * i + 1;
    int right = 2 * i + 2;
    int largest = i;
    if (left < count && heap[left].second > heap[largest].second) {
      largest = left;
    }
    if (right < count && heap[right].second > heap[largest].second) {
      largest = right;
    }
    if (largest != i) {
      std::swap(heap[i], heap[largest]);
      sift_down(largest);
    }
  }

  void insert(Vtx* neighbor, double dist_sq) {
    if (count < k) {
      heap[count] = {neighbor, dist_sq};
      count++;
      if (count == k) {
        // build a max-heap for the k elements
        for (int i = k / 2 - 1; i >= 0; i--)
          sift_down(i);
      }
    } else if (dist_sq < heap[0].second) {
      // If better than the worst, replace and sift down
      heap[0] = {neighbor, dist_sq};
      sift_down(0);
    }
  }

  // fills the ngh array of the vertex
  void get_neighbors(Vtx* v) {
    // The problem description does not require sorted output.
    for (int i = 0; i < count; i++) {
      v->ngh[i] = heap[i].first;
    }
  }
};

// *************************************************************
//    The Octree Node and The Main KNN Class
// *************************************************************

template <class Vtx, int max_k>
class k_nearest_neighbors {
public:
  using vtx = Vtx;
  using point = typename vtx::point_type;
  using box = std::pair<point, point>;
  static constexpr int dim = point::dim;

  // *************************************************************
  //    Octree Node Structure
  // *************************************************************
  struct node {
    point center;
    double size; // half side-length of the bounding box
    node* parent;
    std::array<node*, 1 << dim> children;
    parlay::slice<vtx*> vertices;

    node(point c, double s, node* p, parlay::slice<vtx*> v)
        : center(c), size(s), parent(p), vertices(v) {
      for (int i = 0; i < (1 << dim); i++) children[i] = nullptr;
    }

    bool is_leaf() const { return children[0] == nullptr; }

    size_t depth() const {
      if (is_leaf()) return 1;
      size_t max_d = 0;
      for (auto child : children) {
        if (child) max_d = std::max(max_d, child->depth());
      }
      return 1 + max_d;
    }

    // Parallel map function to apply a function F to all vertices in the tree
    template <typename F>
    void map(F& f) {
      if (is_leaf()) {
        // At leaves, apply the function to all points in parallel
        parlay::parallel_for(0, vertices.size(),
                             [&](size_t i) { f(vertices[i], this); });
      } else {
        // At internal nodes, recurse on children in parallel
        parlay::parallel_for(0, 1 << dim, [&](int i) {
          if (children[i] != nullptr) {
            children[i]->map(f);
          }
        });
      }
    }
  };

private:
  node* root;
  parlay::sequence<vtx*> p_vertices; // pointers to original vertices
  parlay::type_allocator<node> node_allocator;

  static constexpr size_t LEAF_SIZE = 32; // Threshold to stop recursion

  // *************************************************************
  //    Parallel Octree Build
  // *************************************************************
  node* build_tree(parlay::slice<vtx**> P, box B, node* parent) {
    if (P.size() == 0) return nullptr;

    point center = B.first + (B.second - B.first) / 2.0;
    double size = (B.second - B.first).maxDim() / 2.0;
    node* N = node_allocator.alloc(center, size, parent, parlay::slice<vtx*>(P.begin(), P.size()));

    if (P.size() <= LEAF_SIZE) {
      return N;
    }

    // Partition points into 2^dim children groups based on their quadrant
    auto groups = parlay::group_by_key(P, [&](vtx** p) {
      return (*p)->pt.quadrant(center);
    });

    // Recurse on the children in parallel
    parlay::parallel_for(0, groups.size(), [&](size_t i) {
      auto [quadrant, points] = groups[i];
      box child_box;
      for (int d = 0; d < dim; d++) {
        if ((quadrant >> d) & 1) {
          child_box.first[d] = center[d];
          child_box.second[d] = B.second[d];
        } else {
          child_box.first[d] = B.first[d];
          child_box.second[d] = center[d];
        }
      }
      N->children[quadrant] = build_tree(points, child_box, N);
    });

    return N;
  }

  // *************************************************************
  //    Distance and Search Helpers
  // *************************************************************

  // Squared distance from a point to a node's bounding box
  double box_dist_sq(const point& p, const node* n) const {
    double dist_sq = 0.0;
    for (int i = 0; i < dim; ++i) {
      double di;
      double c = n->center[i];
      double s = n->size;
      if (p[i] < c - s) di = p[i] - (c - s);
      else if (p[i] > c + s) di = p[i] - (c + s);
      else di = 0.0;
      dist_sq += di * di;
    }
    return dist_sq;
  }

  // Top-down search within a subtree, used for promising branches
  void search_subtree(vtx* q, node* n, KBest<vtx, max_k>& k_best) {
    if (report_stats) q->counter++;
    if (n->is_leaf()) {
      for (auto p : n->vertices) {
        double d_sq = (q->pt - p->pt).sqLength();
        k_best.insert(p, d_sq);
      }
      return;
    }

    // Best-Bin-First heuristic: visit children ordered by distance
    std::pair<double, node*> child_dists[1 << dim];
    int num_children = 0;
    for (int i = 0; i < (1 << dim); ++i) {
      if (n->children[i] != nullptr) {
        child_dists[num_children++] = {box_dist_sq(q->pt, n->children[i]), n->children[i]};
      }
    }
    std::sort(child_dists, child_dists + num_children);

    for (int i = 0; i < num_children; ++i) {
      // Pruning: only visit subtrees that can contain a better neighbor
      if (child_dists[i].first < k_best.worst_dist()) {
        search_subtree(q, child_dists[i].second, k_best);
      }
    }
  }

public:
  k_nearest_neighbors(parlay::sequence<vtx*>& v, box B) {
    // Create a mutable sequence of pointers to pointers to reorder during the build
    parlay::sequence<vtx**> P(v.size());
    parlay::parallel_for(0, v.size(), [&](size_t i) { P[i] = &v[i]; });
    root = build_tree(parlay::make_slice(P), B, nullptr);

    // The original pointers in v have been reordered in place for locality
    p_vertices = parlay::sequence<vtx*>(v.size());
    parlay::parallel_for(0, v.size(), [&](size_t i) { p_vertices[i] = *P[i]; });
  }

  ~k_nearest_neighbors() {
    node_allocator.clear();
  }

  node* get_root() { return root; }
  parlay::sequence<vtx*>& vertices() { return p_vertices; }

  // *************************************************************
  //    Main K-NN Search Function
  // *************************************************************
  // This version starts the search from the leaf containing the query point
  // and expands outwards, which is highly efficient.
  void k_nearest_leaf(vtx* p, node* start_node, int k) {
    KBest<vtx, max_k> k_best(k);

    // 1. Process points in the starting leaf to get a good initial radius
    for (auto neighbor : start_node->vertices) {
      if (neighbor != p) {
        double dist_sq = (p->pt - neighbor->pt).sqLength();
        k_best.insert(neighbor, dist_sq);
      }
    }

    // 2. Go up the tree, searching promising sibling branches
    node* curr = start_node;
    while (curr != root) {
      node* parent = curr->parent;
      for (int i = 0; i < (1 << dim); i++) {
        node* sibling = parent->children[i];
        if (sibling != nullptr && sibling != curr) {
          // Pruning check: if sibling box is promising, search its subtree
          if (box_dist_sq(p->pt, sibling) < k_best.worst_dist()) {
            search_subtree(p, sibling, k_best);
          }
        }
      }
      curr = parent;
    }

    // 3. Store results back into the vertex
    k_best.get_neighbors(p);
  }

  // A simpler search that always starts from the root. Kept for comparison.
  void k_nearest(vtx* p, int k) {
    KBest<vtx, max_k> k_best(k);
    search_subtree(p, root, k_best);
    k_best.get_neighbors(p);
  }

  // *************************************************************
  //    Static Bounding Box Calculation
  // *************************************************************
  static box get_box(parlay::slice<vtx* const*> v) {
    auto get_min_max = [&](int d) {
      return parlay::minmax_element(v, [=](vtx* a, vtx* b) {
        return a->pt[d] < b->pt[d];
      });
    };

    auto min_max_p_0 = get_min_max(0);
    point min_p = (*min_max_p_0.first)->pt;
    point max_p = (*min_max_p_0.second)->pt;

    for (int i = 1; i < dim; i++) {
      auto min_max_p_i = get_min_max(i);
      min_p[i] = (*min_max_p_i.first)->pt[i];
      max_p[i] = (*min_max_p_i.second)->pt[i];
    }
    return box(min_p, max_p);
  }
};
