### Main Driver Function `ANN`

This is the main procedure that orchestrates the k-NN process. It uses the `k_nearest_neighbors` class defined above.

```cpp
#start
#include <algorithm>
#include <math.h> 
#include <queue>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "common/geometry.h"
#include "k_nearest_neighbors.h" // The header file implemented above

bool report_stats = false;
// Default to algorithm 2, which is the fastest and most scalable.
// 0: Root-based search for each point (slow).
// 2: Leaf-based search via parallel tree map (fast).
int algorithm_version = 2;

// find the k nearest neighbors for all points in tree
// places pointers to them in the .ngh field of each vertex
template <int max_k, class vtx>
void ANN(parlay::sequence<vtx*> &v, int k) {
  timer t("ANN",report_stats);

  using knn_tree = k_nearest_neighbors<vtx, max_k>;
  using node = typename knn_tree::node;
  using box = typename knn_tree::box;

  // Compute the bounding box of all points in parallel
  box whole_box = knn_tree::get_box(parlay::make_slice(v));
  t.next("get box");

  // Build the octree in parallel. This also reorders the pointers in `v`
  // to match the tree's spatial layout, improving cache locality.
  knn_tree T(v, whole_box);
  t.next("build tree");

  if (report_stats) 
    std::cout << "depth = " << T.get_root()->depth() << std::endl;

  if (algorithm_version == 0) { 
    // This version is slow as it starts a full search from the root for every point.
    // It is kept for correctness checking and performance comparison.
    parlay::sequence<vtx*> vr = T.vertices();
    t.next("flatten tree");

    parlay::parallel_for (0, vr.size(), [&] (size_t i) {
      T.k_nearest(vr[i], k);
    }, 1);

  } else { // (algorithm_version == 2)
    // This is the fastest version. It performs a parallel traversal of the tree (map)
    // and for each point found in a leaf, it initiates an efficient k-NN search
    // that starts locally and expands outwards.
    auto f = [&] (vtx* p, node* n){ 
      return T.k_nearest_leaf(p, n, k); 
    };

    // find nearest k neighbors for each point
    T.get_root()->map(f);
  }

  t.next("k-nn search");
  if (report_stats) {
    auto s = parlay::delayed_seq<size_t>(v.size(), [&] (size_t i) {return v[i]->counter;});
    size_t i = parlay::max_element(s) - s.begin();
    size_t sum = parlay::reduce(s);
    if (v.size() > 0) {
      std::cout << "max checks = " << s[i] 
        << ", average checks = " << sum/((double) v.size()) << std::endl;
    }
    t.next("stats");
  }
}
