    std::cout << "depth = " << T.tree->depth() << std::endl;
  }

  // This is the fastest approach: a parallel map over the tree leaves
  // to achieve good data locality for the queries.
  auto f = [&] (vtx* p, node* n) { 
       T.k_nearest_for_point(p, k); 
  };

  // Find nearest k neighbors for each point in parallel
  T.map(f);
  t.next("k-neighbor search");

} // T is destroyed here, tree memory is released.
