// A bounding box for a set of points in arbitrary dimensions.
template <typename Point>
struct bounding_box {
  using point = Point;
  using coord = typename point::coord;
  point p_min, p_max;

  bounding_box() : p_min(), p_max() {}
  explicit bounding_box(point p) : p_min(p), p_max(p) {}
  bounding_box(point p_min, point p_max) : p_min(p_min), p_max(p_max) {}

  // The center of the box.
  point center() const {
    return p_min + (p_max - p_min) / 2.0;
  }

  // The squared distance from point p to the closest point in the box.
  coord min_sq_dist(point p) const {
    coord dist_sq = 0;
    for (int i = 0; i < point::dim; ++i) {
      coord d = 0;
      if (p[i] < p_min[i])
        d = p[i] - p_min[i];
      else if (p[i] > p_max[i])
        d = p[i] - p_max[i];
      dist_sq += d * d;
    }
    return dist_sq;
  }
};

// A highly parallel octree implementation.
namespace oct_tree {

template <class Vtx>
struct node {
  using vtx = Vtx;
  using point = typename vtx::point_type;
  using box = bounding_box<point>;
  static constexpr int dim = point::dim;
  static constexpr int num_children = 1 << dim;
  static constexpr int leaf_cutoff = 16;

  box b;
  node* parent;
  size_t m_size;

  // Children pointers for internal nodes.
  std::array<std::unique_ptr<node>, num_children> children;

  // Points for leaf nodes.
  parlay::sequence<vtx*> items;

  node(box b, node* p) : b(b), parent(p), m_size(0) {}

  bool is_leaf() const {
    return !items.empty();
  }

  size_t size() const { return m_size; }

  int depth() const {
    if (is_leaf()) return 0;
    auto depths = parlay::map(children, [](const auto& child) {
      return child ? child->depth() : -1;
    });
    return 1 + parlay::reduce(depths, parlay::max_f());
  }
};

template <class Vtx>
class tree {
public:
  using vtx = Vtx;
  using point = typename vtx::point_type;
  using box = bounding_box<point>;
  using node = oct_tree::node<vtx>;

  std::unique_ptr<node> root;

  tree(parlay::sequence<vtx*>& V, box b) {
    root = build_recursive(parlay::make_slice(V), b, nullptr);
  }

  // Computes the bounding box of a set of vertices in parallel.
  static box get_box(const parlay::sequence<vtx*>& V) {
    if (V.empty()) return box();
    auto get_point_box = [&](size_t i) { return box(V[i]->pt); };
    auto join_boxes = [&](const box& b1, const box& b2) {
      return box(b1.p_min.minCoords(b2.p_min), b1.p_max.maxCoords(b2.p_max));
    };
    return parlay::reduce(parlay::delayed_seq<box>(V.size(), get_point_box),
                          parlay::make_monoid(join_boxes, box(V[0]->pt)));
  }

  // Applies a function f to all points in the tree in parallel.
  template <class F>
  void map(F f) {
    map_recursive(root.get(), f);
  }

  // Returns a sequence of all vertices, ordered by their position in the tree.
  parlay::sequence<vtx*> vertices() {
    return flatten(root.get());
  }

private:
  std::unique_ptr<node> build_recursive(parlay::slice<vtx**> V, box b, node* parent) {
    auto n = std::make_unique<node>(b, parent);
    n->m_size = V.size();

    if (V.size() <= node::leaf_cutoff) {
      n->items = parlay::sequence<vtx*>(V.begin(), V.end());
      return n;
    }

    point center = b.center();
    auto groups = parlay::group_by_key(V, [&](vtx* p) {
      return p->pt.quadrant(center);
    });

    parlay::parallel_for(0, groups.size(), [&](size_t i) {
      auto [quadrant, points] = groups[i];
      box child_box = get_child_box(b, center, quadrant);
      n->children[quadrant] = build_recursive(points, child_box, n.get());
    });

    return n;
  }

  box get_child_box(const box& parent_box, const point& center, int quadrant) {
      point new_min = parent_box.p_min;
      point new_max = parent_box.p_max;
      for (int d = 0; d < point::dim; d++) {
          if ((quadrant >> d) & 1) {
              new_min[d] = center[d];
          } else {
              new_max[d] = center[d];
          }
      }
      return box(new_min, new_max);
  }

  template <class F>
  void map_recursive(node* n, F f) {
    if (!n) return;
    if (n->is_leaf()) {
      parlay::parallel_for(0, n->items.size(), [&](size_t i) {
        f(n->items[i], n);
      });
    } else {
      parlay::parallel_for(0, node::num_children, [&](size_t i) {
        map_recursive(n->children[i].get(), f);
      });
    }
  }

  parlay::sequence<vtx*> flatten(node* n) {
      if (!n) return parlay::sequence<vtx*>();
      if (n->is_leaf()) {
          return parlay::sequence<vtx*>(n->items.begin(), n->items.end());
      }
      auto children_seqs = parlay::map(n->children, [&](const auto& child) {
          return flatten(child.get());
      });
      return parlay::flatten(children_seqs);
  }
};

} // namespace oct_tree


template <class Vtx, int max_k>
class k_nearest_neighbors {
public:
  using vtx = Vtx;
  using point = typename vtx::point_type;
  using coord = typename point::coord;
  using box = bounding_box<point>;
  using o_tree = oct_tree::tree<vtx>;
  using node = typename o_tree::node;

  std::unique_ptr<o_tree> tree;

  k_nearest_neighbors(parlay::sequence<vtx*>& V, box b) {
    tree = std::make_unique<o_tree>(V, b);
  }

  void k_nearest_leaf(vtx* p, node* leaf_node, int k) {
    using dist_vtx = std::pair<coord, vtx*>;

    // Bounded max-priority queue implemented with std::array and std::*_heap.
    std::array<dist_vtx, max_k> neighbor_arr;
    size_t num_neighbors = 0;

    auto insert_neighbor = [&](vtx* neighbor) {
      p->counter++; // for stats
      coord d_sq = (p->pt - neighbor->pt).sqLength();

      if (num_neighbors < k) {
        neighbor_arr[num_neighbors++] = {d_sq, neighbor};
        if (num_neighbors == k) {
          std::make_heap(neighbor_arr.begin(), neighbor_arr.begin() + k);
        }
      } else if (d_sq < neighbor_arr.front().first) {
        std::pop_heap(neighbor_arr.begin(), neighbor_arr.begin() + k);
        neighbor_arr[k-1] = {d_sq, neighbor};
        std::push_heap(neighbor_arr.begin(), neighbor_arr.begin() + k);
      }
    };

    // 1. Process points in the initial leaf node.
    for (vtx* q : leaf_node->items) {
      if (p != q) insert_neighbor(q);
    }

    // 2. Traverse up the tree, searching promising sibling nodes.
    node* curr = leaf_node;
    while (curr && curr->parent) {
      node* parent = curr->parent;
      for (const auto& child_ptr : parent->children) {
        if (child_ptr && child_ptr.get() != curr) {
          node* sibling = child_ptr.get();
          coord max_dist_sq = (num_neighbors < k) ?
                              std::numeric_limits<coord>::max() :
                              neighbor_arr.front().first;

          if (sibling->b.min_sq_dist(p->pt) < max_dist_sq) {
            search_subtree(sibling, p, k, neighbor_arr, num_neighbors);
          }
        }
      }
      curr = parent;
    }

    // 3. Store results in the vertex's neighbor list.
    p->ngh.resize(num_neighbors);
    for (size_t i = 0; i < num_neighbors; ++i) {
      p->ngh[i] = neighbor_arr[i].second;
    }
  }

private:
  void search_subtree(node* n, vtx* p, int k,
                      std::array<std::pair<coord, vtx*>, max_k>& neighbor_arr,
                      size_t& num_neighbors) {
    if (!n) return;

    // Pruning: if the closest point in the box is further than the current
    // k-th neighbor, no point in this box can be a neighbor.
    coord max_dist_sq = (num_neighbors < k) ?
                        std::numeric_limits<coord>::max() :
                        neighbor_arr.front().first;
    if (n->b.min_sq_dist(p->pt) >= max_dist_sq) {
        return;
    }

    if (n->is_leaf()) {
      for (vtx* q : n->items) {
        p->counter++;
        coord d_sq = (p->pt - q->pt).sqLength();
        if (num_neighbors < k) {
          neighbor_arr[num_neighbors++] = {d_sq, q};
          if (num_neighbors == k) std::make_heap(neighbor_arr.begin(), neighbor_arr.begin() + k);
        } else if (d_sq < neighbor_arr.front().first) {
          std::pop_heap(neighbor_arr.begin(), neighbor_arr.begin() + k);
          neighbor_arr[k-1] = {d_sq, q};
          std::push_heap(neighbor_arr.begin(), neighbor_arr.begin() + k);
        }
      }
      return;
    }

    // For internal nodes, recurse on children, visiting them in order of proximity
    // to tighten the search radius as quickly as possible.
    std::array<std::pair<coord, node*>, node::num_children> child_dists;
    int num_valid_children = 0;
    for(const auto& child : n->children) {
        if (child) {
            child_dists[num_valid_children++] = {child->b.min_sq_dist(p->pt), child.get()};
        }
    }

    std::sort(child_dists.begin(), child_dists.begin() + num_valid_children);

    for (int i = 0; i < num_valid_children; ++i) {
        search_subtree(child_dists[i].second, p, k, neighbor_arr, num_neighbors);
    }
  }
};
