// Defined elsewhere, controls statistics reporting.
extern bool report_stats;

// Finds the k nearest neighbors for all points in the input sequence v.
// Results are stored in the .ngh field of each vertex.
template <int max_k, class vtx>
void ANN(parlay::sequence<vtx*> &v, int k) {
  timer t("ANN", report_stats);

  if (k > max_k) {
    throw std::runtime_error("Error: k is larger than max_k.");
  }
  if (v.empty()) return;

  using knn_tree = k_nearest_neighbors<vtx, max_k>;
  using box = typename knn_tree::box;
  using node = typename knn_tree::node;

  box whole_box = knn_tree::o_tree::get_box(v);
  t.next("get box");

  knn_tree T(v, whole_box);
  t.next("build tree");

  if (report_stats) {
    std::cout << "depth = " << T.tree->depth() << std::endl;
    // Reset counters for stats
    parlay::parallel_for(0, v.size(), [&](size_t i) { v[i]->counter = 0; });
  }

  // Use the tree's parallel map function to apply k_nearest_leaf to each point.
  // This is the most efficient approach as it leverages the tree structure to
  // find the leaf for each query point without redundant traversals.
  auto f = [&](vtx* p, node* n) {
    T.k_nearest_leaf(p, n, k);
  };
  T.tree->map(f);

  t.next("k-nn search");

  if (report_stats) {
    auto s = parlay::delayed_seq<size_t>(v.size(), [&](size_t i) { return v[i]->counter; });
    size_t total_checks = parlay::reduce(s);
    size_t max_checks = parlay::reduce(s, parlay::max_f());
    std::cout << "max checks = " << max_checks
              << ", average checks = " << static_cast<double>(total_checks) / v.size()
              << std::endl;
    t.next("stats");
  }
}
