// This file implements the k_nearest_neighbors class, which includes a
// parallel octree implementation and a fast parallel k-NN search algorithm.
// It is designed to be included by `neighbors.h`.
// The implementation assumes a vertex type `vtx` with members:
// - `vtx::point_t pt`: the point coordinates (e.g., point2d, point3d)
// - `vtx** ngh`: an array to store pointers to the k-nearest neighbors

#ifndef K_NEAREST_NEIGHBORS_H
#define K_NEAREST_NEIGHBORS_H

#include <algorithm>
#include <memory>
#include <vector>
#include <stdexcept>
#include <limits>

#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "common/geometry.h"

// A small, fixed-size max-heap for managing the k-nearest neighbors found so far.
// Using a static array is generally faster than std::priority_queue due to
// better memory locality and no dynamic allocations.
template <class vtx, int max_k>
struct KNeighborSet {
  using neighbor_pair = std::pair<double, vtx*>;

  int k;
  int count = 0;
  neighbor_pair heap[max_k];

  explicit KNeighborSet(int K) : k(K) {
    if (k > max_k) {
        throw std::runtime_error("k is larger than max_k");
    }
  }

  // The squared distance to the farthest neighbor in the current set.
  double max_dist_sq() const {
    // If the set is not full, the search radius is effectively infinite.
    return (count < k) ? std::numeric_limits<double>::max() : heap[0].first;
  }

  // Add a new point to the set if it's closer than the current k-th neighbor.
  void add(double dist_sq, vtx* p) {
    if (count < k) {
      heap[count++] = {dist_sq, p};
      if (count == k) {
        // Turn the array into a max-heap once it's full.
        std::make_heap(heap, heap + k);
      }
    } else if (dist_sq < heap[0].first) {
      // Replace the farthest neighbor with the new, closer one.
      std::pop_heap(heap, heap + k);
      heap[k-1] = {dist_sq, p};
      std::push_heap(heap, heap + k);
    }
  }

  // Finalize and store the neighbors in the vertex's `ngh` array.
  void get_neighbors(vtx* p) {
    // The problem doesn't require sorted output, but sorting is cheap for small k.
    std::sort_heap(heap, heap + count);
    for (int i=0; i < count; i++) {
      p->ngh[i] = heap[i].second;
    }
  }
};

template <class vtx, int max_k>
class k_nearest_neighbors {
public:
  using point_t = typename vtx::point_t;
  using box = std::pair<point_t, point_t>;

  // *************************************************************
  //    THE OCTREE DATA STRUCTURE
  // *************************************************************
  struct o_tree {
    static constexpr int dim = point_t::dim;
    static constexpr int num_children = 1 << dim;
    static constexpr int leaf_size = 16; // Threshold for leaf nodes

    struct node {
      point_t center;
      double size; // Half side-length of the node's box
      node* parent;
      std::unique_ptr<node> children[num_children];
      parlay::sequence<vtx*> vertices; // Only populated for leaves

      node(point_t center, double size, node* parent) :
          center(center), size(size), parent(parent) {}

      bool is_leaf() const { return !vertices.empty(); }

      size_t depth() const {
        if (is_leaf()) return 1;
        auto depths = parlay::tabulate(num_children, [&](size_t i) -> size_t {
            return children[i] ? children[i]->depth() : 0;
        });
        return 1 + parlay::reduce(depths, parlay::maxm<size_t>());
      }

      // Min squared distance from a point to the node's bounding box.
      // This is crucial for pruning the search space.
      double min_sq_dist(const point_t& p) const {
        double dist_sq = 0;
        for (int i = 0; i < dim; i++) {
          double di = 0;
          double p_min_i = center[i] - size;
          double p_max_i = center[i] + size;
          if (p[i] < p_min_i) di = p_min_i - p[i];
          else if (p[i] > p_max_i) di = p[i] - p_max_i;
          dist_sq += di * di;
        }
        return dist_sq;
      }
    };

    std::unique_ptr<node> root;

    // Computes the bounding box of a set of points in parallel.
    static box get_box(parlay::slice<vtx* const> v) {
      auto pts = parlay::map(v, [] (vtx* p) { return p->pt; });
      auto min_max_f = [](const box& a, const box& b) {
          return box(a.first.minCoords(b.first), a.second.maxCoords(b.second));
      };
      auto get_box_f = [](const point_t& p){ return box(p,p); };
      auto pt_boxes = parlay::map(pts, get_box_f);
      return parlay::reduce(pt_boxes, parlay::make_monoid(min_max_f, get_box_f(pts[0])));
    }

    // Parallel octree constructor.
    o_tree(parlay::slice<vtx*> v, box b) {
      point_t center = b.first + (b.second - b.first) / 2.0;
      double size = (b.second - b.first).maxDim() / 2.0;
      root = std::make_unique<node>(center, size, nullptr);
      build_node(root.get(), v);
    }

    // Recursively builds the octree in parallel.
    void build_node(node* T, parlay::slice<vtx*> v) {
      if (v.size() <= leaf_size) {
        T->vertices = parlay::to_sequence(v);
        return;
      }

      auto get_quadrant = [&](vtx* p) { return p->pt.quadrant(T->center); };
      auto grouped = parlay::group_by_key(v, get_quadrant);

      parlay::parallel_for(0, grouped.size(), [&] (size_t i) {
        auto& [quadrant, points] = grouped[i];
        point_t new_center = T->center.offsetPoint(quadrant, T->size / 2.0);
        T->children[quadrant] = std::make_unique<node>(new_center, T->size / 2.0, T);
        build_node(T->children[quadrant].get(), points);
      });
    }

    // Parallel traversal applying a function to each vertex and its leaf node.
    template <typename F>
    void map(F f) { map_node(root.get(), f); }

    template <typename F>
    void map_node(node* T, F f) {
      if (!T) return;
      if (T->is_leaf()) {
        parlay::parallel_for(0, T->vertices.size(), [&] (size_t i) {
          f(T->vertices[i], T);
        });
      } else {
        parlay::parallel_for(0, num_children, [&] (size_t i) {
          if (T->children[i]) map_node(T->children[i].get(), f);
        });
      }
    }

    // Flattens the tree to get a sequence of all vertices.
    parlay::sequence<vtx*> flatten() { return flatten_node(root.get()); }

    parlay::sequence<vtx*> flatten_node(node* T) {
      if (!T) return parlay::sequence<vtx*>();
      if (T->is_leaf()) return T->vertices;
      auto child_results = parlay::tabulate(num_children, [&](size_t i) {
          return flatten_node(T->children[i].get());
      });
      return parlay::flatten(child_results);
    }
  };

  // *************************************************************
  //    K-NEAREST NEIGHBORS IMPLEMENTATION
  // *************************************************************
  using node = typename o_tree::node;
  using box_delta = std::pair<box, double>;

  std::unique_ptr<o_tree> tree;
  parlay::sequence<vtx*> vertices_storage;

  k_nearest_neighbors(parlay::sequence<vtx*>& V, box b) {
      vertices_storage = V; // Keep points alive
      tree = std::make_unique<o_tree>(vertices_storage.slice(), b);
  }

  parlay::sequence<vtx*> vertices() { return tree->flatten(); }

  // Finds the leaf node containing a given point.
  node* find_leaf(const point_t& p, node* T, const box& b, double delta) {
    if (T->is_leaf()) return T;
    int quadrant = p.quadrant(T->center);
    if (T->children[quadrant])
      return find_leaf(p, T->children[quadrant].get(), b, delta);
    // This case occurs if a point falls into an empty sub-quadrant.
    // The search should start from the deepest node containing the point.
    return T;
  }

  box_delta get_box_delta(int dims) { return {{}, 0.0}; }

  void k_nearest(vtx* p, int k) {
      k_nearest_leaf(p, find_leaf(p->pt, tree->root.get(), {}, 0.0), k);
  }

  // Main search function, starting from a given leaf node.
  void k_nearest_leaf(vtx* p, node* start_node, int k) {
    KNeighborSet<vtx, max_k> kns(k);

    // 1. If start_node is a leaf, process its points.
    if (start_node->is_leaf()) {
      for (vtx* pv : start_node->vertices) {
        if (p != pv) {
          double d2 = (p->pt - pv->pt).sqLength();
          kns.add(d2, pv);
        }
      }
    }

    // 2. Ascend the tree, checking sibling boxes for potential neighbors.
    node* curr = start_node;
    while (curr->parent != nullptr) {
      node* parent = curr->parent;
      for (int i = 0; i < o_tree::num_children; i++) {
        node* sibling = parent->children[i].get();
        if (sibling != nullptr && sibling != curr) {
          if (sibling->min_sq_dist(p->pt) < kns.max_dist_sq()) {
            k_search(p, sibling, kns);
          }
        }
      }
      curr = parent;
    }

    // 3. Store the final results in the vertex.
    kns.get_neighbors(p);
  }

private:
  // Recursive search within a subtree.
  void k_search(vtx* p, node* T, KNeighborSet<vtx, max_k>& kns) {
    if (T->is_leaf()) {
      for (vtx* pv : T->vertices) {
        // The query point `p` will not be in this leaf, so no `p!=pv` check needed.
        double d2 = (p->pt - pv->pt).sqLength();
        kns.add(d2, pv);
      }
      return;
    }

    // For internal nodes, visit children in order of proximity. This is a
    // key optimization that shrinks the search radius faster, leading to
    // more effective pruning.
    std::pair<double, node*> child_dists[o_tree::num_children];
    int num_valid_children = 0;
    for (int i = 0; i < o_tree::num_children; i++) {
      if (T->children[i]) {
        child_dists[num_valid_children++] = {T->children[i]->min_sq_dist(p->pt), T->children[i].get()};
      }
    }
    std::sort(child_dists, child_dists + num_valid_children);

    for (int i = 0; i < num_valid_children; i++) {
      if (child_dists[i].first < kns.max_dist_sq()) {
        k_search(p, child_dists[i].second, kns);
      } else {
        // Since children are sorted by distance, we can prune the rest.
        break;
      }
    }
  }
};

#endif // K_NEAREST_NEIGHBORS_H
