  index_t i;
  eventType t;
  event(float v, index_t i, eventType t) : v(v), i(i), t(t) {}
  event() : v(0), i(0), t(START) {}
};

#define GET_INDEX(E) (E.i)
#define IS_START(E) (E.t == START)
#define IS_END(E) (E.t == END)

// Information about a potential cut
struct cutInfo {
  float cost;
  float cutOff;
  index_t numLeft, numRight;
  cutInfo(float cost, float cutOff, index_t numLeft, index_t numRight)
    : cost(cost), cutOff(cutOff), numLeft(numLeft), numRight(numRight) {}
  cutInfo() : cost(0), cutOff(0), numLeft(0), numRight(0) {}
};

// Optimized Möller-Trumbore ray-triangle intersection test
// Returns intersection distance t, or -1.0 if no hit.
// Only considers hits where 0 < t < t_max.
inline double rayTriangleIntersect_opt(
    const ray_t& r, 
    const point& p0, const point& p1, const point& p2,
    double t_max) {

    vect e1 = p1 - p0;
    vect e2 = p2 - p0;
    vect pvec = r.d.cross(e2);
    double det = e1.dot(pvec);

    // If det is close to 0, ray is parallel to triangle plane
    if (det > -epsilon && det < epsilon) return -1.0;

    double inv_det = 1.0 / det;
    vect tvec = r.o - p0;
    double u = tvec.dot(pvec) * inv_det;

    if (u < 0.0 || u > 1.0) return -1.0;

    vect qvec = tvec.cross(e1);
    double v = r.d.dot(qvec) * inv_det;

    if (v < 0.0 || u + v > 1.0) return -1.0;

    double t = e2.dot(qvec) * inv_det;

    if (t > epsilon && t < t_max) {
        return t;
    }
    return -1.0;
}


// The k-d tree node structure.
// Using a union is memory-efficient.
struct treeNode {
    BoundingBox box;
    union {
        struct {
            treeNode *left, *right;
            int cutDim;
            float cutOff;
        } internal;
        struct {
            index_t* indices;
