// Calculate surface area of a bounding box
float boxSurfaceArea(BoundingBox B) {
  float r0 = B[0].max-B[0].min;
  float r1 = B[1].max-B[1].min;
  float r2 = B[2].max-B[2].min;
  return 2.0f * (r0*r1 + r1*r2 + r0*r2);
}

// Ensure a range has non-zero width for robustness
range fixRange(float minv, float maxv) {
  if (minv == maxv) return range(minv, minv + 1e-6f);
  else return range(minv, maxv);
}

// Sequential version of best cut (for small inputs)
// This is identical to the baseline's efficient implementation.
cutInfo bestCutSerial(parlay::sequence<event> const &E, range r, range r1, range r2) {
  double flt_max = std::numeric_limits<double>::max();
  size_t n = E.size();
  if (r.max - r.min == 0.0) return cutInfo(flt_max, r.min, n, n);
  float area = 2.0f * (r1.max-r1.min) * (r2.max-r2.min);
  float orthoPerimeter = 2.0f * ((r1.max-r1.min) + (r2.max-r2.min));

  size_t inLeft = 0;
  size_t inRight = n/2;
  float minCost = flt_max;
  size_t k = 0;
  size_t rn_best = inRight;
  size_t ln_best = inLeft;

  for (size_t i=0; i < n; i++) {
    if (IS_END(E[i])) inRight--;
    float leftLength = E[i].v - r.min;
    float rightLength = r.max - E[i].v;
    float cost = (area + orthoPerimeter * leftLength) * inLeft + 
                 (area + orthoPerimeter * rightLength) * inRight;
    if (cost < minCost) {
      rn_best = inRight;
      ln_best = inLeft;
      minCost = cost;
      k = i;
    }
    if (IS_START(E[i])) inLeft++;
  }
  return cutInfo(minCost, E[k].v, ln_best, rn_best);
}

// Parallel version of best cut using SAH
// This is identical to the baseline's efficient Parlay implementation.
cutInfo bestCut(parlay::sequence<event> const &E, range r, range r1, range r2) {
  size_t n = E.size();
  if (n < minParallelSize)
    return bestCutSerial(E, r, r1, r2);
  double flt_max = std::numeric_limits<double>::max();
  if (r.max - r.min == 0.0) return cutInfo(flt_max, r.min, n, n);

  float orthogArea = 2.0f * ((r1.max-r1.min) * (r2.max-r2.min));
  float orthoPerimeter = 2.0f * ((r1.max-r1.min) + (r2.max-r2.min));

  auto is_end = parlay::delayed::tabulate(n, [&] (size_t i) -> size_t {return IS_END(E[i]);});
  auto end_counts = parlay::delayed::scan_inclusive(is_end);

  using rtype = std::tuple<float,size_t,size_t>;
  auto cost_f = [&] (std::tuple<size_t,size_t> ni) -> rtype {
    auto [ num_ends, i] = ni;
    size_t num_ends_before = num_ends - IS_END(E[i]); 
    size_t inLeft = i - num_ends_before;
    size_t inRight = n/2 - num_ends;
    float leftLength = E[i].v - r.min;
    float rightLength = r.max - E[i].v;
    float cost = (orthogArea + orthoPerimeter * leftLength) * inLeft +
                 (orthogArea + orthoPerimeter * rightLength) * inRight;
    return rtype(cost, num_ends_before, i);};
  auto costs = parlay::delayed::map(parlay::delayed::zip(end_counts, parlay::iota<size_t>(n)), cost_f);

  auto min_f = [&] (rtype a, rtype b) {return (std::get<0>(a) < std::get<0>(b)) ? a : b;};
  rtype identity(std::numeric_limits<float>::max(), 0, 0);
  auto [cost, num_ends_before, i] = parlay::delayed::reduce(costs, parlay::make_monoid(min_f, identity));

  index_t ln = i - num_ends_before;
  index_t rn = n/2 - (num_ends_before + IS_END(E[i]));
  return cutInfo(cost, E[i].v, ln, rn);
}

// Optimized single-pass event splitting function
eventsPair splitEvents_opt(parlay::sequence<range> const &dim_boxes,
                           parlay::sequence<event> const &events, 
                           float cutOff) {
    using T = event;
    size_t n = events.size();

    auto flags = parlay::tabulate(n, [&](size_t i) {
        index_t b = GET_INDEX(events[i]);
        return std::pair<bool, bool>(dim_boxes[b].min < cutOff, dim_boxes[b].max > cutOff);
    });

    auto [offsets, totals] = parlay::scan(flags, parlay::pair_monoid(parlay::addm<size_t>(), parlay::addm<size_t>()));

    auto result1 = parlay::sequence<T>::uninitialized(totals.first);
    auto result2 = parlay::sequence<T>::uninitialized(totals.second);

    parlay::parallel_for(0, n, [&](size_t i) {
        if (flags[i].first) result1[offsets[i].first] = events[i];
        if (flags[i].second) result2[offsets[i].second] = events[i];
    }, minParallelSize);

    return std::make_pair(std::move(result1), std::move(result2));
}

// Recursively generate the k-d tree nodes in parallel
treeNode* generateNode(Boxes &boxes, Events events, BoundingBox B, size_t maxDepth) {
  size_t n = events[0].size();
  if (n <= 2 || maxDepth == 0) {
    auto indices = parlay::tabulate(n/2, [&](size_t i) { return GET_INDEX(events[0][2*i]); });
    auto sorted_indices = parlay::sort(indices);
    auto unique_indices = parlay::unique(sorted_indices);
    return treeNode::make_leaf(std::move(unique_indices), B);
  }

  cutInfo cuts[3];
  parlay::parallel_for(0, 3, [&] (int d) {
    cuts[d] = bestCut(events[d], B[d], B[(d+1)%3], B[(d+2)%3]);
  });

  int cutDim = 0;
  for (int d = 1; d < 3; d++) 
    if (cuts[d].cost < cuts[cutDim].cost) cutDim = d;

  float area = boxSurfaceArea(B);
  float bestCost = CT + CL * cuts[cutDim].cost / area;
  float origCost = (float) (n/2);

  if (bestCost >= origCost || cuts[cutDim].numLeft + cuts[cutDim].numRight > maxExpand * n/2) {
    auto indices = parlay::tabulate(n/2, [&](size_t i) { return GET_INDEX(events[0][2*i]); });
    auto sorted_indices = parlay::sort(indices);
    auto unique_indices = parlay::unique(sorted_indices);
    return treeNode::make_leaf(std::move(unique_indices), B);
  }

  float cutOff = cuts[cutDim].cutOff;
  BoundingBox BBL = B; BBL[cutDim].max = cutOff;
  BoundingBox BBR = B; BBR[cutDim].min = cutOff;

  Events leftEvents, rightEvents;
  parlay::parallel_for (0, 3, [&] (int d) {
    auto [left, right] = splitEvents_opt(boxes[cutDim], events[d], cutOff);
    leftEvents[d] = std::move(left);
    rightEvents[d] = std::move(right);
  });

  treeNode *L, *R;
  parlay::par_do([&] () {L = generateNode(boxes, std::move(leftEvents), BBL, maxDepth-1);},
                 [&] () {R = generateNode(boxes, std::move(rightEvents), BBR, maxDepth-1);});

  return treeNode::make_internal(L, R, cutDim, cutOff, B);
}

// Fast, iterative ray traversal of the k-d tree
index_t findRay(const ray_t& r, treeNode* root, const triangs& Tri) {
    double t_max = std::numeric_limits<double>::max();
    index_t hit_idx = -1;

    vect inv_d(1.0/r.d.x, 1.0/r.d.y, 1.0/r.d.z);

    constexpr int MAX_STACK_DEPTH = 64;
    treeNode* node_stack[MAX_STACK_DEPTH];
    int stack_ptr = 0;

    treeNode* node = root;

    while (true) {
        if (node->is_leaf) {
            for (size_t i = 0; i < node->leaf.n; ++i) {
                index_t j = node->leaf.indices[i];
                const auto& T = Tri.T[j];
                double t = rayTriangleIntersect_opt(r, Tri.P[T[0]], Tri.P[T[1]], Tri.P[T[2]], t_max);
                if (t > 0.0) {
                    t_max = t;
                    hit_idx = j;
                }
            }
            if (stack_ptr == 0) break;
            node = node_stack[--stack_ptr];
            continue;
        }

        int dim = node->internal.cutDim;
        double t_split = (node->internal.cutOff - r.o[dim]) * inv_d[dim];

        treeNode *near_child, *far_child;
        if (r.o[dim] < node->internal.cutOff || (r.o[dim] == node->internal.cutOff && r.d[dim] <= 0)) {
            near_child = node->internal.left;
            far_child = node->internal.right;
        } else {
            near_child = node->internal.right;
            far_child = node->internal.left;
        }

        if (t_split >= t_max || t_split < 0) {
            node = near_child;
        } else {
            if (stack_ptr < MAX_STACK_DEPTH) {
                node_stack[stack_ptr++] = far_child;
            }
            node = near_child;
        }
    }
    return hit_idx;
}


// Main ray casting function
parlay::sequence<index_t> rayCast(triangles<point> const &Tri,
				  parlay::sequence<ray<point>> const &rays, bool verbose) {
  parlay::internal::timer t("ray cast", verbose);
  size_t numRays = rays.size();
  size_t n = Tri.T.size();
  if (n == 0) return parlay::sequence<index_t>(numRays, -1);

  Boxes boxes;
  for (int d = 0; d < 3; d++)
    boxes[d] = parlay::sequence<range>::uninitialized(n);

  parlay::parallel_for (0, n, [&] (size_t i) {
    point p0 = Tri.P[Tri.T[i][0]];
    point p1 = Tri.P[Tri.T[i][1]];
    point p2 = Tri.P[Tri.T[i][2]];
    boxes[0][i] = fixRange(std::min({p0.x,p1.x,p2.x}), std::max({p0.x,p1.x,p2.x}));
    boxes[1][i] = fixRange(std::min({p0.y,p1.y,p2.y}), std::max({p0.y,p1.y,p2.y}));
    boxes[2][i] = fixRange(std::min({p0.z,p1.z,p2.z}), std::max({p0.z,p1.z,p2.z}));
  });
  t.next("compute boxes");

  Events events;
  BoundingBox boundingBox;
  parlay::parallel_for(0, 3, [&](int d) {
    events[d] = parlay::tabulate(2*n, [&] (size_t i) -> event {
      return ((i % 2 == 0) ?
	      event(boxes[d][i/2].min, i/2, START) :
	      event(boxes[d][i/2].max, i/2, END));});
    parlay::sort_inplace(events[d], [] (event a, event b) {return a.v < b.v;}); 
    if (2*n > 0)
      boundingBox[d] = range(events[d][0].v, events[d][2*n-1].v);
  });
  t.next("generate and sort events");

  size_t recursionDepth = std::min<size_t>(maxRecursionDepth, parlay::log2_up(n)-1);
  treeNode* R = generateNode(boxes, std::move(events), boundingBox, recursionDepth);
  t.next("build tree");

  auto results = parlay::tabulate(numRays, [&] (size_t i) -> index_t {
      return findRay(rays[i], R, Tri);
  }, minParallelSize);
  t.next("intersect rays");

  treeNode::delete_tree(R);
  t.next("delete tree");

  return results;
}
