// --- Start of inlined rayTriangleIntersect.h ---
// Using a fast, standard Möller-Trumbore intersection algorithm
inline coord rayTriangleIntersect(const ray<point>& r, const point m[3]) {
    constexpr coord EPSILON = 0.0000001;
    vect edge1 = m[1] - m[0];
    vect edge2 = m[2] - m[0];
    vect h = r.d.cross(edge2);
    coord a = edge1.dot(h);

    if (a > -EPSILON && a < EPSILON)
        return -1.0; // Ray is parallel to the triangle.

    coord f = 1.0 / a;
    vect s = r.o - m[0];
    coord u = f * s.dot(h);

    if (u < 0.0 || u > 1.0)
        return -1.0;

    vect q = s.cross(edge1);
    coord v = f * r.d.dot(q);

    if (v < 0.0 || u + v > 1.0)
        return -1.0;

    // At this stage we can compute t to find out where the intersection point is on the line.
    coord t = f * edge2.dot(q);

    if (t > EPSILON) // ray intersection
        return t;
    else // This is a line intersection but not a ray intersection.
        return -1.0;
}
// --- End of inlined rayTriangleIntersect.h ---


