// --- Start of file: hull.C ---
#include <algorithm>
#include <vector>
#include <limits>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "common/geometry.h"
#include "common/get_time.h"
#include "hull.h"
using namespace std;

// Thresholds for switching between parallel and serial versions.
// These values are chosen based on common practice and may need tuning
// for specific hardware or problem sizes.
constexpr size_t SERIAL_THRESHOLD = 16384;
constexpr size_t PARALLEL_RECURSION_THRESHOLD = 2048;

// Forward declaration
parlay::sequence<indexT> quickHull(parlay::sequence<point> const & Points,
				   parlay::sequence<indexT> &&Idxs,
				   indexT l, indexT mid, indexT r);


// A serial implementation of QuickHull using in-place partitioning.
// This is used as a base case for the parallel version to reduce
// the overhead of parallel scheduling for small subproblems. It finds the hull
// for points in Idxs that lie to one side of the line p1--p2.
parlay::sequence<indexT> serial_hull_recursive(
    parlay::sequence<point> const& Points,
    parlay::slice<indexT*, indexT*> Idxs,
    indexT p1, indexT p2) {
  if (Idxs.empty()) {
    return parlay::sequence<indexT>();
  }

  point p1P = Points[p1];
  point p2P = Points[p2];
  coord max_dist = 0.0;
  indexT max_idx = Idxs[0]; // Initialize with a valid index

  // Find the point furthest from the line p1--p2
  for (indexT idx : Idxs) {
    coord dist = triArea(p1P, p2P, Points[idx]);
    if (dist > max_dist) {
      max_dist = dist;
      max_idx = idx;
    }
  }

  // If no points are strictly above the line, there's no hull to find here.
  if (max_dist <= 1e-12) { // Use a small epsilon for floating point robustness
      return parlay::sequence<indexT>();
  }

  point max_idxP = Points[max_idx];

  // Partition the points into those above p1--max_idx and max_idx--p2.
  // We use std::partition for efficient in-place partitioning.

  // Partition for the left side (p1--max_idx)
  auto it1 = std::partition(Idxs.begin(), Idxs.end(), [&](indexT i) {
    return triArea(p1P, max_idxP, Points[i]) > 1e-12;
  });

  // From the remaining points, partition for the right side (max_idx--p2)
  auto it2 = std::partition(it1, Idxs.end(), [&](indexT i) {
    return triArea(max_idxP, p2P, Points[i]) > 1e-12;
  });

  auto left_indices = parlay::slice(Idxs.begin(), it1);
  auto right_indices = parlay::slice(it1, it2);

  // Recurse on both sides
  auto left_hull = serial_hull_recursive(Points, left_indices, p1, max_idx);
  auto right_hull = serial_hull_recursive(Points, right_indices, max_idx, p2);

  // Combine results: left_hull, then the peak (max_idx), then right_hull
  left_hull.push_back(max_idx);
  left_hull.append(std::move(right_hull));
  return left_hull;
}

// Wrapper for the serial recursive hull function.
// It takes ownership of Idxs to use its memory for in-place partitioning.
parlay::sequence<indexT> serialQuickHull(parlay::sequence<point> const & Points,
                                         parlay::sequence<indexT> &&Idxs,
                                         indexT l, indexT r) {
    return serial_hull_recursive(Points, parlay::make_slice(Idxs), l, r);
}


// The parallel quickhull algorithm
// Points are all the points
// Idxs are the indices of the points (in Points) above the line defined by l--r.
// mid gives the index of the point furthest from the line defined by l--r
// The algorithm identifies the points above the lines l--mid and mid--r
//   and recurses on each
parlay::sequence<indexT> quickHull(parlay::sequence<point> const & Points,
				   parlay::sequence<indexT> &&Idxs,
				   indexT l, indexT mid, indexT r) {
  size_t n = Idxs.size();
  if (n == 0) return parlay::sequence<indexT>();

  // For small inputs, switch to a faster serial implementation
  if (n <= SERIAL_THRESHOLD) { 
    return serialQuickHull(Points, std::move(Idxs), l, r);
  }
  else {
    using cipair = std::pair<coord,indexT>;
    using cipairs = std::pair<cipair,cipair>;
    auto pairMax = [&] (cipairs a, cipairs b) {
      return cipairs((a.first.first > b.first.first) ? a.first : b.first,
		     (a.second.first > b.second.first) ? a.second : b.second);};
    // The identity for the reduction is (negative infinity, 0) for distance and index
    cipairs id = std::make_pair(std::make_pair(std::numeric_limits<coord>::lowest(), 0),
                              std::make_pair(std::numeric_limits<coord>::lowest(), 0));
    auto ci_monoid = parlay::make_monoid(pairMax, id);

    // Precompute vectors for performance
    point lP = Points[l], midP = Points[mid], rP = Points[r];
    vector2d v_lm = midP - lP;
    vector2d v_mr = rP - midP;

    // In a single parallel pass:
    // 1. Calculate furthest (positive) points from the lines l--mid and mid--r
    // 2. Set flags for points which are above each line
    auto leftFlag = parlay::sequence<bool>::uninitialized(n) ;
    auto rightFlag = parlay::sequence<bool>::uninitialized(n) ;

    auto P = parlay::delayed_tabulate(n, [&] (size_t i) {
	indexT j = Idxs[i];
    point currentP = Points[j];
	coord lefta = v_lm.cross(currentP - lP);
	coord righta = v_mr.cross(currentP - midP);
	leftFlag[i] = lefta > 1e-12;
	rightFlag[i] = righta > 1e-12;
	return cipairs(cipair(lefta,j),cipair(righta,j));
      });
    cipairs prs = parlay::reduce(P, ci_monoid);
    indexT maxleft = prs.first.second;
    indexT maxright = prs.second.second;

    // Filter points that are above each line
    parlay::sequence<indexT> left = parlay::pack(Idxs, leftFlag);
    parlay::sequence<indexT> right = parlay::pack(Idxs, rightFlag);

    // Recurse in parallel
    parlay::sequence<indexT> leftR, rightR;
    parlay::par_do_if(n > PARALLEL_RECURSION_THRESHOLD,
	      [&] () {leftR = quickHull(Points, std::move(left), l, maxleft, mid);},
	      [&] () {rightR = quickHull(Points, std::move(right), mid, maxright, r);});

    // Append the results together with mid in the middle
    parlay::sequence<indexT> result = std::move(leftR);
    result.push_back(mid);
    result.append(std::move(rightR));
    return result;
  }
}

// The top-level call has to find the maximum and minimum x coordinates
//   and use them for the initial lines minp--maxp (for the upper hull)
//   and maxp--minp (for the lower hull).
parlay::sequence<indexT> hull(parlay::sequence<point> const &Points) {
  timer t("hull", false);
  size_t n = Points.size();
  if (n < 3) {
      auto result = parlay::tabulate(n, [](indexT i){return i;});
      if (n == 2) {
          if ((Points[0].x > Points[1].x) || (Points[0].x == Points[1].x && Points[0].y > Points[1].y)) {
              std::swap(result[0], result[1]);
          }
      }
      return result;
  }

  auto pntless = [&] (point a, point b) {
    return (a.x < b.x) || ((a.x == b.x) && (a.y < b.y));};

  // Find min and max points by x coordinate using a parallel minmax_element
  auto minmax = parlay::minmax_element(Points, pntless);
  auto min_x_idx = minmax.first - std::begin(Points);
  auto max_x_idx = minmax.second - std::begin(Points);
  t.next("minmax");

  using cipair = std::pair<coord,indexT>;
  using cipairs = std::pair<cipair,cipair>;
  auto pairMinMax = [&] (cipairs a, cipairs b) {
      return cipairs((a.first.first < b.first.first) ? a.first : b.first,
		     (a.second.first > b.second.first) ? a.second : b.second);};
  // Identity for min/max reduction. Max area for min, Min area for max.
  cipairs id = std::make_pair(std::make_pair(std::numeric_limits<coord>::max(), 0),
                            std::make_pair(std::numeric_limits<coord>::lowest(), 0));
  auto ci_monoid = parlay::make_monoid(pairMinMax,id);

  // Precompute for performance
  point min_p = Points[min_x_idx];
  point max_p = Points[max_x_idx];
  vector2d v_minmax = max_p - min_p;

  // Identify points above and below the line minp--maxp
  // and simultaneously find the furthest point in each direction
  auto upperFlag = parlay::sequence<bool>::uninitialized(n) ;
  auto lowerFlag = parlay::sequence<bool>::uninitialized(n) ;
  auto P = parlay::delayed_tabulate(n, [&] (size_t i) {
    coord a = v_minmax.cross(Points[i] - min_p);
    upperFlag[i] = a > 1e-12;
    lowerFlag[i] = a < -1e-12;
    return cipairs(cipair(a,i),cipair(a,i));
    });

  auto max_lower_upper = parlay::reduce(P, ci_monoid);
  size_t max_lower_idx = max_lower_upper.first.second;
  size_t max_upper_idx = max_lower_upper.second.second;

  t.next("flags");

  // Pack the indices of points that are above and below the line
  parlay::sequence<indexT> upper = parlay::internal::pack_index<indexT>(upperFlag);
  parlay::sequence<indexT> lower = parlay::internal::pack_index<indexT>(lowerFlag);
  t.next("pack");

  // Make parallel recursive calls for the upper and lower hulls
  parlay::sequence<indexT> upperR, lowerR;
  parlay::par_do(
	 [&] () {upperR = quickHull(Points, std::move(upper),
				    min_x_idx, max_upper_idx, max_x_idx);},
	 [&] () {lowerR = quickHull(Points, std::move(lower),
				    max_x_idx, max_lower_idx, min_x_idx);}
	 );
  t.next("recurse");

  // Combine the results into the final clockwise-ordered convex hull
  parlay::sequence<indexT> result;
  result.reserve(upperR.size() + lowerR.size() + 2);
  result.push_back(min_x_idx);
  result.append(std::move(upperR));
  result.push_back(max_x_idx);
  result.append(std::move(lowerR));
  t.next("append");
  return result;
}
