// Forward declaration
parlay::sequence<indexT> quickHull(parlay::sequence<point> const & Points,
				   parlay::sequence<indexT> Idxs,
				   indexT l, indexT mid, indexT r);

// This is a sequential implementation of the quickhull recursion step.
// It is called for small problem sizes to avoid the overhead of parallel primitives.
parlay::sequence<indexT> quickHull_serial(parlay::sequence<point> const & Points,
                                          parlay::sequence<indexT> Idxs,
                                          indexT l, indexT mid, indexT r) {
  size_t n = Idxs.size();
  if (n <= 1) return Idxs;

  point lP = Points[l], midP = Points[mid], rP = Points[r];

  parlay::sequence<indexT> left; left.reserve(n);
  parlay::sequence<indexT> right; right.reserve(n);

  indexT maxleft = mid;
  coord maxleft_a = 0.0;
  indexT maxright = mid;
  coord maxright_a = 0.0;

  // Single pass to partition the points and find the furthest points for the subproblems
  for (indexT j : Idxs) {
    coord lefta = triArea(lP, midP, Points[j]);
    if (lefta > 0.0) {
      left.push_back(j);
      if (lefta > maxleft_a) {
        maxleft_a = lefta;
        maxleft = j;
      }
    } else {
      coord righta = triArea(midP, rP, Points[j]);
      if (righta > 0.0) {
        right.push_back(j);
        if (righta > maxright_a) {
          maxright_a = righta;
          maxright = j;
        }
      }
    }
  }

  parlay::sequence<indexT> leftR, rightR;
  // Recurse sequentially. Only recurse if we found a point outside the edge.
  if (maxleft_a > 0.0)
      leftR = quickHull_serial(Points, std::move(left), l, maxleft, mid);
  if (maxright_a > 0.0)
      rightR = quickHull_serial(Points, std::move(right), mid, maxright, r);

  // Combine the results
  parlay::sequence<indexT> result(leftR.size() + rightR.size() + 1);
  auto it = result.begin();
  it = std::copy(leftR.begin(), leftR.end(), it);
  *it++ = mid;
  std::copy(rightR.begin(), rightR.end(), it);
  return result;
}

// The quickhull algorithm
// Points are all the points
// Idxs are the indices of the points (in Points) above the line defined by l--r.
// mid gives the index of the point furthest from the line defined by l--r
// The algorithm identifies the points above the lines l--mid and mid--r
//   and recurses on each
parlay::sequence<indexT> quickHull(parlay::sequence<point> const & Points,
				   parlay::sequence<indexT> Idxs,
				   indexT l, indexT mid, indexT r) {
  size_t n = Idxs.size();
  if (n <= 1) return Idxs;

  // Thresholds for switching to sequential mode and for parallel recursion
  constexpr size_t SERIAL_THRESHOLD = 16384;
  constexpr size_t PAR_DO_THRESHOLD = 65536;

  if (n <= SERIAL_THRESHOLD) { 
    return quickHull_serial(Points, std::move(Idxs), l, mid, r);
  }
  else {
    using cipair = std::pair<coord,indexT>;
    using cipairs = std::pair<cipair,cipair>;
    auto pairMax = [&] (cipairs a, cipairs b) {
      return cipairs((a.first.first > b.first.first) ? a.first : b.first,
		     (a.second.first > b.second.first) ? a.second : b.second);};
    // Initialize with a small negative value to ensure any positive area is greater.
    auto ci_monoid = parlay::make_monoid(pairMax,cipairs({-1.0,0},{-1.0,0}));

    // calculate furthest (positive) points from the lines l--mid and mid--r
    // at the same time set flags for those which are above each line
    auto leftFlag = parlay::sequence<bool>::uninitialized(n) ;
    auto rightFlag = parlay::sequence<bool>::uninitialized(n) ;

    // Pre-calculate line vectors to reduce redundant computations inside the loop
    point lP = Points[l], midP = Points[mid], rP = Points[r];
    const coord l_mid_dx = midP.x - lP.x;
    const coord l_mid_dy = midP.y - lP.y;
    const coord mid_r_dx = rP.x - midP.x;
    const coord mid_r_dy = rP.y - midP.y;

    auto P = parlay::delayed_tabulate(n, [&] (size_t i) {
	const indexT j = Idxs[i];
    const point& p_j = Points[j];
	// triArea(lP, midP, p_j)
	const coord lefta = l_mid_dx * (p_j.y - lP.y) - l_mid_dy * (p_j.x - lP.x);
	// triArea(midP, rP, p_j)
	const coord righta = mid_r_dx * (p_j.y - midP.y) - mid_r_dy * (p_j.x - midP.x);
	leftFlag[i] = lefta > 0.0;
	rightFlag[i] = righta > 0.0;
	return cipairs(cipair(lefta,j),cipair(righta,j));
      });
    cipairs prs = parlay::reduce(P, ci_monoid);
    indexT maxleft = prs.first.second;
    indexT maxright = prs.second.second;

    // keep those above each line
    parlay::sequence<indexT> left = parlay::pack(Idxs, leftFlag);
    parlay::sequence<indexT> right = parlay::pack(Idxs, rightFlag);
    Idxs.clear(); // clear and use std::move to avoid O(n log n) memory usage

    // recurse in parallel
    parlay::sequence<indexT> leftR, rightR;
    parlay::par_do_if(n > PAR_DO_THRESHOLD,
	      [&] () { if (prs.first.first > 0.0) leftR = quickHull(Points, std::move(left), l, maxleft, mid);},
	      [&] () { if (prs.second.first > 0.0) rightR = quickHull(Points, std::move(right), mid, maxright, r);});

    // append the results together with mid in the middle
    parlay::sequence<indexT> result(leftR.size() + rightR.size() + 1);
    auto it = result.begin();
    it = parlay::copy(leftR, it);
    *it++ = mid;
    parlay::copy(rightR, it);
    return result;
  }
}

// The top-level call has to find the maximum and minimum x coordinates
//   and use them for the initial lines minp--maxp (for the upper hull)
//   and maxp--minp (for the lower hull).
parlay::sequence<indexT> hull(parlay::sequence<point> const &Points) {
  timer t("hull", false);
  size_t n = Points.size();
  if (n < 2) {
      return parlay::tabulate(n, [](size_t i) { return static_cast<indexT>(i); });
  }

  auto pntless = [&] (point a, point b) {
    return (a.x < b.x) || ((a.x == b.x) && (a.y < b.y));};

  // min and max points by x coordinate
  auto minmax = parlay::minmax_element(Points, pntless);
  auto min_x_idx = minmax.first - std::begin(Points);
  auto max_x_idx = minmax.second - std::begin(Points);
  t.next("minmax");

  using cipair = std::pair<coord,indexT>;
  using cipairs = std::pair<cipair,cipair>;
  auto pairMinMax = [&] (cipairs a, cipairs b) {
      return cipairs((a.first.first < b.first.first) ? a.first : b.first,
		     (a.second.first > b.second.first) ? a.second : b.second);};
  // Initialize min with a large positive and max with a large negative value.
  auto ci_monoid = parlay::make_monoid(pairMinMax,cipairs({1.0,0},{-1.0,0}));

  // identify those above and below the line minp--maxp
  // and calculate furtherst in each direction
  auto upperFlag = parlay::sequence<bool>::uninitialized(n) ;
  auto lowerFlag = parlay::sequence<bool>::uninitialized(n) ;

  // Pre-calculate line vector for efficiency
  const point& min_p = Points[min_x_idx];
  const point& max_p = Points[max_x_idx];
  const coord min_max_dx = max_p.x - min_p.x;
  const coord min_max_dy = max_p.y - min_p.y;

  auto P = parlay::delayed_tabulate(n, [&] (size_t i) {
    const point& p_i = Points[i];
    // triArea(min_p, max_p, p_i)
    const coord a = min_max_dx * (p_i.y - min_p.y) - min_max_dy * (p_i.x - min_p.x);
    upperFlag[i] = a > 0.0;
    lowerFlag[i] = a < 0.0;
    return cipairs(cipair(a,i),cipair(a,i));
    });

  auto max_lower_upper = parlay::reduce(P, ci_monoid);
  size_t max_lower_idx = max_lower_upper.first.second;
  size_t max_upper_idx = max_lower_upper.second.second;

  t.next("flags");

  // pack the indices of those above and below
  parlay::sequence<indexT> upper = parlay::internal::pack_index<indexT>(upperFlag);
  parlay::sequence<indexT> lower = parlay::internal::pack_index<indexT>(lowerFlag);
  t.next("pack");

  // make parallel calls for upper and lower hulls
  parlay::sequence<indexT> upperR, lowerR;
  parlay::par_do(
	 [&] () { if (max_lower_upper.second.first > 0.0) upperR = quickHull(Points, std::move(upper),
				    min_x_idx, max_upper_idx, max_x_idx);},
	 [&] () { if (max_lower_upper.first.first < 0.0) lowerR = quickHull(Points, std::move(lower),
				    max_x_idx, max_lower_idx, min_x_idx);}
	 );
  t.next("recurse");

  // Combine all parts of the hull in clockwise order.
  parlay::sequence<indexT> result(upperR.size() + lowerR.size() + 2);
  auto it = result.begin();
  *it++ = min_x_idx;
  it = parlay::copy(upperR, it);
  *it++ = max_x_idx;
  parlay::copy(lowerR, it);

  t.next("append");
  return result;
}
