```cpp
// --- Start of file: hull.C ---
#include <algorithm>
#include "common/geometry.h"
#include "parlay/primitives.h"
#include "parlay/sequence.h"
#include "parlay/parallel.h"
#include "parlay/algorithm.h"
#include "hull.h"

// Provided serial implementation, used as a base case for small subproblems.
#include "serialHull.h"

// A threshold for switching from parallel to serial recursion.
// This value is tuned for performance, balancing parallel overhead against work.
constexpr size_t SERIAL_THRESHOLD = 4096;

// Forward declaration of the recursive helper function.
static parlay::sequence<indexT> parallel_quick_hull_rec(
    parlay::slice<const indexT> indices,
    parlay::sequence<point> const& P,
    indexT p1_idx,
    indexT p2_idx);

parlay::sequence<indexT> hull(parlay::sequence<point> const &S) {
  size_t n = S.size();
  auto P = S.begin();

  if (n <= 3) {
    if (n < 3) return parlay::tabulate(n, [](size_t i) { return static_cast<indexT>(i); });

    // For n=3, find min-x point and order others to be clockwise.
    auto indices = parlay::iota<indexT>(3);
    auto min_it = parlay::min_element(indices, [&](indexT i, indexT j) {
        if (S[i].x != S[j].x) return S[i].x < S[j].x;
        return S[i].y < S[j].y;
    });
    indexT p0 = *min_it;
    indexT p1 = (indexT)-1, p2 = (indexT)-1;
    for (indexT i = 0; i < 3; i++) {
        if (i != p0) {
            if (p1 == (indexT)-1) p1 = i;
            else p2 = i;
        }
    }

    if (triArea(S[p0], S[p1], S[p2]) > 0) { // p0, p1, p2 is CCW
        return parlay::sequence<indexT>{p0, p2, p1}; // Return CW
    } else {
        return parlay::sequence<indexT>{p0, p1, p2}; // Already CW or collinear
    }
  }

  // 1. Find points with minimum and maximum x-coordinates in parallel.
  // These points are guaranteed to be on the hull.
  auto indices = parlay::iota<indexT>(n);
  auto minmax_it = parlay::minmax_element(indices, [&](indexT i, indexT j) {
    if (S[i].x != S[j].x) return S[i].x < S[j].x;
    return S[i].y < S[j].y; // Tie-break using y
  });
  indexT l_idx = *minmax_it.first;
  indexT r_idx = *minmax_it.second;

  // 2. Partition the remaining points into two sets:
  //    - top_points: points "above" the line segment (l_idx, r_idx)
  //    - bottom_points: points "below" the line segment (l_idx, r_idx)
  auto other_indices = parlay::filter(indices, [&](indexT i) {
    return i != l_idx && i != r_idx;
  });

  auto flags = parlay::tabulate(other_indices.size(), [&](size_t i) -> int {
      double area = triArea(P[l_idx], P[r_idx], P[other_indices[i]]);
      if (area > 0.0) return 1; // Top
      if (area < 0.0) return 2; // Bottom
      return 0; // Collinear (discard)
  });

  parlay::sequence<indexT> top_points;
  parlay::sequence<indexT> bottom_points;
  parlay::par_do(
      [&] { top_points = parlay::pack(other_indices, parlay::delayed_seq<bool>(flags.size(), [&](size_t i) { return flags[i] == 1; })); },
      [&] { bottom_points = parlay::pack(other_indices, parlay::delayed_seq<bool>(flags.size(), [&](size_t i) { return flags[i] == 2; })); }
  );

  // 3. Recursively find the hull for the top and bottom sets in parallel.
  parlay::sequence<indexT> top_hull, bottom_hull;
  parlay::par_do(
    [&] { top_hull = parallel_quick_hull_rec(parlay::make_slice(top_points), S, l_idx, r_idx); },
    [&] { bottom_hull = parallel_quick_hull_rec(parlay::make_slice(bottom_points), S, r_idx, l_idx); }
  );

  // 4. Combine the results to form the final clockwise convex hull.
  // The final order is: l_idx, reversed top_hull, r_idx, bottom_hull.
  parlay::sequence<indexT> result;
  result.reserve(top_hull.size() + bottom_hull.size() + 2);
  result.push_back(l_idx);
  parlay::reverse_inplace(top_hull);
  result.append(parlay::make_slice(top_hull));
  result.push_back(r_idx);
  result.append(parlay::make_slice(bottom_hull));

  return result;
}

// Recursive helper function for parallel QuickHull.
// Finds the hull for the set of `indices` that lie to one side of the line (p1_idx, p2_idx).
static parlay::sequence<indexT> parallel_quick_hull_rec(
    parlay::slice<const indexT> indices,
    parlay::sequence<point> const& P,
    indexT p1_idx,
    indexT p2_idx) {

  size_t n = indices.size();
  if (n == 0) {
    return parlay::sequence<indexT>();
  }

  // Use serial version for small inputs to reduce parallel overhead.
  if (n < SERIAL_THRESHOLD) {
    // serialQuickHull works in-place, so we need a mutable copy of the indices.
    parlay::sequence<indexT> indices_copy(indices.begin(), indices.end());
    size_t m = serialQuickHull(indices_copy.data(), P.data(), n, p1_idx, p2_idx);
    return indices_copy.cut(0, m);
  }

  // 1. Find the point `p_max_idx` that is furthest from the line segment (p1_idx, p2_idx).
  auto max_it = parlay::max_element(indices, [&](indexT a, indexT b) {
