  });
  indexT p_max_idx = *max_it;

  // 2. Partition the remaining points into two sets for the recursive calls.
  // Points inside the triangle (p1_idx, p_max_idx, p2_idx) are discarded.
  auto flags = parlay::tabulate(indices.size(), [&](size_t i) -> int {
      indexT curr_idx = indices[i];
      if (curr_idx == p_max_idx) return 0; // Exclude p_max_idx itself
      if (triArea(P[p1_idx], P[p_max_idx], P[curr_idx]) > 0.0) return 1; // S1
      if (triArea(P[p_max_idx], P[p2_idx], P[curr_idx]) > 0.0) return 2; // S2
      return 0; // Discard
  });

  parlay::sequence<indexT> s1, s2;
  parlay::par_do(
      [&] { s1 = parlay::pack(indices, parlay::delayed_seq<bool>(flags.size(), [&](size_t i) { return flags[i] == 1; })); },
      [&] { s2 = parlay::pack(indices, parlay::delayed_seq<bool>(flags.size(), [&](size_t i) { return flags[i] == 2; })); }
  );

