  parlay::sequence<indexT> hull1, hull2;
  parlay::par_do(
    [&] { hull1 = parallel_quick_hull_rec(parlay::make_slice(s1), P, p1_idx, p_max_idx); },
    [&] { hull2 = parallel_quick_hull_rec(parlay::make_slice(s2), P, p_max_idx, p2_idx); }
  );

  // 4. Combine the results: hull1, p_max_idx, hull2
  parlay::sequence<indexT> result;
  result.reserve(hull1.size() + hull2.size() + 1);
  result.append(parlay::make_slice(hull1));
  result.push_back(p_max_idx);
  result.append(parlay::make_slice(hull2));

  return result;
}

