// Main hull function: computes the convex hull of a set of 2D points.
parlay::sequence<indexT> hull(parlay::sequence<point> const &S) {
  size_t n = S.size();
  auto P = S.begin();

  // The convex hull of fewer than 3 points is the points themselves.
  // We sort them by x-coordinate to be deterministic, as required.
  if (n < 3) {
    auto I = parlay::tabulate(n, [](size_t i) { return static_cast<indexT>(i); });
    if (n == 2) {
        bool p0_is_left = (P[I[0]].x < P[I[1]].x) || 
                          (P[I[0]].x == P[I[1]].x && P[I[0]].y < P[I[1]].y);
        if (!p0_is_left) std::swap(I[0], I[1]);
    }
    return I;
  }

  // Find the leftmost and rightmost points in parallel.
  // These points are guaranteed to be on the convex hull.
  // The leftmost point `l` is the one with min x, breaking ties with min y.
  auto l_it = parlay::min_element(parlay::iota<indexT>(n), [&](indexT i, indexT j) {
    if (P[i].x != P[j].x) return P[i].x < P[j].x;
    return P[i].y < P[j].y;
  });
  indexT l = *l_it;

  // The rightmost point `r` is the one with max x, breaking ties with max y.
  auto r_it = parlay::max_element(parlay::iota<indexT>(n), [&](indexT i, indexT j) {
    if (P[i].x != P[j].x) return P[i].x < P[j].x;
    return P[i].y < P[j].y;
  });
  indexT r = *r_it;

  // The line segment lr splits the other points into two sets:
  // - "above": points to the left of the directed line l -> r (forms the upper hull)
  // - "below": points to the left of the directed line r -> l (forms the lower hull)
  // We use `parlay::filter` to create these two sets in parallel.
  auto initial_indices = parlay::iota<indexT>(n);

  auto above = parlay::filter(initial_indices, [&](indexT i) {
    return triArea(P[l], P[r], P[i]) > 0.0;
  });
  auto below = parlay::filter(initial_indices, [&](indexT i) {
    return triArea(P[r], P[l], P[i]) > 0.0;
  });

  parlay::sequence<indexT> upper_hull, lower_hull;

  // Recursively find the upper and lower hulls in parallel.
  parlay::par_do(
      [&] { upper_hull = parallel_quick_hull_rec(above.slice(), S, l, r); },
      [&] { lower_hull = parallel_quick_hull_rec(below.slice(), S, r, l); }
  );

  // Combine the results into a single clockwise-ordered hull.
  // The required path is l -> (lower hull points) -> r -> (upper hull points) -> l.
  // `parallel_quick_hull_rec(..., l, r)` returns points ordered from l to r.
  // `parallel_quick_hull_rec(..., r, l)` returns points ordered from r to l.
  // For a clockwise hull, we need the upper hull points ordered from r to l.
  // Our `upper_hull` result is from l to r, so we reverse it.
  parlay::reverse_inplace(upper_hull);

  parlay::sequence<indexT> result;
  result.reserve(1 + upper_hull.size() + 1 + lower_hull.size());
  result.push_back(l);
  result.append(std::move(upper_hull));
  result.push_back(r);
  result.append(std::move(lower_hull));

  return result;
}

// Parallel recursive implementation of QuickHull.
parlay::sequence<indexT> parallel_quick_hull_rec(
    parlay::slice<const indexT*, const indexT*> indices,
    const parlay::sequence<point>& P_seq,
    indexT p1, indexT p2) {

  auto P = P_seq.begin();
  size_t n = indices.size();

  if (n == 0) {
    return parlay::sequence<indexT>();
  }

  // For small subproblems, switch to the serial version to reduce parallel overhead.
  if (n < PARALLEL_THRESHOLD) {
    return serial_quick_hull_rec(indices, P_seq, p1, p2);
  }

  // Find the point `p_max` that is furthest from the line segment p1-p2.
  // This point must be on the hull for this subproblem.
  auto p_max_it = parlay::max_element(indices, [&](indexT i, indexT j) {
    return triArea(P[p1], P[p2], P[i]) < triArea(P[p1], P[p2], P[j]);
  });
  indexT p_max = *p_max_it;

  // Recursively find the hull for points to the left of p1-p_max and p_max-p2.
  // Points inside the triangle p1-p_max-p2 are internal and can be discarded.
  auto s1 = parlay::filter(indices, [&](indexT i) {
    return triArea(P[p1], P[p_max], P[i]) > 0.0;
  });
  auto s2 = parlay::filter(indices, [&](indexT i) {
    return triArea(P[p_max], P[p2], P[i]) > 0.0;
  });

  parlay::sequence<indexT> h1, h2;
  parlay::par_do(
      [&] { h1 = parallel_quick_hull_rec(s1.slice(), P_seq, p1, p_max); },
      [&] { h2 = parallel_quick_hull_rec(s2.slice(), P_seq, p_max, p2); }
  );

  // Combine the results: (hull from p1 to p_max), p_max, (hull from p_max to p2)
  h1.push_back(p_max);
  h1.append(std::move(h2));
  return h1;
}

// Serial recursive implementation of QuickHull for base cases.
parlay::sequence<indexT> serial_quick_hull_rec(
    parlay::slice<const indexT*, const indexT*> indices,
    const parlay::sequence<point>& P_seq,
    indexT p1, indexT p2) {

  auto P = P_seq.begin();
  size_t n = indices.size();

  if (n == 0) {
    return parlay::sequence<indexT>();
  }

  // Find the point `p_max` furthest from the line segment p1-p2.
  indexT p_max = indices[0];
  double max_area = triArea(P[p1], P[p2], P[p_max]);

  for (size_t i = 1; i < n; ++i) {
    double area = triArea(P[p1], P[p2], P[indices[i]]);
    if (area > max_area) {
      max_area = area;
      p_max = indices[i];
    }
  }

  // Partition the remaining points into two sets for recursion.
  // Pre-allocating sequence memory can offer a small speedup.
  parlay::sequence<indexT> s1, s2;
  s1.reserve(n);
  s2.reserve(n);
  for (indexT curr : indices) {
    if (triArea(P[p1], P[p_max], P[curr]) > 0.0) {
      s1.push_back(curr);
    } else if (triArea(P[p_max], P[p2], P[curr]) > 0.0) {
      s2.push_back(curr);
    }
  }

  // Recurse serially.
  auto h1 = serial_quick_hull_rec(s1.slice(), P_seq, p1, p_max);
  auto h2 = serial_quick_hull_rec(s2.slice(), P_seq, p_max, p2);

  // Combine results.
  h1.push_back(p_max);
  h1.append(std::move(h2));
  return h1;
}
