using namespace std;

// Forward declaration of the recursive helper function
parlay::sequence<indexT> quickhull_rec(
    parlay::sequence<point> const& P,
    parlay::sequence<indexT> indices,
    indexT p1_idx, indexT p2_idx);

parlay::sequence<indexT> hull(parlay::sequence<point> const &S) {
    size_t n = S.size();
    if (n <= 3) {
        // For small n, the hull is all the points.
        // The problem expects clockwise order, but for <= 2 points it is ambiguous.
        // For 3 points, sorting would be needed, but n is expected to be large.
        // Returning all points is a reasonable fallback for these trivial cases.
        return parlay::tabulate(n, [](indexT i) { return i; });
    }

    // 1. Find points with min and max x-coordinates in parallel.
    // Tie-break on y-coordinate to get unique, deterministic points.
    auto less_x = [&](indexT i, indexT j) {
        if (S[i].x < S[j].x) return true;
        if (S[i].x > S[j].x) return false;
        return S[i].y < S[j].y;
    };

    auto minmax_it = parlay::minmax_element(parlay::iota<indexT>(n), less_x);
    indexT l = *minmax_it.first;  // Point with min x, then min y
    indexT r = *minmax_it.second; // Point with max x, then max y

    // 2. Partition the other points into upper and lower sets in a single parallel pass.
    // The directed line from l to r splits the plane. We find points to its left (upper)
    // and right (lower).
    auto other_indices = parlay::filter(parlay::iota<indexT>(n), [&](indexT i) {
        return i != l && i != r;
    });

    auto flags = parlay::delayed_seq<int>(other_indices.size(), [&](size_t i) {
        // A small epsilon is used for floating point robustness
        constexpr coord epsilon = 1e-9;
        auto area = triArea(S[l], S[r], S[other_indices[i]]);
        if (area > epsilon) return 0;  // Upper hull candidates (left of l->r)
        if (area < -epsilon) return 2; // Lower hull candidates (right of l->r)
        return 1;                      // Collinear points, discard
    });

    auto parts = parlay::split_three(other_indices, flags);
    parlay::sequence<indexT> upper_indices = std::move(std::get<0>(parts));
    parlay::sequence<indexT> lower_indices = std::move(std::get<2>(parts));

    // 3. Find upper and lower hulls in parallel using recursive calls.
    parlay::sequence<indexT> upper_hull_pts, lower_hull_pts;
    parlay::par_do(
        [&] { upper_hull_pts = quickhull_rec(S, std::move(upper_indices), l, r); },
        // For the lower hull, we check against the directed line from r to l
        [&] { lower_hull_pts = quickhull_rec(S, std::move(lower_indices), r, l); }
    );

    // 4. Combine results into a clockwise sorted hull.
    // The clockwise order is: l -> (lower hull) -> r -> (upper hull) -> l.
    // Our quickhull_rec(..., p1, p2) returns points ordered from p1 to p2.
    // So, upper_hull_pts is l->r, and lower_hull_pts is r->l.
    // To get clockwise order, we need l, lower_hull_pts(r->l), r, upper_hull_pts(r->l).
    // We achieve this by reversing the upper_hull_pts sequence.
    size_t m1 = upper_hull_pts.size();
    size_t m2 = lower_hull_pts.size();
    parlay::sequence<indexT> result(m1 + m2 + 2);

    result[0] = l;
    parlay::parallel_for(0, m1, [&](size_t i) {
        result[i + 1] = upper_hull_pts[m1 - 1 - i];
    });
    result[m1 + 1] = r;
    parlay::parallel_for(0, m2, [&](size_t i) {
        result[m1 + 2 + i] = lower_hull_pts[i];
    });

    return result;
}

// Recursive parallel quickhull implementation.
// Finds hull points to the left of the directed line from p1_idx to p2_idx.
// Returns the indices of these hull points ordered along the hull from p1_idx to p2_idx.
parlay::sequence<indexT> quickhull_rec(
    parlay::sequence<point> const& P,
    parlay::sequence<indexT> indices, // Pass by value for ownership
    indexT p1_idx, indexT p2_idx) {

    // Threshold to switch to the serial implementation for small subproblems.
    // This value can be tuned for optimal performance.
    constexpr size_t SERIAL_THRESHOLD = 4096;

    if (indices.empty()) {
        return parlay::sequence<indexT>();
    }

    if (indices.size() < SERIAL_THRESHOLD) {
        // serialQuickHull modifies the input array in place.
        // Since `indices` is passed by value, it is a unique copy and safe to modify.
        size_t m = serialQuickHull(indices.data(), P.data(), indices.size(), p1_idx, p2_idx);
        return parlay::sequence<indexT>(indices.begin(), indices.begin() + m);
    }

    // 1. Find the point furthest from the line (p1, p2) in parallel.
    // This is the point with the maximum signed area of the triangle (p1, p2, p_i).
    auto furthest_it = parlay::max_element(indices, [&](indexT i, indexT j) {
        return triArea(P[p1_idx], P[p2_idx], P[i]) < triArea(P[p1_idx], P[p2_idx], P[j]);
    });
    indexT h_idx = *furthest_it;

    // 2. Partition the remaining points into two sets for recursive calls.
    // S1: points to the left of the directed line (p1, h)
    // S2: points to the left of the directed line (h, p2)
    // Points inside the triangle (p1, h, p2) are discarded.
    auto flags = parlay::delayed_seq<int>(indices.size(), [&](size_t i) {
        constexpr coord epsilon = 1e-9;
        indexT curr_idx = indices[i];
        if (curr_idx == h_idx) return 1; // Discard h_idx from subproblems
        if (triArea(P[p1_idx], P[h_idx], P[curr_idx]) > epsilon) return 0; // S1
        if (triArea(P[h_idx], P[p2_idx], P[curr_idx]) > epsilon) return 2; // S2
        return 1; // Discard points inside the triangle or on the lines
    });

    auto parts = parlay::split_three(indices, flags);
    parlay::sequence<indexT> s1 = std::move(std::get<0>(parts));
    parlay::sequence<indexT> s2 = std::move(std::get<2>(parts));

    // 3. Recurse in parallel on the two subproblems.
    parlay::sequence<indexT> r1, r2;
    parlay::par_do(
        [&] { r1 = quickhull_rec(P, std::move(s1), p1_idx, h_idx); },
        [&] { r2 = quickhull_rec(P, std::move(s2), h_idx, p2_idx); }
    );

    // 4. Combine results: (hull from p1 to h), h, (hull from h to p2).
    // This creates a sequence of hull points ordered along the hull from p1 to p2.
    size_t len1 = r1.size();
    size_t len2 = r2.size();
    parlay::sequence<indexT> result(len1 + 1 + len2);
    parlay::parallel_for(0, len1, [&](size_t i) { result[i] = r1[i]; });
    result[len1] = h_idx;
    parlay::parallel_for(0, len2, [&](size_t i) { result[len1 + 1 + i] = r2[i]; });

    return result;
}
