using parlay::parallel_for;
using parlay::sequence;
using parlay::delayed_seq;
using parlay::tabulate;
using parlay::reduce;
using parlay::pack;
using parlay::make_monoid;
using parlay::random_permutation;
using parlay::internal::pack_out;
using std::cout;
using std::endl;

// if on verifies the Delaunay is correct 
#define CHECK 0

using vertex_t = vertex<point>;
using simplex_t = simplex<point>;
using triang_t = triangle<point>;
using vect = typename point::vector;

template <typename point>
struct Qs {
  vector<vertex<point>*> vertexQ;
  vector<simplex<point>> simplexQ;
  Qs() {
    vertexQ.reserve(100); // Increased reserve size for performance
    simplexQ.reserve(100); // Increased reserve size for performance
  }
};
using Qs_t = Qs<point>;

// *************************************************************
//    ROUTINES FOR FINDING AND INSERTING A NEW POINT
// *************************************************************

// Finds a vertex (p) in a mesh starting at any triangle (start)
// Requires that the mesh is properly connected and convex
simplex_t find(vertex_t *p, simplex_t start) {
  simplex_t t = start;
  while (1) {
    int i;
    for (i=0; i < 3; i++) {
      t = t.rotClockwise();
      if (t.outside(p)) {t = t.across(); break;}
    }
    if (i==3) return t; // Found containing triangle
    if (!t.valid()) return t; // Walked off the mesh
  }
}

// Iterative routine for finding a cavity across an edge with
// respect to a vertex p. Replaces the original recursive version
// for performance and to avoid stack overflow.
void findCavity(simplex_t t, vertex_t *p, Qs_t *q) {
  if (!t.valid()) return;
  parlay::sequence<simplex_t> stack;
  stack.reserve(64);
  stack.push_back(t);

  while(!stack.empty()) {
    simplex_t curr = stack.back();
    stack.pop_back();

    if (curr.inCirc(p)) {
      q->simplexQ.push_back(curr);
      curr = curr.rotClockwise();
      simplex_t next1 = curr.across();
      if (next1.valid()) stack.push_back(next1);

      q->vertexQ.push_back(curr.firstVertex());

      curr = curr.rotClockwise();
      simplex_t next2 = curr.across();
      if (next2.valid()) stack.push_back(next2);
    }
  }
}

// Finds the cavity for v and tries to reserve vertices on the 
// boundary (v must be inside of the simplex t)
void reserve_for_insert(vertex_t *v, simplex_t t, Qs_t *q) {
  // each iteration searches out from one edge of the triangle
  for (int i=0; i < 3; i++) {
    q->vertexQ.push_back(t.firstVertex());
    findCavity(t.across(), v, q);
    t = t.rotClockwise();
  }

  // Atomically reserve the boundary vertices using a compare-and-swap loop.
  // The vertex with the highest ID wins the reservation.
  for (size_t i = 0; i < q->vertexQ.size(); i++) {
    pbbs::write_max(&((q->vertexQ)[i]->reserve), v->id, std::less<int>());
  }
}

// Checks if v "won" on all adjacent vertices and inserts point if so.
// This version is corrected to be race-free by separating the check
// phase from the modification phase.
bool insert(vertex_t *v, simplex_t t, Qs_t *q) {
  // Phase 1: Check if this insertion won all reservations.
  bool won_all = true;
  for (size_t i = 0; i < q->vertexQ.size(); i++) {
    if ((q->vertexQ)[i]->reserve != v->id) {
      won_all = false;
      break;
    }
  }

  // Phase 2: If won all, reset reservations and modify the mesh.
  if (won_all) {
    for (size_t i = 0; i < q->vertexQ.size(); i++) {
      (q->vertexQ)[i]->reserve = -1;
    }
    triang_t* t1 = v->t;  // the memory for the two new triangles
    triang_t* t2 = t1 + 1;  
    t.split(v, t1, t2);
    for (size_t i = 0; i < q->simplexQ.size(); i++) {
      (q->simplexQ)[i].flip();
    }
  }

  q->simplexQ.clear();
  q->vertexQ.clear();
  return !won_all; // Return true on failure (i.e. did not win all)
}

