// *************************************************************
//    CREATING A BOUNDING CIRCULAR REGION AND FILL WITH INITIAL SIMPLICES
// *************************************************************

void generate_boundary(sequence<point> const &P,
		       size_t boundary_size,
		       sequence<vertex_t> &V,
		       sequence<triang_t> &T) {

  size_t n = P.size();
  auto min_f = [] (point x, point y) { return x.minCoords(y);};
  auto max_f = [] (point x, point y) { return x.maxCoords(y);};
  point identity = P[0];
  point min_corner = reduce(P, make_monoid(min_f, identity));
  point max_corner = reduce(P, make_monoid(max_f, identity));
  double size = (max_corner-min_corner).Length();
  double stretch = 10.0;
  double radius = stretch*size;
  point center = min_corner + (max_corner-min_corner)/2.0;
  double pi = 3.14159265358979323846;

  // Generate the bounding points on a circle far outside the bounding box
  parallel_for (0, boundary_size, [&] (size_t i) {
    double x = radius * cos(2*pi*((float) i)/((float) boundary_size));
    double y = radius * sin(2*pi*((float) i)/((float) boundary_size));
    point pt = center + vect(x,y);
    V[i+n] = vertex_t(pt, i + n);
  });

  // Fill with triangles (boundary_size - 2 total)
  simplex_t s = simplex_t(&V[0+n], &V[1+n], &V[2+n], &T[0 + 2*n]); 
  for (size_t i = 3; i < boundary_size; i++)
    s = s.extend(&V[i+n], &T[i - 2 + 2*n]); 
}


// *************************************************************
//    MAIN LOOP
// *************************************************************

void incrementally_add_points(sequence<vertex_t*> v, vertex_t* start) {
  size_t n = v.size();

  size_t max_block_size = (size_t) (n/1000) + 1;

  sequence<vertex_t*> done(n);
  sequence<vertex_t*> buffer(max_block_size);
  sequence<vertex_t*> remain;
  sequence<simplex_t> t(max_block_size);
  sequence<bool> flags(max_block_size);
  auto VQ = tabulate(max_block_size, [&] (size_t i) -> Qs_t {return Qs_t();});

  using KNN = k_nearest_neighbors<vertex_t,1>;
  sequence<vertex_t*> init(1,start);
  KNN knn = KNN(init);

  size_t num_done = 0;
  size_t rounds = 0;
  size_t num_remain = 0;
  size_t num_next_rebuild = 100;
  size_t multiplier = 4; // Tuned for more frequent k-NN rebuilds

  while (num_done < n) {
    // Periodically rebuild the point location structure with all inserted points.
    if (num_done >= num_next_rebuild && num_done < n/2) {
      auto vtxs = parlay::to_sequence(done.cut(0,num_done));
      knn = KNN(vtxs);
      num_next_rebuild *= multiplier;
    }

    // Determine how many vertices to try in parallel for this round.
    size_t num_round = std::min({(size_t) (1 + num_done/25), n-num_done, max_block_size});

    // Phase 1: For each trial vertex, find its containing triangle,
    // determine the cavity, and reserve boundary vertices.
    parallel_for (0, num_round, [&] (size_t j) {
      buffer[j] = (j < num_remain) ? remain[j] : v[j + num_done];
      vertex_t *u = knn.nearest(buffer[j]);
      t[j] = find(buffer[j], simplex(u->t, 0));
      reserve_for_insert(buffer[j], t[j], &VQ[j]);});

    // Phase 2: Check reservations and insert points that won all their conflicts.
    parallel_for (0, num_round, [&] (size_t j) {
				  flags[j] = insert(buffer[j], t[j], &VQ[j]);});

    // Pack failed vertices to be retried, and successful vertices into the 'done' list.
    remain = pack(buffer.cut(0,num_round), flags.cut(0,num_round));
    num_remain = remain.size();
    size_t num_done_in_round = num_round - num_remain;
    auto not_flags = delayed_seq<bool>(num_round, [&] (size_t i) {return !flags[i];});
    pack_out(buffer.cut(0,num_round), not_flags, done.cut(num_done, num_done + num_done_in_round));

    num_done += num_done_in_round;
    rounds++;
  }
}


// *************************************************************
//    DRIVER
// *************************************************************

triangles<point> delaunay(sequence<point> &P) {
  timer t("delaunay", false);
  t.start();
  size_t boundary_size = 10;
  size_t n = P.size();

  if (n == 0) {
      return triangles<point>();
  }

  // Allocate memory for all vertices and triangles up front
  size_t num_vertices = n + boundary_size;
  auto Vertices = sequence<vertex_t>(num_vertices);

  size_t boundary_triangles = (boundary_size - 2);
  size_t num_triangles = 2 * n + boundary_triangles;
  auto Triangles = sequence<triang_t>(num_triangles); 

  // Put points in a random order to avoid worst-case insertion scenarios
  sequence<size_t> perm = random_permutation<size_t>(n);
  parallel_for(0, n, [&] (size_t i) {
    Vertices[perm[i]] = vertex_t(P[i], i);
    // Each new vertex gets memory for two new triangles it will create upon insertion.
    Vertices[perm[i]].t = &Triangles[2*perm[i]];
  });

  // Generate boundary points and the initial triangulation
  generate_boundary(P, boundary_size, Vertices, Triangles);

  // Create a sequence of pointers to the vertices to be inserted
  auto V = tabulate(n, [&] (size_t i) -> vertex_t* {
			 return &Vertices[i];});
  vertex_t* v0 = &Vertices[n]; // A starting vertex on the boundary

  t.next("initialize");

  // Main parallel insertion loop
  incrementally_add_points(V, v0);
  t.next("add points");

  if (CHECK) check_delaunay(Triangles, boundary_size);

  // Filter out uninitialized triangles and format the output
  auto is_initialized = parlay::delayed_seq<bool>(num_triangles, [&] (size_t i) {
      return Triangles[i].vtx[0] != nullptr;
  });
  auto valid_triangles = parlay::pack(Triangles, is_initialized);

  auto result_triangles = tabulate(valid_triangles.size(), [&] (size_t i) -> tri {
    vertex_t** vtx = valid_triangles[i].vtx;
    return {(int) vtx[0]->id, (int) vtx[1]->id, (int) vtx[2]->id};
  });

  auto result_points = tabulate(num_vertices, [&] (size_t i) {
    return Vertices[i].pt;
  });

  t.next("generate output");

  return triangles<point>(result_points, result_triangles);
}
