using vertex_t = vertex<point>;
using simplex_t = simplex<point>;
using triang_t = triangle<point>;
using vect = typename point::vector;

template <typename point>
struct Qs {
  // Use std::vector for cheap clear() and dynamic growth.
  // Pre-reserving helps avoid reallocations.
  std::vector<vertex<point>*> vertexQ;
  std::vector<simplex<point>> simplexQ;
  Qs() {
    vertexQ.reserve(64);
    simplexQ.reserve(64);
  }
};
using Qs_t = Qs<point>;

// *************************************************************
//    ROUTINES FOR FINDING AND INSERTING A NEW POINT
// *************************************************************

// Finds a vertex (p) in a mesh starting at any triangle (start)
// Requires that the mesh is properly connected and convex
simplex_t find(vertex_t *p, simplex_t start) {
  simplex_t t = start;
  while (true) {
    int i;
    for (i=0; i < 3; i++) {
      t = t.rotClockwise();
      if (t.outside(p)) {
        t = t.across();
        break;
      }
    }
    if (i==3) return t;
    if (!t.valid()) return t;
  }
}

// Recursive routine for finding a cavity across an edge with
// respect to a vertex p.
// The simplex has orientation facing the direction it is entered.
void findCavity(simplex_t t, vertex_t *p, Qs_t *q) {
  if (t.valid() && t.inCirc(p)) {
    q->simplexQ.push_back(t);
    t = t.rotClockwise();
    findCavity(t.across(), p, q);
    q->vertexQ.push_back(t.firstVertex());
    t = t.rotClockwise();
    findCavity(t.across(), p, q);
  }
}

// Finds the cavity for v and tries to reserve vertices and triangles on the
// boundary (v must be inside of the simplex t)
void reserve_for_insert(vertex_t *v, simplex_t t, Qs_t *q) {
  // 1. Find the cavity by recursive expansion
  for (int i=0; i < 3; i++) {
    q->vertexQ.push_back(t.firstVertex());
    findCavity(t.across(), v, q);
    t = t.rotClockwise();
  }

  // 2. Sort and unique boundary vertices. This is a small sequential task per thread.
  std::sort(q->vertexQ.begin(), q->vertexQ.end());
  q->vertexQ.erase(std::unique(q->vertexQ.begin(), q->vertexQ.end()), q->vertexQ.end());

  // 3. Attempt to lock all required mesh elements with the vertex's ID.
  int v_id = v->id;
  // Lock containing triangle
  pbbs::write_max(&(t.t->reserve), v_id, std::less<int>());
  // Lock triangles within the cavity
  for (auto& s : q->simplexQ) {
    pbbs::write_max(&(s.t->reserve), v_id, std::less<int>());
  }
  // Lock vertices on the cavity boundary
  for (auto& u : q->vertexQ) {
    pbbs::write_max(&(u->reserve), v_id, std::less<int>());
  }
}

// Checks if v "won" all locks and inserts the point if so.
// Returns true on failure (needs retry), false on success.
bool insert(vertex_t *v, simplex_t t, Qs_t *q) {
  bool success = true;
  int v_id = v->id;

  // 1. Atomically check all locks.
  if (t.t->reserve.load(std::memory_order_relaxed) != v_id) success = false;

  if (success) {
    for (vertex_t* u : q->vertexQ) {
      if (u->reserve.load(std::memory_order_relaxed) != v_id) {
        success = false;
        break;
      }
    }
  }

  if (success) {
    for (auto& s : q->simplexQ) {
      if (s.t->reserve.load(std::memory_order_relaxed) != v_id) {
        success = false;
        break;
      }
    }
  }

  // 2. If successful, modify the mesh and release locks.
  if (success) {
    triang_t* t1 = v->t;
    triang_t* t2 = t1 + 1;
    t.split(v, t1, t2);
    for (size_t i=0; i<q->simplexQ.size(); i++) {
      (q->simplexQ)[i].flip();
    }
    // Release locks (atomic not required, we are the sole owner)
    t.t->reserve.store(-1, std::memory_order_relaxed);
    for (auto& s : q->simplexQ) s.t->reserve.store(-1, std::memory_order_relaxed);
    for (auto& u : q->vertexQ) u->reserve.store(-1, std::memory_order_relaxed);
  } else {
    // 3. If failed, clean up any locks this thread might have won.
    // Use CAS to avoid overwriting a lock from a thread with a higher ID.
    pbbs::atomic_compare_and_swap(&(t.t->reserve), v_id, -1);
    for (auto& s : q->simplexQ) {
      pbbs::atomic_compare_and_swap(&(s.t->reserve), v_id, -1);
    }
    for (auto& u : q->vertexQ) {
      pbbs::atomic_compare_and_swap(&(u->reserve), v_id, -1);
    }
  }

  q->simplexQ.clear();
  q->vertexQ.clear();
  return !success; // return true if retry is needed
}


// *************************************************************
//    CHECKING THE TRIANGULATION
