void check_delaunay(sequence<triang_t> &Triangles, size_t boundary_size) {
  size_t n = Triangles.size();
  sequence<size_t> boundary_count(n, 0);
  parallel_for (0, n, [&] (size_t i) {
    if (Triangles[i].vtx[0] != nullptr) { // Check if triangle is valid
      simplex_t t = simplex(&Triangles[i], 0);
      for (int j=0; j < 3; j++) {
        simplex_t a = t.across();
        if (a.valid()) {
          vertex_t* v = a.rotClockwise().firstVertex();
          if (!t.outside(v)) {
            cout << "Inside Out: "; v->pt.print(); t.print();}
          if (t.inCirc(v)) {
            cout << "In Circle Violation: "; v->pt.print(); t.print(); }
        } else boundary_count[i]++;
        t = t.rotClockwise();
      }
    } });
  if (boundary_size != reduce(boundary_count))
    cout << "Wrong boundary size: should be " << boundary_size
         << " is " << reduce(boundary_count) << endl;
}

// *************************************************************
//    CREATING A BOUNDING REGION
// *************************************************************

void generate_boundary(sequence<point> const &P,
                       size_t boundary_size,
                       sequence<vertex_t> &V,
                       sequence<triang_t> &T) {

  size_t n = P.size();
  auto min_f = [] (point x, point y) { return x.minCoords(y);};
  auto max_f = [] (point x, point y) { return x.maxCoords(y);};
  point identity = P[0];
  point min_corner = reduce(P, make_monoid(min_f, identity));
  point max_corner = reduce(P, make_monoid(max_f, identity));
  vect diff = max_corner-min_corner;
  point center = min_corner + diff/2.0;
  double size = diff.Length();
  double radius = size * 10.0; // Large circle
  double pi = 3.14159265358979323846;

  // Generate bounding points on a circle
  parallel_for (0, boundary_size, [&] (size_t i) {
    double angle = 2.0 * pi * i / boundary_size;
    point pt = center + vect(radius * cos(angle), radius * sin(angle));
    V[i+n] = vertex_t(pt, i + n);
  });

  // Fill with triangles
  simplex_t s = simplex_t(&V[n], &V[n+1], &V[n+2], &T[2*n]);
  for (size_t i = 3; i < boundary_size; i++)
    s = s.extend(&V[i+n], &T[2*n + i - 2]);
}

// *************************************************************
//    MAIN LOOP
// *************************************************************

void incrementally_add_points(sequence<vertex_t*> v, vertex_t* start) {
  size_t n = v.size();
  if (n == 0) return;

  size_t max_block_size = (n / 1000) + 128;
  sequence<vertex_t*> done(n);
  sequence<vertex_t*> buffer(max_block_size);
  sequence<simplex_t> t(max_block_size);
  sequence<bool> flags(max_block_size);
  auto VQ = tabulate(max_block_size, [&] (size_t i) {return Qs_t();});

  using KNN = k_nearest_neighbors<vertex_t,1>;
  sequence<vertex_t*> init(1,start);
  KNN knn(init);

  size_t num_done = 0;
  size_t num_remain = 0;
  size_t rounds = 0;
  size_t num_next_rebuild = 100;

  sequence<vertex_t*> remain;

  while (num_done < n) {
    // Periodically rebuild the k-NN structure for faster point location
    if (num_done >= num_next_rebuild && num_done < n/2) {
      auto vtxs = parlay::to_sequence(done.cut(0,num_done));
      knn = KNN(vtxs);
      num_next_rebuild *= 10;
    }

    // Determine number of vertices to process in this round
    size_t num_round = std::min({(size_t)1 + num_done/20, n - num_done, max_block_size});

    // Phase 1: Point location and cavity reservation
    parallel_for (0, num_round, [&] (size_t j) {
      buffer[j] = (j < num_remain) ? remain[j] : v[j - num_remain + num_done];
      vertex_t *u = knn.nearest(buffer[j]);
      t[j] = find(buffer[j], simplex(u->t, 0));
      reserve_for_insert(buffer[j], t[j], &VQ[j]);
    });

    // Phase 2: Check locks and commit insertions
    parallel_for (0, num_round, [&] (size_t j) {
      flags[j] = insert(buffer[j], t[j], &VQ[j]);
    });

    // Pack failed vertices for the next round, and successful ones to the done array
    remain = pack(buffer.cut(0,num_round), flags.cut(0,num_round));
    num_remain = remain.size();
    size_t num_done_in_round = num_round - num_remain;

    auto not_flags = delayed_seq<bool>(num_round, [&] (size_t i) {return !flags[i];});
    pack_out(buffer.cut(0,num_round), not_flags, done.cut(num_done, num_done + num_done_in_round));

    num_done += num_done_in_round;
    rounds++;
  }
}

// *************************************************************
//    DRIVER
// *************************************************************

triangles<point> delaunay(sequence<point> &P) {
  timer t("delaunay", false);
  t.start();
  size_t n = P.size();
  if (n == 0) return triangles<point>();

  size_t boundary_size = 10;
  size_t num_vertices = n + boundary_size;
  auto Vertices = sequence<vertex_t>(num_vertices);

  size_t boundary_triangles = (boundary_size - 2);
  size_t num_triangles = 2 * n + boundary_triangles;
  auto Triangles = sequence<triang_t>(num_triangles);

  // Initialize reserve fields to -1 (unlocked)
  parallel_for(0, num_triangles, [&](size_t i) { Triangles[i].reserve = -1; });

  // Create vertices from points in a random order
  sequence<size_t> perm = random_permutation<size_t>(n);
  parallel_for(0, n, [&] (size_t i) {
    Vertices[perm[i]] = vertex_t(P[i], i);
  });

  // Assign triangle memory for each new vertex
  parallel_for (0, n, [&] (size_t i) {
    Vertices[i].t = &Triangles[2*i];
  });

  // Create a bounding region and initial triangulation
  generate_boundary(P, boundary_size, Vertices, Triangles);

  // Create a sequence of pointers to the vertices to be inserted
  auto V = tabulate(n, [&] (size_t i) -> vertex_t* { return &Vertices[i]; });
  vertex_t* v_start = &Vertices[n]; // A vertex on the boundary

  t.next("initialize");

  // Main parallel incremental insertion loop
  incrementally_add_points(V, v_start);
  t.next("add points");

  if (CHECK) check_delaunay(Triangles, boundary_size);

  // Format output: filter out invalidated triangles from the pre-allocated block
  auto live_triangles_map = tabulate(num_triangles, [&](size_t i) {
    return Triangles[i].vtx[0] != nullptr;
  });
  auto live_triangles = pack(parlay::iota(num_triangles), live_triangles_map);

  auto result_triangles = tabulate(live_triangles.size(), [&] (size_t i) -> tri {
    vertex_t** vtx = Triangles[live_triangles[i]].vtx;
    return {(int) vtx[0]->id, (int) vtx[1]->id, (int) vtx[2]->id};
  });

  // All original points plus boundary points
  auto result_points = tabulate(num_vertices, [&] (size_t i) {
    return Vertices[i].pt;
  });

  t.next("generate output");

  return triangles<point>(result_points, result_triangles);
}
