    cout << "Wrong boundary size: should be " << boundary_size
         << " is " << reduce(boundary_count) << endl;
}

// *************************************************************
//    CREATING A BOUNDING REGION
// *************************************************************

void generate_boundary(sequence<point> const &P,
                       size_t boundary_size,
                       sequence<vertex_t> &V,
                       sequence<triang_t> &T) {

  size_t n = P.size();
  auto min_f = [] (point x, point y) { return x.minCoords(y);};
  auto max_f = [] (point x, point y) { return x.maxCoords(y);};
  point identity = P[0];
  point min_corner = reduce(P, make_monoid(min_f, identity));
  point max_corner = reduce(P, make_monoid(max_f, identity));
  double size = (max_corner-min_corner).Length();
  double stretch = 10.0;
  double radius = stretch*size;
  point center = min_corner + (max_corner-min_corner)/2.0;
  double pi = 3.141592653589793;

  // Generate the bounding points on a circle
  for (size_t i=0; i < boundary_size; i++) {
    double x = radius * cos(2*pi*((float) i)/((float) boundary_size));
    double y = radius * sin(2*pi*((float) i)/((float) boundary_size));
    point pt = center + vect(x,y);
    V[i+n] = vertex_t(pt, i + n);
  }

  // Fill with triangles
  simplex_t s = simplex_t(&V[n], &V[n+1], &V[n+2], &T[2*n]);
  for (size_t i = 3; i < boundary_size; i++)
    s = s.extend(&V[i+n], &T[2*n + i - 2]);
}


// *************************************************************
//    MAIN LOOP
// *************************************************************

void incrementally_add_points(sequence<vertex_t*> &v,
                              sequence<vertex_t*> &initial_mesh) {
    size_t n = v.size();

    sequence<vertex_t*> work_q = v;
    sequence<vertex_t*> inserted_v(n + initial_mesh.size());
    parlay::parallel_for(0, initial_mesh.size(), [&](size_t i) { inserted_v[i] = initial_mesh[i]; });
    std::atomic<size_t> inserted_v_count = initial_mesh.size();

    parlay::random rand_gen;

    size_t block_size = 256;
    const size_t max_block_size = 1 << 14; // 16384

    while (inserted_v_count < n + initial_mesh.size()) {
        size_t num_to_process = work_q.size();
        size_t current_block_size = std::min({block_size, num_to_process, max_block_size});
        if (current_block_size == 0) break;

        auto current_batch = work_q.cut(0, current_block_size);

        sequence<simplex_t> containing_t(current_block_size);
        auto Qs_vec = tabulate(current_block_size, [&](size_t i) { return Qs_t(); });
        sequence<bool> failed_flags(current_block_size);

        // Phase 1: Locate and Reserve
        parallel_for(0, current_block_size, [&](size_t i) {
            auto r = rand_gen.fork(i);
            vertex_t* p = current_batch[i];
            size_t count = inserted_v_count.load();
            size_t start_idx = r.ith_rand(0) % count;
            vertex_t* start_v = inserted_v[start_idx];
            containing_t[i] = find(p, simplex(start_v->t, 0));
            reserve_for_insert(p, containing_t[i], &Qs_vec[i]);
        });

        // Phase 2: Insert
        parallel_for(0, current_block_size, [&](size_t i) {
            failed_flags[i] = insert(current_batch[i], containing_t[i], &Qs_vec[i]);
        });

        // Update worklists
        auto successful_flags = parlay::delayed_seq<bool>(current_block_size, [&](size_t i) { return !failed_flags[i]; });
        size_t num_succeeded = parlay::count(successful_flags, true);
        size_t num_failed = current_block_size - num_succeeded;

        // Pack successful vertices into the inserted_v array
        parlay::pack_into(current_batch, successful_flags, inserted_v.cut(inserted_v_count, inserted_v_count + num_succeeded));
        inserted_v_count += num_succeeded;

        // Pack failed vertices into a temporary buffer
        sequence<vertex_t*> failed_v(num_failed);
        parlay::pack_into(current_batch, parlay::delayed_seq<bool>(current_block_size, [&](size_t i) { return failed_flags[i]; }), failed_v);

        // Create new work queue for next round: failed vertices first, then remaining.
        auto remaining_from_work_q = work_q.cut(current_block_size, work_q.size());
        work_q = parlay::append(failed_v, remaining_from_work_q);

        // Adapt block size based on success rate
        if (num_failed > num_succeeded * 0.2 && block_size > 256) {
             block_size = std::max((size_t)256, block_size / 2);
        } else if (num_succeeded > num_failed * 4) {
             block_size = std::min(max_block_size, block_size * 3 / 2);
        }
    }
}


// *************************************************************
//    DRIVER
// *************************************************************

triangles<point> delaunay(sequence<point> &P) {
  timer t("delaunay", false);
  t.start();
  size_t boundary_size = 10;
  size_t n = P.size();
  if (n == 0) return triangles<point>();

  // All vertices needed
  size_t num_vertices = n + boundary_size;
  auto Vertices = sequence<vertex_t>(num_vertices);

  // All triangles needed
  size_t boundary_triangles = (boundary_size - 2);
  size_t num_triangles = 2 * n + boundary_triangles;
  auto Triangles = sequence<triang_t>(num_triangles);

  // random permutation to put points in a random order
  sequence<size_t> perm = random_permutation<size_t>(n);
  parallel_for(0, n, [&] (size_t i) {
    Vertices[perm[i]] = vertex_t(P[i], i);});

  // give two triangles to each non-boundary vertex
  parallel_for (0, n, [&] (size_t i) {
    Vertices[i].t = &Triangles[2*i];});

  // generate boundary points and fill with simplices
  generate_boundary(P, boundary_size, Vertices, Triangles);

  // pointers to first n vertices
  auto V = tabulate(n, [&] (size_t i) -> vertex_t* {
                         return &Vertices[i];});

  // Create initial mesh of boundary vertices for point location
  auto initial_mesh = tabulate(boundary_size, [&](size_t i) -> vertex_t* {
      return &Vertices[n+i];
  });

  t.next("initialize");

  // main loop to add all points
  incrementally_add_points(V, initial_mesh);
  t.next("add points");

  if (CHECK) check_delaunay(Triangles, boundary_size);

  // Filter out triangles that were not used or are part of the boundary
  auto valid_triangles = parlay::filter(Triangles, [&](const triang_t& tr) {
    for (int i = 0; i < 3; ++i) {
      if (tr.vtx[i] == nullptr || tr.vtx[i]->id >= n) return false;
    }
    return true;
  });

  // just the three corner ids for each triangle
  auto result_triangles = tabulate(valid_triangles.size(), [&] (size_t i) -> tri {
    vertex_t** vtx = valid_triangles[i].vtx;
    tri r = {(int) vtx[0]->id, (int) vtx[1]->id, (int) vtx[2]->id};
    return r;});

  // just the original points
  auto result_points = P.cut(0, n);

  t.next("generate output");

  return triangles<point>(result_points, result_triangles);
}
