using vertex_t = vertex<point>;
using simplex_t = simplex<point>;
using triang_t = triangle<point>;
using vect = typename point::vector;

template <typename point>
struct Qs {
  // Use parlay::sequence for better integration with the parallel runtime
  // and to avoid potential std::vector reallocations.
  parlay::sequence<vertex<point>*> vertexQ;
  parlay::sequence<simplex<point>> simplexQ;
  Qs() {
    // Reserve a reasonable initial capacity. The average cavity size is small.
    vertexQ.reserve(64);
    simplexQ.reserve(64);
  }
};
using Qs_t = Qs<point>;

// *************************************************************
//    ROUTINES FOR FINDING AND INSERTING A NEW POINT
// *************************************************************

// Finds a vertex (p) in a mesh starting at any triangle (start)
// Requires that the mesh is properly connected and convex
simplex_t find(vertex_t *p, simplex_t start) {
  simplex_t t = start;
  while (true) {
    int i;
    for (i=0; i < 3; i++) {
      t = t.rotClockwise();
      if (t.outside(p)) {
        t = t.across();
        break;
      }
    }
    if (i==3) return t; // Found containing triangle
    if (!t.valid()) return t; // Should not happen in a closed mesh
  }
}

// Recursive routine for finding a cavity across an edge with
// respect to a vertex p. The simplex has orientation facing the
// direction it is entered.
void findCavity(simplex_t t, vertex_t *p, Qs_t *q) {
  if (t.valid() && t.inCirc(p)) {
    q->simplexQ.push_back(t);
    // Recurse on the two neighbors across the other two edges
    simplex_t t1 = t.rotClockwise();
    findCavity(t1.across(), p, q);
    q->vertexQ.push_back(t1.firstVertex());
    simplex_t t2 = t1.rotClockwise();
    findCavity(t2.across(), p, q);
  }
}

// Finds the cavity for v and tries to reserve vertices on the 
// boundary (v must be inside of the simplex t)
// The boundary vertices are pushed onto q->vertexQ and
// simplices to be deleted on q->simplexQ (both initially empty)
// It makes no side effects to the mesh other than to X->reserve
void reserve_for_insert(vertex_t *v, simplex_t t, Qs_t *q) {
  // each iteration searches out from one edge of the triangle
  for (int i=0; i < 3; i++) {
    q->vertexQ.push_back(t.firstVertex());
    findCavity(t.across(), v, q);
    t = t.rotClockwise();
  }
  // The vertex with the maximum id that tries to reserve a boundary vertex 
  // will have its id written. `reserve` starts out as -1.
  for (size_t i = 0; i < q->vertexQ.size(); i++) {
    pbbs::write_max(&((q->vertexQ)[i]->reserve), v->id, std::less<int>());
  }
}

// Checks if v "won" on all adjacent vertices and inserts point if so.
// This version is corrected for race conditions.
// Returns true on failure (needs retry), false on success.
bool insert(vertex_t *v, simplex_t t, Qs_t *q) {
  // Phase 1: Check if we won all locks.
  bool won_all_locks = true;
  for (size_t i = 0; i < q->vertexQ.size(); i++) {
    if ((q->vertexQ)[i]->reserve != v->id) {
      won_all_locks = false;
      break;
    }
  }

  // Phase 2: If we won, atomically reset locks and insert.
  // Otherwise, do nothing and fail.
  if (won_all_locks) {
    for (size_t i = 0; i < q->vertexQ.size(); i++) {
      // Atomically reset the reservation. This is critical to avoid a race
      // with threads from a future batch trying to reserve the same vertex.
      // We only replace it if it is still our id.
      pbbs::atomic_compare_and_swap(&((q->vertexQ)[i]->reserve), v->id, -1);
    }

    triang_t* t1 = v->t;  // the memory for the two new triangles
    triang_t* t2 = t1 + 1;

    // Perform the topological changes to the mesh.
    t.split(v, t1, t2);
    for (size_t i = 0; i < q->simplexQ.size(); i++) {
      (q->simplexQ)[i].flip();
    }
  }

  // Clear the queues for the next use.
  q->simplexQ.clear();
  q->vertexQ.clear();

  // Return true if we failed (!won_all_locks), indicating a retry is needed.
  return !won_all_locks;
}


// *************************************************************
//    CHECKING THE TRIANGULATION
// *************************************************************

void check_delaunay(sequence<triang_t> &Triangles, size_t boundary_size) {
  size_t n = Triangles.size();
  sequence<size_t> boundary_count(n, 0);
  parallel_for (0, n, [&] (size_t i) {
    if (Triangles[i].vtx[0] != nullptr) { // Check if triangle is valid
      simplex_t t = simplex(&Triangles[i], 0);
      for (int j=0; j < 3; j++) {
        simplex_t a = t.across();
        if (a.valid()) {
          vertex_t* v = a.rotClockwise().firstVertex();
          if (!t.outside(v)) {
            cout << "Inside Out Violation: "; v->pt.print(); t.print();}
          if (t.inCirc(v)) {
            cout << "In Circle Violation: "; v->pt.print(); t.print(); }
        } else boundary_count[i]++;
        t = t.rotClockwise();
      }
    } });
  if (boundary_size != reduce(boundary_count))
    cout << "Wrong boundary size: should be " << boundary_size 
	 << " is " << reduce(boundary_count) << endl;
}

// *************************************************************
//    CREATING A BOUNDING REGION AND INITIAL TRIANGULATION
// *************************************************************

void generate_boundary(sequence<point> const &P,
		       size_t boundary_size,
		       sequence<vertex_t> &V,
		       sequence<triang_t> &T) {

  size_t n = P.size();
  auto min_f = [] (point x, point y) { return x.minCoords(y);};
  auto max_f = [] (point x, point y) { return x.maxCoords(y);};
  point identity = P[0];
  point min_corner = reduce(P, make_monoid(min_f, identity));
  point max_corner = reduce(P, make_monoid(max_f, identity));
  vect diff = max_corner - min_corner;
  point center = min_corner + diff/2.0;
  double size = diff.Length();
  double radius = 10.0 * size; // Stretch factor for the bounding circle
  double pi = 3.141592653589793;

  // Generate the bounding points on a circle far outside the bounding box
  parallel_for (0, boundary_size, [&] (size_t i) {
    double angle = 2.0 * pi * (static_cast<double>(i) / boundary_size);
    point pt = center + vect(radius * cos(angle), radius * sin(angle));
    V[i+n] = vertex_t(pt, i + n);
  });

  // Fill with triangles (boundary_size - 2 total)
  // This part is sequential as it builds a fan of triangles
  simplex_t s = simplex_t(&V[n], &V[n+1], &V[n+2], &T[2*n]); 
  for (size_t i = 3; i < boundary_size; i++)
    s = s.extend(&V[i+n], &T[2*n + i - 2]); 
}


// *************************************************************
//    MAIN LOOP
// *************************************************************

void incrementally_add_points(sequence<vertex_t*> v, vertex_t* start) {
  size_t n = v.size();
  size_t num_workers = parlay::num_workers();

  // Adaptive batch size parameters. Start conservatively and grow/shrink based on contention.
  size_t max_block_size = std::min(n, (size_t) 16 * num_workers);
  if (max_block_size == 0) max_block_size = 1;
  size_t current_block_size = std::min(max_block_size, (size_t) num_workers);
  if (current_block_size == 0) current_block_size = 1;

  sequence<vertex_t*> done(n);
  sequence<vertex_t*> buffer(max_block_size);
  sequence<vertex_t*> remain;
  sequence<simplex_t> t(max_block_size);
  sequence<bool> flags(max_block_size);
  auto VQ = tabulate(max_block_size, [&] (size_t i) -> Qs_t {return Qs_t();});

  using KNN = k_nearest_neighbors<vertex_t,1>;
  sequence<vertex_t*> init(1,start);
  KNN knn = KNN(init);

  size_t num_done = 0;
  size_t num_tried = 0; // High-water mark for points taken from v
  size_t rounds = 0;
  size_t num_next_rebuild = 100;
  size_t multiplier = 10;

  while (num_done < n) {
    // Periodically rebuild the point location structure on a log scale.
    if (num_done >= num_next_rebuild && num_done < n/2) {
      auto vtxs = parlay::to_sequence(done.cut(0,num_done));
      knn = KNN(vtxs);
      num_next_rebuild *= multiplier;
    }

    size_t num_remain = remain.size();
    size_t num_to_grab_from_v = (current_block_size > num_remain)
                              ? std::min(current_block_size - num_remain, n - num_tried)
                              : 0;
    size_t num_round = num_remain + num_to_grab_from_v;

    // Populate buffer with retries and new points. This logic is corrected
    // to use a high-water mark `num_tried`.
    parallel_for(0, num_remain, [&] (size_t i) { buffer[i] = remain[i]; });
    parallel_for(0, num_to_grab_from_v, [&] (size_t i) { buffer[i + num_remain] = v[num_tried + i]; });
    num_tried += num_to_grab_from_v;

    // Phase 1: Point location and cavity reservation
    parallel_for (0, num_round, [&] (size_t j) {
      vertex_t *u = knn.nearest(buffer[j]);
      t[j] = find(buffer[j], simplex(u->t, 0));
      reserve_for_insert(buffer[j], t[j], &VQ[j]);
    });

    // Phase 2: Insertion attempt
    parallel_for (0, num_round, [&] (size_t j) {
      flags[j] = insert(buffer[j], t[j], &VQ[j]);
    });

    // Separate successful points from failed ones
    auto buffer_slice = buffer.cut(0,num_round);
    auto flags_slice = flags.cut(0,num_round);
    remain = pack(buffer_slice, flags_slice);
    size_t num_failed_in_round = remain.size();

    auto not_flags = delayed_seq<bool>(num_round, [&] (size_t i) { return !flags[i]; });
    size_t num_done_in_round = parlay::internal::pack_out(buffer_slice, not_flags, done.cut(num_done, num_done + num_round));
    num_done += num_done_in_round;
    rounds++;

    // Adapt block size for the next round based on contention.
    // If failure rate is high (>25%), reduce batch size.
    // If failure rate is low (<6.25%), increase batch size.
    if (num_failed_in_round > num_round / 4 && current_block_size > num_workers) {
      current_block_size = std::max(num_workers, current_block_size / 2);
    } else if (num_failed_in_round * 16 < num_round) {
      current_block_size = std::min(max_block_size, (current_block_size * 5) / 4 + 1);
    }
  }
}


// *************************************************************
//    DRIVER
// *************************************************************

triangles<point> delaunay(sequence<point> &P) {
  timer t("delaunay", false);
  t.start();
  size_t boundary_size = 10;
  size_t n = P.size();

  if (n == 0) return triangles<point>();

  // All vertices needed
  size_t num_vertices = n + boundary_size;
  auto Vertices = sequence<vertex_t>(num_vertices);

  // All triangles needed
  size_t boundary_triangles = (boundary_size - 2);
  size_t num_triangles = 2 * n + boundary_triangles;
