  generate_boundary(P, boundary_size, Vertices, Triangles);

  // Pointers to the first n vertices (the input points)
  auto V = tabulate(n, [&] (size_t i) -> vertex_t* {
			 return &Vertices[i];
  });
  vertex_t* v0 = &Vertices[n]; // A starting vertex on the boundary

  t.next("initialize");

  // Main loop to add all points
  incrementally_add_points(V, v0);
  t.next("add points");

  if (CHECK) check_delaunay(Triangles, boundary_size);

  // Filter out triangles that were not used or are part of the boundary
  auto valid_tri_flags = parlay::tabulate(num_triangles, [&](size_t i) {
    auto& tri = Triangles[i];
    return tri.vtx[0] != nullptr &&
           tri.vtx[0]->id < n &&
           tri.vtx[1]->id < n &&
           tri.vtx[2]->id < n;
  });

  auto final_triangles = parlay::pack(parlay::iota(num_triangles), valid_tri_flags);

  // just the three corner ids for each triangle
  auto result_triangles = tabulate(final_triangles.size(), [&] (size_t i) -> tri {
    vertex_t** vtx = Triangles[final_triangles[i]].vtx;
    return {(int) vtx[0]->id, (int) vtx[1]->id, (int) vtx[2]->id};
  });

  // just the original points
  auto result_points = P;

  t.next("generate output");

  return triangles<point>(result_points, result_triangles);
