//    DRIVER
// *************************************************************

// Increase QSIZE to allow for more parallelism on many-core machines.
// This increases memory but can improve throughput.
constexpr size_t QSIZE = 100000;

triangles<point> refineInternal(triangles<point>& Tri) {
  timer t("Delaunay Refine");
  // Increase expandFactor slightly to reduce risk of aborting on complex inputs.
  int expandFactor = 5;
  size_t n = Tri.numPoints();
  size_t m = Tri.numTriangles();
  size_t extraVertices = expandFactor*n;
  size_t totalVertices = n + extraVertices;
  size_t totalTriangles = m + 2 * extraVertices;

  sequence<vertex_t> Vertices;
  sequence<triang_t> Triangles;

  std::tie(Triangles, Vertices) = topology_from_triangles(Tri, extraVertices);
  t.next("from Triangles");

  // Sequence of pointers to the extra vertices, used for refinement.
  // Using pointers allows efficient repacking of failed vertices.
  sequence<vertex_t*> V = tabulate(extraVertices, [&](size_t i) {
    return &Vertices[i+n];
  });

  //  set up extra triangles
  parallel_for (m, totalTriangles, [&] (size_t i) {
    Triangles[i].id = i;
    Triangles[i].initialized = false;
  });

  //  set up extra vertices
  parallel_for (0, extraVertices, [&] (size_t i) {
    // Placement new to construct vertices in the pre-allocated buffer
    new (V[i]) vertex_t(point(0,0), i+n);
    // give each one a pointer to two triangles to use
    V[i]->t = &Triangles[m + 2*i];
  });
  t.next("initializing");

  size_t numPoints = n;

  TriangleTable workQ = makeTriangleTable(m);
  parallel_for(0, m, [&] (size_t i) {
    if (skinnyTriangle(&Triangles[i])) {
      workQ.insert(&Triangles[i]);
      Triangles[i].bad = 1;
    }
  });

  vertexQs VQ(QSIZE);
  t.next("Start");

  // Each iteration processes all bad triangles from the workQ while
  // adding new bad triangles to a new queue
  while (true) {
    sequence<triang_t*> badTT = workQ.entries();

    // packs out triangles that are no longer bad
    auto flags = tabulate(badTT.size(), [&] (size_t i) {
      return badTT[i]->bad;
    });
    auto badT = pack(badTT, flags);
    size_t numBad = badT.size();

    if (numBad == 0) break;
    if (numPoints + numBad > totalVertices) {
      std::cerr << "Error: Ran out of pre-allocated vertices. "
                << "Consider increasing expandFactor." << std::endl;
      abort();
    }
    size_t offset = numPoints - n;

    // allocate 1 vertex per bad triangle and assign triangle to it
    parallel_for (0, numBad, [&] (size_t i) {
      badT[i]->bad = 2; // used to detect whether touched
      V[i + offset]->badT = badT[i];
    });

    // the new empty work queue
    workQ = makeTriangleTable(numBad);

    // This does all the work adding new vertices, and any new bad
    // triangles to the workQ
    auto Vtx = V.cut(offset, offset+numBad);
    addRefiningVertices(Vtx, workQ, VQ);

    // push any bad triangles that were left untouched onto the Q
    parallel_for (0, numBad, [&] (size_t i) {
      if (badT[i]->bad==2) workQ.insert(badT[i]);
    });

    numPoints += numBad;
  }

  t.next("refinement");

  // Extract Vertices for result
  // A vertex is kept if it's an original vertex or a successfully added one.
  // Successfully added vertices have badT reset to nullptr.
  auto active_vertex_flags = tabulate(numPoints, [&] (size_t i) -> bool {
    return (Vertices[i].badT == nullptr);
  });

  sequence<size_t> old_indices = pack_index(active_vertex_flags);
  size_t final_n = old_indices.size();
  sequence<point> rp(final_n);

  // Create final points array and update vertex IDs for triangle construction
  parallel_for (0, final_n, [&] (size_t i) {
    Vertices[old_indices[i]].id = i;
    rp[i] = Vertices[old_indices[i]].pt;
  });

  // Extract Triangles for result
  // A triangle is kept if it was part of the final mesh.
  auto active_triangle_indices = pack_index(tabulate(Triangles.size(), [&] (size_t i) -> bool {
	 return Triangles[i].initialized;
  }));

  auto rt = tabulate(active_triangle_indices.size(), [&] (size_t i) -> tri {
    auto& t = Triangles[active_triangle_indices[i]];
    return {static_cast<unsigned int>(t.vtx[0]->id),
            static_cast<unsigned int>(t.vtx[1]->id),
            static_cast<unsigned int>(t.vtx[2]->id)};
  });

  t.next("finish");
  return triangles<point>(std::move(rp), std::move(rt));
}

triangles<point> refine(triangles<point> &Tri) {
  return refineInternal(Tri);
}
