    else {
      t2->initialized = 1;
      t.split(v, t1, t2);
    }

    // update the cavity
    for (size_t i = 0; i<q->simplexQ.size(); i++)
      (q->simplexQ)[i].flip();
    q->simplexQ.push_back(simplex_t(t0,0));
    q->simplexQ.push_back(simplex_t(t1,0));
    if (!t.isBoundary()) q->simplexQ.push_back(simplex_t(t2,0));

    for (size_t i = 0; i<q->simplexQ.size(); i++) {
      triang_t* current_t = (q->simplexQ)[i].t;
      if (skinnyTriangle(current_t)) {
        TT.insert(current_t);
        current_t->bad = 1;
      } else current_t->bad = 0;
    }
    v->badT = NULL;
  }
  q->simplexQ.clear();
  q->vertexQ.clear();
  return flag;
}


// *************************************************************
//    MAIN REFINEMENT LOOP
// *************************************************************

// Optimized version of addRefiningVertices.
// This version removes the costly inner retry loop. Failed insertions
// are deferred to the next round of the main refinement algorithm, which
// is a more efficient strategy for handling conflicts.
template <typename Slice>
void addRefiningVertices(Slice &V, TriangleTable &TT, vertexQs& VQ) {
  const size_t n = V.size();
  const size_t q_size = VQ.size();
  if (n == 0) return;

  // Process in batches to not overuse the temporary Qs storage
  size_t num_batches = (n + q_size - 1) / q_size;
  for (size_t i = 0; i < num_batches; ++i) {
    size_t offset = i * q_size;
    size_t count = std::min(q_size, n - offset);

    sequence<simplex_t> simplices(count);
    sequence<bool> can_insert(count);

    // Phase 1: All threads find their cavities and try to reserve
    // the boundary vertices. This must finish for the whole batch
    // before phase 2 begins.
    parallel_for(0, count, [&](size_t j) {
      can_insert[j] = findAndReserveCavity(V[offset + j], simplices[j], &VQ[j]);
    });

    // Phase 2: Check who won the reservations and insert points.
    parallel_for(0, count, [&](size_t j) {
      if (can_insert[j]) {
        addCavity(V[offset + j], simplices[j], &VQ[j], TT);
      }
    });
  }
}

// *************************************************************
//    DRIVER
// *************************************************************

#define QSIZE 20000

triangles<point> refineInternal(triangles<point>& Tri) {
  timer t("Delaunay Refine");
  int expandFactor = 4;
  size_t n = Tri.numPoints();
  size_t m = Tri.numTriangles();
  size_t extraVertices = expandFactor*n;
  size_t totalVertices = n + extraVertices;
  size_t totalTriangles = m + 2 * extraVertices;

  sequence<vertex_t> Vertices;
  sequence<triang_t> Triangles;
  sequence<vertex_t*> V(extraVertices);

  std::tie(Triangles, Vertices) = topology_from_triangles(Tri, extraVertices);
  t.next("from Triangles");

  //  set up extra triangles
  parallel_for (m, totalTriangles, [&] (size_t i) {
    Triangles[i].id = i;
    Triangles[i].initialized = 0;
  });

  //  set up extra vertices
  parallel_for (0, extraVertices, [&] (size_t i) {
    new (&Vertices[i+n]) vertex_t(point(0,0), i+n);
    V[i] = &Vertices[i+n];
    V[i]->t = &Triangles[m + 2*i];
  });
  t.next("initializing");

  size_t numTriangs = m;
  size_t numPoints = n;

  TriangleTable workQ = makeTriangleTable(numTriangs);
  parallel_for(0, numTriangs, [&] (size_t i) {
    if (skinnyTriangle(&Triangles[i])) {
      workQ.insert(&Triangles[i]);
      Triangles[i].bad = 1;
    } else {
      Triangles[i].bad = 0;
    }
  });

  vertexQs VQ(QSIZE);
  t.next("Start");

  while (true) {
    sequence<triang_t*> badTT = workQ.entries();

    auto flags = tabulate(badTT.size(), [&] (size_t i) -> bool {
      return badTT[i]->bad;});
    auto badT = pack(badTT, flags);
    size_t numBad = badT.size();

    if (numBad == 0) break;
    if (numPoints + numBad > totalVertices) {
      std::cerr << "Error: ran out of pre-allocated vertices." << endl;
      abort();
    }
    size_t offset = numPoints - n;

    // allocate 1 vertex per bad triangle and assign triangle to it
    parallel_for (0, numBad, [&] (size_t i) {
      badT[i]->bad = 2; // used to detect whether touched
      V[i + offset]->badT = badT[i];
    });

    // the new empty work queue for the next round
    workQ = makeTriangleTable(numBad > 0 ? 2*numBad : 1);

    // This does all the work adding new vertices, and any new bad
    // triangles to the new workQ
    auto Vtx = V.cut(offset, offset+numBad);
    addRefiningVertices(Vtx, workQ, VQ);

    // push any bad triangles that were left untouched onto the Q
    parallel_for (0, numBad, [&] (size_t i) {
      if (badT[i]->bad==2) workQ.insert(badT[i]);});

    numPoints += numBad;
    numTriangs += 2*numBad; // An estimate, could be less
  }

  t.next("refinement");

  // Robustly extract final mesh
  auto I_t = pack_index(tabulate(numTriangs, [&](size_t i) {
      return Triangles[i].initialized;
  }));
  size_t final_m = I_t.size();

  if (final_m == 0) {
      return triangles<point>();
  }

  // Collect all unique vertex pointers from final triangles
  auto all_vtx_p = parlay::flatten(parlay::tabulate(final_m, [&](size_t i) {
      auto& t = Triangles[I_t[i]];
      return parlay::make_slice(t.vtx, t.vtx + 3);
  }));
  parlay::sort_inplace(all_vtx_p);
  auto final_vtx_p = parlay::unique(all_vtx_p);
  size_t final_n = final_vtx_p.size();

  // Assign new, compact IDs
  parallel_for(0, final_n, [&](size_t i) {
      final_vtx_p[i]->id = i;
  });

  // Create final points array
  sequence<point> rp = tabulate(final_n, [&](size_t i) {
      return final_vtx_p[i]->pt;
  });

  // Create final triangles array with new indices
  auto rt = tabulate(final_m, [&](size_t i) -> tri {
      auto& t = Triangles[I_t[i]];
      return {static_cast<unsigned int>(t.vtx[0]->id),
              static_cast<unsigned int>(t.vtx[1]->id),
              static_cast<unsigned int>(t.vtx[2]->id)};
  });

  t.next("finish");
  return triangles<point>(std::move(rp), std::move(rt));
}

triangles<point> refine(triangles<point> &Tri) {
  return refineInternal(Tri);
}
// --- End of file: refine.C ---
