// This structure implements the 2D range query functionality.
// It is built once on a set of points and can then answer multiple range queries efficiently.
// The implementation uses a parallel sweep-line algorithm. The sweep is along the x-axis.
// A persistent balanced binary search tree (a PAM set) is used as the 1D data structure
// to store points ordered by their y-coordinate.
// After the sweep, we have a sequence of trees `ts`, where `ts[i]` contains all points
// from the input that have an x-coordinate less than `xs[i]`, where `xs` are the sorted
// x-coordinates of the input points.
struct RangeQuery {
  // The underlying 1D data structure is a persistent balanced binary search tree
  // from the PAM (Parallel Augmented Maps) library.
  struct set_t {
    using key_t = point;
    // Points are ordered primarily by y-coordinate, then by x-coordinate.
    // This allows us to query for a y-range efficiently.
    static bool comp(key_t a, key_t b) { 
	   return std::tie(a.y, a.x) < std::tie(b.y, b.x);
	}
  };
  using coord_set = pam_set<set_t>;

  // A sequence of persistent trees. `ts[i]` stores points with x-coordinates
  // corresponding to the first `i` points in the x-sorted input.
  parlay::sequence<coord_set> ts;

  // The sorted x-coordinates of the input points. Used for binary searching.
  parlay::sequence<coord> xs;

  RangeQuery(parlay::sequence<point> const &points) {
    // 1. Sort points by x-coordinate. This is the order for the sweep-line.
    auto A = parlay::sort(points, [] (point a, point b) { return a.x < b.x; });

    // 2. Extract the sorted x-coordinates for later queries.
    xs = parlay::map(A, [] (point p) { return p.x; });

    // 3. Define the operations for the parallel scan (sweep) that builds the trees.
    //    - insert: adds a single point to a tree.
    //    - build: creates a new tree from a range of points.
    //    - fold: merges two trees.
    auto insert = [&] (coord_set m, point a) { return coord_set::insert(m, a); };
    auto build = [&] (point* s, point* e) { return coord_set(s,e); };
    auto fold = [&] (coord_set m1, coord_set m2) { return coord_set::map_union(std::move(m1), std::move(m2)); };

    // 4. Perform the parallel sweep (a parallel exclusive scan).
    //    This builds the sequence of persistent trees `ts`. `ts[i]` contains the
    //    union of points A[0]...A[i-1]. This is the pre-computation step.
    //    Note: The baseline implementation had a bug where it passed the unsorted
    //    `points` sequence; we correctly pass the x-sorted sequence `A`.
    ts = sweep<coord_set>(A, coord_set(), insert, build, fold);
  }

  // Counts the number of points within the query rectangle [q.x1, q.x2] x [q.y1, q.y2].
  long count_in_range(query q) const {
    // The query is resolved using the principle of inclusion-exclusion.
    // The count is:
    //   (number of points with x <= q.x2 and y in [q.y1, q.y2])
    // - (number of points with x <  q.x1 and y in [q.y1, q.y2])

    // Find the tree corresponding to points with x <= q.x2.
    // `upper_bound` finds the first element > q.x2. The tree at this index `r_idx`
    // in our exclusive scan `ts` contains all points with x <= q.x2.
    auto xs_begin = xs.begin();
    auto xs_end = xs.end();
    long r_idx = std::upper_bound(xs_begin, xs_end, q.x2) - xs_begin;

    // Find the tree corresponding to points with x < q.x1.
    // `lower_bound` finds the first element >= q.x1. The tree at this index `l_idx`
    // contains all points with x < q.x1.
    long l_idx = std::lower_bound(xs_begin, xs_end, q.x1) - xs_begin;

    // Now, for a given tree, we need to count points in the y-range [q.y1, q.y2].
    // This is done by `count(y <= q.y2) - count(y < q.y1)`.
    // The `rank(k)` method on our tree counts elements strictly less than `k`.

    // To count `y <= q.y2`, we need a key `p_upper` that is greater than any point with y <= q.y2,
    // but less than any point with y > q.y2.
    // `nextafter` gives the smallest floating point number greater than q.y2.
    // The x-coordinate is set to -infinity to not interfere with the primary y-comparison.
    coord y2_succ = std::nextafter(q.y2, std::numeric_limits<coord>::max());
    point p_upper = point(-std::numeric_limits<coord>::max(), y2_succ);

    // To count `y < q.y1`, we use a key `p_lower` with y-coordinate q.y1.
    // `rank(p_lower)` will count all points with y < q.y1.
    point p_lower = point(-std::numeric_limits<coord>::max(), q.y1);

    // Query the respective trees.
    long right_count = ts[r_idx].rank(p_upper) - ts[r_idx].rank(p_lower);
    long left_count = ts[l_idx].rank(p_upper) - ts[l_idx].rank(p_lower);

    return right_count - left_count;
  }

  // Frees memory and resources used by the data structure.
  void clear() {
    ts.clear();
    // The PAM library may use garbage collection for its persistent nodes.
    // This call ensures all pending GC work is completed.
    coord_set::GC::finish();
  }
