// The RangeQuery class builds a data structure over a set of points
// to answer 2D range queries efficiently.
// It uses a plane sweep algorithm, building a series of persistent
// balanced binary search trees (BSTs).
struct RangeQuery {
  // A specialized version of a balanced BST from the PAM library.
  // It stores points, ordered lexicographically by their y then x coordinates.
  struct set_t {
    using key_t = point;
    // Comparison function for points in the BST.
    // Primary sort key is the y-coordinate, secondary is the x-coordinate.
    static bool comp(key_t a, key_t b) {
      return a.y < b.y || (a.y == b.y && a.x < b.x);
    }
  };
  using coord_set = pam_set<set_t>;

  // ts[i] stores a BST of the first i points from the x-sorted sequence.
  parlay::sequence<coord_set> ts;
  // xs stores the x-coordinates of the points, sorted.
  // This allows for efficient binary searching for the x-range of a query.
  parlay::sequence<coord> xs;

  // Constructor builds the data structure from the input points.
  // The algorithm is as follows:
  // 1. Sort the points by their x-coordinate.
  // 2. Perform a parallel prefix sum (scan) over the sorted points.
  //    The operation at each step is to insert the point into a BST.
  //    This creates a sequence of BSTs, where ts[i] contains all points
  //    with index less than i in the sorted array.
  // This structure allows querying the set of points in any x-range [x1, x2]
  // by inspecting the trees at the start and end of the range.
  RangeQuery(parlay::sequence<point>& points) {
    // Sort points by x-coordinate. This is the "sweep line" ordering.
    auto less = [](point a, point b) { return a.x < b.x; };
    parlay::sort_inplace(points, less);

    // Extract the sorted x-coordinates for efficient binary searching in queries.
    xs = parlay::map(points, [](point p) { return p.x; });

