      return coord_set::insert(m, a);
    };

    // build: constructs a BST from a range of points. This is used by the
    // scan for building BSTs for blocks of the input in parallel.
    auto build = [&](point* s, point* e) {
      return coord_set(s, e);
    };

    // fold: merges two BSTs. This is the associative operator for the scan.
    auto fold = [&](coord_set m1, coord_set m2) {
      return coord_set::map_union(std::move(m1), std::move(m2));
    };

    // The sweep function is a parallel scan that builds the prefix BSTs.
    // ts[i] will contain the union of points[0...i-1].
    ts = sweep<coord_set>(points, coord_set(), insert, build, fold);
  }

  // Counts the number of points within a given query rectangle [x1, x2] x [y1, y2].
  long count_in_range(const query& q) const {
    // Find the indices [l, r) in the x-sorted array that correspond to the
    // query's x-range [x1, x2].
    // lower_bound finds the first element >= x1.
    // upper_bound finds the first element > x2.
    // This correctly covers the inclusive range [x1, x2].
    auto it_l = std::lower_bound(xs.begin(), xs.end(), q.x1);
    auto it_r = std::upper_bound(xs.begin(), xs.end(), q.x2);
    long l = it_l - xs.begin();
    long r = it_r - xs.begin();

    if (l >= r) {
      return 0;
    }

    // The number of points in the x-range [x1, x2] is the difference
    // between the number of points up to index r and the number up to index l.
    // We query the BSTs ts[r] and ts[l] for the y-range.

    // Create query points to find counts for the y-range [y1, y2].
    // `rank(p)` in PAM counts elements strictly less than p.
    // To count points with y <= y2, we need a key that is greater than all
    // such points. A point with y=y2 and a very large x works.
    point p_upper(std::numeric_limits<coord>::max(), q.y2);
    // To count points with y < y1, we need a key that is greater than all
    // such points. A point with y=y1 and a very small x works.
    point p_lower(std::numeric_limits<coord>::lowest(), q.y1);

    // `count_y(S)` calculates the number of points in a BST `S`
    // whose y-coordinate is in the range [y1, y2].
    auto count_y = [&](const coord_set& s) {
      // s.rank(p_upper) counts points with y <= y2.
      // s.rank(p_lower) counts points with y < y1.
      // The difference is the count of points with y in [y1, y2].
      return s.rank(p_upper) - s.rank(p_lower);
    };

    // The final count is the number of points in the desired y-range in ts[r]
    // minus the number of points in that y-range in ts[l].
    return count_y(ts[r]) - count_y(ts[l]);
  }

  // Frees memory used by the persistent BSTs.
  void clear() {
    ts.clear();
    coord_set::GC::finish();
  }
};

long range(Points const &points, Queries const &queries, bool verbose) {
  parlay::internal::timer t("range", verbose);
  // Create a mutable copy of points for sorting.
  auto P = points;
  RangeQuery r(P);
  t.next("build");

  // Process all queries in parallel using parlay::map.
  auto counts = parlay::map(queries, [&](const query& q) {
    return r.count_in_range(q);
  });

  // Sum up the counts from all queries.
  long total = parlay::reduce(counts);
  t.next("query");

  // Clean up the data structure and perform garbage collection.
  r.clear();
  t.next("clear");
  return total;
}
