//    - We perform binary searches on the sorted x-coordinates to find the indices
//      `l` and `r` that correspond to the query's x-range [x1, x2].
//    - The count of points in the rectangle is the number of points in the tree
//      for the upper x-bound (`ts[r-1]`) with y in [y1, y2] minus the number of
//      points in the tree for the lower x-bound (`ts[l-1]`) with y in [y1, y2].
//    - The y-range count within a PAM set is found efficiently using two rank
//      queries, giving a total query time of O(log n) per query.
//
// This approach is parallelized at all stages using ParlayLib and PAM, resulting
// in a high-performance, scalable solution.
struct RangeQuery {
  // PAM set, a parallel balanced binary search tree.
  // It stores points and compares them lexicographically on (y, x).
  struct set_t {
    using key_t = point;
    // Comparison for sorting points by y, then x.
    static bool comp(key_t a, key_t b) { 
      if (a.y < b.y) return true;
      if (a.y > b.y) return false;
      return a.x < b.x;
	  }
  };
  using coord_set = pam_set<set_t>;

  // ts[i] is a coord_set of the first i+1 points in x-sorted order.
  parlay::sequence<coord_set> ts;
  // xs contains the sorted x-coordinates of the points.
  parlay::sequence<coord> xs;

  explicit RangeQuery(parlay::sequence<point> const &points) {
    // Sort points by x-coordinate. This is the sweep line order.
    auto A = parlay::sort(points, [] (point a, point b) { return a.x < b.x; });

    // Store the sorted x-coordinates for efficient searching during queries.
    xs = parlay::map(A, [] (point p) { return p.x; });

    // Define operations for the parallel sweep.
    // insert: used for sequential building (not in parallel path).
    auto insert = [&] (coord_set m, point a) {
      return coord_set::insert(m, a);};

    // build: create a coord_set from a subsequence of points.
    auto build = [&] (point* s, point* e) {
      return coord_set(s, e);};

    // fold: merge two coord_sets. `map_union` is an efficient parallel merge for PAM.
    auto fold = [&] (coord_set m1, coord_set m2) {
      return coord_set::map_union(std::move(m1), std::move(m2));};

    // The sweep builds a sequence of persistent coord_sets.
    // ts[i] will contain the points A[0...i].
    // CRITICAL FIX: We must pass the x-sorted points `A` to the sweep.
    ts = sweep<coord_set>(A, coord_set(), insert, build, fold);
