  // Counts the number of points within the query rectangle q.
  long count_in_range(const query& q) const {
    // Find the range of indices [l, r) in the sorted `xs` array
    // that correspond to the query's x-range [q.x1, q.x2].
    // `lower_bound` finds the first element >= q.x1.
    auto it_l = std::lower_bound(xs.begin(), xs.end(), q.x1);
