    // correct for a closed interval [x1, x2].
    auto it_r = std::upper_bound(xs.begin(), xs.end(), q.x2);

    long l_idx = it_l - xs.begin();
    long r_idx = it_r - xs.begin();

    if (l_idx >= r_idx) return 0;

    // The set of points with x <= x_r is ts[r_idx-1].
    // The set of points with x < x_l is ts[l_idx-1].
    // The difference in y-range counts gives the result for the x-range [x_l, x_r].

    // A point `p` used for rank query. `rank(p)` counts elements strictly less than `p`.
    // To count elements with y-coordinate <= q.y2, we query for rank of a point
    // that is guaranteed to be greater than all such points, e.g., {DBL_MAX, q.y2}.
    // To count elements with y-coordinate < q.y1, we query for rank of { -DBL_MAX, q.y1}.
