  // A sequence of persistent balanced trees.
  // ts[i] stores all points from the first i+1 points of the x-sorted sequence.
  parlay::sequence<coord_set> ts;

  // The sorted x-coordinates of the points, used for binary searching.
  parlay::sequence<coord> xs;

  RangeQuery(parlay::sequence<point> const &points) {
    // 1. Sort points by x-coordinate. This is the primary axis for our structure.
    auto A = parlay::sort(points, [] (point a, point b) { return a.x < b.x; });

    // 2. Extract the sorted x-coordinates for efficient searching.
    xs = parlay::map(A, [] (point p) { return p.x; });

    // 3. Define operations for the parallel prefix sum (sweep).
    // The sweep builds a sequence of trees, where ts[i] is the union
    // of the trees for all points up to A[i].

    // insert: used by sweep for single-element base cases.
    auto insert = [&] (coord_set m, point a) {
      return coord_set::insert(m, a);
    };

    // build: create a tree from a chunk of points.
    auto build = [&] (point* s, point* e) {
      return coord_set(s, e);
    };

    // fold: merge two trees. This is the key associative operation for the parallel scan.
    auto fold = [&] (coord_set m1, coord_set m2) {
      return coord_set::map_union(std::move(m1), std::move(m2));
    };

    // 4. The sweep function is a parallel scan (prefix sum).
    // It must operate on the x-sorted points to build the prefix structure correctly.
    // A block size of 2048 is used for better performance by reducing parallel overhead.
    ts = sweep<coord_set>(A, coord_set(), insert, build, fold, 2048);
  }

  long count_in_range(query q) const {
    // We want to count points (x, y) such that x1 <= x <= x2 and y1 <= y <= y2.
    // The strategy is an inclusion-exclusion on the x-axis:
    // Count = (points with x <= x2 and y in [y1, y2])
    //       - (points with x < x1 and y in [y1, y2])

    // Find the number of points with x < x1.
    // std::lower_bound finds the first element >= q.x1.
    // The distance to this iterator is the count of elements < q.x1.
    auto it_l = std::lower_bound(xs.begin(), xs.end(), q.x1);
    long l_idx = std::distance(xs.begin(), it_l);

    // Find the number of points with x <= x2.
    // std::upper_bound finds the first element > q.x2.
    // The distance to this iterator is the count of elements <= q.x2.
    auto it_r = std::upper_bound(xs.begin(), xs.end(), q.x2);
    long r_idx = std::distance(xs.begin(), it_r);

    // Helper lambda to perform the y-range count on a given prefix tree.
    auto count_y = [&](long end_idx) {
      if (end_idx <= 0) {
        return 0L;
      }
      // ts[end_idx - 1] is the tree for points A[0...end_idx-1].
      const auto& tree = ts[end_idx - 1];

      // We need to count points with y in [y1, y2].
      // This is (count of points with y <= y2) - (count of points with y < y1).
      // tree.rank(k) counts elements strictly less than k.

      // To count y < y1: use a key with y=y1 and a minimal x.
      // Any point p with p.y < y1 will be smaller.
      // Any point p with p.y == y1 will not be smaller (since p.x >= -DBL_MAX).
      long count_lt_y1 = tree.rank(point(-DBL_MAX, q.y1));

