      // Any point p with p.y < y2 will be smaller.
      // Any point p with p.y == y2 will also be smaller (since p.x < DBL_MAX).
      long count_le_y2 = tree.rank(point(DBL_MAX, q.y2));

      return count_le_y2 - count_lt_y1;
    };

    // Calculate the counts for the two x-ranges and find the difference.
    long count_le_x2 = count_y(r_idx);
    long count_lt_x1 = count_y(l_idx);

    return count_le_x2 - count_lt_x1;
  }

  void clear() {
    ts.clear();
    coord_set::GC::finish();
  }
