#include <algorithm>
#include <limits>
#include <cfloat>
#include "parlay/primitives.h"
#include "parlay/internal/get_time.h"
#include "pam/pam.h"
#include "sweep.h"
#include "range.h"

// This data structure is built on a classic technique for 2D range queries.
// 1. The points are first sorted by their x-coordinate.
// 2. A sequence of persistent balanced binary search trees (BSTs) is built.
//    The i-th BST, ts[i], stores all points from the first i points in the
//    x-sorted list. These BSTs are ordered by the y-coordinate of the points.
//    This sequence of trees is built efficiently in parallel using a sweep-line
//    algorithm, which is functionally equivalent to a parallel scan (prefix sum).
// 3. A query for a rectangle [x1, x2] x [y1, y2] is answered by using this structure.
//    a. Find the indices `l` and `r` in the x-sorted array corresponding to the
//       start of the range `x >= x1` and the end of the range `x <= x2`.
//    b. The set of points with x-coordinates in [x1, x2] is the set of points in
//       the r-th prefix minus the set of points in the l-th prefix.
//    c. Because the BSTs are persistent, we can access ts[r] and ts[l] to represent
//       these two sets.
//    d. The number of points in the query rectangle is then the number of points
//       in ts[r] with y in [y1, y2] minus the number of points in ts[l] with
//       y in [y1, y2].
//    e. A y-range query in a BST can be answered in O(log n) time using rank queries.
//
// This approach has an O(n log n) parallel build time and an O(log n) query time,
// which is highly efficient. Queries themselves are run in parallel.
struct RangeQuery {
  // PAM Set ordered by y-coordinate, then x-coordinate.
  struct set_t {
    using key_t = point;
    // Comparator for y-major order.
    static bool comp(key_t a, key_t b) {
      if (a.y < b.y) return true;
      if (a.y > b.y) return false;
      return a.x < b.x;
    }
  };
  using coord_set = pam_set<set_t>;

  // ts[i] stores the first i points from the x-sorted list in a y-sorted BST.
  parlay::sequence<coord_set> ts;
  // Sorted x-coordinates for efficient binary searching.
  parlay::sequence<coord> xs;

  RangeQuery(parlay::sequence<point> const &points) {
    // Sort points by x-coordinate to enable the sweep-line approach.
    auto A = parlay::sort(points, [] (point a, point b) {
      return a.x < b.x;
    });

    xs = parlay::map(A, [] (point p) { return p.x; });

    // Define operations for the parallel sweep (scan) that builds the trees.
    auto insert = [&] (coord_set m, point a) {
      return coord_set::insert(m, a);
    };

    auto build = [&] (point* s, point* e) {
      return coord_set(s, e);
    };

    auto fold = [&] (coord_set m1, coord_set m2) {
      return coord_set::map_union(std::move(m1), std::move(m2));
    };

    // The sweep function builds a sequence of n+1 structures. ts[i] is the
    // aggregation of the first i elements. ts[0] is the identity.
    // The sweep must be performed on the x-sorted points for the query logic to be correct.
    ts = sweep<coord_set>(A, coord_set(), insert, build, fold, 1);
  }

  // Counts the number of points within the query rectangle [x1, x2] x [y1, y2].
  long count_in_range(query q) {
    // Find the range of indices [l, r) in the x-sorted array.
    // l: index of the first point p such that p.x >= q.x1.
    // r: index of the first point p such that p.x > q.x2.
    auto it_l = std::lower_bound(xs.begin(), xs.end(), q.x1);
    auto it_r = std::upper_bound(xs.begin(), xs.end(), q.x2);
    long l = it_l - xs.begin();
    long r = it_r - xs.begin();

    // If the range is empty, there are no points.
    if (l >= r) return 0;

    // ts[i] contains points with index < i in the sorted array A.
    // The set of points with x <= q.x2 is effectively represented by ts[r].
    // The set of points with x < q.x1 is effectively represented by ts[l].
    // The difference of counts gives the result for points with x in [q.x1, q.x2].
    const auto& tree_r = ts[r];
    const auto& tree_l = ts[l];

    // Create keys for rank queries to find points in the y-range [q.y1, q.y2].
    // rank(key) counts elements strictly less than key.
    // To count elements with y <= q.y2, we need a key that is greater than
    // all points with y <= q.y2, but less than any with y > q.y2.
    // A key with y=q.y2 and x=DBL_MAX works for this.
    point key_y2_upper(DBL_MAX, q.y2);
    // To count elements with y < q.y1, we need a key that is greater than
    // all points with y < q.y1, but less than or equal to any with y >= q.y1.
    // A key with y=q.y1 and x=-DBL_MAX works for this.
    point key_y1_lower(-DBL_MAX, q.y1);

    // Calculate count for points with x <= q.x2
    long right_count = tree_r.rank(key_y2_upper) - tree_r.rank(key_y1_lower);

    // Calculate count for points with x < q.x1
    long left_count = tree_l.rank(key_y2_upper) - tree_l.rank(key_y1_lower);

    return right_count - left_count;
  }

  void clear() {
    ts.clear();
    xs.clear();
    // PAM uses a custom garbage collector that needs to be finalized.
    coord_set::GC::finish();
  }
};

long range(Points const &points, Queries const &queries, bool verbose) {
  parlay::internal::timer t("range", verbose);
  if (points.empty() || queries.empty()) return 0;

  RangeQuery r(points);
  t.next("build");

  // Process all queries in parallel and sum the results.
  auto counts = parlay::map(queries, [&] (query q) {
    return r.count_in_range(q);
  });
  long total = parlay::reduce(counts);
  t.next("query");

#ifdef CHECK
  // Check the correctness of the first 10 queries against a naive serial implementation.
  // Note: The naive check is O(n*m) and very slow.
  int num_queries_to_check = std::min((size_t)10, queries.size());
  size_t n = points.size();

  for (int i = 0; i < num_queries_to_check; i++) {
    size_t naive_count = 0;
    for (size_t j = 0; j < n; j++) {
      if ((points[j].x >= queries[i].x1) && (points[j].x <= queries[i].x2) &&
          (points[j].y >= queries[i].y1) && (points[j].y <= queries[i].y2)) {
        naive_count++;
      }
    }
    long algo_result = counts[i];
    if (naive_count != algo_result) {
      std::cout << "Query " << i << " incorrect. Naive: " << naive_count 
                << ", Algo: " << algo_result << std::endl;
    }
  }
#endif

  r.clear();
  t.next("clear");
  return total;
}
