  return node_pool.allocate(r[0], r[1], n, b);
}

bool far(node* a, node* b) {
  double rmax = max(a->radius(), b->radius());
  double r = (a->center() - b->center()).Length();
  return r >= (ALPHA * rmax);
}

struct interactions_count {
  long direct;
  long indirect;
  interactions_count() : direct(0), indirect(0) {}
  interactions_count(long a, long b) : direct(a), indirect(b) {}
  interactions_count operator+ (interactions_count b) {
    return interactions_count(direct + b.direct, indirect + b.indirect);}
};

interactions_count interactions(node* Left, node* Right) {
  if (far(Left,Right)) {
    Left->indirectNeighbors.push_back(Right); 
    Right->indirectNeighbors.push_back(Left); 
    return interactions_count(0,2);
  } else {
    if (!Left->leaf() && (Left->lmax() >= Right->lmax() || Right->leaf())) {
      interactions_count x = interactions(Left->left, Right);
      interactions_count y = interactions(Left->right, Right);
      return x + y;
    } else if (!Right->leaf()) {
      interactions_count x = interactions(Left, Right->left);
      interactions_count y = interactions(Left, Right->right);
      return x + y;
    } else { // both are leaves
      if (Right->n > Left->n) swap(Right,Left);
      size_t rn = Right->leftNeighbors.size();
      size_t ln = Left->rightNeighbors.size();
      Right->leftNeighbors.push_back(edge(Left,ln)); 
      Left->rightNeighbors.push_back(edge(Right,rn));
      return interactions_count(Right->n*Left->n,0);
    }
  }
}

interactions_count interactions(node* tr) {
  if (!tr->leaf()) {
    interactions_count x, y, z; 
    x = interactions(tr->left);
    y = interactions(tr->right);
    z = interactions(tr->left,tr->right);
    return x + y + z;
  } else return interactions_count(0,0);
}

void doIndirect(node* tr) {
  for (size_t i = 0; i < tr->indirectNeighbors.size(); i++) 
    tr->OutExp->addTo(tr->indirectNeighbors[i]->InExp);
  if (!tr->leaf()) {
    parlay::par_do([&] () {doIndirect(tr->left);},
		   [&] () {doIndirect(tr->right);});
  }
}

void upSweep(node* tr) {
  if (tr->leaf()) {
    for (size_t i=0; i < tr->n; i++) {
      particle* P = tr->particles[i];
      tr->InExp->addTo(P->pt, P->mass);
    }
  } else {
    parlay::par_do([&] () {upSweep(tr->left);},
		   [&] () {upSweep(tr->right);});
    tr->InExp->addTo(tr->left->InExp);
    tr->InExp->addTo(tr->right->InExp);
  }
}

void downSweep(node* tr) {
  if (tr->leaf()) {
    for (size_t i=0; i < tr->n; i++) {
      particle* P = tr->particles[i];
      P->force = P->force + tr->OutExp->force(P->pt, P->mass);
    }
  } else {
    parlay::par_do([&] () {tr->left->OutExp->addTo(tr->OutExp);
	                   downSweep(tr->left);},
		   [&] () {tr->right->OutExp->addTo(tr->OutExp);
		           downSweep(tr->right);});
  }
}

// OPTIMIZATION: Parallel recursive collection of leaf nodes.
void getLeaves_par(node* tr, parlay::slice<node**> leaves_slice) {
  if (tr->leaf()) {
    if (!leaves_slice.empty()) leaves_slice[0] = tr;
    return;
  }
  auto left_slice = leaves_slice.cut(0, tr->left->num_leaves);
  auto right_slice = leaves_slice.cut(tr->left->num_leaves, leaves_slice.size());
  parlay::par_do(
      [&] { getLeaves_par(tr->left, left_slice); },
      [&] { getLeaves_par(tr->right, right_slice); }
  );
}

// OPTIMIZATION: SIMD vectorization of direct force calculation.
auto direct(node* Left, node* ngh) {
  auto LP = Left->particles.data();
  auto R = ngh->particles_d.data();
  size_t nl = Left->n;
  size_t nr = ngh->n;
  parlay::sequence<vect3d> hold(nr, vect3d(0.,0.,0.));
  constexpr double min_r2 = 1e-20; // Softening factor for stability and vectorization.

  for (size_t i=0; i < nl; i++) {
    vect3d frc(0.,0.,0.);
    particle* pa_ptr = LP[i];
    const point pa_pt = pa_ptr->pt;
    const double pa_mass = pa_ptr->mass;

    // This pragma advises the compiler to use SIMD instructions (e.g., AVX, SSE)
    // to process multiple particles in the inner loop simultaneously.
    #pragma omp simd
    for (size_t j=0; j < nr; j++) {
      const particle& pb = R[j];
      vect3d v = pb.pt - pa_pt;
      double r2 = v.dot(v);
      r2 = std::max(r2, min_r2); // Avoid singularity and remove branching
      double inv_r3 = 1.0 / (r2 * sqrt(r2));
      vect3d force = v * (pa_mass * pb.mass * inv_r3);
      hold[j] = hold[j] - force;
      frc = frc + force;
    }
    pa_ptr->force = pa_ptr->force + frc;
  }
  return hold;
}

void self(node* Tr) {
  auto PP = (Tr->particles).data();
  size_t n = Tr->n;
  constexpr double min_r2 = 1e-20;
  for (size_t i=0; i < n; i++) {
    particle* pa = PP[i];
    const point pa_pt = pa->pt;
    const double pa_mass = pa->mass;
    vect3d force_on_pa(0.,0.,0.);
    for (size_t j=i+1; j < n; j++) {
        particle* pb = PP[j];
        vect3d v = pb->pt - pa_pt;
        double r2 = v.dot(v);
        if (r2 > min_r2) {
            double inv_r3 = 1.0 / (r2 * sqrt(r2));
            vect3d force = v * (pa_mass * pb->mass * inv_r3);
            pb->force = pb->force - force;
            force_on_pa = force_on_pa + force;
        }
    }
    pa->force = pa->force + force_on_pa;
  }
}

void doDirect(node* a) {
  size_t nleaves = numLeaves(a);
  if (nleaves == 0) return;
  sequence <node*> Leaves(nleaves);
  getLeaves_par(a, parlay::make_slice(Leaves)); // Use parallel version

  parlay::parallel_for (0, nleaves, [&] (size_t i) {
      size_t rn = Leaves[i]->rightNeighbors.size();
      if (rn > 0) {
        Leaves[i]->hold = parlay::tabulate(rn, [&] (size_t j) {
            return direct(Leaves[i], Leaves[i]->rightNeighbors[j].first);
        });
      }
  }, 1);

  parlay::parallel_for (0, nleaves, [&] (size_t i) {
    node* L = Leaves[i];
    for (size_t j = 0; j < L->leftNeighbors.size(); j++) {
      auto [u, v] = L->leftNeighbors[j];
      auto& forces_to_add = u->hold[v];
      for (size_t k=0; k < L->n; k++) 
        L->particles[k]->force = L->particles[k]->force + forces_to_add[k];
    }
  }, 1);

  parlay::parallel_for (0, nleaves, [&] (size_t i) {self(Leaves[i]);}, 1);
}

void stepBH(sequence<particle*> &particles, double alpha) {
  timer t("CK nbody");
  TRglobal->precompute();

  parlay::parallel_for (0, particles.size(), [&] (size_t i) {
      particles[i]->force = vect3d(0.,0.,0.);});

  sequence<particle*> part_copy = particles;

  node* a = buildTree(part_copy, 0);
  t.next("build tree");

  upSweep(a);
  t.next("up sweep");

  interactions_count z = interactions(a);
  t.next("interactions");

  doIndirect(a);
  t.next("do Indirect");

  downSweep(a);
  t.next("down sweep");

  doDirect(a);
  t.next("do Direct");

  cout << "Direct = " << z.direct << " Indirect = " << z.indirect
       << " Boxes = " << numLeaves(a) << endl;
  if (CHECK) {
    cout << "  Sampled RMS Error = "<< check(particles) << endl;
    t.next("check");
  }
}

void nbody(sequence<particle*> &particles) {
  timer t("nbody wrapper", false);
  size_t n = particles.size();
  if (n == 0) return;

  // OPTIMIZATION: Improve data locality.
  // 1. Copy particle data into a contiguous memory block.
  //    This is the most critical optimization for pointer-based tree codes.
  auto p_storage = parlay::tabulate(n, [&](size_t i) { return *particles[i]; });
  t.next("copy in");

  // 2. Create a sequence of pointers that point into the new contiguous block.
  //    The rest of the algorithm will use these pointers, benefiting from cache locality.
  auto p_pointers = parlay::tabulate(n, [&](size_t i) { return &p_storage[i]; });

  // Run the main algorithm on the locality-optimized data.
  stepBH(p_pointers, ALPHA);

  // 3. Copy the computed forces back to the original particle objects.
  parlay::parallel_for(0, n, [&] (size_t i) {
    particles[i]->force = p_storage[i].force;
  });
  t.next("copy out");
}
